insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zelportret-van-gogh','Zelportret van Gogh','Vincent van Gogh (1887) \nEen van de vele zelfportretten die van Gogh schilderde. Ditmaal met een grijs/blauw kleurenschema wat een vrij onbekend kleurenpallet voor van Gogh was. Hierdoor heeft hij in dit schilderij zelfs de kleur van zijn ogen veranderd, deze zijn van nature groen. \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2022/04/Zelfportet-van-Gogh-Kunstdoekje-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],true,true,6334) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-skelet','Het skelet','Vincent van Gogh (1887) \nEen fleurige weergave van een somber element. Van Gogh schilderde deze schedel tijdens zijn periode in Parijs, mei 1887 om precies te zijn!','https://kunstdoekje.nl/wp-content/uploads/2022/04/Het-skelet-kunstdoekje-optimized.jpg',(select id from categories where slug='van-gogh'),array['van-gogh'],true,true,6428) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('populierenlaan-in-de-herfst','Populierenlaan in de herfst','Duik in de wereld van "Avenue of Poplars in Autumn", een meesterwerk van Vincent van Gogh uit 1884. Dit schilderij vangt de magie van de herfst met levendige kleuren en schaduwen. Voor de beste ervaring raden we je aan dit kunstwerk op onze fluwele stof te bestellen.','https://kunstdoekje.nl/wp-content/uploads/2022/04/222.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,6457) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonnebloemen','Zonnebloemen','Duik in "Zonnebloemen", een stralend kunstdoekje van Vincent van Gogh uit 1889. Gecreëerd in het schilderachtige Arles, Zuid-Frankrijk, brengt dit kunstdoekje de levendige zonnebloemen tot leven met drie schitterende tinten geel. Voor Van Gogh symboliseerden deze zonnebloemen ''dankbaarheid''.','https://kunstdoekje.nl/wp-content/uploads/2022/04/217.png',(select id from categories where slug='bloemen'),array['bloemen','van-gogh'],true,true,6486) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cafetafel-met-absint','Cafétafel met absint','"Cafétafel met absint", een intrigerend kunstdoekje van Vincent van Gogh uit 1887. Geschilderd in Parijs, toont het een cafétafeltje met een glas absint, een populair aperitief met een hoog alcoholpercentage. Van Gogh''s techniek, genaamd ''peinture à l’essence'', geeft het doek een waterverfachtige uitstraling. Hoewel Van Gogh zelf vaak absint dronk, waarschuwt dit kunstdoekje voor de gezondheidsrisico''s ervan.','https://kunstdoekje.nl/wp-content/uploads/2022/04/228.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,6515) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zelfportret-met-strohoed','Zelfportret met strohoed','Zelfportret met pijp en strohoed", een fascinerend kunstdoekje van Vincent van Gogh. Dit zelfportret, gemaakt in 1887, toont Van Gogh met een kenmerkende strohoed en pijp, en belicht zijn unieke stijl en techniek. De levendige kleuren en expressieve penseelstreken geven een diepgaand inzicht in de ziel van de kunstenaar.','https://kunstdoekje.nl/wp-content/uploads/2022/04/226.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,6544) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-roze-perzikboom','De roze perzikboom','\n \n "De roze perzikboom", een levendig kunstdoekje van Vincent van Gogh uit 1888. Tijdens zijn eerste weken in Arles, Zuid-Frankrijk, zette Van Gogh bijna dagelijks zijn ezel op in de boomgaard om de schitterende bloesems vast te leggen. In korte tijd schilderde hij vijftien boomgaarden, in de hoop dat deze schilderijen goed zouden verkopen, aangezien hij geloofde dat de onderwerpen de kracht hadden om iedereen op te vrolijken. Dit specifieke kunstdoekje is een van de twee versies; de eerste werd opgedragen aan Anton Mauve, een bekende kunstenaar en Van Gogh''s oom door huwelijk, terwijl deze','https://kunstdoekje.nl/wp-content/uploads/2022/04/218.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,6573) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vaas-met-gladiolen','Vaas met gladiolen','"Vaas met tuingladiolen en Chinese asters", een betoverend kunstdoekje van Vincent van Gogh uit 1886. Tijdens zijn tijd in Parijs schilderde Van Gogh dit levendige bloemstilleven, waarbij hij speelde met sterke kleurcontrasten zoals groen naast rood en blauw naast oranje. Geïnspireerd door de kleurentheorie van Eugène Delacroix, een Franse kunstenaar die Van Gogh bewonderde, is dit kunstdoekje een prachtige weergave van zijn experimenten met complementaire kleuren.','https://kunstdoekje.nl/wp-content/uploads/2022/04/224.png',(select id from categories where slug='bloemen'),array['bloemen','van-gogh'],false,true,6602) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen','Stilleven met bloemen','"Vaas met Chinese asters en tuingladiolen", een levendig kunstdoekje van Vincent van Gogh uit 1886. Na zijn ontmoeting met de bloemstillevens van Adolphe Monticelli in Parijs, begon Van Gogh met een robuustere schilderstijl, waarbij hij de bloemen met dikke, nadrukkelijke penseelstreken op het doek zette. Het afgebeelde vaasje, dat zich in de collectie van het Van Gogh Museum bevindt, is in werkelijkheid kleiner dan op het schilderij.','https://kunstdoekje.nl/wp-content/uploads/2022/04/227.png',(select id from categories where slug='bloemen'),array['bloemen','van-gogh'],false,true,6659) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-groen','Stilleven met bloemen (groen)','"Vaas met bloemen", een sprankelend kunstdoekje van Vincent van Gogh uit 1886. Dit stuk, geschilderd in het pittoreske Auvers-sur-Oise, toont een boeket dat lijkt te dansen met levendige kleuren en expressieve penseelstreken. Van Gogh schilderde dit kunstdoekje met een losse hand en duidelijke vaart, waardoor de bloemen nog net herkenbaar zijn, omlijst door vrij grove blauwe contouren. En een leuk weetje voor jou: hij schilderde dit boeket thuis bij zijn arts en goede vriend, Paul-Ferdinand Gachet, op diens rode tafel die hier als ondergrond voor de vaas dient.','https://kunstdoekje.nl/wp-content/uploads/2022/04/220.png',(select id from categories where slug='bloemen'),array['bloemen','van-gogh'],false,true,6688) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zelfportet-als-schilder','Zelfportet als schilder','"Zelfportret als schilder", een intrigerend kunstdoekje van Vincent van Gogh uit 1887-1888. In dit zelfportret stelt Van Gogh zichzelf voor als een moderne kunstenaar, met palet en penselen in de hand, staand achter een doek op een schildersezel. De felle, bijna ongemengde kleuren en de complementaire kleurenparen op zijn palet tonen zijn gedurfde experimenten met kleur. Het blauw van zijn kiel en het oranjerood van zijn baard versterken elkaar prachtig. Dit kunstdoekje, gemaakt tijdens zijn laatste dagen in Parijs, weerspiegelt zowel zijn artistieke evolutie als de persoonlijke uitdagingen wa','https://kunstdoekje.nl/wp-content/uploads/2022/04/234.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,6754) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-man-met-een-oog','Portret van man met één oog','"Portret van een man met één oog", een intrigerend kunstdoekje van Vincent van Gogh uit de herfst van 1889. Dit portret, geschilderd in Saint-Rémy-de-Provence, toont een man wiens ene oog opvalt door zijn heldere, blauwgroene kleur, terwijl het andere ooglid naar beneden hangt, wat suggereert dat hij mogelijk blind was aan dat oog of een oogziekte had. Deze man was een van de patiënten in de psychiatrische inrichting waar Van Gogh een jaar verbleef. Ondanks zijn soms aanwezige angst voor zijn medepatiënten, koos Van Gogh ervoor om er toch twee te portretteren. Een opvallend detail is de vurige','https://kunstdoekje.nl/wp-content/uploads/2022/04/Portret-van-man-met-één-oog-kunstdoekje-optimized.jpg',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,6783) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-hut','De hut','"De hut" van Adriaen van de Velde is een venster naar de rust van het 17e-eeuwse platteland. Dit kunstdoekje onthult een vrouw bij een herdershut, omringd door grazend vee, met een stijlvolle ruiter op de achtergrond. De subtiele elegantie van het schilderij en de charme van de Gouden Eeuw maken het tot een verfijnde keuze voor elk interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/04/De-hut-kunstdoekje-optimized.jpg',(select id from categories where slug='rijks'),array['rijks'],true,true,6839) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-liefdesbrief','De liefdesbrief','"De Liefdesbrief" van Johannes Vermeer betovert met een intiem moment tussen twee vrouwen in een sfeervolle kamer. De jongedame in blauw leest een liefdesbrief, haar gezicht een toonbeeld van verrukking, terwijl een oudere vrouw nieuwsgierig toekijkt. Vermeer''s zachte kleurenpalet en meesterlijke lichtspel maken dit kunstdoekje tot een tijdloze blikvanger voor elk interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/04/414.png',(select id from categories where slug='rijks'),array['rijks'],false,true,6890) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('melkmeisje','Melkmeisje','"Het Melkmeisje". In een kamer badend in zacht licht, giet een jonge vrouw zorgvuldig melk, haar concentratie haast voelbaar. De meesterlijke combinatie van subtiele kleuren en lichtspel maakt dit kunstdoekje tot een tijdloze aanwinst voor je interieur. Laat je betoveren door de eenvoud en schoonheid van dit iconische meesterwerk. Perfect voor die speciale plek in jouw stijlvolle ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/04/415.png',(select id from categories where slug='rijks'),array['rijks'],false,true,6919) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('apostel-paulus','Apostel Paulus','"Zelfportret als de apostel Paulus." De meesterlijke penseelstreken onthullen een doordringende blik, terwijl het zwaard en de brief symbolen zijn van Paulus'' martelaarschap en schrijverschap. Dit kunstdoekje, rijk aan emotie en techniek, is een verfijnde keuze voor de liefhebber van klassieke kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/04/416.png',(select id from categories where slug='rijks'),array['rijks'],false,true,6948) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-zuiderhavendijk','De Zuiderhavendijk','Cornelis Springer''s "De Zuiderhavendijk in Enkhuizen" uit 1868 is een ode aan het dagelijks leven in een historische stad. Dit kunstdoekje toont een rustig varende boot op de gracht en een stad die bruist van activiteit. Met zijn scherpe oog voor detail en passie voor architectuur, brengt Springer een moment uit het verleden prachtig tot leven. Een kunstwerk dat elke kunstliefhebber zal waarderen en koesteren','https://kunstdoekje.nl/wp-content/uploads/2022/04/420.png',(select id from categories where slug='rijks'),array['rijks'],false,true,6977) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-7034','Stilleven met bloemen','"Stilleven met bloemen" van Abraham van Beyeren is een sprankelend kunstdoekje uit de Nederlandse Gouden Eeuw. Dit levendige boeket, met tulpen en rozen, straalt pure schoonheid uit. Naast de vaas schittert een subtiel horloge, een knipoog naar de vergankelijkheid van tijd. Van Beyeren combineert hier natuurlijke pracht met 17e-eeuwse luxe, perfect voor elke kunstliefhebber die zijn ruimte een vleugje elegantie wil geven.','https://kunstdoekje.nl/wp-content/uploads/2022/04/421.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,7034) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vaas-met-bloemen','Vaas met bloemen','Pieter van Loo met dit betoverende kunstdoekje. "Vaas met bloemen" is een viering van de natuur in al haar glorie. Van Loo, meesterlijk in zijn techniek, legt elk bloemblaadje en elke schaduw vast met een precisie die de kijker doet verlangen naar de geur van verse bloemen. Dit kunstdoekje is niet alleen een ode aan de schoonheid van de natuur, maar ook aan de ongeëvenaarde vaardigheid van de kunstenaar. Voeg een vleugje elegantie en verfijning toe aan elke ruimte met dit meesterwerk. Perfect voor liefhebbers van kunst en natuur.','https://kunstdoekje.nl/wp-content/uploads/2022/04/422.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,7090) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('woelige-zee','Woelige zee','Woelige zee \n Pieter van Loo (1745) \n \n Eye-catcher op de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme optie op het gebied van wanddecoratie. Met een kunstdoekjes tover jij jouw muur om een handomdraai om tot een creatieve oogstrelende creatie. \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje is eigenlijk een waar kunstwerk, welke bestaat uit een hoogwaardig geprint textieldoek die strakgespannen zit in een zwart aluminium frame. \n \n Het luxe aluminium frame \nOnze kunstdoekjes inclusief frame worden standaard geleverd ','https://kunstdoekje.nl/wp-content/uploads/2022/04/434.png',(select id from categories where slug='rijks'),array['rijks'],false,true,7119) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pelegronium-album-bicalor','Pelegronium album Bicalor','Duik in de wereld van de botanische kunst met "Pelargonium album bicolor" door M. de Gijselaar uit 1830. Dit kunstdoekje toont een verfijnde tekening van de pelargoniumbloem, prachtig vastgelegd met een oog voor detail. De Gijselaar''s talent voor het vastleggen van de natuur in al haar glorie is evident in dit stuk, waarbij elk blaadje en bloemblad tot leven komt. Perfect voor liefhebbers van zowel kunst als natuur, dit kunstdoekje is een tijdloze toevoeging aan elke collectie.','https://kunstdoekje.nl/wp-content/uploads/2022/04/423.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,7148) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-7177','Stilleven met bloemen','Laat je charmeren door dit kunstdoekje van Jacob Marrel uit 1634. Een uitbundig boeket bloemen steelt de show, terwijl een nieuwsgierige kikker aan de voet een verrassend detail toevoegt. Marrel''s talent voor kleur en detail maakt dit stuk een vrolijke en intrigerende toevoeging aan elke ruimte. Perfect voor die speelse touch in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/04/424.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,7177) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kalfje-met-wit-zwart-gevlekt','Kalfje met wit zwart gevlekt','''Kalfje, zwart en wit gevlekt'' van Geo Poggenbeek. Dit kunstdoekje, geïnspireerd op het werk uit de periode 1873-1903, toont een nieuwsgierig kalfje dat met zijn onschuldige ogen de wereld inkijkt. De zachte penseelstreken en het levendige contrast tussen zwart en wit brengen het kalfje tot leven. Een perfecte toevoeging voor iedereen die zijn ruimte een vleugje natuurlijke schoonheid wil geven.','https://kunstdoekje.nl/wp-content/uploads/2022/04/427.png',(select id from categories where slug='rijks'),array['rijks'],false,true,7234) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landschap-met-vee','Landschap met vee','"Landschap met vee". Geschilderd tussen 1649 en 1653, toont Pijnacker zijn meesterschap in het vastleggen van de natuurlijke schoonheid van het landschap. Het kunstdoekje, vervaardigd met olie op eikenhout, meet 36 cm in hoogte en 48 cm in breedte. Laat je meevoeren door de serene sfeer en de harmonie tussen mens en natuur die Pijnacker zo prachtig heeft vastgelegd. Een tijdloze toevoeging aan elke kunstcollectie.','https://kunstdoekje.nl/wp-content/uploads/2022/04/428.png',(select id from categories where slug='rijks'),array['rijks'],false,true,7263) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fleurige-bloemen','Fleurige bloemen','"Fleurige Bloemen"! Een explosie van kleur die elke kamer opfleurt. Van zonnige gele tinten tot dromerige lavendel, dit kunstwerk is als een zomerse dag in je woonkamer. Perfect voor die dagen dat je een beetje extra zonneschijn nodig hebt.','https://kunstdoekje.nl/wp-content/uploads/2022/04/340.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme'],false,true,7292) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('impressionisme-bloemen','Impressionisme (bloemen)','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/04/326.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme'],false,true,7322) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
