insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amerikaanse-flamingo','Amerikaanse flamingo','"American Flamingo" Deze levendige roze vogel, prachtig vastgelegd door John James Audubon in 1785, is een icoon uit de ornithologische kunst. Audubon, een pionier in vogelillustraties, reisde door Amerika om deze prachtige wezens in hun natuurlijke habitat vast te leggen. Nu kun je een stukje van die geschiedenis en avontuur in huis halen met dit kunstdoekje. Perfect voor een vleugje vintage charme en kleur!','https://kunstdoekje.nl/wp-content/uploads/2022/04/23-1.png',(select id from categories where slug='natuur'),array['natuur','oude-meesters','specials'],true,true,7623) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('buddha','Buddha','Duik in de serene wereld van ons kunstdoekje "Buddha". Dit prachtige stuk straalt rust en vrede uit, perfect voor die momenten waarop je even wilt ontsnappen aan de dagelijkse drukte. De gedetailleerde afbeelding van Buddha komt nog beter tot zijn recht op onze luxe fluwele stof, waardoor de kleuren dieper en rijker aanvoelen.','https://kunstdoekje.nl/wp-content/uploads/2022/04/5-1.png',(select id from categories where slug='specials'),array['specials'],true,true,7651) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fleurige-ijsvogel','Fleurige ijsvogel','"Fleurige IJsvogel'''' Met sprankelende tinten aqua blauw, levendig oranje en zachte roze, brengt deze ijsvogel een explosie van kleur naar elke ruimte. De combinatie van deze kleuren komt prachtig tot zijn recht. Voor een ultieme beleving en om de kleuren echt te laten stralen, raden we je aan dit kunstdoekje op onze fluwele stof te bestellen.','https://kunstdoekje.nl/wp-content/uploads/2022/04/3-1.png',(select id from categories where slug='dieren'),array['dieren','specials'],false,true,7680) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-7711','Stilleven met bloemen','"Stilleven met bloemen" van Eelke Jelles Eelkema. Een rijk boeket met rozen, tulpen en vlinders komt tot leven in levendige kleuren. Elk detail, van bloemblad tot vlinder, is met zorg en vakmanschap vastgelegd. Voor een extra luxueuze uitstraling raden we aan om dit kunstdoekje op onze fluwelen stof te bestellen.','https://kunstdoekje.nl/wp-content/uploads/2022/04/71-1.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,7711) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-puttertje','Het Puttertje','"Het Puttertje" van Carel Fabritius! Dit kleine vogeltje, met zijn heldere kleuren en nieuwsgierige blik, is een echte blikvanger. Geschilderd in 1654, maar nog steeds even fris en levendig. Een vleugje oude meester voor je moderne interieur. Perfect voor iedereen die houdt van een mix van geschiedenis en stijl.','https://kunstdoekje.nl/wp-content/uploads/2022/04/18-2.png',(select id from categories where slug='dieren'),array['dieren'],false,true,7738) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vaas-met-bloemen-7765','Vaas met bloemen','"Vaas met bloemen" door Georges Jeannin op ons kunstdoekje. Dit kunstwerk, zorgvuldig geschilderd tussen 1856 en 1891, toont een elegant boeket dat de meesterlijke techniek van Jeannin belicht. De levendige kleuren en details brengen een tijdloze charme in elke ruimte. Voor een optimale weergave van dit stuk, overweeg dan om fluweel te bestellen.','https://kunstdoekje.nl/wp-content/uploads/2022/04/230.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','rijks'],false,true,7765) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-straatje','Het straatje','"Het Straatje" van Johannes Vermeer. Dit intieme stadsgezicht, met zijn kenmerkende lichtinval en gedetailleerde architectuur, biedt een tijdloze blik op het leven in Delft. De rustige straat en de spelende kinderen roepen een gevoel van nostalgie op. Voor een weergave die de subtiele nuances van Vermeer''s meesterschap echt tot zijn recht laat komen, overweeg dan om fluweel te bestellen. Een verfijnde keuze voor elke kunstliefhebber.','https://kunstdoekje.nl/wp-content/uploads/2022/04/401.png',(select id from categories where slug='rijks'),array['rijks'],false,true,7792) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('molen-in-de-poldervaart','Molen in de poldervaart','"Een molen aan een poldervaart, bekend als ‘In de maand juli’". Dit schilderij, zorgvuldig vastgelegd door Paul Joseph Constantin Gabriël in 1889, ademt de rust van een luie zomerdag bij een molen. Voel de warmte, hoor het zachte ruisen van het water en droom weg. Voor een extra rijke beleving van dit prachtige stuk, bestel fluweel. Een stijlvolle toevoeging voor elke kunstliefhebber.','https://kunstdoekje.nl/wp-content/uploads/2022/04/38-1.png',(select id from categories where slug='rijks'),array['rijks'],false,true,7819) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-7846','Stilleven met bloemen','"Stilleven met bloemen" door Balthasar van der Ast. Dit levendige stuk, geschilderd tussen 1625 en 1630, zit boordevol bloemen in volle bloei en nieuwsgierige insecten. Van der Ast stond bekend om zijn gedetailleerde stillevens en dit kunstwerk is daar een perfect voorbeeld van. Het is een feest voor het oog en een prachtige manier om een vleugje 17e-eeuwse flair in huis te halen. En voor die extra sprankeling? Bestel fluweel bij Kunstdoekje','https://kunstdoekje.nl/wp-content/uploads/2022/04/371.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,7846) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-de-balon','Meisje met de balon','"Meisje met de ballon" van de mysterieuze straatartiest Banksy. Dit iconische beeld van een meisje dat reikt naar een wegvliegende rode ballon staat symbool voor verloren onschuld en de vergankelijkheid van het leven. Banksy, bekend om zijn provocerende en vaak politiek geladen kunstwerken, raakt met dit stuk een universele snaar. Het is zowel een blikvanger als een gespreksstarter.','https://kunstdoekje.nl/wp-content/uploads/2022/04/21-1.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','banksy','specials'],true,true,7873) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tijger-met-barcode','Tijger met barcode','"Tijger met barcode" van de wereldberoemde Banksy. Dit kunstwerk, waarbij een felle tijger een barcode op zijn lichaam draagt, is een krachtige uitspraak over consumentisme en de commercialisering van wilde dieren. Banksy, altijd scherp en maatschappijkritisch, nodigt ons uit om na te denken over de prijs van de natuur in onze moderne wereld. Dit stuk is niet alleen een visueel spektakel, maar ook een denkvoer.','https://kunstdoekje.nl/wp-content/uploads/2022/04/Tijger-met-barcode.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','banksy'],false,true,7900) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
