insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mona-lisa','Mona Lisa','"Mona Lisa" Dit iconische meesterwerk van Leonardo da Vinci brengt charme en raadselachtigheid in elke ruimte. Laat je betoveren door de enigmatische blik van deze tijdloze dame, geschilderd door een meesterhand. De "Mona Lisa" straalt een onmiskenbare aantrekkingskracht uit en blijft een bron van verwondering en bewondering. Overweeg om dit prachtige kunstwerk op fluweel te bestellen voor een extra vleugje elegantie en stijl.','https://kunstdoekje.nl/wp-content/uploads/2022/04/199-1.png',(select id from categories where slug='da-vinci'),array['da-vinci','specials'],true,true,8164) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
