insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landschap','Landschap','"Landschap" van Vincent van Gogh. Ontdek de rijke penseelstreken en levendige kleuren die de natuur tot leven brengen. Breng de schoonheid van het buitenleven in huis en voel de passie van de kunstenaar. Ervaar de kracht van Van Gogh''s unieke stijl en overweeg om dit prachtige schilderij op fluweel te bestellen, voor een extra vleugje levendigheid.','https://kunstdoekje.nl/wp-content/uploads/2022/05/585.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,9790) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kerk-in-nuenen','Kerk in Nuenen','Van Gogh''s "Kerk in Nuenen" schilderij. Geniet van de rust van een landelijk dorp en de sfeer van een eeuwenoude kerk. Geschilderd in 1884-1885, legt dit werk de eenvoudige schoonheid van het dorpsleven vast. Haal een stukje geschiedenis in huis en ervaar de kalmerende uitstraling van dit tijdloze stuk.','https://kunstdoekje.nl/wp-content/uploads/2022/05/584.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,9823) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landweg-in-de-provence-bij-nacht','Landweg in de Provence bij nacht','"Landweg in de Provence bij nacht"! Geschilderd door Vincent van Gogh, neemt dit kunstwerk je mee naar een rustig landweggetje badend in het maanlicht. De levendige penseelstreken en levendige kleuren brengen de magie van de nacht tot leven, waardoor je keer op keer nieuwe details kunt ontdekken. Voeg een vleugje Provençaalse charme toe aan je ruimte met dit meesterwerk aan je muur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-583-.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,9854) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('straat-bij-arles','Straat bij Arles','"Straat bij Arles" van Vincent van Gogh. De serene schoonheid van het platteland komt tot leven in dit meesterwerk. Met gedurfde penseelstreken vangt Van Gogh de levendige kleuren en textuur van de natuur. Ons kunstdoekje brengt deze pracht naar je interieur, waardoor je elke dag kunt genieten van de tijdloze charme van Van Gogh''s kunstwerk aan je muur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-582.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,9888) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('salvator-mundi','Salvator Mundi','"Salvator Mundi" van Leonardo da Vinci. Dit meesterwerk straalt rust en grootsheid uit, met een sublieme afbeelding van Christus als Verlosser van de wereld. De fijnheid van elk detail en de zorgvuldige weergave van licht en schaduw getuigen van da Vinci''s ongeëvenaarde vakmanschap. \n \n Van een bescheiden begin tot een verbazingwekkende reis: "Salvator Mundi" werd ooit per ongeluk gekocht voor 10 duizend euro, maar veranderde van eigenaar en reisde door de tijd. Na een intensieve veiling in Londen werd het uiteindelijk verworven door de Saudische kroonprins Mohammed bin Salman voor een ongel','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-581.png',(select id from categories where slug='da-vinci'),array['da-vinci'],false,true,9920) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dame-met-een-hermelijn','Dame met een Hermelijn','"Dame met Hermelijn" van Leonardo da Vinci. Je krijgt een glimp van de high society van toen, compleet met een elegante dame en haar onwaarschijnlijke metgezel, een hermelijn. Dit schilderij ademt klasse en zit vol met details die je mee terug in de tijd nemen. Als je een vleugje geschiedenis en stijl aan je ruimte wilt toevoegen, is dit kunstdoekje dé oplossing.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-580.png',(select id from categories where slug='da-vinci'),array['da-vinci'],false,true,9955) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('op-de-drempel-van-eeuwigheid','Op de drempel van eeuwigheid','"Op de Drempel van de Eeuwigheid", een schilderij gecreëerd door de meester Vincent van Gogh. In dit kunstwerk zie je een man die eenzaamheid en innerlijke strijd uitdrukt door het gebruik van levendige kleuren en expressieve penseelstreken. Vincent schilderde dit tijdens zijn verblijf in een zorginstelling, waar hij zocht naar verlichting voor zijn innerlijke onrust. Het werk weerspiegelt zijn zoektocht naar sereniteit te midden van tumultueuze gedachten.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-579.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,9984) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-muurkruipers','Twee muurkruipers','"Twee Muurkruipers" van Aert Schouman. Dit kunstdoekje vangt de levendigheid van twee vogels op prachtige wijze, met oog voor elk fijn detail. Laat je verrassen door de levendige kleuren en de speelse charme van de muurkruipers, en geef je muur een vleugje natuurlijke schoonheid met dit kunstdoekje dat perfect is voor elke natuurliefhebber.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-570.png',(select id from categories where slug='aert-schouman'),array['aert-schouman'],false,true,10017) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cackatoo-10044','Cackatoo','"Kakatoekop" van Aert Schouman. Dit meesterwerk, geschilderd tussen 1725 en 1792, is een indrukwekkende weergave van een kakatoe die tot in de kleinste details is vastgelegd. Aert Schouman, een kunstenaar uit die tijd, staat bekend om zijn nauwkeurige en levendige afbeeldingen van vogels en dieren.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-569.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','rijks'],false,true,10044) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('karmozijnrode-topaaskolibrie-cyclamen-rode-postbode-en-schelpen-uit-he','Karmozijnrode topaaskolibrie, cyclamen, rode postbode en schelpen uit het natuurhistorisch kabinet','"Karmozijn Topaas Kolibrie & Cyclamen". Dit kunstdoekje is een reproductie van een meesterwerk uit 1768 door de getalenteerde James Bolton. Je ziet een levendige karmozijn topaas kolibrie, prachtig gecombineerd met de delicate schoonheid van cyclamen bloemen en een selectie van natuurlijke schelpen.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-568.png',(select id from categories where slug='natuur'),array['natuur','oude-meesters'],false,true,10079) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
