insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-omgevallen-boeket','Het omgevallen boeket','"Het omgevallen boeket" door Abraham Mignon. \n \n Ontdek de speelse chaos van een omgestoten boeket, meesterlijk vastgelegd door Abraham Mignon. Deze 17e-eeuwse kunstenaar had een scherp oog voor detail, van dartelende katten tot glinsterende dauwdruppels op bloemen. Kies voor een levendig geprint deco doek of voel de details op ons fluweelzachte materiaal. Een stukje geschiedenis, perfect voor jouw moderne interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-601.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,10406) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('papegaai-op-de-tak-van-een-bloeiende-rozenstruik','Papegaai op de tak van een bloeiende rozenstruik','"Papegaai op de tak van een bloeiende rozenstruik" door Itō Jakuchū \n \n Duik in de betoverende wereld van de Japanse kunst met dit kunstdoekje. Itō Jakuchū, een meester uit de 18e eeuw, toont een levendige papegaai te midden van een bloeiende rozenstruik. Zijn gedetailleerde penseelstreken en levendige kleuren komen prachtig tot hun recht op ons fluweelzachte doek. Een stukje historische elegantie, ideaal voor een modern interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-599.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,10472) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('drie-vogels-een-ijsvogel-een-toekan-van-prins-von-wied-en-een-mus','Drie vogels: een ijsvogel, een toekan van prins von Wied en een mus','"Drie vogels: een ijsvogel, een toekan van prins von Wied en een mus" door Aert Schouman \n \n Laat je betoveren door dit kunstdoekje, waarin Aert Schouman drie prachtige vogels tot leven brengt. De schitterende ijsvogel, de exotische toekan van prins von Wied en de alledaagse mus worden samen afgebeeld in een harmonieus tafereel. Schouman''s kenmerkende aandacht voor detail en zijn vermogen om de essentie van elke vogel vast te leggen, zijn duidelijk zichtbaar in dit werk. Beschikbaar in zowel geprint deco als fluweelzacht doek.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-549_1.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','dieren','rijks'],false,true,10506) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jabiru','Jabiru','"Jabiru" door Aert Schouman \n \n Ontmoet de ''Jabiru'', een tropische ooievaar die rechtstreeks uit de Amerikaanse wildernis lijkt te zijn gevlogen. Schouman''s penseelstreken brengen deze vogel tot leven met een flair die alleen hij kan. Van zijn statige houding tot zijn sprankelende veren - dit kunstdoekje is een feest voor het oog. Ga voor geprint deco of kies voor fluweelzachte luxe. Een vleugje exotisch avontuur voor jouw muur','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-593.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','dieren','rijks'],false,true,10537) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('brieflezend-meisje-bij-het-venster','Brieflezend meisje bij het venster','"Brieflezend meisje bij het venster" door Johannes Vermeer \n \nOntdek de serene wereld van Vermeer met dit kunstdoekje. Een jong meisje, verloren in de woorden van een brief, staat centraal in dit intieme tafereel. De zachte lichtinval door het venster en Vermeer''s meesterlijke gebruik van kleur en schaduw maken dit kunstwerk tot een tijdloze klassieker. Of je nu kiest voor een geprint deco doek of de fluweelzachte variant, dit kunstwerk brengt een vleugje 17e-eeuwse charme in jouw ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-591.png',(select id from categories where slug='rijks'),array['rijks','specials'],false,true,10595) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('la-fumeur','La fumeur','"La Fumeur" (De Roker) door Vincent van Gogh \n \nDit expressieve portret van Vincent van Gogh toont een man die diep in gedachten verzonken is terwijl hij een pijp rookt. De kenmerkende penseelstreken van Van Gogh zijn duidelijk zichtbaar, waarbij hij een rijk palet van kleuren gebruikt om zowel de textuur van de man''s baard als de rook van de pijp vast te leggen. De achtergrond, bestaande uit levendige en contrasterende kleuren, draagt bij aan de intensiteit van het tafereel. "La Fumeur" is een prachtig voorbeeld van Van Gogh''s vermogen om emotie en karakter vast te leggen in zijn portretten','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-590.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,10627) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-populieren-in-de-apilles-bij-saint-remy','Twee populieren in de Apilles Bij Saint-Rémy','"Twee populieren in de Apilles Bij Saint-Rémy" door Vincent van Gogh \n \nDompel jezelf onder in Van Gogh''s levendige wereld met dit schilderij. Twee trotse populieren steken af tegen een stralende blauwe lucht, terwijl de wervelende penseelstreken van de kunstenaar het Franse platteland tot leven brengen. Een perfect stukje natuur, vastgelegd door een meesterhand.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-588.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,10659) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-postman','The Postman','"The Postman (Portrait of Joseph Roulin)" door Vincent van Gogh, 1888 \n \n In 1888 schilderde Vincent van Gogh dit levendige portret van Joseph Roulin, een postbode in Arles, Frankrijk. Roulin, met zijn kenmerkende blauwe uniform en weelderige baard, wordt afgebeeld met een doordringende blik en een houding van waardigheid. Van Gogh''s expressieve penseelstreken en rijke kleurgebruik brengen het karakter en de persoonlijkheid van de postbode tot leven. De kunstenaar had een diepe vriendschap met Roulin en dit is duidelijk te zien in de zorg en aandacht waarmee hij dit portret heeft gemaakt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-586.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,10688) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('graffiti-monkey','Graffiti Monkey','banksy \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-619.png',(select id from categories where slug='banksy'),array['banksy'],false,true,10719) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('childsoldier','Childsoldier','"Child Soldier" door Banksy \n \n Banksy, de wereldberoemde straatkunstenaar, staat bekend om zijn provocerende en maatschappijkritische kunstwerken. "Child Soldier" is daar geen uitzondering op. Dit stuk toont een jonge soldaat, gewapend met een machinegeweer.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-618.png',(select id from categories where slug='banksy'),array['banksy'],false,true,10749) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-en-vlinders','Stilleven met bloemen en vlinders','"Vintage Bloemenboeket" \n \n Duik in de sfeer van vervlogen tijden met dit kunstdoekje. Een zorgvuldig samengesteld boeket in zachte, nostalgische tinten, dat de elegantie en verfijning van weleer ademt. Een subtiele knipoog naar de klassieke charme van vroeger. Beschikbaar als een geprint deco doek of in fluweelzacht materiaal, het is een stijlvolle toevoeging aan elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-552.png',(select id from categories where slug='bloemen'),array['bloemen','dieren','natuur','specials'],false,true,10808) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blue-turtle','Blue turtle','"Schildpad Onderwater" \n \n Duik in de diepten van de oceaan met dit kunstdoekje. Een gracieuze schildpad, omgeven door het levendige koraal, nodigt je uit voor een onderwateravontuur. De gedetailleerde afbeelding en de sprankelende kleuren brengen de magie van het mariene leven rechtstreeks naar jouw ruimte. Of je nu gaat voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een stijlvolle ode aan de wonderen van de zee.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-551.png',(select id from categories where slug='dieren'),array['dieren'],false,true,10841) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-de-parel-wit','Meisje met de parel (wit)','"Het meisje met de parel - Witte Editie" \n \n Ervaar Vermeer''s meesterwerk op een geheel nieuwe manier met dit kunstdoekje. "Het meisje met de parel", bekend om haar betoverende blik en die glinsterende parel, wordt nu gepresenteerd tegen een stralende witte achtergrond. Deze moderne draai aan een klassiek kunstwerk brengt haar schoonheid en mysterie nog meer naar voren. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een frisse en stijlvolle toevoeging aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-550.png',(select id from categories where slug='rijks'),array['rijks'],false,true,10870) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amerikaanse-flamingo-blauw','Amerikaanse flamingo (blauw)','"American Flamingo - Blauwe Editie" door John James Audubon \n \n Dit kunstdoekje brengt de iconische ''American Flamingo'' van Audubon naar voren tegen een opvallende blauwe achtergrond. De gedetailleerde tekening van de flamingo, gecombineerd met de frisse blauwe tint, maakt dit kunstdoekje tot een stijlvolle blikvanger. Perfect voor liefhebbers van klassieke kunst met een moderne twist. Beschikbaar in geprint deco of fluweelzacht doek, het is een elegante toevoeging aan elke collectie.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-550_1.png',(select id from categories where slug='dieren'),array['dieren'],false,true,10902) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amerikaanse-flamingo-geel','Amerikaanse flamingo (geel)','"American Flamingo - Gele Editie" door John James Audubon \n \n Laat je interieur stralen met dit kunstdoekje waarop Audubon''s ''American Flamingo'' schittert tegen een levendige gele achtergrond. De gedetailleerde tekening van de flamingo krijgt een frisse, moderne uitstraling dankzij de zonnige tint. Een ideale keuze voor wie houdt van een mix van klassieke kunst en hedendaagse flair. Of je nu gaat voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een sprankelende toevoeging aan je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/11/549.png',(select id from categories where slug='dieren'),array['dieren','specials'],false,true,10929) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tucan-aqua','Tucan Aqua','"Toco Toucan Vintage - Groene Editie" \n \n Dit kunstdoekje presenteert de iconische Toco Toekan in al zijn kleurrijke glorie, prachtig contrasterend tegen een diepgroene achtergrond. De levendige kleuren en gedetailleerde tekening van de toekan maken dit kunstwerk tot een echte blikvanger. Het is een viering van zowel de natuurlijke schoonheid van de vogel als de klassieke kunststijl. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje voegt een vleugje tropische elegantie toe aan elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-547.png',(select id from categories where slug='dieren'),array['dieren','rijks','specials'],false,true,10961) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bruine-papegaai-silhouet-schilderij','Bruine Papegaai Silhouet Schilderij','"Bruine Papegaai Silhouet Schilderij" \n \nDit kunstdoekje toont het sierlijke silhouet van een bruine papegaai, prachtig afgebeeld tegen een contrasterende achtergrond. De eenvoud van het silhouet benadrukt de herkenbare vorm van de papegaai, terwijl het kleurenpalet zorgt voor een moderne touch. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een subtiele, maar stijlvolle toevoeging aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/05/547_1.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11026) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-en-fruit','Stilleven met bloemen en fruit','"Stilleven van Bloemen en Vruchten" door Jean Bernard (1775-1883) \n \n Dit kunstdoekje brengt een klassiek stilleven tot leven, meesterlijk geschilderd door Jean Bernard. Het kunstwerk, oorspronkelijk te vinden in het Rijksmuseum, toont een rijke verzameling van bloemen en vruchten, elk detail zorgvuldig en levendig vastgelegd. De compositie en het kleurgebruik van Bernard weerspiegelen de kunstzinnigheid van de late 18e en vroege 19e eeuw. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje voegt een vleugje historische elegantie toe aan je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/05/546.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,11053) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('paradijsvogel','Paradijsvogel','"Vintage Illustratie van de Paradijsvogel" \n \n Dit kunstdoekje toont een prachtige vintage illustratie van de Paradijsvogel, een vogel bekend om zijn opvallende kleuren en unieke veren. De gedetailleerde tekening laat de sierlijkheid en het karakter van deze bijzondere vogel zien, terwijl de klassieke stijl van de illustratie een nostalgisch gevoel oproept. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een betoverende toevoeging aan elke collectie voor liefhebbers van natuur en kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/05/546_1.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11086) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rechthoekig-ruitvormig-frame','Rechthoekig Ruitvormig Frame','"Rechthoekig Ruitvormig Frame" \n \n Dit kunstdoekje presenteert een modern en strak ontwerp: een rechthoekig frame met een intrigerend ruitvormig patroon. De symmetrie en eenvoud van het ontwerp maken het ideaal voor een minimalistisch interieur, terwijl het tegelijkertijd een subtiele visuele interesse toevoegt. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een stijlvolle en eigentijdse toevoeging aan je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/05/545.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,11113) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sluierstaart-goudvis-vintage','Sluierstaart goudvis vintage','"Sluierstaart Goudvis - Vintage Meesterwerk" \n \n Laat je betoveren door de gracieuze bewegingen van de sluierstaart goudvis, subtiel vastgelegd in deze vintage illustratie. Elk detail, van de wervelende vinnen tot de sprankelende schubben, is met uiterste precisie getekend, waardoor het kunstdoekje de tijdloze schoonheid van deze geliefde vis viert. Een kunstwerk dat de essentie van de natuurlijke wereld vangt, verpakt in een klassiek jasje. Kies voor geprint deco of het fluweelzachte doek en voeg een stukje onderwatermagie toe aan je collectie.','https://kunstdoekje.nl/wp-content/uploads/2022/05/544.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11145) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-koy','Roze Koy','"Vintage Koi Karpers in Zacht Blauw en Roze" \n \n Duik in de kalme wateren van dit kunstdoekje, waarin koi karpers sierlijk zwemmen tegen een achtergrond van zacht blauw. De roze tinten van de karpers contrasteren prachtig met het water, waardoor een harmonieus en rustgevend beeld ontstaat. Dit kunstwerk, met zijn vintage charme, voegt een vleugje elegantie en rust toe aan elke ruimte. Beschikbaar in geprint deco of fluweelzacht doek, het is een stijlvolle keuze voor elke kunstliefhebber.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-544.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,11177) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-bloeiende-roos','Roze Bloeiende Roos','"Roze Bloeiende Roos" \n \n Dit kunstdoekje vangt de essentie van een roze bloeiende roos tegen een kraakheldere witte achtergrond. De prachtige roze tinten van de roos springen er echt uit, waardoor elk detail, van de fluweelzachte bloemblaadjes tot de subtiele kleurovergangen, wordt benadrukt. Het contrast tussen de levendige roos en de serene witte achtergrond maakt dit kunstdoekje tot een tijdloos stuk. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een stijlvolle toevoeging die romantiek en natuurlijke schoonheid in elke ruimte brengt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-542.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,11241) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-giraffe','Roze Giraffe','"Vintage Giraffe (Giraffa camelopardalis)" \n \n Dit kunstdoekje brengt een speelse twist op de klassieke giraf. De illustratie toont een sierlijke giraf in een verrassende roze tint, wat zorgt voor een unieke en moderne interpretatie van dit majestueuze dier. De naam "Vintage Giraffe (Giraffa camelopardalis)" eert de wetenschappelijke benaming, terwijl de kleurkeuze een vleugje whimsy toevoegt. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een opvallende en stijlvolle toevoeging aan je collectie.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-541.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11269) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('etherische-bloem','Etherische bloem','"Aesthetic Flower: Oker Gele Bloem op Aqua Blauw" \n \n Duik in de wereld van kleur met dit kunstdoekje. Een stralende oker gele bloem staat centraal, prachtig contrasterend tegen een achtergrond van verfrissend aqua blauw. De combinatie van deze tinten zorgt voor een esthetisch aangenaam geheel dat zowel modern als tijdloos aanvoelt. Of je nu kiest voor geprint deco of het fluweelzachte doek, dit kunstdoekje is een stijlvolle viering van natuur en design.','https://kunstdoekje.nl/wp-content/uploads/2022/05/etherische-bloem-kunstdoekje-.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,11303) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
