insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('no-iv','No. IV','"Mondriaan: Compositie No IV (1914)" \n \n Ervaar de verfijning van Mondriaan''s meesterwerk, nu binnen handbereik. Dit kunstdoekje is niet zomaar een stukje kunst, maar een statement van klasse en innovatie. Voor een ultieme luxe uitstraling adviseren wij het fluweelzachte doek, waarop elk detail en elke kleur nog beter tot zijn recht komt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-485.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,11513) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('in-the-spirit-of-hoffmann','In the spirit of Hoffmann','"In the Spirit of Hoffmann (1921)" door Paul Klee. \n \n Stap in de boeiende wereld van Paul Klee met dit kunstdoekje. "In the Spirit of Hoffmann" is een prachtig voorbeeld van Klee''s talent, waarbij droom en werkelijkheid samensmelten. De zachte kleuren en patronen trekken je blik en nodigen uit tot nadenken. Voor de beste kijkervaring raden we het fluweelzachte doek aan. Een kunstwerk dat elke ruimte verrijkt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-483.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,11534) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('reiger-zwart-wit','Reiger (zwart-wit)','"Heron (Reiger) (1911)" door Samuel Jessurun de Mesquita \n \n Dit kunstdoekje brengt een stukje natuur naar je huis. De reiger, met zijn lange nek en sierlijke houding, is prachtig vastgelegd door Samuel Jessurun de Mesquita. De hoge resolutie print op fluweelzacht doek zorgt voor een levendige en gedetailleerde weergave, waardoor je elke keer weer iets nieuws ontdekt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-481.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11555) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-bronzen-buddha-in-kamakura','De bronzen buddha in Kamakura','"The Bronze Buddha at Kamakura" \n \n Dit kunstdoekje neemt je mee naar het hart van Japan met een prachtige afbeelding van de Bronzen Boeddha in Kamakura. De handgekleurde albumen zilverprint brengt elk detail tot leven, waardoor je de rijke geschiedenis en cultuur van Japan kunt voelen. Perfect voor diegenen die een vleugje Aziatische elegantie in hun ruimte willen.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-477.png',(select id from categories where slug='fotografie'),array['fotografie'],false,true,11570) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-vogels-een-blauwe-gaai-en-een-paarse-borstkas','Twee vogels: een blauwe gaai en een paarse borstkas','"Twee Vogels: een Blauwe Gaai en een Paarsborst Cotinga (1760)" door Aert Schouman \n \n Laat je betoveren door de gedetailleerde weergave van deze twee vogels, meesterlijk geschilderd door Aert Schouman. De hoge resolutie van dit kunstdoekje zorgt ervoor dat je elke penseelstreek en kleurnuance kunt waarderen. Een stukje natuurlijke kunst voor je interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-474.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','dieren'],false,true,11590) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-sluierstaart-goudvissen','Twee Sluierstaart Goudvissen','"Twee Sluierstaart Goudvissen (1926)" door Ohara Koson. \n \n Dit kunstdoekje toont de kunstzinnige precisie van Ohara Koson. De goudvissen, met hun sierlijke vinnen en heldere kleuren, zijn een lust voor het oog. Een authentiek stuk uit het Rijksmuseum dat de schoonheid van de natuur en kunst samenbrengt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-473.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,11612) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-exotische-vogels-een-rotshaan-en-een-kleurvink','Twee exotische vogels: een Rotshaan en een kleurvink','"Twee Exotische Vogels (1762)" door Aert Schouman. \n \n Dit kunstdoekje neemt je mee op een reis naar verre oorden met de prachtige afbeelding van twee exotische vogels, meesterlijk vastgelegd door Aert Schouman. De levendige kleuren en gedetailleerde weergave maken het een echte blikvanger. Een stukje Nederlandse kunstgeschiedenis, rechtstreeks vanuit het Rijksmuseum.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-472.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','dieren'],false,true,11629) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roodsnavel-toekan','Roodsnavel Toekan','"Roodsnavel Toekan (1748)" door Aert Schouman \n \n Dit kunstdoekje toont de pracht van de natuur, met een levendige afbeelding van een roodsnavel toekan. Geschilderd door Aert Schouman, is het een tijdloze herinnering aan de schoonheid van exotische vogels. Een authentiek stuk uit het Rijksmuseum dat elke ruimte zal verrijken.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-470.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','dieren'],false,true,11651) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amerikaanse-flamingo-blauw-11675','Amerikaanse flamingo (blauw)','"Amerikaanse Flamingo" door John James Audubon. \n \n Dit kunstdoekje toont de elegante Amerikaanse Flamingo, prachtig geïllustreerd door John James Audubon. De vogel, met zijn sierlijke houding en levendige roze tinten, steekt schitterend af tegen de aqua blauwe achtergrond. Het is een tijdloze combinatie van natuurlijke schoonheid en artistieke finesse, perfect voor elke ruimte die een vleugje kleur en klasse kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-532.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11675) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blossom','Blossom','"Pruimentakken met Bloesems (1870-1880)" door Megata Morikaga. \n \n Dit kunstdoekje neemt je mee naar de serene wereld van de Japanse kunst. Megata Morikaga heeft met grote zorg en aandacht voor detail de pruimentakken en hun delicate bloesems vastgelegd. De subtiele kleuren en traditionele stijl maken dit kunstwerk een tijdloze toevoeging voor elke kunstliefhebber. Een authentiek stuk, rechtstreeks vanuit de Library of Congress.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-469.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen','specials'],false,true,11690) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amerikaanse-flamingo-beige','Amerikaanse flamingo (beige)','"Flamingo (1785)" door John James Audubon. \n \n Dit kunstdoekje presenteert de statige flamingo, meesterlijk vastgelegd door John James Audubon. De opvallende roze tinten van de vogel contrasteren prachtig met de zachte beige achtergrond, waardoor het kunstwerk een warme en elegante uitstraling krijgt. Het is een perfecte combinatie van natuurlijke schoonheid en artistieke flair, ideaal voor elke ruimte die een vleugje klasse en kleur kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-531.png',(select id from categories where slug='dieren'),array['dieren','specials'],false,true,11705) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-in-een-griekse-vaas','Stilleven in een Griekse vaas','"Stilleven met Bloemen in een Griekse Vaas: Allegorie van de Lente (1817)" door Georgius Jacobus Johannes van Os. \n \n Dit kunstdoekje is een viering van de lente, prachtig vastgelegd door de getalenteerde Georgius Jacobus Johannes van Os. Het boeket bloemen, rijk aan kleur en detail, staat centraal in een klassieke Griekse vaas, waardoor het geheel een tijdloze elegantie uitstraalt. Het is een stuk dat de schoonheid van de natuur en de finesse van kunst samenbrengt, ideaal voor elke liefhebber van klassieke kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-527.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,11727) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fazant-koppel-en-bloesem','Fazant koppel en bloesem','"Fazantenpaar en pruimenbloesem" (1900 - 1930) door Ohara Koson (1877-1945) \n \n Haal de charme van de natuur in huis met het kunstdoekje "Fazantenpaar en pruimenbloesem" door Ohara Koson. Deze prachtige illustratie toont een paar fazanten te midden van pruimenbloesems, in een subtiel palet van kleuren. Met oog voor detail vastgelegd, brengt dit kunstdoekje de schoonheid van de natuurlijke wereld naar voren. Voeg dit meesterwerk toe aan je interieur en geniet dagelijks van de harmonie en sereniteit die het uitstraalt. We raden aan om dit kunstdoekje op fluweel te bestellen voor een extra vleu','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-520.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,11778) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kaketoe-en-granaatappel','Kaketoe en Granaatappel','"Kaketoe en Granaatappel" (1925 - 1936) - Ohara Koson. \n \nLaat je ruimte bloeien met dit kunstdoekje geïnspireerd op het werk van Ohara Koson. Dit meesterwerk, te bewonderen in het Rijksmuseum, brengt een kaketoe en granaatappel samen in harmonieuze pracht. De levendige kleuren en verfijnde details van dit kunstdoekje voegen een vleugje natuurlijke schoonheid toe aan je omgeving.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-519.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,11793) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('reiger-in-de-sneeuw','Reiger in de sneeuw','"Reiger in de sneeuw" (1920 - 1930) door Ohara Koson. \n \nBreng de serene schoonheid van de natuur in je ruimte met dit prachtige kunstdoekje. "Heron in Snow" is geïnspireerd op het werk van Ohara Koson en toont een majestueuze reiger in een winterlandschap. De fijne details van de sneeuw en de gracieuze houding van de reiger zijn meesterlijk vastgelegd. Dit kunstdoekje brengt de rust en elegantie van de natuur naar binnen en herinnert je aan de betovering van het buitenleven, zelfs als je binnen bent.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-518.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,11808) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cherry-blossom','Cherry blossom','"Cherry Blossom" door Ogawa Kazumasa. \n \nLaat de prachtige bloesems van de lente tot leven komen in je ruimte met dit betoverende kunstdoekje. "Cherry Blossom" is een meesterwerk van Ogawa Kazumasa, dat de delicate schoonheid van kersenbloesems vastlegt. De zachte kleuren en gedetailleerde weergave brengen de sfeer van de lente rechtstreeks naar je interieur.','https://kunstdoekje.nl/wp-content/uploads/2022/11/Artboard-53.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen'],false,true,11824) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('compositie-met-ovaal-in-kleurvlakken-ii','Compositie met Ovaal in Kleurvlakken II','"Piet Mondriaan''s Compositie met Ovaal in Kleurvlakken II (1914)". \n \nLaat de iconische stijl van Piet Mondriaan je interieur verrijken met dit opvallende kunstdoekje. "Compositie met Ovaal in Kleurvlakken II (1914)" is een meesterwerk dat de kenmerkende rechte lijnen, primaire kleuren en geometrische vormen van Mondriaan weergeeft. De combinatie van vormen en kleuren creëert een harmonieus geheel dat zowel modern als tijdloos aanvoelt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-513.png',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters','specials'],false,true,11843) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('piet-mondriaan-s-compositie-in-ovaal-met-kleurvlakken-1','Piet Mondriaan''s Compositie in Ovaal met Kleurvlakken 1','"Piet Mondriaan''s Compositie in Ovaal met Kleurvlakken 1 (1914)" \n \nErvaar de innovatieve kunst van Piet Mondriaan met dit opvallende kunstdoekje. "Compositie in Ovaal met Kleurvlakken 1 (1914)" is een meesterwerk dat de kenmerkende rechte lijnen, geometrische vormen en levendige kleuren van Mondriaan belichaamt. De compositie straalt een gevoel van harmonie en balans uit, waardoor het een tijdloos kunstwerk is dat zowel moderne als klassieke interieurs verrijkt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-511.png',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,11858) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-vintage','Abstract vintage','Abstract vintage \n \n Eye-catcher aan de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme keuze op het gebied van wanddecoratie. Een kunstdoekje is namelijk erg eenvoudig te monteren aan de muur en ook nog eens heel makkelijk te wisselen . Je hebt al een nieuw kunstdoekje vanaf 37,50 (inclusief gratis verzending ). \n \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje bestaat uit een hoogwaardig geprint textieldoek welke strakgespannen zit in een 25mm zwart aluminium frame. Doordat het kunstdoekje licht absorbeert en over het geh','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-510.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,11878) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('camprodon-spanje','Camprodon, Spanje','"Camprodon, Spanje (ca. 1892) door John Singer Sargent" \n \nLaat je meeslepen naar het charmante landschap van Camprodon, Spanje, met dit prachtige kunstdoekje. Geschilderd door John Singer Sargent, vangt dit werk de schoonheid en de sfeer van het pittoreske dorpje in de Spaanse Pyreneeën. De levendige penseelstreken en de keuze van de kleuren brengen de serene rust van het landschap tot leven, waardoor je elke keer dat je ernaar kijkt, weer wordt meegevoerd naar deze idyllische plek.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-507.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,11898) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hoofd-van-cackatoo','Hoofd van Cackatoo','"Kaketoe (1725-1792) - Prachtig Portret door Aert Schouman. \n \nStap in de betoverende wereld van deze kaketoe met dit kunstdoekje. Een waar meesterwerk van Aert Schouman dat de charme van de kaketoe in volle pracht vastlegt. De levendige kleuren en het karakteristieke charisma van de kaketoe springen echt in het oog.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-454.png',(select id from categories where slug='dieren'),array['dieren'],false,true,11913) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flower-set','Flower set','"Prachtige Bloemenset uit La Botanique de J. J. Rousseau door Pierre-Joseph Redouté (1759-1840). \n \nLaat je betoveren door deze schitterende bloemenset, ontsproten uit de verbeelding van de beroemde kunstenaar Pierre-Joseph Redouté. Deze kunstdoekjes brengen de schoonheid van bloemen tot leven in levendige details en levendige kleuren. Verrijk je leefruimte met deze elegante en tijdloze flora en voeg een vleugje natuurlijke pracht toe aan je omgeving.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-458-.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen'],false,true,11933) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-helene-klimt','Portret van Helene Klimt','"Gustav Klimt''s Portret van Helene Klimt (1898). \n \nDompel jezelf onder in de wereld van dit beeldschone kunstwerk dat de beroemde schilder Gustav Klimt heeft gewijd aan Helene Klimt. Helene, het nichtje van Klimt, dient als het charmante en intrigerende onderwerp van dit portret. Klimt''s meesterschap komt tot uiting in de manier waarop hij haar delicaat vastlegt, met een subtiele elegantie die haar persoonlijkheid en unieke schoonheid omarmt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-447.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,11960) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mount-fuji-from-lake-yamanaka','Mount Fuji from Lake Yamanaka','"Mount Fuji from Lake Yamanaka - Hiroaki Takahashi (1871). \n \nBreng de majestueuze schoonheid van Mount Fuji in je huis met dit adembenemende kunstdoekje. Geschilderd door Hiroaki Takahashi in 1871, toont dit kunstwerk een betoverend uitzicht op Mount Fuji vanaf het Meer van Yamanaka. Laat je inspireren door de tijdloze pracht van dit schilderij en voeg een vleugje Japanse natuurlijke pracht toe aan je leefruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-446.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,11978) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('about-a-motif-from-hammamet','About a motif from Hammamet','"Over een motief uit Hammamet"(1914) - Paul Klee. \n \n"Breng de abstracte creativiteit van Paul Klee in je huis met dit kunstdoekje dat is geïnspireerd op zijn schilderij ''Over een motief uit Hammamet'' uit 1914. Klee''s unieke stijl en kleurgebruik worden prachtig vastgelegd in dit kunstwerk. Laat je meeslepen door de dynamische vormen en levendige kleuren die een visueel avontuur creëren en je ruimte verrijken met artistieke expressie.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-444.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,11997) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('allegory-of-sculpture','Allegory of Sculpture','Gustav Klimts Allegorie van Beeldhouwkunst (1889). \n \nOntdek de betoverende wereld van Gustav Klimt met dit kunstdoekje geïnspireerd op zijn schilderij ''Allegorie van Beeldhouwkunst'' uit 1889. Laat je meevoeren door Klimts symbolische en decoratieve stijl, die tot leven komt in dit prachtige kunstwerk. Dit kunstdoekje brengt de diepere betekenis en artistieke expressie van Klimts werk tot uiting, en voegt een vleugje verfijning toe aan je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/11/kunstdoekje-443.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,12019) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landschap-uit-pontoise','Landschap uit Pontoise','Camille Pissarro''s Landschap uit Pontoise (1874) \n \nErvaar de schoonheid van het landschap zoals gezien door de ogen van Camille Pissarro met dit prachtige kunstdoekje. Het schilderij ''Landschap uit Pontoise'' uit 1874 komt tot leven op dit hoogwaardige kunstdoekje, dat de meesterlijke penseelstreken en kleuren van Pissarro''s werk op indrukwekkende wijze weergeeft.','https://kunstdoekje.nl/wp-content/uploads/2022/06/kruiwagen-kunstdoekje-nl-1.png',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,12040) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('struisvogel','Struisvogel','Robert Jacob Gordon''s Struthio camelus: Struisvogel (1777–1786). \n \nBreng de majestueuze wereld van de struisvogel tot leven met dit prachtige kunstdoekje. Het schilderij ''Struthio camelus: Struisvogel'' uit de periode 1777-1786, geschilderd door Robert Jacob Gordon, wordt met dit hoogwaardige kunstdoekje op een unieke manier tot uitdrukking gebracht.','https://kunstdoekje.nl/wp-content/uploads/2022/06/kunstdoekje-441.png',(select id from categories where slug='dieren'),array['dieren'],false,true,12059) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('threskiornis-aethiopicus','Threskiornis aethiopicus','Robert Jacob Gordon''s Threskiornis aethiopicus: Afrikaanse heilige ibis (1778). \n \nBreng de betoverende wereld van de Afrikaanse heilige ibis tot leven met dit prachtige kunstdoekje. Het schilderij ''Threskiornis aethiopicus: Afrikaanse heilige ibis'', geschilderd door Robert Jacob Gordon in 1778, wordt met dit hoogwaardige kunstdoekje op een unieke manier tot uitdrukking gebracht. Bewonder de subtiele details en de majestueuze uitstraling van de ibis terwijl het kunstdoekje een vleugje natuurlijke schoonheid toevoegt aan je omgeving.','https://kunstdoekje.nl/wp-content/uploads/2022/06/kunstdoekje-499.png',(select id from categories where slug='dieren'),array['dieren','oude-meesters'],false,true,12077) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zelfportret','Zelfportret','Zelfportret \n Helaas is er weinig bekend over dit abstracte schilderij.. \n \n Eye-catcher aan de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme keuze op het gebied van wanddecoratie. Een kunstdoekje is namelijk erg eenvoudig te monteren aan de muur en ook nog eens heel makkelijk te wisselen . Je hebt al een nieuw kunstdoekje vanaf 37,50 (inclusief gratis verzending ). \n \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje bestaat uit een hoogwaardig geprint textieldoek welke strakgespannen zit in een 25mm zwart aluminium frame.','https://kunstdoekje.nl/wp-content/uploads/2022/06/kunstdoekje-495.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,12097) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('group-of-ergets','Group of Ergets','Ohara Koson (1877) \n Hoogwaardig geprint decodoek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n Kies jouw formaat om de prijs te zien','https://kunstdoekje.nl/wp-content/uploads/2022/06/groep-reigers-kunstdoekje-nl-.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,12116) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-kraanvogels','Twee kraanvogels','Jacob Gordon(1877) \n \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/06/kraanvogels-kunstdoekje-nl-1-1.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,12136) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
