insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kaketoe','Kaketoe','Robert Jacob Gordon (1780) \n \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/06/kaketoe-kunstdoekje-nl-.png',(select id from categories where slug='dieren'),array['dieren'],false,true,12202) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-vintage-kraanvogel','Japanse vintage Kraanvogel','Japanse vintage kraanvogel \n \n Eye-catcher aan de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme keuze op het gebied van wanddecoratie. Een kunstdoekje is namelijk erg eenvoudig te monteren aan de muur en ook nog eens heel makkelijk te wisselen . Je hebt al een nieuw kunstdoekje vanaf 37,50 (inclusief gratis verzending ). \n \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje bestaat uit een hoogwaardig geprint textieldoek welke strakgespannen zit in een 25mm zwart aluminium frame. Doordat het kunstdoekje licht absorbeert en ov','https://kunstdoekje.nl/wp-content/uploads/2022/07/722.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,14999) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('waterval-in-de-provincie-mino','Waterval in de provincie Mino','Katsushika Hokusai (1800) \n \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/07/714.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','natuur'],false,true,15015) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-vintage-kraanvogel-ii','Japanse vintage kraanvogel II','Japanse vintage kraanvogel II \n \n Eye-catcher aan de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme keuze op het gebied van wanddecoratie. Een kunstdoekje is namelijk erg eenvoudig te monteren aan de muur en ook nog eens heel makkelijk te wisselen . Je hebt al een nieuw kunstdoekje vanaf 37,50 (inclusief gratis verzending ). \n \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje bestaat uit een hoogwaardig geprint textieldoek welke strakgespannen zit in een 25mm zwart aluminium frame. Doordat het kunstdoekje licht absorbeert en','https://kunstdoekje.nl/wp-content/uploads/2022/07/716.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15036) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-ganzen','Twee ganzen','Ohara Koson (1900-1930) \n \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/07/726.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','rijks'],false,true,15051) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fazant-in-de-sneeuw','Fazant in de sneeuw','"Fazantenpaar en Pruimbloesem (1900-1930)" door Ohara Koson. \n \n Dit kunstdoekje toont een sierlijk fazantenpaar te midden van delicate pruimbloesems, meesterlijk vastgelegd door Ohara Koson. De harmonie tussen de vogels en de bloesems weerspiegelt de schoonheid en balans van de natuur. Afkomstig uit het Rijksmuseum, is dit kunstwerk een prachtige combinatie van traditionele Japanse kunst en tijdloze elegantie, perfect voor elke kunstliefhebber.','https://kunstdoekje.nl/wp-content/uploads/2022/07/725.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','rijks'],false,true,15070) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zorg-voor-de-chrysanten','Zorg voor de chrysanten','"Zorgen voor de Chrysanten (1887-1896)" door Ogata Gekko. \n \n Dit kunstdoekje brengt een intiem moment tot leven waarin de zorg voor chrysanten centraal staat, prachtig geïllustreerd door Ogata Gekko. De hoge resolutie van de print legt elk detail vast, van de fijne bloemblaadjes tot de toewijding in de handelingen van de verzorger. Het is een tijdloze weergave van harmonie tussen mens en natuur, een kunstwerk dat de essentie van traditionele Japanse kunst belichaamt.','https://kunstdoekje.nl/wp-content/uploads/2022/07/711.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15087) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-een-acteur','Portret van een acteur','"Portret van een Acteur" door Toyohara Kunichika (1835-1900). \n \n Dit kunstdoekje toont een van de intrigerende portretten uit de collectie van Toyohara Kunichika. Met de traditionele Japanse Ukiyo-e stijl brengt Kunichika de expressie en emotie van de acteur prachtig in beeld. De gedetailleerde illustratie, afkomstig uit de Library of Congress, is een eerbetoon aan de rijke kunst en cultuur van het historische Japan en een must-have voor liefhebbers van traditionele Aziatische kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/698.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15104) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ontwerp-voor-een-vaas','Ontwerp voor een vaas','"Ontwerp voor een Vaas (1880-1910)" door Noritake Factory. \n \n Dit kunstdoekje onthult het verfijnde vakmanschap van de Noritake Factory met een prachtig ontwerp voor een vaas. De hoge resolutie van de schildering legt elk detail en elke nuance vast, wat getuigt van de expertise en het artistieke inzicht van de maker. Afkomstig uit The Smithsonian Institution, is dit kunstwerk een prachtige combinatie van design en geschiedenis, ideaal voor liefhebbers van zowel kunst als antiek.','https://kunstdoekje.nl/wp-content/uploads/2022/07/718.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15119) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloeiende-azalea-in-blauwe-pot','Bloeiende azalea in blauwe pot','"Bloeiende Azalea in Blauwe Pot (1920-1930)" door Ohara Koson. \n \nDit kunstdoekje toont een levendige azalea in volle bloei, zorgvuldig geplaatst in een sierlijke blauwe pot, meesterlijk vastgelegd door Ohara Koson. De combinatie van de heldere bloemkleuren en het rustige blauw van de pot creëert een harmonieus geheel. Een authentiek stuk uit het Rijksmuseum, dit kunstwerk is een viering van natuurlijke schoonheid en traditionele Japanse kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/705.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen'],false,true,15140) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('chrysanten-en-stromend-water','Chrysanten en stromend water','"Chrysanten (1925-1936)" door Ohara Koson. \n \n Dit kunstdoekje brengt de tijdloze schoonheid van chrysanten naar voren, subtiel en sierlijk vastgelegd door Ohara Koson. De gedetailleerde bloemen, symbool van lang leven en geluk in veel culturen, stralen in hun eenvoud en elegantie. Een authentiek stuk uit het Rijksmuseum, dit kunstwerk is een ode aan de natuur en de verfijnde kunst van het traditionele Japanse schilderen.','https://kunstdoekje.nl/wp-content/uploads/2022/07/721.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15156) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ikebana-exhibition','Ikebana Exhibition','"Ikebana Tentoonstelling (1896)" door Ogata Gekko. \n \n Dit kunstdoekje neemt je mee naar de verfijnde wereld van Ikebana, de Japanse kunst van het bloemschikken, prachtig in beeld gebracht door Ogata Gekko. De hoge resolutie van de print legt elk detail van de zorgvuldig gearrangeerde bloemen vast, waardoor de essentie en esthetiek van Ikebana volledig tot zijn recht komt. Een tijdloos stuk dat de harmonie tussen natuur en kunst viert.','https://kunstdoekje.nl/wp-content/uploads/2022/07/713.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15174) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mandarijnen-eend','Mandarijnen eend','"Mandarijneenden (1925-1936)" door Ohara Koson. \n \n Dit kunstdoekje toont een sierlijk paar mandarijneenden, symbool van liefde en trouw, prachtig vastgelegd door Ohara Koson. De gedetailleerde weergave en levendige kleuren brengen de eenden tot leven, waardoor je hun natuurlijke habitat bijna kunt voelen. Een authentiek stuk uit het Rijksmuseum, dit kunstdoekje is een viering van de natuur en de traditionele Japanse kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/723.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15189) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-pestvogel-op-esdoorn','Japanse pestvogel op esdoorn','"Japanse Pestvogel op Esdoorn (1877)" door Ohara Koson. \n \n Dit kunstdoekje toont een sierlijke Japanse pestvogel, rustend op een esdoorn, meesterlijk vastgelegd door Ohara Koson. De gedetailleerde tekening en de subtiele kleuren van de vogel en de esdoornbladeren vormen een harmonieus geheel. Dit kunstdoekje, daterend uit 1877, is een prachtige weergave van de natuurlijke schoonheid en de traditionele Japanse kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/715.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15204) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('3-japanse-mannen-of-vrouwen','3 Japanse mannen of vrouwen','"Seiro Niwaka Onna Geisha no Bu Tojin Shishi Sumo" door Utamaro Kitagawa (1754–1806). \n \n Dit kunstdoekje onthult een levendige scène uit het Edo-tijdperk, zorgvuldig vastgelegd door de legendarische Utamaro Kitagawa. De afbeelding, rijk aan detail en expressie, toont geisha''s, buitenlandse handelaren en sumoworstelaars in een dynamische samenstelling. Het is een prachtige weergave van de culturele diversiteit en levendigheid van het historische Japan, vastgelegd door een van de meesters van de ukiyo-e kunststijl.','https://kunstdoekje.nl/wp-content/uploads/2022/07/717.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15220) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-kraanvogel','Japanse Kraanvogel','"Japanse Vintage Houtsnede van een Kraanvogel uit Yatsuo no Tsubaki (1860-1869)" door Taguchi Tomoki. \n \n Dit kunstdoekje presenteert een elegant afgebeelde kraanvogel, een symbool van geluk en eeuwigheid in de Japanse cultuur. Vakkundig gecreëerd door Taguchi Tomoki middels de traditionele houtsnedetechniek, straalt het kunstwerk een tijdloze charme uit. Afkomstig uit de periode van Yatsuo no Tsubaki, is dit kunstdoekje een prachtige weergave van historische Japanse kunst en vakmanschap.','https://kunstdoekje.nl/wp-content/uploads/2022/07/719.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15235) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bos-illustratie','Bos illustratie','"Bos Illustratie uit Shin Bijutsukai" \n \n De gedetailleerde tekeningen van de bomen en het ondergroen brengen de rust en sereniteit van een boslandschap tot leven. Het is een perfecte combinatie van traditionele kunst en moderne technologie, waardoor het ideaal is voor liefhebbers van natuur en design.','https://kunstdoekje.nl/wp-content/uploads/2022/07/724.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15250) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('aap-hangend-aan-bamboetak','Aap, hangend aan bamboetak','"Aap, Hangend aan een Bamboetak (1900-1930)" door Ohara Koson. \n \n Dit kunstdoekje toont een speelse aap, behendig hangend aan een bamboetak, meesterlijk vastgelegd door Ohara Koson. De fijne details en de levendige uitdrukking van de aap maken het tot een levendig en boeiend beeld. Afkomstig uit het Rijksmuseum, is dit kunstdoekje een prachtige weergave van de natuurlijke schoonheid en de traditionele Japanse kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/720.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15265) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('yu-no-ka','Yu no ka','"Yu no ka (1930)" door Shinsui Itō. \n \n Dit kunstdoekje onthult de delicate kunst van Shinsui Itō, waarbij elke penseelstreek en nuance zorgvuldig is vastgelegd. "Yu no ka" is een prachtige representatie van Shinsui''s kenmerkende stijl, die de essentie van de Japanse esthetiek en traditie belichaamt. Afkomstig uit de Library of Congress, is dit kunstdoekje een tijdloze toevoeging voor elke kunstliefhebber en bewonderaar van traditionele Japanse kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/710.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15280) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ontwerp-voor-een-vaas-15295','Ontwerp voor een vaas','"Ontwerp voor een Vaas (1880-1910)" door Noritake Factory. \n \n Dit kunstdoekje toont het verfijnde vakmanschap van de Noritake Factory met een elegant ontwerp voor een vaas. De hoge resolutie van de schildering legt elk detail en elke nuance vast, wat getuigt van de expertise en het artistieke inzicht van de maker. Afkomstig uit The Smithsonian Institution, is dit kunstdoekje een prachtige combinatie van design en geschiedenis, ideaal voor liefhebbers van zowel kunst als antiek.','https://kunstdoekje.nl/wp-content/uploads/2022/07/706.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15295) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-fox-spirit','The fox spirit','"De Vosgeest (1896)" door Ogata Gekko. \n \nDit kunstdoekje onthult de mystieke wereld van de Japanse mythologie met de afbeelding van de Vosgeest, prachtig vastgelegd door Ogata Gekko. De hoge resolutie van de print benadrukt de fijne details en de sfeer van het verhaal achter de vosgeest. Een stuk dat de rijke folklore en artistieke tradities van Japan viert, dit kunstdoekje is een must-have voor liefhebbers van traditionele Japanse kunst en verhalen.','https://kunstdoekje.nl/wp-content/uploads/2022/07/700.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,15310) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('siesta','Siesta','"De Siësta (1890)" door Vincent van Gogh. \n \n Dompel jezelf onder in de rust en sereniteit van "De Siësta", een iconisch kunstdoekje van de meesterlijke Vincent van Gogh. De levendige kleuren en kenmerkende penseelstreken vangen een vredig tafereel van rust in het zonovergoten Franse platteland.','https://kunstdoekje.nl/wp-content/uploads/2022/07/695.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15340) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kraanvogels','Kraanvogels','"Kraanvogels uit Momoyogusa–Bloemen van Honderd Generaties (1909)" door Kamisaka Sekka. \n \n Dit kunstdoekje toont een elegant ensemble van kraanvogels, symbool van geluk en lang leven, prachtig geïllustreerd door Kamisaka Sekka. De gedetailleerde tekeningen en harmonieuze kleuren brengen deze majestueuze vogels tot leven tegen een achtergrond van tijdloze schoonheid. Afkomstig uit de The New York Public Library, is dit kunstdoekje een viering van traditionele Japanse kunst en de rijke geschiedenis van design en illustratie.','https://kunstdoekje.nl/wp-content/uploads/2022/07/660.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,15358) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-grote-golf-van-kanagawa','De grote golf van Kanagawa','"Kanazawa Oki Nami Ura" door Katsushika Hokusai (1760-1849). \n \n Dit kunstdoekje onthult de kracht en schoonheid van de natuur in de traditionele Japanse Ukiyo-e stijl. Hokusai''s meesterlijke illustratie toont woeste golven die dreigend op boten neerbaren, terwijl op de achtergrond de tijdloze majesteit van de Mount Fuji zichtbaar is. Het is een levendige herinnering aan de kracht van de natuur en de delicate balans van het leven, prachtig vastgelegd door een van de grootmeesters van de Japanse kunst.','https://kunstdoekje.nl/wp-content/uploads/2022/07/664.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,15380) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sterrennacht-boven-de-rhone','Sterrennacht boven de Rhône','"Starry Night Over the Rhone (1888)" door Vincent van Gogh \n \n Dit kunstdoekje brengt de betoverende nachtelijke hemel boven de Rhône tot leven, zoals alleen Van Gogh dat kon. Geschilderd in 1888, de fonkelende sterren en de reflectie van de stadslichten op het water creëren een sfeer van rust en verwondering.','https://kunstdoekje.nl/wp-content/uploads/2022/07/690.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15400) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vissersboten-op-het-strand-van-saintes-maries','Vissersboten op het strand van Saintes-Maries','"Visboten op het Strand bij Saintes-Maries (1888)" door Vincent van Gogh. \n \n Dit kunstdoekje toont een levendig landschap dat de sfeer van het Zuid-Franse Saintes-Maries weerspiegelt, zoals vastgelegd door Vincent van Gogh in 1888. De vissersboten rusten op het zand, omringd door de sprankelende zee en de lucht. Van Gogh''s unieke penseelstijl en rijke kleuren brengen dit tafereel tot leven, en maken dit kunstdoekje een eerbetoon aan zowel de kunstenaar als de pracht van de natuur.','https://kunstdoekje.nl/wp-content/uploads/2022/07/675.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15419) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('krab-op-zijn-rug','Krab op zijn rug','"Krab op zijn Rug (1888)" door Vincent van Gogh. \n \n Dit kunstdoekje toont een intrigerend en gedetailleerd portret van een krab, zoals geschilderd door Vincent van Gogh in 1888. De levendige kleuren en de expressieve weergave van het dier vangen de aandacht en nieuwsgierigheid van de toeschouwer. Dit kunstdoekje is een uniek inkijkje in Van Gogh''s interesse voor de natuur en zijn vermogen om zelfs het alledaagse tot kunst te verheffen.','https://kunstdoekje.nl/wp-content/uploads/2022/07/678.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15437) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-ii','Abstract II','Abstract II \n \n Eye-catcher aan de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme keuze op het gebied van wanddecoratie. Een kunstdoekje is namelijk erg eenvoudig te monteren aan de muur en ook nog eens heel makkelijk te wisselen . Je hebt al een nieuw kunstdoekje vanaf 37,50 (inclusief gratis verzending ). \n \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje bestaat uit een hoogwaardig geprint textieldoek welke strakgespannen zit in een 25mm zwart aluminium frame. Doordat het kunstdoekje licht absorbeert en over het gehele o','https://kunstdoekje.nl/wp-content/uploads/2022/07/696.png',(select id from categories where slug='asbtract'),array['asbtract','landschapmodus'],false,true,15458) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-rode-kroonkranen-vintage','Japanse rode kroonkranen vintage','','https://kunstdoekje.nl/wp-content/uploads/2022/07/669.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','landschapmodus'],false,true,15492) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lord-rivers-stud-farm','Lord Rivers Stud Farm','"Lord Rivers Stud Farm (1807)" door Laurent Agasse. \n \n Dit kunstdoekje brengt de weelderige omgeving van Lord Rivers'' Stoeterij tot leven, vastgelegd door Laurent Agasse in 1807. Het gedetailleerde landschap toont het erfgoed van de paardenfokkerij, omringd door de rust van de natuur. De compositie en kleuren weerspiegelen Agasse''s vaardigheid om de schoonheid van zowel het landelijke leven als het dierenrijk vast te leggen, waardoor dit kunstdoekje een prachtig eerbetoon is aan de geschiedenis en de kunst van die tijd.','https://kunstdoekje.nl/wp-content/uploads/2022/07/677.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,15512) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-i','Abstract I','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/07/697.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,15527) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('langlois-brug-in-arles','Langlois brug in Arles','"Langlois brug in Arles" door Vincent van Gogh (1888). \n \n Dit kunstdoekje belicht de "Langlois Brug in Arles", een meesterwerk vastgelegd door Vincent van Gogh in 1888. De brug strekt zich sierlijk uit over het water en is omringd door het serene landschap van Arles. Van Gogh''s expressieve penseelstreken en rijke kleurenpalet benadrukken de tijdloze schoonheid van het tafereel. Het kunstdoekje biedt een venster naar Van Gogh''s artistieke visie en een vleugje geschiedenis in elke penseelstreek.','https://kunstdoekje.nl/wp-content/uploads/2022/07/694.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15547) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-kleine-vijver','De kleine vijver','"De kleine vijver" door Frederik Childe Hassam (1890). \n \n Dit kunstdoekje presenteert "The Little Pond", een prachtig werk gemaakt door Frederik Childe Hassam in 1890. De schilder legt met meesterlijke precisie de rust en sereniteit vast van een kleine vijver. Hassam''s penseelstreken brengen de delicate reflecties van het water en de omringende flora tot leven. Het kunstdoekje biedt een blik in de tijd en een moment van contemplatie, verweven met Hassam''s artistieke visie.','https://kunstdoekje.nl/wp-content/uploads/2022/07/657.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,15564) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('trap-in-ouvers','Trap in Ouvers','"Trap in Auvers" door Vincent van Gogh (1890) \n \n Dit kunstdoekje onthult "Trap in Auvers", vastgelegd door Vincent van Gogh in 1890. De schilderij toont een karakteristieke trap in het dorp Auvers-sur-Oise. Van Gogh''s expressieve stijl en levendige kleurenpalet vangen de eenvoud en de schoonheid van het dagelijks leven. Het kunstdoekje nodigt uit tot een reis terug in de tijd en biedt een glimp van Van Gogh''s ongeëvenaarde artistieke vermogen.','https://kunstdoekje.nl/wp-content/uploads/2022/07/691.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,15582) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('boys-wadin-1873','Boys Wadin (1873)','"Jongens aan het Waden" door Winslow Homer (1873). \n \n Dit kunstdoekje brengt "Jongens aan het Waden" tot leven, een prachtig werk gemaakt door Winslow Homer in 1873. Het tafereel vangt een intiem moment waarin jongens genieten van het waden in het water. Homer''s meesterlijke penseelstreken en gebruik van licht en schaduw vangen de speelsheid en levendigheid van het tafereel. Het kunstdoekje biedt een venster naar een tijd waarin kinderlijke vreugde en de schoonheid van de natuur samenkomen in een tijdloos meesterwerk.','https://kunstdoekje.nl/wp-content/uploads/2022/07/686.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,15597) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('groene-tarweveld-met-cipres','Groene tarweveld met cipres','"Groene Tarweveld met Cipres" door Vincent van Gogh (1889). \n \n In dit kunstdoekje verkennen we het "Groene Tarweveld met Cipres", een meesterwerk van Vincent van Gogh uit 1889. Het tafereel vangt de serene pracht van een veld met groeiende tarwe, omringd door de opvallende vorm van een cipresboom. Van Gogh''s kenmerkende penseelstreken en levendige kleurenpalet brengen de levendigheid van de natuur tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/07/672.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15616) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-gele-huis','Het gele huis','"Het Gele Huis" door Vincent van Gogh (1888) \n \n Stap binnen in de wereld van "Het Gele Huis", een kunstdoekje dat het iconische gele huis in Arles vereeuwigt. Vincent van Gogh creëerde dit meesterwerk in 1888 en bracht het karakter en de warmte van het huis tot leven. Het huis, met zijn levendige gele gevel, stond als een baken van creativiteit en inspiratie voor Van Gogh. De kunstenaar omarmde de heldere kleuren van de Provence en gebruikte zijn expressieve penseelstreken om de textuur van het huis vast te leggen, van de stenen muren tot de uitnodigende ramen. "Het Gele Huis" is meer dan e','https://kunstdoekje.nl/wp-content/uploads/2022/07/680.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','van-gogh'],false,true,15631) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('caribische-vogels','Caribische vogels','Caribische vogels \n \n Eye-catcher aan de muur! \n Wat is een kunstdoekje? \nHou jij van variatie in je leven? Dan is een Kunstdoekje de ultieme keuze op het gebied van wanddecoratie. Een kunstdoekje is namelijk erg eenvoudig te monteren aan de muur en ook nog eens heel makkelijk te wisselen . Je hebt al een nieuw kunstdoekje vanaf 37,50 (inclusief gratis verzending ). \n \n \n Hoogwaardig geprint doek + Luxe frame \nJe kunstdoekje bestaat uit een hoogwaardig geprint textieldoek welke strakgespannen zit in een 25mm zwart aluminium frame. Doordat het kunstdoekje licht absorbeert en over het ge','https://kunstdoekje.nl/wp-content/uploads/2022/07/659.png',(select id from categories where slug='dieren'),array['dieren','landschapmodus','specials'],false,true,15646) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-veteraan-in-een-nieuw-veld','De veteraan in een nieuw veld','"De Veteraan in een Nieuw Veld" door Winslow Homer (1865). \n \n Beleef "De Veteraan in een Nieuw Veld", een kunstdoekje dat Winslow Homers werk uit 1865 tot leven brengt. Dit meesterwerk toont een terugkerende veteraan uit de Burgeroorlog, omringd door bloeiende velden die een nieuw begin symboliseren. De krachtige emotie en de hoopvolle transformatie komen samen in Homer''s penseelstreken. Het kunstdoekje biedt een korte reis door tijd en emotie, en herinnert ons aan veerkracht in veranderende tijden.','https://kunstdoekje.nl/wp-content/uploads/2022/07/687.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,15665) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kimono-met-ruitontwerp','Kimono met ruitontwerp','\n \n "Kimono met Ruitontwerp" door Katsushika Hokusai (1760-1849) \n \n Verken dit kunstdoekje, een traditionele Japanse Ukyio-e stijl illustratie gemaakt door Katsushika Hokusai tussen 1760 en 1849. Het beeld toont een Japanse vrouw in kimono, staand en kijkend naar links terwijl ze een waaier vasthoudt. Haar kimono is versierd met een check design, en Hokusai''s meesterlijke hand vangt de elegantie en de details van het moment. Dit kunstdoekje biedt een glimp van de Japanse cultuur en esthetiek, een reis naar het verleden in de vorm van een tijdloos kunstdoekje. \n \n','https://kunstdoekje.nl/wp-content/uploads/2022/08/745.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,16066) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('profiel-van-een-jonge-verloofde','Profiel van een jonge verloofde','"Profiel van een Jonge Verloofde" door Leonardo da Vinci (15e eeuw). \n \n Laat je betoveren door dit meesterwerk van Leonardo da Vinci, dat het verfijnde profiel van een jonge verloofde vangt. Om de diepte en details van het kunstwerk volledig tot hun recht te laten komen, raden we je aan om te kiezen voor een fluweelzachte afwerking. Met fluweel creëer je niet alleen een visueel prachtige weergave, maar ook een tastbare en luxe ervaring.','https://kunstdoekje.nl/wp-content/uploads/2022/08/746.png',(select id from categories where slug='da-vinci'),array['da-vinci'],false,true,16081) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mona-lisa-16095','Mona Lisa','"Mona Lisa" door Leonardo da Vinci (1503-1506). \n \n Bewonder het iconische meesterwerk van Leonardo da Vinci, de "Mona Lisa". Dit kunstdoekje brengt de mysterieuze glimlach en betoverende ogen van de dame tot leven. Voor een extra vleugje allure en elegantie raden we je aan om te kiezen voor een fluweelzachte afwerking. Fluweel accentueert de subtiliteiten van het schilderij en geeft het een unieke textuur die je kunt voelen.','https://kunstdoekje.nl/wp-content/uploads/2022/08/730.png',(select id from categories where slug='da-vinci'),array['da-vinci'],false,true,16095) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fulfillment','Fulfillment','"Fulfillment" door Gustav Klimt (1905-1909). \n Ontdek de prachtige kunst van Gustav Klimt met zijn meesterwerk "Fulfillment". Dit kunstdoekje brengt de harmonie van menselijke figuren en geometrische vormen tot leven. Om de diepte en verfijning van dit werk te benadrukken, raden we aan te kiezen voor een fluweelzachte afwerking. Fluweel voegt niet alleen een gevoel van luxe toe, maar brengt ook de textuur van het schilderij tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/747_1.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,16117) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kolibris-s-kunstformen-der-natur','Kolibris''s Kunstformen der Natur','"Trochilidae–Kolibris" uit Kunstformen der Natur (1904) door Ernst Haeckel. \n \n Duik in de wonderlijke wereld van de natuur met dit kunstdoekje, gecreëerd door Ernst Haeckel in 1904. De betoverende illustratie van kolibries uit zijn werk Kunstformen der Natur laat je de pracht van deze kleine vogels in volle glorie ervaren. De gedetailleerde weergave en levendige kleuren nemen je mee naar de weelderige wereld van de natuur. Met "Trochilidae–Kolibris" aan je muur haal je een stukje natuurlijke pracht in huis en laat je je verwonderen door de schoonheid van deze kunstvorm.','https://kunstdoekje.nl/wp-content/uploads/2022/08/731.png',(select id from categories where slug='dieren'),array['dieren','natuur','specials'],false,true,16133) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kunstformen-der-natur','Kunstformen der Natur','"Ascidiae–Seescheiden" uit Kunstformen der Natur (1904) door Ernst Haeckel. \n \n Stap binnen in de intrigerende wereld van Ernst Haeckel''s kunst in dit kunstdoekje. "Ascidiae–Seescheiden" is een boeiende illustratie uit zijn werk Kunstformen der Natur, dat in 1904 verscheen. De verfijnde weergave van de zeedieren laat je de verbazingwekkende diversiteit en schoonheid van de natuur ontdekken. Met dit kunstdoekje aan je muur breng je een stukje van de oceanische pracht in huis en laat je je inspireren door de wonderen van de natuur.','https://kunstdoekje.nl/wp-content/uploads/2022/08/749.png',(select id from categories where slug='bloemen'),array['bloemen','specials'],false,true,16158) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hygiea-1907','Hygiea (1907)','"Hygiea" door Gustav Klimt (1900-1907). \n \n Laat je betoveren door het meesterwerk "Hygiea" van Gustav Klimt. Dit kunstdoekje weerspiegelt de harmonie tussen mens en natuur en brengt een gevoel van sereniteit in je ruimte. De verfijnde details en symboliek van het schilderij maken het een tijdloos kunstwerk om te bewonderen. Haal de pracht van Klimt''s visie op genezing en gezondheid in huis met dit kunstdoekje en voeg een vleugje artistieke verfijning toe aan je omgeving.','https://kunstdoekje.nl/wp-content/uploads/2022/08/733.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,16174) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hoofd-van-buddha','Hoofd van Buddha','"Hoofd van Boeddha" door Reijer Stolk (1943). \n \n Laat je meevoeren naar een wereld van spirituele diepgang met het kunstdoekje "Hoofd van Boeddha" door Reijer Stolk. Dit meesterwerk vangt de rust en sereniteit van de Boeddha op een prachtige wijze. Voor een extra vleugje verfijning en textuur raden we je aan te kiezen voor een kunstdoekje met een fluweelzachte afwerking. Fluweel accentueert niet alleen de details, maar versterkt ook de symboliek van dit spirituele beeld.','https://kunstdoekje.nl/wp-content/uploads/2022/08/747.png',(select id from categories where slug='specials'),array['specials'],false,true,16191) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenontwerp-met-vogels','Bloemenontwerp met vogels','"Bloemontwerpen met Vogels en Griffioen" door Giacomo Cavenezia (1784). \n \n Ontdek de prachtige wereld van florale ontwerpen en mythische wezens met dit kunstdoekje. "Bloemontwerpen met Vogels en Griffioen" is een meesterwerk gecreëerd door Giacomo Cavenezia in 1784. De combinatie van vogels, bloemen en de majestueuze griffioen brengt een harmonie van natuur en mythologie tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/748.1-1.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,16212) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vaas-met-bloemen-16232','Vaas met bloemen','"Vaas met Bloemen " door Odilon Redon (1906). \n \n Ervaar de betovering van het kunstdoekje "Vaas met Bloemen (Roze Achtergrond)" door Odilon Redon. Dit meesterwerk toont een weelderige verzameling bloemen in een vaas, tegen een serene roze achtergrond. De subtiele kleuren en zachte tonen brengen een gevoel van rust en schoonheid in je ruimte. Dit kunstdoekje is een tijdloze viering van de natuurlijke pracht en Redon''s artistieke visie.','https://kunstdoekje.nl/wp-content/uploads/2022/08/734.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,16232) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('naakte-japanse-vrouw-met-kimono','Naakte japanse vrouw met Kimono','Naked Japanese woman posing sensually with a kimono, vintage erotic art. Study of Flesh Color and Gold (1888) by William Merritt Chase. Original from The National Gallery of Art. Digitally enhanced by rawpixel.','https://kunstdoekje.nl/wp-content/uploads/2022/08/Naakte-japanse-vrouw-Kunstdoekje-optimized.jpg',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,16252) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('trogan-variegatus','Trogan Variegatus','"Trogan Variegatus" (1804–1908) door John Gould en William Matthew Hart. \n \n Laat de pracht van de natuur in volle glorie tot leven komen met het kunstdoekje "Trogan Variegatus". Dit meesterwerk, gecreëerd door John Gould en William Matthew Hart, vangt de prachtige details van de Trogan Variegatus vogel. Met behulp van hoge resolutie printtechnologie wordt de schoonheid van dit zeldzame exemplaar tot in de kleinste details weergegeven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/749_1.png',(select id from categories where slug='dieren'),array['dieren','natuur','oude-meesters'],false,true,16274) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dame-in-wit','Dame in wit','Meisje in Wit" (1890) door Vincent van Gogh. \n \n Laat je betoveren door het kunstdoekje "Meisje in Wit" door Vincent van Gogh. Dit meesterwerk uit 1890 toont een meisje gehuld in een prachtige witte jurk. Van Gogh''s kenmerkende penseelstreken en gebruik van kleur komen tot leven in dit kunstdoekje, dat de tederheid en eenvoud van het moment vastlegt.','https://kunstdoekje.nl/wp-content/uploads/2022/08/754.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,16299) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kunstformen-der-natur-1904','Kunstformen der Natur (1904)','"Actiniae–Zeeanemonen" uit Kunstformen der Natur (1904) door Ernst Haeckel. \n \n Ontdek de intrigerende wereld van zeeanemonen met het kunstdoekje "Actiniae–Zeeanemonen" uit Kunstformen der Natur, gemaakt door Ernst Haeckel in 1904. Dit meesterwerk toont gedetailleerde illustraties van deze fascinerende zeedieren. De nauwkeurigheid en aandacht voor detail in Haeckel''s werk brengen de pracht van de natuurlijke wereld tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/750.png',(select id from categories where slug='natuur'),array['natuur'],false,true,16315) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('etherisch-hertje','Etherisch hertje','Etherisch hertje \n \n Hoogwaardig geprint decodoek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n Kies jouw formaat om de prijs te zien \n','https://kunstdoekje.nl/wp-content/uploads/2022/08/Hert-kunstdoekje-optimized.jpg',(select id from categories where slug='dieren'),array['dieren','specials'],false,true,16330) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('huis-en-persoon','Huis en persoon','"Huizen en persoon" (1890) door Vincent van Gogh. \n \n Laat je meevoeren naar het kunstdoekje "Huizen en Figuur" door Vincent van Gogh. Dit meesterwerk uit 1890 toont een intiem tafereel van huizen en een figuur. Van Gogh''s expressieve penseelstreken en levendige kleurgebruik komen tot leven in dit kunstdoekje, dat een moment van alledaagse schoonheid vastlegt.','https://kunstdoekje.nl/wp-content/uploads/2022/08/752_1.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,16349) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kunstformen-der-natur-iii','Kunstformen der Natur III','"Muscinae–Bladmossen" / A. Giltsch, edelsteen uit Kunstformen der Natur (1904) door Ernst Haeckel. \n \n Duik in de pracht van de natuur met het kunstdoekje "Muscinae–Bladmossen" uit Kunstformen der Natur, samengesteld door Ernst Haeckel in 1904. Dit meesterwerk toont verfijnde illustraties van bladmossen, met specifieke aandacht voor detail en vorm. De diepte en schoonheid van Haeckel''s werk brengen de intrigerende wereld van bladmossen tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/Kunstformen-der-natur-III-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','natuur'],false,true,16387) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('madonna','Madonna','"Madonna" (ca. 1895–1896) door Edvard Munch. \n \nBewonder het kunstdoekje "Madonna" door Edvard Munch. Dit meesterwerk, geschilderd rond 1895-1896, toont Munch''s karakteristieke stijl en emotionele diepgang. De afbeelding van de Madonna straalt zowel kwetsbaarheid als kracht uit, en nodigt uit tot contemplatie over menselijke emoties en spiritualiteit. Voeg dit kunstdoekje toe aan je ruimte en geniet dagelijks van Munch''s meesterlijke interpretatie van een tijdloos onderwerp.','https://kunstdoekje.nl/wp-content/uploads/2022/08/736.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','specials'],false,true,16411) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('magnolia','Magnolia','"Magnoliaposter, vintage kunstdruk" (1886) in hoge resolutie door L. Prang & Co. \n \n Breng een vleugje klassieke elegantie in je ruimte met het kunstdoekje "Magnoliaposter, vintage kunstdruk" uit 1886, gemaakt door L. Prang & Co. Deze prachtige afbeelding van een magnoliabloesem straalt tijdloze schoonheid en verfijning uit. Met hoge resolutie printtechnologie komt elk detail van deze vintage kunstdruk tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/742.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,16430) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('orchidee','Orchidee','"Orchideae–Orchideeën" / A. Giltsch, juweel uit Kunstformen der Natur (1904) door Ernst Haeckel. \n \n Verken de delicate schoonheid van orchideeën met het kunstdoekje "Orchideae–Orchideeën" uit Kunstformen der Natur, gecureerd door Ernst Haeckel in 1904. Dit meesterwerk toont gedetailleerde illustraties van deze betoverende bloemen, met aandacht voor hun elegante vormen en structuren.','https://kunstdoekje.nl/wp-content/uploads/2022/08/739.1.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,16451) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('boeket-van-bloemen-in-urn','Boeket van Bloemen in urn','"Boeket van Bloemen in een Vaas (1724)" door Jan van Huysum: \n \nDit kunstdoekje brengt de pracht van een rijk boeket in een sierlijke vaas tot leven met een ongeëvenaarde precisie. De schilder legt elk detail van de bloemen vast, van hun kleuren tot de textuur van de bladeren. Met dit kunstdoekje haal je een tijdloos stukje natuur in huis en breng je een vleugje klassieke schoonheid in je leefruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/08/755.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,16471) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('filicinae-varens','Filicinae–Varens','"Filicinae–Varens" uit Kunstformen der Natur (1904) door Ernst Haeckel \n \nLaat je betoveren door het kunstdoekje "Filicinae–Varens" uit Kunstformen der Natur, samengesteld door Ernst Haeckel in 1904. Dit meesterwerk toont gedetailleerde illustraties van prachtige varens, met aandacht voor hun intrigerende vormen en delicate structuren. De diepte en precisie van Haeckel''s werk brengen de fascinerende wereld van varens tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/08/740.png',(select id from categories where slug='natuur'),array['natuur','specials'],false,true,16496) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ibis-met-een-ei','Ibis met een ei','"Rode Ibis met een Ei" (1699–1700) door Maria Sibylla Merian. \n \nBreng de pracht van de natuur in huis met het kunstdoekje "Rode Ibis met een Ei" door Maria Sibylla Merian. Deze indrukwekkende illustratie toont een rode ibis samen met een ei, vastgelegd met een artistiek oog voor detail en kleur. Dit meesterwerk van Maria Sibylla Merian brengt de schoonheid van vogels en hun leefomgeving tot leven. Voeg dit kunstdoekje toe aan je interieur en geniet dagelijks van de kleurrijke en natuurlijke pracht. Origineel beschikbaar in The Rijksmuseum.','https://kunstdoekje.nl/wp-content/uploads/2022/08/741.png',(select id from categories where slug='dieren'),array['dieren'],false,true,16515) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tafelkleed-met-blokprint-uit-de-industriele-kunsten-van-de-negentiende','Tafelkleed met blokprint uit de industriële kunsten van de negentiende eeuw','"Geblokte Gedrukte Tafelbedekking" uit de Industriële kunsten van de Negentiende Eeuw (1851-1853) door Sir Matthew Digby Wyatt (1820-1877) \n \nOntdek het kunstdoekje "Geblokte Gedrukte Tafelbedekking" uit de Industriële kunsten van de Negentiende Eeuw, gemaakt door Sir Matthew Digby Wyatt. Dit unieke kunstwerk, gedrukt op textiel, brengt de elegantie en ambachtelijke charme van die tijd tot leven. Laat dit meesterlijke ontwerp je interieur verrijken en bewonder de kunst van het verleden.','https://kunstdoekje.nl/wp-content/uploads/2022/08/743.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,16532) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-bruin-zwart','Abstract bruin-zwart','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/764.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,18443) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('boeket-van-bloemen-in-een-vaas','Boeket van bloemen in een vaas','"Bloemenboeket in een Vaas" (na 1802) schilderij in hoge resolutie door Georgius Jacobus Johannes van Os \n \nGeniet van het kunstdoekje "Bloemenboeket in een Vaas", een prachtig schilderij in hoge resolutie gemaakt door Georgius Jacobus Johannes van Os. Laat de kleuren en details van dit meesterwerk je interieur verfraaien en een vleugje natuurlijke schoonheid toevoegen. Met levendige penseelstreken en oog voor detail legt de kunstenaar de pracht van een boeket bloemen vast.','https://kunstdoekje.nl/wp-content/uploads/2022/10/767-1.png',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters'],false,true,18459) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('album-le-turf-par-sem-polaire-lithographie-couleur','"Album "le Turf" par Sem; Polaire". Lithographie couleur.','"Album "Le Turf" par Sem; Polaire" (1863-1934) \n \nLithografie in kleur Ontdek de lithografie "Album "Le Turf" par Sem; Polaire", een kleurrijke creatie van Sem (Georges Goursat). Deze lithografie, te bewonderen in het Musée Carnavalet in Parijs, neemt je mee naar de charmante wereld van de belle époque. Geniet van de levendige kleuren en gedetailleerde weergave van dit tijdsbeeld en haal een stukje Parijse geschiedenis in huis.','https://kunstdoekje.nl/wp-content/uploads/2022/10/762.png',(select id from categories where slug='specials'),array['specials'],false,true,18476) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
