insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-hemelvaart-van-de-maagd','De Hemelvaart van de Maagd','De Hemelvaart van de Maagd door Sir Peter Paul Rubens (ca. 1620) \n \nDit kunstdoekje, gemaakt door de beroemde schilder Sir Peter Paul Rubens, toont de indrukwekkende Hemelvaart van de Maagd Maria. Op dit meesterwerk wordt Maria omringd door engelen terwijl ze opstijgt naar de hemel. De kunst roept een gevoel van verwondering en spiritualiteit op en brengt de majesteit van Rubens'' talent tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/10/759.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,18584) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
