insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mada-primavesi','Mäda Primavesi','Gustav Klimt - Mäda Primavesi (ca. 1912–1913) \n \nDit is Gustav Klimt''s "Mäda Primavesi," geschilderd rond 1912–1913. Een prachtig kunstdoekje dat de tijdloze schoonheid van Mäda Primavesi vastlegt. Het is een meesterwerk dat elke ruimte verrijkt. Bekend en bewonderd, te zien in The MET Museum.','https://kunstdoekje.nl/wp-content/uploads/2022/10/766.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt'],false,true,18622) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('madame-bonnard','Madame Bonnard','Eduard Vuillard - Madame Bonnard (1895-1900) \n \nIn Eduard Vuillard''s "Madame Bonnard," geschilderd tussen 1895 en 1900, zien we een prachtige vrouw in een intieme en huiselijke setting. De schilder legt de nadruk op het alledaagse, en toch wordt deze eenvoudige scène getransformeerd tot een moment van tijdloze schoonheid.','https://kunstdoekje.nl/wp-content/uploads/2022/10/756-1.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,18644) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
