insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ijsvogel-met-lotusbloem','IJsvogel met lotusbloem','Ohara Koson - IJsvogel met Lotusbloem (1900) \n \nDit kunstdoekje, geschilderd door Ohara Koson in 1900, toont een prachtige ijsvogel die elegant boven een serene lotusbloem zweeft. De vloeiende lijnen en subtiele kleurschakeringen geven dit kunstwerk een betoverende uitstraling. Het is een meesterwerk van de natuurlijke schoonheid, waarin de ijsvogel symbool staat voor gratie en de lotusbloem voor puurheid.','https://kunstdoekje.nl/wp-content/uploads/2022/10/911-optimized-1.jpg',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','oude-meesters'],false,true,20131) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
