insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stillleven-met-bloemen','Stillleven met bloemen','De "Vaas met Bloemen" ofwel Stilleven geschilderd door Jan Davidsz de Heem in 1670 is een waar pronkstuk van de Nederlandse Gouden Eeuw. Dit kunstdoekje barst van kleur en leven, met een overvloed aan bloemen die in een prachtige vaas zijn geschikt.','https://kunstdoekje.nl/wp-content/uploads/2022/10/stilleven-met-bloemen-kunstdoekje-.webp',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters','rijks'],false,true,20206) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jonge-vrouw-met-een-waaier','Jonge vrouw met een waaier','Jonge Vrouw met Waaier - Rijksmuseum. \n \nDe "Jonge Vrouw met Waaier" is een intrigerend kunstdoekje te vinden in de collectie van het Rijksmuseum. Dit schilderij, gemaakt door een onbekende kunstenaar, vangt het sierlijke en mysterieuze van een jonge vrouw die met een waaier poseert. De zachte kleuren en het verfijnde penseelwerk maken dit een betoverend werk om naar te kijken.','https://kunstdoekje.nl/wp-content/uploads/2022/10/899-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,20228) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('standbeeld-met-bloemen','Standbeeld met bloemen','Cartouche met Bloemen - Jan Philip van Thielen, 1665. \n \nDit prachtige kunstdoekje is gemaakt door Jan Philip van Thielen in 1665. Het toont een fraaie cartouche omringd door bloemen. De levendige kleuren en gedetailleerde bloemmotieven maken dit stuk een elegante toevoeging aan elke kunstcollectie. Het brengt de schoonheid van de 17e-eeuwse kunst in jouw ruimte.','https://kunstdoekje.nl/wp-content/uploads/2022/10/891-1-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,20246) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-bloemen','Roze bloemen','\n Roze bloemen \n \n Hoogwaardig geprint decodoek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n Kies jouw formaat om de prijs te zien \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/905-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,20264) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('aap-met-insect-in-z-n-hand','Aap met insect in z''n hand','Aap met Insect - Ohara Koson (1877-1945). \n \nDit prachtige kunstdoekje, gecreëerd door de getalenteerde kunstenaar Ohara Koson tussen 1900 en 1930, vangt op een bijzondere manier het moment van verwondering en nieuwsgierigheid van een aap die een insect onderzoekt. De fijne details en de gevoelige penseelstreken van de kunstenaar brengen de natuurlijke schoonheid van dit tafereel tot leven.','https://kunstdoekje.nl/wp-content/uploads/2022/10/910-optimized.jpg',(select id from categories where slug='dieren'),array['dieren','oude-meesters'],false,true,20286) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('twee-vogels-in-volle-vlucht','Twee vogels in volle vlucht','Drie Vogels in Volle Vlucht - Ohara Koson (1877-1945) \n \nDit kunstdoekje, gecreëerd door de getalenteerde kunstenaar Ohara Koson, vangt op een meesterlijke manier het moment van drie vogels in volle vlucht. De levendige penseelstreken en de prachtige details geven deze afbeelding een gevoel van beweging en vrijheid. Het is alsof de vogels bijna uit het doek lijken te springen.','https://kunstdoekje.nl/wp-content/uploads/2022/10/912-optimized.jpg',(select id from categories where slug='dieren'),array['dieren','oude-meesters'],false,true,20307) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
