insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hope-ii','Hope II','Gustav Klimt''s "Hope II" (1907-1908). \n \nDit kunstdoekje is een meesterwerk dat diep emotioneel en spiritueel geladen is. Dit kunstdoekje toont een vrouwelijke figuur, omringd door een gouden aureool en gewikkeld in kleurrijke patronen en symboliek. Het straalt een gevoel van hoop en verlichting uit, met prachtige ornamenten en details die je blijven boeien. Klimt''s vermogen om emoties in zijn werk vast te leggen is ronduit betoverend, en dit kunstdoekje is daar een perfect voorbeeld van. Een prachtige toevoeging aan elke ruimte en een bron van inspiratie en contemplatie.','https://kunstdoekje.nl/wp-content/uploads/2022/10/914-optimized.jpg',(select id from categories where slug='gustav-klimt'),array['gustav-klimt'],false,true,20382) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('marilyn-monroe-street-art','Marilyn Monroe street art','\n Marilyn Monroe street art \n \n Hoogwaardig geprint decodoek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n Kies jouw formaat om de prijs te zien \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/889-optimized.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,20401) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ijsvogel-die-op-vis-jaagt','IJsvogel die op vis jaagt','\n \n \n \n \n \n \n \n IJsvogel Op Visvangst - Ohara Koson(1907-1908). \n \nDit kunstdoekje, gecreëerd door de meesterlijke kunstenaar Ohara Koson, toont een prachtige ijsvogel in volle jacht naar vis. De levendige kleuren en gedetailleerde weergave vangen het moment van opwinding en concentratie van de ijsvogel perfect. De afbeelding straalt zowel de kwetsbaarheid als de kracht van de natuur uit, waardoor het een indrukwekkend stuk is om te bewonderen. Met dit kunstdoekje haal je een stukje natuurpracht in huis en breng je een vleugje sereniteit in je leefruimte. \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/909-optimized.jpg',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,20484) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-een-brede-hoed','Meisje met een brede hoed','Meisje Met Een Brede Hoed (1650) - Caesar Boëtius van Everdingen. \n \nDit betoverende kunstdoekje, gecreëerd door de getalenteerde schilder Caesar Boëtius van Everdingen in 1650, toont een elegant meisje met een brede hoed. De schilder legde met meesterhand de charme en schoonheid van dit tafereel vast. De brede hoed geeft het meisje een mysterieuze uitstraling en voegt een vleugje intrige toe aan het kunstwerk. Met levendige kleuren en fijne details vangt dit kunstdoekje de tijdloze elegantie van het schilderij.','https://kunstdoekje.nl/wp-content/uploads/2022/10/870-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','rijks'],false,true,20501) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-bloemen','Meisje met bloemen','\n Meisje met bloemen \n \n Hoogwaardig geprint decodoek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n Kies jouw formaat om de prijs te zien \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/894-optimized.jpg',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,20522) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('balearica-regulorum','Balearica regulorum','\n \n Balearica regulorum: Grijze Gekroonde Kraanvogel (1777–1786) - Robert Jacob Gordon. \n \n \n \n \n \n \n \n \nDit schitterende kunstdoekje, geschilderd door Robert Jacob Gordon tussen 1777 en 1786, brengt de majestueuze grijze gekroonde kraanvogel tot leven. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/882-optimized.jpg',(select id from categories where slug='dieren'),array['dieren'],false,true,20541) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-in-een-glazen-vaas','Stilleven met bloemen in een glazen vaas','Stilleven met Bloemen op een Marmeren Tafelblad (1716) - Rachel Ruysch. \n \nBetreed de betoverende wereld van de 18e-eeuwse Nederlandse kunst met dit prachtige kunstdoekje. Geschilderd door de getalenteerde Rachel Ruysch in 1716, biedt dit meesterwerk een weelderig en gedetailleerd stilleven van bloemen die op een marmeren tafelblad zijn geplaatst. De natuurlijke schoonheid en levendige kleuren van de bloemen komen tot leven dankzij het meesterlijke penseelwerk van de kunstenaar.','https://kunstdoekje.nl/wp-content/uploads/2022/10/881-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,20558) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kinderen-met-fiets','Kinderen met fiets','\n Kinderen met fiets \n \n Hoogwaardig geprint decodoek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n Kies jouw formaat om de prijs te zien \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/888-optimized.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,20576) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('willem-van-oranje','Willem van Oranje','Portret van Willem I, Prins van Oranje (ca. 1579) - Adriaen Thomasz. \n \nDit meesterlijke kunstdoekje toont een historisch portret van niemand minder dan Willem I, Prins van Oranje, een belangrijke figuur in de Nederlandse geschiedenis. Geschilderd door de bekwame kunstenaar Adriaen Thomasz. Key rond 1579, vangt dit portret de nobele uitstraling en de trots van de prins in een tijd van politieke verandering.','https://kunstdoekje.nl/wp-content/uploads/2022/10/871-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','rijks'],false,true,20594) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
