insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('festoen-van-vruchten-en-bloemen','Festoen van vruchten en bloemen','"Festoen van vruchten en bloemen" door Jan Davidsz de Heem (1660-1670). \n \nDit kunstdoekje is een meesterlijk voorbeeld van Nederlandse stillevenschilderkunst uit de Gouden Eeuw. De weelderige compositie toont een overvloed aan kleurrijke bloemen en rijpe vruchten, minutieus geschilderd met oog voor detail.','https://kunstdoekje.nl/wp-content/uploads/2022/10/878-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters','rijks'],false,true,20633) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('een-leeuw-uit-de-menagerie-van-koning-lodewijk-napoleon','Een leeuw uit de menagerie van koning Lodewijk Napoleon','"Leeuw uit de menagerie van koning Lodewijk Napoleon" door Pieter Gerardus van Os (1808). \n \nDit kunstdoekje biedt een intrigerende kijk op de exotische dierenwereld van koning Lodewijk Napoleon. Het schilderij toont een imposante leeuw in een weelderige koninklijke omgeving. De gedetailleerde weergave en compositie getuigen van de kunstenaarsvaardigheid van Pieter Gerardus van Os.','https://kunstdoekje.nl/wp-content/uploads/2022/10/883-optimized.jpg',(select id from categories where slug='dieren'),array['dieren','rijks'],false,true,20654) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gemberpot-met-anemonen','Gemberpot met anemonen','Gemberpot met Anemonen (ca. 1900 - ca. 1923) - George Hendrik Breitner. \n \nDit prachtige kunstdoekje toont een gemberpot met levendige anemonen, geschilderd door de Nederlandse kunstenaar George Hendrik Breitner tussen 1900 en 1923. De gemberpot, die vaak werd gebruikt om specerijen op te slaan, staat in scherp contrast met de frisse kleuren en delicate schoonheid van de anemonen. Breitner''s meesterlijke penseelstreken brengen de details van de bloemen tot leven en laten de kijker de subtiele nuances van hun bloemblaadjes waarderen. Dit kunstdoekje straalt een tijdloze elegantie uit en voegt','https://kunstdoekje.nl/wp-content/uploads/2022/10/876-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,20675) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
