insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-pipe-bearer','The Pipe Bearer','De Pijpdrager (1856) - John Frederick Lewis. \n \nDit kunstdoekje, gecreëerd door de Britse kunstenaar John Frederick Lewis in 1856, vangt een intrigerend moment in de tijd waarin een pijpdrager wordt afgebeeld, zijn pijp in de hand. Lewis staat bekend om zijn gedetailleerde en realistische weergave van oriëntaalse scènes, en dit schilderij is een meesterwerk van zijn talent.','https://kunstdoekje.nl/wp-content/uploads/2022/10/900-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,20727) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemen-in-een-fles','Bloemen in een fles','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/879-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,20757) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-don-ramon-satue','Portret van Don Ramón Satué','Portret van Don Ramón Satué (1823) - Francisco Goya \n \nHet "Portret van Don Ramón Satué," geschilderd door de beroemde Spaanse kunstenaar Francisco Goya in 1823, is een meesterwerk van portretschilderkunst. Het doek legt de elegante uitstraling en de persoonlijkheid van Don Ramón Satué vast met verbluffend realisme. Goya''s meesterschap in het vastleggen van de menselijke expressie en zijn subtiele gebruik van licht en schaduw maken dit portret tot een tijdloos kunstwerk.','https://kunstdoekje.nl/wp-content/uploads/2022/10/874-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','rijks'],false,true,20771) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-kerk-bij-auvers-frankrijk','De kerk bij Auvers (Frankrijk)','De Kerk in Auvers-sur-Oise, Gezien vanaf het Koor (1890) - Vincent van Gogh \n \nVincent van Gogh''s "De Kerk in Auvers-sur-Oise, Gezien vanaf het Koor," geschilderd in 1890, is een prachtig voorbeeld van zijn unieke post-impressionistische stijl. In dit kunstdoekje wordt de sfeer van het pittoreske Franse platteland vastgelegd met levendige kleuren en expressieve penseelstreken. Het schilderij toont de kerk in Auvers-sur-Oise en de omliggende natuur in het warme licht van de zonsondergang. Van Gogh''s gebruik van krachtige kleuren en het spelen met licht en schaduw geven het kunstdoekje een onm','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-918-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,21560) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-kus','De Kus','\n De Kus (1907-1908) - Gustav Klimt. \n Gustav Klimt''s "De Kus" is een meesterwerk geschilderd tussen 1907 en 1908. Het toont een innige omhelzing en kus tussen een man en een vrouw, gehuld in decoratieve gewaden en omgeven door gouden patronen. Dit schilderij belichaamt de kracht van liefde en symboliseert de rijke ornamentatie van de Art Nouveau-beweging. Het is een tijdloos symbool van romantiek en esthetiek. \n \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-920-optimized.jpg',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,21574) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vogelstudie','Vogelstudie','Vogelstudie - George Edwards (1694-1773) \n \nDe "Vogelstudie" door George Edwards, die leefde van 1694 tot 1773, is een fascinerend kunstwerk dat de schoonheid van vogels vastlegt in buitengewone detail. Edwards staat bekend om zijn botanische en ornithologische illustraties, en dit werk is daar een prachtig voorbeeld van. Met behulp van hoogwaardige techniek en oog voor detail brengt hij de verenpracht en kenmerken van vogels tot leven op het doek.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-922-optimized.jpg',(select id from categories where slug='dieren'),array['dieren','oude-meesters'],false,true,21594) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenpatroon','Bloemenpatroon','Bloemenpatroon - Voorbeelden van Chinees ornament door Owen Jones (1867). \n \nDit prachtige bloemenpatroon is afkomstig uit het werk van Owen Jones, een gerenommeerde 19e-eeuwse Britse architect en ontwerper. Zijn verzameling van Chinese ornamenten, getrokken uit de collecties van het South Kensington Museum en andere bronnen, heeft eeuwenoude artistieke tradities tot leven gebracht.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-926-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,21634) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenpatroon-lichtgroen-roze','Bloemenpatroon lichtgroen/roze','Bloemenillustratie - Voorbeelden van Chinese Ornamenten (1867). \n \nDeze prachtige bloemenillustratie, afkomstig uit Owen Jones'' werk, toont verfijnde Chinese ornamenten uit 1867. Haar elegante ontwerpen brengen een vleugje klassieke schoonheid en culturele rijkdom in elke ruimte. Een tijdloze keuze voor kunstliefhebbers.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-929-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,21653) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('scene-from-the-noh-theater-play-arashiyama','Scene from the Noh theater play Arashiyama','Scène uit het Noh Theaterstuk Arashiyama (Maart 1923). \n \nDeze intrigerende scène uit het Noh-theaterstuk "Arashiyama" gecreëerd door Kogyo Tsukioka in maart 1923, vangt de diepte en de mystiek van traditionele Japanse podiumkunst. De kunstzinnige weergave is een eerbetoon aan de rijke culturele erfenis van Japan. Een prachtig kunstdoekje dat de schoonheid van de theaterkunst in al zijn glorie weerspiegelt.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-930-optimized.jpg',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,21667) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hoofd-van-een-meisje','Hoofd van een meisje','\n John Singer Sargent (1856 -1925) \n \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending! \n \n','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-931-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','specials'],false,true,21682) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('aardpeer-bloemen','Aardpeer bloemen','Aardpeer bloemen door Claude Monet (1880). \n \nIn dit prachtige kunstdoekje, gemaakt door Claude Monet in 1880, zie jij de levendige Jeruzalem artisjokbloemen in volle bloei. Monet, de beroemde impressionistische schilder, heeft met verbluffende precisie de fijne details van deze bloemen vastgelegd. De kunstzinnige penseelstreken en kleurenspel van Monet brengen de schoonheid van de natuur op een unieke manier tot leven. Dit kunstdoekje voegt een vleugje impressionistische pracht toe aan jouw ruimte en laat je genieten van de natuur zoals alleen Monet dat kon vastleggen.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-932-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','claude-monet','oude-meesters'],false,true,21700) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hoopoe-common-hoopoe','Hoopoe: Common Hoopoe','Hoopoe: De Gewone Hop door William Lewin (1790) \n \nHier zie je een prachtig kunstdoekje, geschilderd door William Lewin in 1790, dat de sierlijke schoonheid van de gewone hop (hoopoe) vastlegt. Het kunstzinnige werk van Lewin brengt deze kleurrijke vogel tot leven met verfijnde details en levendige kleuren. Het kunstdoekje brengt de natuurlijke pracht van de gewone hop rechtstreeks in jouw ruimte en laat je genieten van de natuur zoals weinigen dat kunnen vastleggen.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-933-optimized.jpg',(select id from categories where slug='dieren'),array['dieren','oude-meesters'],false,true,21717) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landschap-studie','Landschap studie','August Strindberg (1905) \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-935-optimized.jpg',(select id from categories where slug='natuur'),array['natuur','oude-meesters'],false,true,21733) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('see-non-ty-a','See-non-ty-a','George Catlin''s "See-non-ty-a, an Iowa Medicine Man" (1844/1845). \n \nEen indrukwekkend portret van een inheemse Amerikaanse medicijnman. Dit kunstdoekje biedt een intrigerende blik op de cultuur en spiritualiteit van de Iowa-stam. De gedetailleerde weergave van het individu en zijn traditionele kleding en versieringen is een eerbetoon aan de rijke erfgoed en geschiedenis van de inheemse volkeren van Amerika. Het schilderij brengt een gevoel van diep respect en bewondering voor de inheemse Amerikaanse gemeenschappen en herinnert ons aan de waarde van het behoud van hun tradities en levenswijz','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-940-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21766) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('king-vulture','King vulture','De Koningsgier (1758) door Aert Schouman. \n \nDit meesterlijke kunstdoekje, geschilderd door Aert Schouman in 1758, brengt de majestueuze koningsgier tot leven met een ongeëvenaarde precisie. De levendige details van dit schilderij vangen de koninklijke schoonheid van de vogel op een sublieme manier.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-943-optimized.jpg',(select id from categories where slug='aert-schouman'),array['aert-schouman','dieren'],false,true,21784) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-gogh','Portret Van Gogh','Portret van Vincent van Gogh (1886) door John Russell - Een Inkijkje in een Kunstenaarsziel. \n \nDit aangrijpende portret, geschilderd door John Russell in 1886, biedt een diepgaand inzicht in de ziel van de beroemde kunstenaar Vincent van Gogh. De krachtige penseelstreken en het expressieve gebruik van kleur brengen de passie en de innerlijke wereld van van Gogh op een indrukwekkende manier tot leven. Dit kunstdoekje is meer dan alleen een schilderij; het is een venster naar de gedachten en emoties van een meesterlijke kunstenaar.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-948-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21800) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('nederlands-afrikaanse-man-in-europese-kledij','Nederlands: Afrikaanse man in Europese kledij','Jan Jansz Mostaert (1474–1552) \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-949-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21822) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vaas-met-rozen','Vaas met rozen','Vaas met Rozen (1870) door Eva Gonzales - Een Ode aan Romantiek. \n \nDit prachtige kunstdoekje, geschilderd door Eva Gonzales in de jaren 1870, is een ware ode aan romantiek en schoonheid. De gedetailleerde weergave van de rozen in de vaas getuigt van de meesterlijke vaardigheden van Gonzales in het vastleggen van de natuurlijke pracht. De zachte kleurenpaletten en de verfijnde penseelstreken stralen een gevoel van sereniteit uit dat elke ruimte verfraait en een vleugje romantiek toevoegt.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-951-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters'],false,true,21837) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vintage-ananas','Vintage ananas','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-952-optimized.jpg',(select id from categories where slug='natuur'),array['natuur','specials'],false,true,21854) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-jeugd','Portret van Jeugd','Portret van een Jongeman (ca. 1495–1498) door Giovanni Antonio Boltraffio. \n \nDit meesterwerk, geschilderd door Giovanni Antonio Boltraffio in de late 15e eeuw, is een prachtig voorbeeld van de Renaissance-schilderkunst. Het portret van de jonge man straalt een onmiskenbare tijdloze schoonheid uit, vastgelegd met meesterlijke precisie en aandacht voor detail.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-953-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21873) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vincent-van-gogh-zelfportret','Vincent van Gogh zelfportret','Zelfportret (1889) door Vincent Van Gogh - Een Glimp van Genialiteit. \n \nIn dit zelfportret uit 1889 onthult Vincent van Gogh niet alleen zijn gezicht, maar ook zijn ziel. Het is een meesterlijke weergave van de innerlijke strijd en emoties van de kunstenaar. De krachtige penseelstreken en het intense kleurgebruik benadrukken de gepassioneerde aard van Van Gogh. Zijn doordringende blik lijkt recht in de ziel van de beschouwer te kijken, waardoor een diepe verbinding ontstaat. Dit kunstdoekje, met het geniale werk van Van Gogh, brengt zijn kunst dichterbij dan ooit.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-954-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,21890) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vincent-van-gogh-zelfportret-ii','Vincent van Gogh zelfportret II','Vincent van Gogh''s Self-Portrait (1887) - Een Blik in de Ziel van de Kunstenaar. \n \nDit intrigerende zelfportret uit 1887, geschilderd door niemand minder dan Vincent van Gogh zelf, vangt de kijker meteen. Met intense ogen en een karakteristieke rode baard, straalt Van Gogh''s passie voor kunst uit elk penseelstreek. Dit kunstdoekje biedt een unieke kans om de diepte van de kunstenaar''s ziel te verkennen en zijn innerlijke wereld te voelen.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-955-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,21904) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vincent-van-gogh-zelfportret-met-een-donkere-vilt-hoed','Vincent van Gogh zelfportret met een donkere vilt hoed','Vincent van Goghs Zelfportret met Donkere Vilthoed aan de Schildersezel (1886) - De Essentie van de Kunstenaar Vastgelegd. \n \nDit beroemde schilderij, "Zelfportret met Donkere Vilthoed aan de Schildersezel," gemaakt door Vincent van Gogh in 1886, biedt een boeiende blik in de wereld van de kunstenaar. De intensiteit in zijn blik en de zelfverzekerde penseelstreken onthullen de gepassioneerde geest die Van Gogh dreef om enkele van de meest iconische kunstwerken in de geschiedenis te creëren.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-956-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,21918) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('funereal-cockatoo','Funereal Cockatoo','Funereal Cockatoo door Elizabeth Gould (ca. 1841) - Een Hommage aan de Australische Natuur. \n \nDit prachtige kunstdoekje, "Funereal Cockatoo," geïllustreerd door Elizabeth Gould in de 19e eeuw voor John Gould, eert de ongelooflijke biodiversiteit van Australië. Elizabeth''s verfijnde talent in het vastleggen van de natuurlijke schoonheid van de Funereal Cockatoo, samen met John''s wetenschappelijke bijdragen aan de ornithologie, maken dit kunstwerk een schat voor natuurliefhebbers en kunstliefhebbers.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-957-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21932) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hoofd-en-gezicht-van-een-vrouw','Hoofd en gezicht van een vrouw','Vrouwelijk Portret door Leo Gestel (ca. 1891–1941) - Een Diepe Inkijk in de Kunst van Leo Gestel. \n \nDit kunstdoekje, "Vrouwelijk Portret," gecreëerd door Leo Gestel in het begin van de 20e eeuw, biedt een intrigerende blik in de kunst van deze Nederlandse kunstenaar. Leo Gestel stond bekend om zijn diversiteit aan stijlen en technieken, en dit portret is geen uitzondering. Met nauwgezette aandacht voor detail en een uitgebreid begrip van de menselijke vorm, weet Gestel de kijker te betoveren met de schoonheid van het gezicht van de vrouw.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-958-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21946) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('distel','Distel','Distel door Aert Schouman (ca. 1725–1792) - Een Botanische Pracht. \n \nDit kunstdoekje, getiteld "Distel," geschilderd door de getalenteerde kunstenaar Aert Schouman, biedt een diepgaande blik op de wereld van de botanische kunst. Schouman, een meester in het vastleggen van de natuurlijke wereld, brengt met buitengewone precisie en aandacht voor detail de delicatesse van de distel tot leven. De subtiele schakeringen van kleur en de zorgvuldig weergegeven texturen maken dit kunstwerk tot een meesterwerk in zijn genre.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-959-optimized.jpg',(select id from categories where slug='aert-schouman'),array['aert-schouman','oude-meesters'],false,true,21960) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('man-met-een-hoed-van-stro','Man met een hoed van stro','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-960-optimized.jpg',(select id from categories where slug='fotografie'),array['fotografie'],false,true,21974) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-julien-de-la-rochenoire','Portret van Julien de la Rochenoire','Portret van Julien de la Rochenoire (1882) door Edouard Manet. \n \nHet "Portret van Julien de la Rochenoire," geschilderd door Edouard Manet in 1882, is een opvallend meesterwerk dat de persoonlijkheid en het karakter van de geportretteerde op indrukwekkende wijze vastlegt. Manet''s beheersing van licht en schaduw creëert een diepgaand portret dat de ziel van Rochenoire op een buitengewone manier tot leven brengt.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-961-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,21988) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rozen','Rozen','Rozen1890) door Vincent Van Gogh. \n \n"Rozen" geschilderd door Vincent Van Gogh in 1890, is een meesterwerk dat de pracht van bloemen op een opvallende manier viert. Van Gogh''s unieke penseelstreken en kleurgebruik creëren een levendige weergave van deze delicate bloemen, waarbij de rozen bijna tot leven lijken te komen op het doek.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-962-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','oude-meesters','van-gogh'],false,true,22002) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-nature-motre','Stilleven (Nature motre)','Nature morte (1888) door Vincent Van Gogh - Een Levendig Stilleven. \n \nVincent Van Gogh''s "Stil leven (Nature morte)" uit 1888 is een bruisend stilleven dat de eenvoud van alledaagse objecten viert.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-963-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','oude-meesters','van-gogh'],false,true,22016) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('birds-of-america','Birds of America','Arctic Tern uit "Birds of America" (1827) door John James Audubon. \n \nDe "Arctic Tern" zoals vastgelegd door John James Audubon in zijn iconische werk "Birds of America" uit 1827, is een meesterlijke weergave van deze majestueuze vogel. De afbeelding toont de elegante vlucht van de Arctic Tern en vangt de details van zijn verenpracht op indrukwekkende wijze. Een prachtig stuk voor liefhebbers van vogels en natuurlijke schoonheid.','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-965-optimized.jpg',(select id from categories where slug='dieren'),array['dieren'],false,true,22044) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
