insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vintage-bloemen-illustratie','Vintage Bloemen illustratie','Ambrosius Bosschaer \n Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2022/10/kunstdoekje-966-optimized.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,22072) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gezicht-op-delft','Gezicht op Delft','Gezicht op Delft door Johannes Vermeer (1660-1661). \n \n"Gezicht op Delft" is een meesterwerk van de Nederlandse schilder Johannes Vermeer, geschilderd tussen 1660 en 1661. Dit schilderij toont een prachtig stadsgezicht van Delft, met de pittoreske grachten, huizen en een serene lucht. Vermeer staat bekend om zijn nauwkeurige weergave van licht en details, wat dit schilderij tot een buitengewoon voorbeeld van zijn talent maakt.','https://kunstdoekje.nl/wp-content/uploads/2022/11/679-optimized.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,23794) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-de-parel','Meisje met de parel','Meisje met de Parel door Johannes Vermeer (1665). \n \n"Meisje met de Parel" is een iconisch schilderij van de Nederlandse meester Johannes Vermeer, geschilderd in 1665. Het toont een jonge vrouw met een mysterieuze blik, gehuld in een exotische tulband en met een glinsterende parel als hoofddeksel. Vermeer''s meesterlijke gebruik van licht en schaduw en zijn ongelooflijke aandacht voor detail maken dit schilderij tot een meesterwerk van de 17e-eeuwse kunst. De serene uitdrukking op het gezicht van het meisje en de schittering van de parel hebben generaties van kunstliefhebbers betoverd, waardo','https://kunstdoekje.nl/wp-content/uploads/2023/03/Meisje-met-de-parel-kunstdoekje-1.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,27078) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lichtblauwe-kaketoe','lichtblauwe kaketoe','Hoogwaardig geprint deco of fluweelzacht doek \n \n Verkrijgbaar in 6 verschillende formaten \n \n Inclusief luxe frame \n \n Gratis verzending!','https://kunstdoekje.nl/wp-content/uploads/2023/06/1134.jpg',(select id from categories where slug='dieren'),array['dieren'],false,false,27845) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-in-een-donkere-kamer','stilleven in een donkere kamer','','https://kunstdoekje.nl/wp-content/uploads/2023/06/1146.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters','rijks'],false,true,27856) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blue-bird-paradise','Blue bird paradise','Vogel en Khaki - Ohara Koson (1900-1930). \n \nDit prachtige kunstdoekje van Ohara Koson brengt de natuur tot leven in je ruimte. Met levendige kleuren en gedetailleerde illustraties brengt het de schoonheid van vogels dichterbij dan ooit. Perfect voor natuurliefhebbers en kunstliefhebbers die een vleugje frisheid en sereniteit in hun interieur willen brengen.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1148-1.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28435) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ijsvogel-op-een-boomstronk','IJsvogel op een boomstronk','IJsvogel op een boomstronk - Ohara Koson (1900-1936). \n \nDit prachtige kunstdoekje van Ohara Koson brengt de ijsvogel in al zijn glorie tot leven, zittend op een sfeervolle boomstronk. De levendige kleuren en verfijnde details geven je interieur een stijlvolle touch. Haal de schoonheid van de natuur in huis en laat je betoveren door de serene sfeer die dit kunstdoekje creëert.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1149-1.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28496) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('waterhoen-bij-bloeiende-plant','Waterhoen bij Bloeiende Plant','Waterhoen bij Bloeiende Plant - Ohara Koson (1900-1936). \n \nEen kunstdoekje dat de gracieuze eenvoud van de natuur vastlegt, met een waterhoen te midden van prachtige bloeiende planten. Ohara Koson''s meesterlijke weergave van de delicate details van de flora en fauna brengt de schoonheid van de natuur rechtstreeks in je huis.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1151-1.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28557) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zangvogel-en-pruimenbloesem','Zangvogel en Pruimenbloesem','Zangvogel en Pruimenbloesem (1900 - 1936) - Ohara Koson. \n \nDit kunstwerk, geschilderd door de getalenteerde kunstenaar Ohara Koson, vangt de pracht van de natuur op een indrukwekkende manier. Het toont een sierlijke zangvogel te midden van bloeiende pruimenbloesems. De fijne details in de vogel en de bloemen brengen de schoonheid van de natuurlijke wereld tot leven.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1152.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28564) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vijf-zilvermeeuwen-boven-een-turbulente-zee','Vijf zilvermeeuwen boven een turbulente zee','Vijf Zilvermeeuwen boven een Turbulente Zee (1900 - 1930) - Ohara Koson. \n \nDit kunstdoekje, gemaakt door de meesterlijke kunstenaar Ohara Koson, brengt de kracht en schoonheid van de natuur op een opvallende manier tot leven. Het toont vijf majestueuze zilvermeeuwen zwevend boven een woelige zee. De kunstenaar heeft met verfijnde penseelstreken de beweging van de golven en de gratie van de meeuwen vastgelegd. Het is een meesterwerk dat zowel de kracht van de natuur als de delicate schoonheid van deze vogels viert.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1153.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28570) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vogel-en-rups','Vogel en Rups','Vogel en Rups (1900 - 1930) - Ohara Koson. \n \nDit betoverende kunstdoekje, gemaakt door de bekwame kunstenaar Ohara Koson, neemt je mee in de wereld van de natuurlijke harmonie. Het schilderij toont een prachtige vogel die zich voorbereidt om zijn volgende maaltijd, een rups, te vangen. De levendige kleuren en gedetailleerde penseelstreken brengen zowel de elegantie van de vogel als de intrigerende dynamiek van de natuurlijke wereld tot leven.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1154.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28573) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('two-fighting-birds','Two fighting birds','Two fighting birds (1900 - 1936) Ohara Koson. \n \n"Two fighting birds" is een prachtig schilderij dat laat zien waar Kunstdoekje voor staat. Het schilderij, gemaakt tussen 1900 en 1936, laat twee vogels zien die met elkaar vechten. Dit beeld staat voor de mix van kracht en schoonheid. Koson heeft met zijn talent niet alleen de vogels mooi geschilderd, maar ook hun gevoelens laten zien.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1155.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28576) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('yokugo-no-onna','Yokugo no onna','Yokugo no onna (1915) \n door Goyō Hashiguchi \n \n"Yokugo no onna", wat vertaald kan worden als "Vrouw na een bad", is een kunstwerk dat de delicate schoonheid en intimiteit van een moment vastlegt. Goyō Hashiguchi, een meester in zijn vak, heeft een naakte vrouw afgebeeld die net heeft gebaad, zittend en naar rechts kijkend. Het kunstwerk straalt een gevoel van rust en sereniteit uit, terwijl het tegelijkertijd de kijker uitnodigt om de diepere emoties en verhalen achter het beeld te verkennen.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1156.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,28578) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mount-fuji-and-the-pines-at-miho','Mount Fuji and the Pines at Miho','Mount Fuji and the Pines at Miho (eerste helft 19e eeuw) \n door Suzuki Kiitsu \n \nDit schilderij toont een uniek beeld van Mount Fuji, gezien vanaf Miho-no-matsubara, een beroemde met pijnbomen bedekte landtong. In tegenstelling tot Kiitsu''s gebruikelijke heldere stijl, biedt dit werk een ingetogen blik op de natuur. Het laat de vijf pieken van Mount Fuji zien, wat ongebruikelijk is. Een prachtig stuk dat de schoonheid van Japan en de waarden van Kunstdoekje weerspiegelt.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1157.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28580) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('baby-monkey-and-mother','Baby monkey and mother','Baby monkey and mother \n door G.A. Audsley - Japanse illustratie (1884) \n \nDit kunstdoekje, afkomstig uit de originele 1884 editie van "The Ornamental Arts Of Japan", toont een intiem moment tussen een babyaapje en zijn moeder. G.A. Audsley heeft met fijne details en zachte kleuren de liefdevolle band tussen moeder en kind vastgelegd. Het kunstwerk straalt warmte en geborgenheid uit en nodigt de kijker uit om even stil te staan bij de eenvoudige schoonheid van de natuur en familiebanden.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1158.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28583) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gele-rijders','De Gele Rijders','De Gele Rijders (1885 - 1886) \n door George Hendrik Breitner \n \nDit schilderij toont het elitekorps van De Gele Rijders in volle vaart, rijdend van het duin af. Breitner heeft op meesterlijke wijze gebruik gemaakt van de contrasterende kleuren: het zwart met rode hoofddeksels en de opvallende gele lissen op de uniformen. Deze kleuraccenten versterken de dynamiek van de beweging in het schilderij. Het opstuivende zand van de voorste paarden maakt het zicht op de volgende rijen wat wazig, waardoor de focus ligt op de kleuren zwart, geel en rood.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1159.png',(select id from categories where slug='dieren'),array['dieren','rijks'],false,true,28585) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-in-een-griekse-vaas-allegorie-op-de-lente','Stilleven met bloemen in een Griekse vaas: allegorie op de Lente','Stilleven met bloemen in een Griekse vaas: allegorie op de Lente (1817) \n door Georgius Jacobus Johannes van Os \n \nDit schilderij toont een prachtig stilleven van bloemen, zorgvuldig gerangschikt in een Griekse vaas. Het is een allegorie op de Lente, wat de vernieuwing en het ontwaken van de natuur symboliseert. Van Os heeft met zijn gedetailleerde penseelstreken en levendige kleuren de essentie van de lente vastgelegd. De bloemen in de vaas stralen frisheid en levendigheid uit, wat de kijker een gevoel van hoop en vernieuwing geeft.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1160.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,28587) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanese-uil-uit-album','Japanese uil uit Album','Japanese uil uit Album \n door Katsushika Hokusai \n \nIn deze schets heeft Katsushika Hokusai, een van de meest gevierde kunstenaars van Japan, de essentie van een Japanse uil vastgelegd. De tekening toont de kenmerkende stijl van Hokusai: gedetailleerd, levendig en met een diep respect voor de natuur. De uil, met zijn doordringende blik en majestueuze houding, staat symbool voor wijsheid en mysterie.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1162.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28589) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kirifuri-waterfall-at-mount-kurokami-in-shimotsuke-province','Kirifuri Waterfall at Mount Kurokami in Shimotsuke province','Kirifuri Waterfall at Mount Kurokami in Shimotsuke province \n door Utagawa Hiroshige \n \nDit kunstwerk van Utagawa Hiroshige, een vooraanstaand figuur in de ukiyo-e kunst, toont de majestueuze Kirifuri-waterval op de berg Kurokami. Met zijn kenmerkende stijl heeft Hiroshige de waterval en het omliggende landschap vastgelegd, waarbij hij de beweging van het vallende water en de serene sfeer van de natuurlijke omgeving benadrukt. De gedetailleerde afbeelding en de harmonieuze kleuren nodigen de kijker uit om zich te verdiepen in de schoonheid van de Japanse natuur.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1163.png',(select id from categories where slug='bloemen'),array['bloemen','rijks'],false,true,28591) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('waterfall-where-yoshitsune-washed-his-horse','Waterfall where Yoshitsune Washed his Horse','Waterfall where Yoshitsune Washed his Horse, Yoshino, Yamato Province \n door Katsushika Hokusai \n \nDit meesterwerk van Katsushika Hokusai vertelt een verhaal dat diep geworteld is in de Japanse geschiedenis en folklore. De afbeelding toont de waterval waar Yoshitsune, een legendarische samurai, zijn paard waste. Hokusai''s kenmerkende stijl is duidelijk zichtbaar in de gedetailleerde weergave van het vallende water en het omliggende landschap. De dynamiek van het water en de rust van de natuurlijke omgeving komen samen om een beeld te creëren dat zowel krachtig als vredig is.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1164.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,28639) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-moon-of-shinobugaoka','The Moon of Shinobugaoka','The Moon of Shinobugaoka (1904) \n door Yoshitoshi Tsukioka \n \nDit kunstwerk laat een Japanse vrouw zien met een heldere maan op de achtergrond. Yoshitoshi Tsukioka heeft met veel aandacht de kleding van de vrouw en haar rustige blik getekend. De maan geeft het plaatje een speciaal en dromerig gevoel. Dit stuk laat goed zien hoe knap Yoshitoshi was en past goed bij wat Kunstdoekje belangrijk vindt: mooie kunst die mensen raakt.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1165.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,28641) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('warrior-archer','Warrior Archer','Warrior Archer (1800-1870) \n Japanse Ukiyo-e \n \nDeze Ukiyo-e toont een strijdlustige boogschutter, klaar voor actie. De details van zijn harnas en de vastberadenheid in zijn ogen laten de vaardigheid en passie van de kunstenaar zien. De tekening geeft een kijkje in het leven van een krijger uit het oude Japan en de eer en moed die hij vertegenwoordigt. Dit kunstwerk is een prachtig voorbeeld van de traditionele Japanse kunst en laat zien wat Kunstdoekje waardeert: kunst die een verhaal vertelt en mensen inspireert.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1166.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,28644) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('chinese-birds-and-flowers','Chinese Birds and Flowers','Chinese Birds and Flowers (1430-1500) \n door Yin Hong \n \nDit schilderij van Yin Hong toont een harmonieuze scène van vogels te midden van bloeiende bloemen. Elk detail, van de sierlijke veren van de vogels tot de fijne bloemblaadjes, is met zorg en precisie geschilderd. De compositie weerspiegelt de schoonheid en balans van de natuur, en de interactie tussen de vogels en de bloemen geeft een gevoel van vrede en sereniteit.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1167.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen'],false,true,28650) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanese-plum-blossoms-in-moonlight','Japanese Plum Blossoms in Moonlight','Japanese Plum Blossoms in Moonlight (18th century) \n door Sō Shizan \n \nDit kunstwerk, zorgvuldig geschilderd op zijde, toont een tafereel van pruimbloesems die oplichten onder de zachte gloed van de maan. Sō Shizan''s techniek is te zien in de fijne details van de bloesemtakken en de subtiele schaduwen die ze werpen. De keuze om inkt en kleur te gebruiken, benadrukt de contrasten tussen de donkere nachthemel en de heldere, bijna lichtgevende bloesems. De compositie leidt het oog van de kijker naar de maan, die op de achtergrond hangt en een kalmerende aanwezigheid biedt.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1168.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen'],false,true,28652) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('nuthatcher-atop-persimmons','Nuthatcher atop Persimmons','Nuthatcher atop Persimmons (ca. 1910) \n door Ohara Koson \n \nDit kunstdoekje van Ohara Koson toont een nuthatcher, een soort zangvogel, die trots zit bovenop glanzende persimmons, oftewel kaki''s. Koson, bekend om zijn vermogen om de natuur in al haar glorie vast te leggen, heeft de fijne details van de vogel en het glanzende oppervlak van de rijpe kaki''s prachtig weergegeven. De compositie is zowel eenvoudig als krachtig, met de vogel als centraal punt, omringd door de rijke oranje tinten van de vruchten.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1169.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,28654) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-begroeting-van-de-regeringssloep-door-de-binnenvloot','De begroeting van de regeringssloep door de binnenvloot','De begroeting van de regeringssloep door de binnenvloot (1650) \n door Jan van de Cappelle \n \nDit schilderij toont een levendig tafereel van schepen op de Nederlandse wateren. Jan van de Cappelle heeft met precisie de regeringssloep en de binnenvloot afgebeeld, omringd door een kalme zee. De reflecties in het water en de gedetailleerde schepen laten zijn vakmanschap zien. Het kunstwerk geeft een kijkje in het maritieme leven van de 17e eeuw en de rijke zeegeschiedenis van Nederland. Een prachtig stuk dat de schoonheid en het erfgoed van het land vastlegt.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1170.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','rijks'],false,true,28657) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gezicht-op-olinda','Gezicht op Olinda','Gezicht op Olinda (1662) \n door Frans Jansz Post \n \nDit schilderij van Frans Jansz Post toont een adembenemend uitzicht op Olinda, een historische stad in Brazilië. Met zijn kenmerkende aandacht voor detail heeft Post de architectonische kenmerken van de stad en het omliggende landschap prachtig vastgelegd. De levendige kleuren en de nauwkeurige compositie geven een gevoel van diepte en ruimte, waardoor de kijker wordt getransporteerd naar het Brazilië van de 17e eeuw. Het kunstwerk is een getuigenis van Post''s meesterschap en zijn vermogen om verre landen en culturen tot leven te brengen o','https://kunstdoekje.nl/wp-content/uploads/2023/09/1171.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','rijks'],false,true,28659) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('visser-in-de-sneeuw','Visser in de Sneeuw','Visser in de Sneeuw (1821) \n door Katsushika Hokusai \n \nDit houtsnede kunstwerk van Hokusai toont een visser te midden van een sneeuwlandschap. De fijne details van de vallende sneeuw en de traditionele kleding van de visser benadrukken Hokusai''s vakmanschap. Het kunstwerk geeft een beeld van het dagelijks leven in het vroege 19e-eeuwse Japan en de harmonie tussen mens en natuur. Het is een treffend voorbeeld van de ukiyo-e stijl waar Hokusai bekend om stond.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1175.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28662) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kirifuri-waterval-op-de-berg-kurokami-in-de-provincie-shimotsuke','Kirifuri-waterval op de berg Kurokami in de provincie Shimotsuke','Kirifuri-waterval op de berg Kurokami in de provincie Shimotsuke \n door Utagawa Hiroshige \n \nDit kunstwerk van Utagawa Hiroshige toont de indrukwekkende Kirifuri-waterval die neerstort van de berg Kurokami. Hiroshige, een meester in de ukiyo-e kunst, heeft met zijn kenmerkende stijl de kracht en schoonheid van de waterval vastgelegd. De dynamische beweging van het water contrasteert met de stille, majestueuze berg op de achtergrond. Het schilderij biedt een blik op de natuurlijke wonderen van Japan en de harmonie tussen land en water. Het is een prachtig voorbeeld van Hiroshige''s talent om ','https://kunstdoekje.nl/wp-content/uploads/2023/09/1179.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28673) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kaketoe-illustratie','Kaketoe illustratie','Kaketoe illustratie \n \n door Onbekende Kunstenaar \n \nOp een opvallende aqua blauwe achtergrond staat een kaketoe centraal in deze illustratie. De levendige achtergrondkleur benadrukt de helderheid en het detail van de kaketoe, waardoor hij nog meer opvalt. De kunstenaar heeft met zorg en precisie de unieke kenmerken van de vogel vastgelegd, van zijn kenmerkende kuif tot zijn scherpe blik.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1180.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28675) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-geisha-in-kimono','Japanse Geisha in Kimono','Japanse Geisha in Kimono (1828) \n door Keisai Eisen \n \nDeze houtsnede van Keisai Eisen toont een elegante geisha gehuld in een prachtige kimono. De fijne details van de kimono, samen met de sierlijke houding van de geisha, weerspiegelen Eisen''s meesterschap en aandacht voor detail. De compositie en kleurgebruik brengen de geisha tot leven, waardoor ze lijkt te bewegen binnen het frame. Dit kunstwerk, origineel van Utagawa, is een prachtige weergave van de traditionele Japanse cultuur en esthetiek. Het belichaamt de waarden van Kunstdoekje: elegantie, inspiratie en een diepe waardering voor ','https://kunstdoekje.nl/wp-content/uploads/2023/09/1181.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28677) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zee-en-strand','Zee en strand','Zee en strand \n \n Fotograaf onbekend','https://kunstdoekje.nl/wp-content/uploads/2023/09/1185.png',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus'],false,true,28679) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('actor-band-hikosabur-iii-als-kud-suketsune','Actor Bandō Hikosaburō III als Kudō Suketsune','Actor Bandō Hikosaburō III als Kudō Suketsune \n Origineel uit het Minneapolis Institute of Art \n \nDeze afbeelding toont kabuki-acteur Bandō Hikosaburō III in een levendig kostuum, uitbeeldend Kudō Suketsune. Zijn gezicht, met traditionele make-up, straalt intense emotie uit. Dit kunstwerk is een prachtige weergave van de kunst en cultuur van het traditionele Japanse theater.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1186.png',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus'],false,true,28681) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zachte-abstractie','Zachte abstractie','Zachte abstractie','https://kunstdoekje.nl/wp-content/uploads/2023/09/1188.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,28683) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('grote-ganzen-in-vlucht','Grote Ganzen in Vlucht','Grote Ganzen in Vlucht (1925 - 1936) \n door Ohara Koson \n \nDit kunstwerk van Ohara Koson toont een groep ganzen die majestueus door de lucht vliegen. Koson, bekend om zijn vaardigheid in het vastleggen van de natuur, heeft met fijne details en subtiele kleuren de beweging en elegantie van de ganzen vastgelegd. De compositie geeft een gevoel van vrijheid en ruimte, waarbij de ganzen lijken te zweven tegen een uitgestrekte hemel.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1192.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28685) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zachte-abstractie-ii','Zachte abstractie II','Zachte abstractie II','https://kunstdoekje.nl/wp-content/uploads/2023/09/1193.png',(select id from categories where slug='asbtract'),array['asbtract','aziatische-kunst'],false,true,28688) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gang-in-het-asiel','Gang in het Asiel','Gang in het Asiel (1889) \n door Vincent Van Gogh \n \nDit schilderij van Vincent van Gogh toont een gang in een inrichting, waarschijnlijk geïnspireerd door zijn eigen verblijf in een psychiatrische kliniek in Saint-Rémy-de-Provence. De diepe, rijke kleuren en de kenmerkende penseelstreken van Van Gogh brengen de gang tot leven, waarbij de herhaling van de deuropeningen een gevoel van eindeloosheid en isolatie creëert. De kunstenaar heeft met dit werk de sfeer van de inrichting vastgelegd, waarbij de leegte en stilte bijna voelbaar zijn.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1194.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,28690) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koolmees-op-paulownia-tak','Koolmees op Paulownia Tak','Koolmees op Paulownia Tak (1925 - 1936) \n door Ohara Koson \n \nDit kunstwerk van Ohara Koson toont een koolmees, sierlijk rustend op een tak van de Paulownia-boom. Koson, een meester in de shin-hanga stijl, heeft met verfijnde details en subtiele kleurschakeringen de delicate aard van de vogel en de textuur van de tak vastgelegd. De compositie, met de vogel als centraal punt tegen een rustige achtergrond, benadrukt de eenvoudige schoonheid van de natuur.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1195.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28692) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tweemast-schoener-met-dory','Tweemast Schoener met Dory','Tweemast Schoener met Dory (1894) \n door Winslow Homer \n \nDit schilderij van Winslow Homer toont een tweemast schoener op zee, vergezeld van een kleine dory boot. Homer, bekend om zijn maritieme taferelen, heeft met nauwkeurige penseelstreken de beweging van de golven en de reflectie van het licht op het water vastgelegd','https://kunstdoekje.nl/wp-content/uploads/2023/09/1196.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,28695) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('umezawa-reigers-in-de-provincie-sagami','Umezawa reigers in de Provincie Sagami','Umezawa reigers in de Provincie Sagami (1830–1833) \n door Katsushika Hokusai','https://kunstdoekje.nl/wp-content/uploads/2023/09/1197.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28704) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-juweelrivier-in-de-provincie-musashi','De Juweelrivier in de Provincie Musashi','De Juweelrivier in de Provincie Musashi (1830–1833) \n door Katsushika Hokusai \n \nDit kunstwerk van Katsushika Hokusai toont de Juweelrivier die door de provincie Musashi stroomt. Hokusai, een meester in de ukiyo-e kunst, heeft met zijn kenmerkende stijl en aandacht voor detail de levendigheid en schoonheid van de rivier en zijn omgeving vastgelegd.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1198.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,28710) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsondergang-op-de-seine-bij-lavacourt','Zonsondergang op de Seine bij Lavacourt','Zonsondergang op de Seine bij Lavacourt (1880) \n door Claude Monet \n \nDit schilderij van Claude Monet toont een betoverende zonsondergang op de Seine bij Lavacourt. Monet, een pionier van het impressionisme, heeft met zijn kenmerkende losse penseelstreken de veranderende kleuren van de lucht en het reflecterende water vastgelegd.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1199.png',(select id from categories where slug='claude-monet'),array['claude-monet','landschapmodus'],false,true,28712) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('goten-yama-heuvel-shinagawa-aan-de-tokaido','Goten-Yama Heuvel, Shinagawa aan de Tokaido','Goten-Yama Heuvel, Shinagawa aan de Tokaido (1760-1849) \n door Katsushika Hokusai \n \nDit traditionele Japanse Ukiyo-e kunstwerk van Katsushika Hokusai toont de Goten-Yama heuvel in Shinagawa aan de Tokaido. De illustratie komt tot leven met bloeiende sakura-bomen, terwijl op de achtergrond de majestueuze Mount Fuji te zien is. Dorpsbewoners genieten van een picknick en vieren het leven, wat de essentie van de lente en gemeenschapsvreugde vastlegt.','https://kunstdoekje.nl/wp-content/uploads/2023/09/1200.png',(select id from categories where slug='aert-schouman'),array['aert-schouman','landschapmodus'],false,true,28714) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsondergang-bij-scheveningen-een-vloot-van-vissersschepen-voor-anker','Zonsondergang bij Scheveningen: Een Vloot van Vissersschepen voor Anker','Zonsondergang bij Scheveningen: Een Vloot van Vissersschepen voor Anker (1894) \n door Hendrik Willem Mesdag \n \nDit schilderij van Mesdag toont de vissersvloot van Scheveningen, rustend bij zonsondergang. De warme gloed van de ondergaande zon belicht de schepen, die symbool staan voor de bruisende vissersgemeenschap van die tijd. Mesdag''s gedetailleerde weergave van de zee en de schepen benadrukt zijn diepe waardering voor het maritieme leven en de natuurlijke schoonheid van de Nederlandse kust. Het kunstwerk is een eerbetoon aan het dagelijkse leven van de vissers en de onlosmakelijke band ','https://kunstdoekje.nl/wp-content/uploads/2023/09/1206.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,28718) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-reflectie','Gouden Reflectie','\n \n \n \n \n Gouden Reflectie \n \n \n \n \n \n Door ons creatieve team \n \n \n \n \n \n \n \n Ontdek "Gouden Reflectie", waar moderne geometrie samensmelt met tijdloze elegantie. Het schilderij toont een vrouw, verlicht door gouden tinten en doorsneden door abstracte lijnen. Haar blik, vol diepte, vangt onmiddellijk de aandacht, terwijl de geometrische accenten een moderne flair toevoegen. Dit stuk straalt een rustige schoonheid uit, ideaal voor wie op zoek is naar een subtiele mix van verleden en heden in kunst. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1237.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28896) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('herinterpretatie-van-een-icoon','Herinterpretatie van een Icoon','\n \n \n \n \n Herinterpretatie van een Icoon \n Door ons creatieve team \n Beleef een nieuwe kijk op Vermeer''s beroemde "Meisje met de Parel" in dit kunstwerk dat de stijlen van Mondriaan en Klimt prachtig vermengt. De onmiskenbare blik van het meisje wordt verrijkt door een achtergrond van strakke geometrische vormen, typerend voor Mondriaan, terwijl de rijke gouden elementen en sierlijke patronen een knipoog zijn naar Klimt''s kenmerkende stijl. Dit stuk is een eerbetoon aan drie meesters en hun onvergetelijke invloeden in de kunstwereld, een samensmelting van klassieke schoonheid en moderne','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1236.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28902) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('moderne-muse','Moderne Muse','\n \n \n \n \n Moderne Muse \n Door ons creatieve team \n Duik diep in de blik van onze "Moderne Muse". Met haar sierlijke neklijn en gedurfde geometrische achtergrond, vertegenwoordigt dit kunstdoekje een naadloze samensmelting van traditionele portretkunst en moderne abstractie. De pastelkleurige tinten vermengen zich met krachtige zwarten en roden, wat zorgt voor een intrigerend visueel spektakel. Laat je woonruimte stralen met dit betoverende stuk dat zowel elegantie als avant-garde uitstraalt. Een perfecte keuze voor de kunstliefhebber die zowel het verleden als de toekomst wil omarmen. \','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1235.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28904) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mondriaanse-schoonheid','Mondriaanse Schoonheid','\n \n \n \n \n Mondriaanse Schoonheid \n Door ons creatieve team \n Duik diep in de harmonie van strakke lijnen en gewaagde kleurblokken met "Mondriaanse Meditatie". Dit kunstdoekje, geïnspireerd op de onmiskenbare stijl van Piet Mondriaan, vangt de essentie van de Nederlandse kunstbeweging De Stijl. Terwijl het gezicht van een vrouw subtiel tevoorschijn komt tussen de geometrische vormen, creëert dit stuk een balans tussen abstractie en realisme. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1234.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28906) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-sereniteit','Gouden Sereniteit','\n \n \n \n \n Gouden Sereniteit \n Door ons creatieve team \n Betreed een wereld van elegantie en verfijning met "Gouden Sereniteit". Dit kunstdoekje toont een etherisch portret van een vrouw, gekroond met een schitterende melange van bloemen, gouden ornamenten en delicate structuren. De diepte en schittering van elk detail nodigen uit tot reflectie en bewondering. M \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1233.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28910) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fluisteringen-van-de-natuur','Fluisteringen van de Natuur','\n \n \n \n \n Fluisteringen van de Natuur \n Door ons creatieve team \n Betreed een wereld van elegantie en verfijning met "Gouden Sereniteit". Dit kunstdoekje toont een etherisch portret van een vrouw, gekroond met een schitterende melange van bloemen, gouden ornamenten en delicate structuren. De diepte en schittering van elk detail nodigen uit tot reflectie en bewondering. M \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1232.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28912) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-tijger','Kleurrijke tijger','\n \n \n \n \n Kleurrijke tijger \n Door ons creatieve team \n Dit levendige kunstdoekje, "Kleurrijke tijger", is een explosie van tinten en texturen die samenkomen om de majestueuze aanwezigheid van een tijger vast te leggen. Het spel van felle kleuren en spatten vormt een krachtig contrast met de intense blik van het roofdier, waardoor een gevoel van beweging en energie wordt opgeroepen. Dit kunstdoekje straalt de wilde, ongetemde essentie van de natuur uit en zou een gedurfd statement maken in elke ruimte. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1231.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28914) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tussen-oorlog-en-vrede','Tussen oorlog en vrede','\n \n \n \n \n Tussen oorlog en vrede \n Door ons creatieve team \n Laat je meevoeren door de provocerende wereld van straatkunst met deze indrukwekkende interpretatie van Banksy''s stijl. Twee militaire figuren worden afgebeeld, ondergedompeld in een mist van zachte roze en grijze tinten, wat zorgt voor een sterk contrast tussen het harde van oorlog en het zachte van vrede. De onverwachte spatten van roze verf symboliseren wellicht de hoop die schuilt in de donkerste momenten. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1229.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28916) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dromen-van-vrijheid','Dromen van Vrijheid','\n \n \n \n \n Dromen van Vrijheid \n Door ons creatieve team \n Dit kunstwerk nodigt de kijker uit om de wereld door de ogen van een kind te zien. De afbeelding van een jongen met een ballon in de vorm van de wereld roept gevoelens op van verwondering en de eindeloze mogelijkheden van de jeugd. De kleurrijke en toch vervallen achtergrond weerspiegelt wellicht de complexiteit en uitdagingen van de wereld waarin we leven. Het stuk spreekt tot de verbeelding en herinnert ons eraan dat, ondanks de uitdagingen, hoop en dromen altijd levendig blijven in het hart van de jeugd. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1227.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28918) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gelaagde-gedachten','Gelaagde Gedachten','\n \n \n \n \n Gelaagde Gedachten \n Door ons creatieve team \n Dit intrigerende kunstwerk illustreert de complexiteit van de menselijke geest. De afbeelding van een gezicht met overlappende en gelaagde penseelstreken symboliseert wellicht de talloze gedachten, gevoelens en ervaringen die in ons binnenste verborgen liggen. Het levendige kleurenpalet en het contrast tussen het gedetailleerde gezicht en de abstracte achtergrond maken dit stuk zowel visueel aantrekkelijk als diepgaand betekenisvol. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1226.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28920) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('elegante-abstractie','Elegante Abstractie','\n \n \n \n \n Elegante Abstractie \n Door ons creatieve team \n Dit stuk, met zijn gestroomlijnde vormen en gedurfde kleuraccenten, belichaamt de moderne interpretatie van vrouwelijke elegantie. De geometrische contouren van het gezicht worden gecomplementeerd door zachte kleurovergangen, waardoor er een samenspel ontstaat tussen het abstracte en het herkenbare. De toevoeging van gouddetails voegt een vleugje luxe toe, waardoor dit kunstwerk een gevoel van geraffineerde moderniteit uitstraalt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1225.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28922) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-bloesempracht','Gouden bloesempracht','\n \n \n \n \n Gouden bloesempracht \n Door ons creatieve team \n \nBetreed de wereld van "Gouden bloesempracht," waar hedendaagse kunst een eerbetoon brengt aan de beroemde schilder Gustav Klimt. Deze interpretatie toont een vrouw gehuld in een zee van kleurrijke bloemen, die haar haar tot leven brengen als een weelderig bloementapijt. De levendige kleuren en gedurfde patronen weerspiegelen de weelde en artistieke flair die Klimt kenmerkten. Dit kunstwerk is een viering van zowel natuurlijke schoonheid als kunstzinnige expressie. Een betoverende en eigentijdse toevoeging aan elke ruimte die v','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1221.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28924) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('impressionistische-parel','Impressionistische Parel','\n \n \n \n \n Impressionistische Parel \n Door ons creatieve team \n \nBetreed de wereld van de "Impressionistische Parel," een eigentijdse herinterpretatie van het iconische "Meisje met de Parel." In deze meesterlijke weergave wordt de verfijning van het originele schilderij gekoesterd in een impressionistische stijl. De fluweelzachte penseelstreken creëren een prachtig spel van licht en schaduw, terwijl het mystieke meisje in het midden van het doek blijft schitteren. Dit kunstdoekje is een eerbetoon aan de tijdloze schoonheid van Vermeer''s meesterwerk, omgezet in een subliem nieuw licht. \','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1218.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28926) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vlucht-voor-vrijheid','Vlucht voor vrijheid','\n \n \n \n \n Vlucht voor vrijheid \n Door ons creatieve team \n \nStap in de wereld van "Vlucht voor Vrijheid", een hedendaagse kunstuiting die de kenmerkende stijl van Banksy omarmt. Dit kunstdoekje toont een soldaat die de vogel van vrijheid achtervolgt. De kleurrijke bloemen symboliseren de hoop op een betere toekomst. De combinatie van strakke lijnen en gewaagde spatten van kleur creëert een visueel statement dat zowel krachtig als prikkelend is. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1216.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28928) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vlinders-van-verbeelding','Vlinders van verbeelding','\n \n \n \n \n Vlinders van verbeelding \n Door ons creatieve team \n \nHet hoofd van een dame versmelt met de gratie van vlinders. Dit kunstdoekje vangt de poëzie van metamorfose en verbeelding, waarbij de kleurrijke vlinders symbool staan voor de transformatie van gedachten en dromen. De vrouw kijkt met een blik vol verwondering, alsof ze haar gedachten de vrije loop laat in de wereld van verbeeldin \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/09/kunstdoekje-1215.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28930) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('graffiti-wildernis','Graffiti Wildernis','\n \n \n \n \n Graffiti Wildernis \n Door ons creatieve team \n \n"Graffiti Wildernis" is een fascinerend kunstdoekje dat de grenzen van traditionele artistieke expressie verkent. In het centrum van dit kunstwerk straalt een majestueuze luipaard, waarvan de kracht wordt versterkt door de levendige graffiti-accenten die de achtergrond sieren. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1265.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28933) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('street-owl','Street Owl','\n \n \n \n \n Street Owl \n Door ons creatieve team \n \nDe "Street Owl" is een verbluffend kunstdoekje dat de inspiratiebronnen van bekende street artists samenbrengt in een opvallende uiting van moderne creativiteit. De uil, symbool van wijsheid en mysterie, schittert te midden van een levendige explosie van kleuren en patronen. Deze unieke samenkomst van stijlen biedt een visuele viering van popart en hedendaagse expressie. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1288.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28935) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('street-monkey','Street Monkey','\n \n \n \n \n Street Monkey \n Door ons creatieve team \n \nIn dit werk zie je een aap met een relaxte houding, compleet met een coole zonnebril. Het vangt de creatieve en vrijgevochten geest van straatkunst, waar de straten dienen als het canvas voor artistieke expressie. De felle kleuren en levendige lijnen voegen een gevoel van dynamiek en urbaniteit toe, terwijl de aap een knipoog is naar de eigenzinnigheid en speelsheid van de stadscultuur. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1277.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28938) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('street-owl-copy','Street Owl (Copy)','\n \n \n \n \n Street Owl \n Door ons creatieve team \n \nDe "Street Owl" is een verbluffend kunstdoekje dat de inspiratiebronnen van bekende street artists samenbrengt in een opvallende uiting van moderne creativiteit. De uil, symbool van wijsheid en mysterie, schittert te midden van een levendige explosie van kleuren en patronen. Deze unieke samenkomst van stijlen biedt een visuele viering van popart en hedendaagse expressie. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1288.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,false,28939) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('graffiti-beertje','Graffiti Beertje','\n \n \n \n \n Graffiti Beertje \n Door ons creatieve team \n \nIDit kunstdoekje, getiteld "Graffiti Beertje," vangt de vitaliteit en creatieve energie van straatkunst in één speels beeld. Het beertje, omgeven door levendige graffiti, vertegenwoordigt de levendige kunstvorm die overal in de stad opduikt. Dit kunstwerk brengt een vleugje urbaniteit en zelfexpressie in elke ruimte en herinnert ons eraan dat kunst verrassend en divers kan zijn, waar je ook kijkt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1283.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28942) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('graffiti-beertje-copy','Graffiti Beertje  (Copy)','\n \n \n \n \n Graffiti Beertje \n Door ons creatieve team \n \nIDit kunstdoekje, getiteld "Graffiti Beertje," vangt de vitaliteit en creatieve energie van straatkunst in één speels beeld. Het beertje, omgeven door levendige graffiti, vertegenwoordigt de levendige kunstvorm die overal in de stad opduikt. Dit kunstwerk brengt een vleugje urbaniteit en zelfexpressie in elke ruimte en herinnert ons eraan dat kunst verrassend en divers kan zijn, waar je ook kijkt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1283.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,false,28944) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('street-veal','Street Veal','\n \n \n \n \n Street Veal \n Door ons creatieve team \n \nWelkom in de wereld van "Street Kalfje," een kunstdoekje dat de onbevangenheid van straatkunst omarmt. Dit werk toont het schattige hoofd van een kalfje in een speelse, street art-stijl. De gedurfde lijnen en levendige kleuren brengen een gevoel van energie en zelfexpressie naar voren, terwijl het kalfje een onverwachte en charmante artistieke twist toevoegt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1252.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28945) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('streetwise-owl','Streetwise Owl','\n \n \n \n \n Streetwise Owl \n Door ons creatieve team \n \neen kunstdoekje dat de straatkunst in al haar facetten verkent. Dit werk brengt de uil tot leven met invloeden van diverse straatartiesten, en weeft elementen van street art in een boeiende en veelzijdige compositie. De levendige kleuren en gedurfde lijnen weerspiegelen de vrijheid en creativiteit van de stedelijke kunstscène. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1289.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28947) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ninja-aapje','Ninja Aapje','\n \n \n \n \n Ninja Aapje \n Door ons creatieve team \n \nStap binnen in de wereld van het "Ninja Aapje," een kunstdoekje dat de essentie van straatkunst omarmt. Dit werk brengt het aapje tot leven met invloeden van verschillende straatkunstenaars, waarbij elementen van street art worden samengevoegd in een uitdagende en dynamische compositie. De gewaagde kleuren en gedurfde lijnen weerspiegelen de vrije en creatieve geest van de stedelijke kunstscene. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1281-1.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28949) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloeiende-parel','Bloeiende parel','\n \n \n \n \n Bloeiende Parel \n Door ons creatieve team \n \n"Bloeiende Parel" is een unieke herinterpretatie van het iconische "Meisje met de Parel," waarbij bloemen en natuurlijke schoonheid samenkomen in een betoverende compositie. Dit kunstdoekje eert het klassieke schilderij door de parel te vervangen door een bloem die in volle bloei staat. De combinatie van zowel de traditionele als de organische elementen creëert een visueel gedicht dat de tijdloze pracht van het originele werk viert, terwijl het de natuurlijke wereld omarmt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1247.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28951) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('goudbruine-straatbeer','Goudbruine Straatbeer','\n \n \n \n \n Goudbruine Straatbeer \n Door ons creatieve team \n \nOntmoet "Goudbruine straatbeer," een uniek kunstdoekje dat de stoere en charismatische wereld van straatkunst tot leven brengt. Deze opvallende beer met zijn gouden vacht tegen een levendige roze achtergrond is een artistieke uiting die de aandacht trekt. Met dit kunstwerk breng je een flinke dosis creatieve flair en een vleugje straatcultuur in elke ruimte. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1278.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28953) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('nachtelijke-betovering','Nachtelijke Betovering','\n \n \n \n \n Nachtelijke Betovering \n Door ons creatieve team \n \nDompel je onder in de esthetische pracht van een levendige ijsvogel, schitterend afgebeeld tegen een dromerige, nachtelijke achtergrond. De heldere blauw- en oranjetinten van de ijsvogel vormen een betoverend contrast met de delicate pastelbloemen, waardoor een beeld van pure schoonheid en inspiratie ontstaat. Perfect voor de kunstliefhebber die zoekt naar een stuk dat zowel persoonlijke flair als diepe betekenis toevoegt aan hun ruimte. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1266.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28955) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('coliblue','Coliblue','\n \n \n \n \n Coliblue \n Door ons creatieve team \n Dit Kunstdoekje brengt de betoverende charme van een colibri, subtiel balancerend op een touw, naar je leefruimte. De schitterende kleuren van de vogel komen tot leven tegen de rustige lucht, zorgvuldig gekozen om een harmonieuze sfeer te creëren. Het is een treffend beeld dat niet alleen de pracht van de natuur viert, maar ook een vleugje rust en elegantie toevoegt aan elke ruimte. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1260-1.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28957) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koninklijke-rebel','Koninklijke Rebel','\n \n \n \n \n Koninklijke Rebel \n Door ons creatieve team \n Dit Kunstdoekje is een explosie van kleuren en texturen, en vertegenwoordigt de unieke samensmelting van stijlen van diverse street artists. In het middelpunt staat een beer met een trotse kroon, die zowel kracht als onschuld uitstraalt, omgeven door levendige en chaotische penseelstreken. Het is een viering van rebellie, koninklijke waardigheid en artistieke vrijheid. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1270-1.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28959) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mozaiek-aap-reflectie','Mozaïek Aap Reflectie','\n \n \n \n \n Mozaïek Aap Reflectie \n Door ons creatieve team \n "Mozaïek Aap Reflectie" is een kunstdoekje dat de complexiteit van introspectie verkent. Het levendige patroon en de kleuren binnen het gezicht van de aap symboliseren onze innerlijke gedachten en emoties. Dit kunstdoekje nodigt uit tot diepe reflectie en zal zeker opvallen in elke ruimte. Het is een samensmelting van kleur, vorm en betekenis, perfect voor de moderne kunstliefhebber. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1280.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28961) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mozaiek-aap-reflectie-copy','Mozaïek Aap Reflectie (Copy)','\n \n \n \n \n Mozaïek Aap Reflectie \n Door ons creatieve team \n "Mozaïek Aap Reflectie" is een kunstdoekje dat de complexiteit van introspectie verkent. Het levendige patroon en de kleuren binnen het gezicht van de aap symboliseren onze innerlijke gedachten en emoties. Dit kunstdoekje nodigt uit tot diepe reflectie en zal zeker opvallen in elke ruimte. Het is een samensmelting van kleur, vorm en betekenis, perfect voor de moderne kunstliefhebber. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1280.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,false,28964) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mozaiek-aap-reflectie-copy-28965','Mozaïek Aap Reflectie (Copy)','\n \n \n \n \n Mozaïek Aap Reflectie \n Door ons creatieve team \n "Mozaïek Aap Reflectie" is een kunstdoekje dat de complexiteit van introspectie verkent. Het levendige patroon en de kleuren binnen het gezicht van de aap symboliseren onze innerlijke gedachten en emoties. Dit kunstdoekje nodigt uit tot diepe reflectie en zal zeker opvallen in elke ruimte. Het is een samensmelting van kleur, vorm en betekenis, perfect voor de moderne kunstliefhebber. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1280.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,false,28965) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kijk-van-onschuld','Kijk van onschuld','\n \n \n \n \n Kijk van onschuld \n Door ons creatieve team \n Dit kunstdoekje, genaamd ''Kijk van Onschuld'', onthult een ontroerend portret van een kind wiens ogen een wereld van verwondering en nieuwsgierigheid vastleggen. Het bijzondere hoofddeksel, rijkelijk versierd met patronen geïnspireerd door Gustav Klimt, contrasteert prachtig met de serene uitdrukking van het kind. Elk detail nodigt de kijker uit dieper in het verhaal achter de betoverende ogen te duiken, terwijl het ook hulde brengt aan de klassieke stijl van Klimt. Een tijdloos kunstdoekje dat zowel emotie als artistieke finesse be','https://kunstdoekje.nl/wp-content/uploads/2023/10/1261.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28966) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-curiositeit','Kleurrijke Curiositeit','\n \n \n \n \n Kleurrijke Curiositeit \n Door ons creatieve team \n Dit kunstdoekje, getiteld ''Kleurrijke Curiositeit'', toont een levendig en sprankelend portret van een varken, ondergedompeld in een caleidoscoop van kleuren. Het speelse en toch intense uiterlijk van het varken, gecombineerd met de dynamische verfspatten, zorgt voor een visueel feest dat elke ruimte kan opfleuren. Dit kunstdoekje is niet alleen een viering van kleur, maar ook van de onschuld en nieuwsgierigheid van het dierenrijk. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1248.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28968) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stedelijke-aap','Stedelijke Aap','\n \n \n \n \n Stedelijke Aap \n Door ons creatieve team \n Dit kunstdoekje, ''Stedelijke Aap'', presenteert een uniek en gedurfd beeld van een aap in stedelijke stijl. Gekleed in een opvallende jas met geometrische patronen en een bijpassende pet, straalt deze aap een verfijnde flair uit. De achtergrond, een wirwar van lijnen en kleuren, versterkt het moderne en stedelijke gevoel. Dit doekje is perfect voor liefhebbers van eigentijdse kunst en dierenportretten met een twist. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1269.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28970) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-gorilla','Kleurrijke Gorilla','\n \n \n \n \n Kleurrijke Gorilla \n Door ons creatieve team \n Een levendige weergave van een gorilla omhuld in een spectrum van heldere kleuren. De intense blik van de gorilla, gecombineerd met de spatten van kleur, geeft het een energieke en dynamische uitstraling. De achtergrond, gevuld met abstracte penseelstreken en druppels, voegt diepte en textuur toe aan het beeld. Dit zou een opvallende aanvulling zijn op elke ruimte, perfect voor diegenen die hun omgeving willen verlevendigen met een beetje wildheid en kleur. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1268.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28972) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-blik','Gouden Blik','\n \n \n \n \n Gouden Blik \n Door ons creatieve team \n Geïnspireerd door Gustav Klimt, toont dit portret een betoverende vrouw omhuld in rijke blauwtinten en opvallend goud. Haar hoofddoek, versierd met Klimt-achtige patronen, straalt luxe uit. Haar sterke blik vangt de essentie van de krachtige vrouwelijke figuren die Klimt vaak afbeeldde. Een tijdloos stuk dat zowel klassiek als hedendaags aanvoelt. Ideaal voor kunstliefhebbers en interieurverfraaing. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1255-1.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28974) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ijsbeer-illusie','IJsbeer Illusie','\n \n \n \n \n IJsbeer Illusie \n Door ons creatieve team \n Een ijsbeer te midden van een explosie van kleur en geometrische vormen. De mix van het koele wit van de beer en de levendige tinten eromheen schept een contrast dat zowel opvallend als harmonieus is. De verfstreken en kleurspatten voegen dynamiek toe, wat het gevoel geeft dat de ijsbeer zich een weg baant door een wereld vol kleur. Een prachtig stuk voor liefhebbers van dieren en moderne kunst. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1250.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28980) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mystieke-leeuw','Mystieke Leeuw','\n \n \n \n \n Mystieke Leeuw \n Door ons creatieve team \n Een betoverende weergave van een leeuw, verlicht door de schittering van kosmische kleuren en tinten. Zijn doordringende ogen zijn als poorten naar een andere dimensie, terwijl de golvende manen een regenboog van kleur uitstralen. Deze kunst straalt kracht en mysterie uit, perfect voor diegenen die een vleugje majestueuze wildheid in hun ruimte willen brengen. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1267.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28983) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('reflecties-van-de-denker','Reflecties van de Denker','\n \n \n \n \n Reflecties van de Denker \n Door ons creatieve team \n Een dynamische weergave van een chimpansee, met levendige kleuren die zijn gedachten en emoties vangen. De achtergrond, vol energieke penseelstreken en geometrische vormen, contrasteert met de diepe, contemplatieve blik van de chimpansee. Deze kunst nodigt de kijker uit om dieper te graven, voorbij het oppervlak, en na te denken over het samenspel van natuur, emotie en kunst. Perfect voor een ruimte die zowel schoonheid als betekenis zoekt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1273.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28985) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rebel-cat','Rebel cat','\n \n \n \n \n Rebel cat \n Door ons creatieve team \n Dit kunstdoekje combineert de edgy stijlen van verschillende straatkunstenaars, resulterend in een kat die zowel koninklijkheid als rebellie uitstraalt. Met een kroon die zijn heerschappij symboliseert en een halsband vol urban iconografie, belichaamt dit kunstwerk de essentie van straatcultuur. Een perfect stuk voor liefhebbers van zowel katten als hedendaagse kunst. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1271.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28989) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-majesteit','Kleurrijke Majesteit','\n \n \n \n \n Kleurrijke Majesteit \n Door ons creatieve team \n \n \n \n \n \n \n \n \n \nEen dynamische en kleurrijke interpretatie van een leeuw, waarbij elke penseelstreek de kracht en elegantie van dit majestueuze dier benadrukt. "Kleurrijke Majesteit" is een compact kunstdoekje dat grootsheid en levendigheid uitstraalt. Perfect voor liefhebbers van natuur en kunst. \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1254-2.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28991) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stedelijke-blik','Stedelijke blik','\n \n \n \n \n Stedelijke blik \n Door ons creatieve team \n \n \n \n \n \n \n \n \n \nDit kunstdoekje vermengt de intense, nieuwsgierige blik van een kat met het bruisende ritme van de stad. "Stedelijke Blik" is een visueel verhaal van contrasten, waarbij natuurlijke elegantie botst met de rauwe energie van stedelijke landschappen. Een ode aan zowel de zelfstandige geest van katten als de levendige chaos van de stad. \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1272.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28993) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('nachtelijke-wijsheid','Nachtelijke wijsheid','\n \n \n \n \n Nachtelijke wijsheid \n Door ons creatieve team \n \n \n \n \n \n \n \n \n \nDeze expressieve uil, afgebeeld tegen een mozaïek van stedelijke fragmenten, symboliseert de wijsheid en kennis die vaak geassocieerd worden met dit mysterieuze nachtdier. "Nachtelijke Wijsheid" combineert traditionele symboliek met hedendaagse kunstelementen, waardoor het een boeiende visuele ervaring is die zowel de geest als het oog aanspreekt. \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1279.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28997) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurenvlucht-van-de-ijsvogel','Kleurenvlucht van de IJsvogel','\n \n \n \n \n Kleurenvlucht van de IJsvogel \n Door ons creatieve team \n \n \n \n \n \n \n \n \n \nDeze levendige voorstelling van een ijsvogel brengt de schoonheid en helderheid van de natuur samen tegen een duister, bijna kosmisch achtergrond. De spatten van kleur suggereren een dynamische beweging, alsof de ijsvogel op het punt staat zich in een schilderachtige vlucht te storten. Het kunstwerk viert de harmonie tussen natuurlijke pracht en abstract expressionisme. \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/10/1249.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,28999) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('klimt-s-moderne-muse','Klimt''s Moderne Muse','\n \n \n \n \n Klimt''s Moderne Muse \n Door ons creatieve team \n \n \n \n \n \n \n \n \n \nGeïnspireerd door de kenmerkende stijl van Gustav Klimt, presenteert dit portret een hedendaagse interpretatie van zijn gouden periode. De vrouw op het schilderij draagt een glinsterende gouden hoofdtooi die doet denken aan Klimt''s iconische kunstwerken. Haar diepe, doordringende blik weerspiegelt de kracht en mystiek die vaak in Klimt''s vrouwelijke figuren te vinden zijn. De samensmelting van moderne schoonheid en klassieke invloeden maakt dit kunstwerk een eerbetoon aan de blijvende invloed van Klimt ','https://kunstdoekje.nl/wp-content/uploads/2023/10/1256.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,29001) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hager-selsilis','Hager Selsilis','door David Roberts (1796–1864) \n \n"Hager Selsilis (Gebel el Silsila)" illustratie door David Roberts, origineel van The New York Public Library, toont de majestueuze landschappen van Egypte met zijn kenmerkende aandacht voor detail en sfeer. Deze werken zijn een weerspiegeling van Roberts'' reizen door het Midden-Oosten, vastleggend de monumentale architectuur en natuurlijke schoonheid van de regio.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1298.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,29402) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tatsuta-berg-en-tatsuta-rivier','Tatsuta berg en Tatsuta rivier','door Utagawa Hiroshige \n \nEen serene weergave van de Tatsuta-rivier die sierlijk door het landschap slingert, met Hiroshige''s kenmerkende subtiele kleurgebruik en aandacht voor detail. Herfsttinten accentueren de bomen langs de waterkant, terwijl de Tatsuta-berg statig toekijkt.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1291-1.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29407) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('huizen-op-de-achterzaan','Huizen op de Achterzaan','door Claude Monet \n \nDit kunstdoekje brengt de serene schoonheid van een middag langs de Achterzaan tot leven, geschilderd door Monet in 1871. De reflecties van Nederlandse huizen en groen dansen op het water, terwijl de meesterlijke licht- en kleurbehandeling van de impressionist de levendige sfeer van de Zaanstreek vastlegt.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1292-1.png',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus','oude-meesters'],false,true,29412) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('siberische-blauwchat-naast-een-pioenroos','Siberische Blauwchat naast een pioenroos','door Ohara Koson \n \nOp dit verfijnde kunstdoekje brengt Ohara Koson een moment van winterse stilte tot leven. Een Siberische blauwborst rust naast een weelderige pioenroos, beschut door een sneeuwbedekte hooiberg. De subtiele contrasten en het verfijnde kleurgebruik weerspiegelen Koson''s meesterschap in het vastleggen van de serene schoonheid van de natuur, waardoor dit werk een oase van rust vormt voor elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1293.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29418) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('grote-bonte-specht-in-boom-met-rode-klimop','Grote bonte specht in boom met rode klimop','\n \n \n \n door Ohara Koson \n \n \n \n \n \nEen grote bonte specht is vereeuwigd in minutieuze details door Ohara Koson, rustend tegen een achtergrond van rood klimop en herfstbladeren. Koson''s kunstwerk is een stille getuige van de overgangsseizoenen, waarin de specht''s zwart-witte verenkleed opvalt tegen de warme herfsttinten. Dit stuk brengt de subtiele schoonheid van de natuur naar binnen, perfect voor het verlevendigen van een rustige hoek of een contemplatieve ruimte in huis.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1294.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','natuur','oude-meesters'],false,true,29422) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bamboo-bloemenmand','Bamboo bloemenmand','\n \n \n \n door Ohara Koson \n \n \n \n \n \nKoson''s ''Bamboo Flowerbasket'' is een prachtig kunstwerk dat de perfecte balans tussen schoonheid en eenvoud weerspiegelt. Het toont een weelderige pioenroos die trots uit een bamboe mand steekt tegen een diepblauwe achtergrond. De kunstenaar heeft hiermee een sierlijk samenspel van bloemen vastgelegd. Dit kunstdoekje brengt een vleugje natuurlijke elegantie in elke ruimte, met zijn subtiele tinten en rustgevende uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1295.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen','oude-meesters'],false,true,29426) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('regatta-at-sainte-adresse','Regatta at Sainte-Adresse','door Claude Monet \n \nMonet''s "Regatta at Sainte-Adresse" brengt de bruisende energie van zeilboten op het water tot leven. Heldere zeilen en een levendige kustlijn, geschilderd in 1867, tonen een zonnige dag aan de Franse kust, waarbij het licht speels met het water danst. Dit kunstdoekje is een snapshot van zomerplezier, ideaal om een vleugje Monet''s meesterschap in elke ruimte te brengen.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1296.png',(select id from categories where slug='claude-monet'),array['claude-monet','landschapmodus','oude-meesters'],false,true,29430) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-brug-bij-argenteuil','De brug bij Argenteuil','door Claude Monet \n \nMonet''s ''The Bridge at Argenteuil'' toont levendig licht en reflecties op het water, met een kleurrijke hemel en boten die de rust van de Franse Seine vangen. Geschilderd in 1874, belichaamt dit stuk het Impressionisme, met licht penseelwerk en heldere kleuren die uitnodigen tot ontspanning en contemplatie.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1299.png',(select id from categories where slug='claude-monet'),array['claude-monet','oude-meesters'],false,true,29434) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('karmozijnrode-langoesten','Karmozijnrode Langoesten','\n \n \n \n \n \n \n \n \n \n \n \n \n Crimson Crawfish (Palemon Ornatum) \n \nDit kunstdoekje van D'' Orbigny''s "Crimson Crawfish" brengt de natuurlijke elegantie van zeeleven in huis met zijn scherpe, gouden details tegen een donkere achtergrond. De afbeelding combineert wetenschappelijke precisie met kunstzinnige flair, waardoor het een opvallend stuk is voor elke liefhebber van zowel kunst als natuur. \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/11/1300.png',(select id from categories where slug='dieren'),array['dieren','natuur','oude-meesters','specials'],false,true,29440) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-grote-golf-bij-kanagawa','De grote golf bij Kanagawa','\n \n \n \n \n \n door Katsushika Hokusai (ca. 1830) \n \n"De grote golf bij Kanagawa" is wellicht het beroemdste werk van Katsushika Hokusai, kenmerkend voor de ukiyo-e houtsnedekunst uit de Edo-periode. Deze dynamische afbeelding toont een immense golf die dreigt boten bij Kanagawa te overspoelen, met Mt. Fuji op de achtergrond, en symboliseert de nietige positie van de mens tegenover de kracht van de natuur. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/11/1301.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,29446) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('regattas-at-argenteuil','Regattas at Argenteuil','\n \n \n \n \n Regattas at Argenteuil \n \n \n \n \n \n \n \n \n \n \n \n \n door Claude Monet \n \nIn dit levendige impressionistische schilderij van Claude Monet uit 1872 worden de schoonheid en levendigheid van een zonnige dag op de rivier weerspiegeld. De zachte kleuren en losse penseelstreken van Monet geven een adempauze van kleur en vreugde. De scene wordt bewoond door een menigte van zeilschepen die zich vertonen op de rivier en het water afglanst in de zon. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/11/1303.png',(select id from categories where slug='claude-monet'),array['claude-monet','landschapmodus','oude-meesters'],false,true,29451) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-louvre-van-de-pont-neuf','The Louvre van de Pont Neuf','door Camille Pissarro \n \nPissarro''s "The Louvre from the Pont Neuf" toont een levendig Parijs gezien vanaf de oudste brug van de stad. Met zachte kleuren en lichte streken legt hij de rust van de Seine en de drukte van de stad vast, een dagelijkse scène met een tijdloze charme. Dit kunstdoekje brengt een stukje historisch Parijs in elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1302.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters'],false,true,29455) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kataoka-nizaemon','Kataoka Nizaemon','Deze prent toont Kataoka Nizaemon, een legendarische figuur uit het Japanse Kabuki-theater, gekleed in traditionele gewaden. Zijn uitdrukking is doordringend en weerspiegelt de dramatische flair van Kabuki. Met strakke lijnen en gedempte kleuren brengt de afbeelding de krachtige aanwezigheid van Nizaemon op het podium. over.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1304.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,29459) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('uitzicht-in-het-bentheim-woud','Uitzicht in het Bentheim woud','door George Andries Roth \n \n"View in the Bentheim Forest" van Roth is een schilderij dat de rust en bedrijvigheid van het bosleven vastlegt. Het toont een machtige boom met zonlicht dat door de bladeren speelt, terwijl mensen en paarden in de schaduw werken. Dit stuk is een rustiek tafereel, ideaal voor wie de stilte van het bos en de eenvoud van het landelijke leven in huis wil halen.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1305.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','natuur'],false,true,29463) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amerikaanse-schoonheid','Amerikaanse schoonheid','American Beauty \n \nDeze charmante prent, getiteld "American Beauty", toont een jonge vrouw in een stralende gouden jurk, met een boeket dieprode rozen in haar handen. Haar zachte blik en bloeiende schoonheid worden benadrukt door de warme tinten en zachte penseelstreken, waardoor dit kunstdoekje een tijdloze uitstraling van elegantie en gratie heeft.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1306-1.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','oude-meesters'],false,true,29467) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-jaagpad','Het Jaagpad','door Johan Barthold Jongkind \n \nJongkind''s "The Towpath" uit 1864 toont een vredige dag langs het kanaal, met lange rijen bomen die het pad omzomen. Een figuur te paard voegt een menselijke aanraking toe aan het landelijke landschap. Dit schilderij, met zijn zachte licht en kalme water, is een serene weergave van het 19e-eeuwse plattelandsleven.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1307.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters'],false,true,29470) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tamaca-palmbomen','Tamaca Palmbomen','door Frederic Edwin Church \n \n"Tamaca Palms" van Frederic Edwin Church, geschilderd in 1854, toont de prachtige natuur in volle glorie. Met weelderige palmbomen vooraan en machtige bergen op de achtergrond, geeft dit schilderij het schitterende tropische landschap weer. De rustige rivier en het bootje maken het plaatje compleet en nemen je even mee naar deze idyllische en vredige plek.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1308.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','natuur','oude-meesters'],false,true,29476) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zeegezicht-met-zes-zwemmers-bellport','Zeegezicht met zes zwemmers, Bellport','door William James Glackens \n \nIn ''Seascape with Six Bathers, Bellport'' uit 1915 vangt William James Glackens een zorgeloos moment aan de kust. Levendige kleuren en speelse penseelstreken brengen een zomerse sfeer tot leven, met baders die genieten van het water en zeilboten die zachtjes door de bries worden voortbewogen. Glackens'' meesterlijke weergave van licht en beweging laat de toeschouwer bijna de zilte zeelucht voelen.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1309.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,29480) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('exotische-vogel-op-victoriaanse-boekomslag','Exotische Vogel op Victoriaanse Boekomslag','Exotische Vogel op Victoriaanse Boekomslag \n \n door Alexander Francis Lydon \n \nDeze victoriaanse boekomslag, versierd door Alexander Francis Lydon, toont een sierlijke, gouden vogel rustend op een tak. Het gedetailleerde houtgravurewerk en het gebruik van goud tegen een donkere achtergrond straalt elegantie en verfijning uit. Dit ontwerp is kenmerkend voor de tijd waarin boeken niet alleen voor hun inhoud, maar ook als decoratieve objecten werden gewaardeerd.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1310.png',(select id from categories where slug='natuur'),array['natuur','oude-meesters'],false,true,29484) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('waterloo-brug-grijze-dag','Waterloo brug, Grijze Dag','door Claude Monet \n \nClaude Monet''s "Waterloo Bridge, Grijze Dag" uit 1903 laat een nevelige atmosfeer zien boven de Theems, waarbij de brug en Londen''s skyline vaag verschijnen door de mist. De impressionistische penseelstreken en het subtiele kleurenpalet van grijstinten en pastels creëren een gevoel van rust en verstilling, typisch voor Monet''s vermogen om licht en sfeer vast te leggen. Dit werk maakt deel uit van een serie waarin Monet de veranderlijke natuur van licht en weer boven de rivier verkent.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1311.png',(select id from categories where slug='claude-monet'),array['claude-monet','landschapmodus','oude-meesters'],false,true,29488) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('wi-jun-jon-een-assinneboin-hoofd','Wi-Jun-Jon, Een Assinneboin Hoofd','Wi-Jun-Jon, Een Assinneboin Hoofd \n \n door onbekend \n \nDeze kleurrijke illustratie toont Wi-Jun-Jon, een vooraanstaand leider van de Assinneboin-stam, gekleed in traditionele kledij met een imposante verentooi. Naast hem staat een contrasterend beeld van Wi-Jun-Jon in een westerse militaire uniform, wat de culturele assimilatie en identiteitsverandering symboliseert die veel inheemse volkeren hebben ervaren.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1312.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,29492) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fluisteringen-van-de-lente-elegantie-onder-de-sakura','Fluisteringen van de Lente: Elegantie onder de Sakura','door Katsushika Hokusai (ca. 1830) \n \nDit kunstwerk van Hokusai brengt de delicate schoonheid van de Japanse kersenbloesem in beeld, symbolisch voor de vergankelijkheid. De fijngeklede figuren, afgebeeld met subtiele details en rijke kleuren, illustreren de elegantie van de Edo-periode. Het tafereel vangt een moment van sociale interactie en bewondering voor de natuur, en nodigt de kijker uit tot contemplatie','https://kunstdoekje.nl/wp-content/uploads/2023/11/1313.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29521) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-bonenplukker','De Bonenplukker','door Winslow Homer (ca. 1875) \n \n"The Bean Picker" door Winslow Homer, origineel uit de collectie van The Smithsonian, toont de eenvoud en hardheid van het landelijke leven rond 1875. Dit werk legt de aandacht op de dagelijkse taak van een boonplukker, met een focus op natuurlijk licht en de relatie tussen mens en natuur.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1314.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,29553) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-kraanvogels','Japanse Kraanvogels','Schilder onbekend \n \n De vintage Japanse houtsnede prints van Japanse kraanvogels tonen de tijdloze elegantie en spirituele betekenis van deze vogels in de Japanse cultuur. Deze periode kenmerkt zich door een diepe waardering voor de natuur, vastgelegd in de verfijnde kunst van houtsnede.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1315.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29555) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('karmozijnrode-ibis','Karmozijnrode Ibis','door Paul Gervais (1842) \n \nDe scharlaken ibis, vastgelegd in de 1842 editie van "Le Jardin Des Plantes" door Paul Gervais, biedt een gedetailleerde blik op deze opvallende rode vogel. Gervais'' werk benadrukt de schoonheid en bijzonderheid van de ibis binnen de natuurlijke wereld.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1316.png',(select id from categories where slug='dieren'),array['dieren','natuur','oude-meesters'],false,true,29557) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bladgroen-symfonie','Bladgroen Symfonie','Schilder onbekend \n \nDe illustratie van het groene Musa Vittata blad toont de unieke details en kleur van dit tropische blad, een voorbeeld van de rijke diversiteit binnen de plantenwereld.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1318.png',(select id from categories where slug='natuur'),array['natuur'],false,true,29561) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('talismanic-tiger','Talismanic Tiger','Schilder onbekend \n \n"Talismanic Tiger" is een vintage Japanse schilderij uit de 20e eeuw die de krachtige symboliek en artistieke vaardigheid van Japanse kunstenaars in het portretteren van dieren en mythologische thema''s toont. Dit kunstwerk weerspiegelt de culturele waardering voor tijgers als symbolen van kracht en bescherming.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1319.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,29563) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('actors-in-the-noh-theater-play-eboshiori','Actors in the Noh Theater Play Eboshiori','door Kogyo Tsukioka \n \n"Actors in the Noh Theater Play Eboshiori" illustreert met verfijnde detail de theatrale expressie en traditionele kostumering van acteurs in het klassieke Noh-theater. Dit werk van Tsukioka, een meester in het vastleggen van de essentie van Noh, biedt een unieke inkijk in deze eeuwenoude Japanse podiumkunst.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1320.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29565) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('long-eared-owl-in-ginkgo','Long-eared Owl in Ginkgo','door Ohara Koson (1900 - 1930) \n \nDe prent "Long-eared Owl in Ginkgo" door Ohara Koson, actief tussen 1877 en 1945, toont een prachtig tafereel van een ransuil te midden van ginkgo bladeren. Dit werk is een prachtig voorbeeld van Koson''s meesterschap in het vastleggen van de rustige schoonheid van vogels en de natuur, kenmerkend voor de Shin-hanga beweging in Japan.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1322-1.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,29569) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ry-sh-ten','Ryū shōten','door Ogata Gekko (1897) \n \n"Ryū shōten" is een hoge resolutie print van Ogata Gekko uit 1897, die de opstijgende draak als een krachtig symbool in de Japanse cultuur uitbeeldt. Dit werk is een prachtig voorbeeld van Gekko''s vaardigheid in het combineren van traditionele Japanse esthetiek met zijn eigen unieke stijl.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1323.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29572) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('crimson-crawfish','Crimson Crawfish','door Charles Dessalines D'' Orbigny (1806-1876) \n \n"Crimson Crawfish (Palemon Ornatum)" geïllustreerd door Charles Dessalines D'' Orbigny, toont met detail de rijke kleur en complexiteit van deze zeedieren. D'' Orbigny''s werk, kenmerkend voor zijn bijdrage aan de natuurlijke geschiedenis, biedt een gedetailleerde en wetenschappelijke weergave van de biodiversiteit.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1324.png',(select id from categories where slug='dieren'),array['dieren'],false,true,29574) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jongen-en-meisje-in-het-veld-met-een-schaap','Jongen en meisje in het veld met een schaap','door Winslow Homer (1878) \n \n"Boy and Girl in a Field with Sheep" van Winslow Homer uit 1878 toont een idyllisch tafereel van jeugd en natuur, waarin twee kinderen vreedzaam samen zijn met schapen in een veld. Dit kunstwerk weerspiegelt de harmonie tussen mens en natuur, kenmerkend voor Homer''s werk uit deze periode.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1325.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','impressionisme','landschapmodus','natuur'],false,true,29576) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('oceaangolf-bij-kojima-island','oceaangolf bij Kojima Island','Schilder onbekend \n \nDe vintage houtsnede van een oceaangolf bij Kojima Island is een prachtig voorbeeld van de traditionele Japanse houtsnijkunst, die de kracht en schoonheid van de natuurlijke wereld vangt. Dit stuk, kenmerkend voor de gedetailleerde en expressieve stijl van Japanse houtsnedes, biedt een tijdloos uitzicht op de dynamische en ongetemde oceaan.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1326.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','landschapmodus'],false,true,29578) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanese-butterfly','Japanese butterfly','door Kamisaka Sekka (1904) \n \n"Japanese butterfly" uit de 1904 editie van Kamisaka Sekka''s "Cho senshu" toont de fijne schoonheid en diversiteit van vlinders in de Japanse kunst. Sekka''s werk, bekend om zijn vernieuwende aanpak binnen de traditionele Japanse esthetiek, biedt een frisse blik op de natuurlijke wereld door zijn delicate en kleurrijke illustraties van vlinders.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1327.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','landschapmodus'],false,true,29580) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanese-butterflies-2','Japanese butterflies 2','door Kamisaka Sekka \n \n"Japanese Butterfly" uit Kamisaka Sekka''s "Cho senshu" illustreert de subtiele schoonheid van vlinders, een thema dat vaak terugkomt in de Japanse kunst en symboliek.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1328.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','landschapmodus'],false,true,29582) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('slapende-kat','Slapende kat','door Kōno Bairei (1844-1895) \n \n"Sleeping Cat" door Kōno Bairei is een rustgevende afbeelding die de sereniteit en gratie van een slapende kat vastlegt. Dit werk is typerend voor Bairei''s vermogen om de essentie van zijn onderwerpen met eenvoud en elegantie te vangen.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1329.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,29584) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fish-illustration','Fish illustration','door Mochizuki Gyokusen (1891) \n \nDe ukiyo-e illustratie van vissen en schelpen door Mochizuki Gyokusen, getekend in 1891, toont Gyokusen''s vakmanschap in het vastleggen van de delicate schoonheid van het onderwaterleven. Dit kunstwerk weerspiegelt de waardering voor de eenvoud en de esthetische charme van de natuur in de Japanse kunsttraditie.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1330.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','oude-meesters'],false,true,29586) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('yang-lin','Yang Lin','door Utagawa (1797-1861) \n \n"Yang Lin (Kinhyoshi Yorin)", uit de serie "One Hundred and Eight Heroes of the Popular Water Margin (Tsuzoku Suikoden goketsu hyakuhachinin no hitori)" door Utagawa, toont een van de moedige helden uit het klassieke Chinese literaire werk. Utagawa''s interpretatie brengt het verhaal tot leven met rijke details en levendige kleuren, kenmerkend voor de ukiyo-e kunststijl van deze periode.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1331.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29588) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-gele-jasje','Het gele jasje','door Winslow Homer (1879) \n \n"The Yellow Jacket" door Winslow Homer illustreert zijn vermogen om dagelijkse momenten en de Amerikaanse geest vast te leggen. Dit werk uit 1879 toont mogelijk een scène van vrije tijd of werk buitenshuis, kenmerkend voor Homer''s interesse in het leven en landschappen van die tijd.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1332.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,29590) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-vrouw','Japanse Vrouw','door Yamanaka Kodō (1929) \n \n"Japanese woman" is een vintage houtsnede van Yamanaka Kodō, die een delicate weergave van een Japanse vrouw uit 1929 toont, kenmerkend voor de verfijnde esthetiek van de periode.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1333.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,29592) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sait-no-oniwakamaru','Saitō no Oniwakamaru','door Tsukioka Yoshitoshi (1872) \n \n"Saitō no Oniwakamaru" uit 1872–1873 is een krachtig werk van Tsukioka Yoshitoshi, dat het legendarische kind, Oniwakamaru, toont, bekend om zijn bovennatuurlijke kracht en moed. Deze afbeelding behoort tot Yoshitoshi''s beroemde reeks van historische krijgers, gevuld met dramatiek en emotionele diepte.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1334.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','oude-meesters'],false,true,29594) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ghost-of-a-genius','Ghost of a genius','door Paul Klee \n \n"Ghost of a Genius" weerspiegelt Paul Klee''s unieke abstracte stijl waarbij hij gebruikmaakt van geometrische vormen en gedurfde kleuren om de essentie van een inspirerende geest weer te geven. Dit werk is een eerbetoon aan de ongrijpbare vonk van creativiteit.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1337.png',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,29598) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwaluwen-dans-in-de-wisteria-bloesem','Zwaluwen dans in de Wisteria-bloesem"','door Ohara Koson \n \n"Zwaluwen en Wisteria" uit 1926 is een verfijnd Japans vogelillustratie van Ohara Koson. De afbeelding brengt de gracieuze interactie tussen zwaluwen en de sierlijke wisteria bloesems tot leven, een typisch thema in de natuur-geïnspireerde kunst van Koson.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1338.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen','dieren','oude-meesters'],false,true,29600) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vrouw-na-het-badderen','Vrouw na het badderen','door Goyo Hashiguchi \n \nDit kunstdoekje belicht het moment van rust van model Tomi uit 1920. Hashiguchi staat bekend om zijn vermogen om vrouwelijke schoonheid en elegantie te vangen met een gevoel van stilte en contemplatie. Dit werk, dat het subtiele spel van licht en schaduw benadrukt, is een prachtige weergave van de Japanse Shin-hanga beweging, waarbij traditionele ukiyo-e technieken worden gecombineerd met moderne elementen.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1339.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,29602) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('groen-parkietenpaar','Groen Parkietenpaar','Schilder onbekend','https://kunstdoekje.nl/wp-content/uploads/2023/11/1340.png',(select id from categories where slug='dieren'),array['dieren'],false,true,29604) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fluistering-van-de-natuur-stilleven-harmonie','Fluistering van de Natuur: Stilleven Harmonie','door G.A. Audsley (Jaar onbekend) \n \nDit kunstdoekje toont een stilleven in traditioneel Japanse stijl met vogels en fruit, gekenmerkt door de rijke details en het contrastrijke kleurgebruik. Het kunstwerk van G.A. Audsley nodigt uit tot waardering voor de rust en eenvoud die zo typerend zijn voor de Japanse kunstopvatting.','https://kunstdoekje.nl/wp-content/uploads/2023/11/1341.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','bloemen'],false,true,29606) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amsterdamse-reflectie-spiegel-van-de-gracht','Amsterdamse Reflectie: Spiegel van de Gracht','Amsterdamse Reflectie: Spiegel van de Gracht \n \nWaar de tijdloze charme van Amsterdamse architectuur zich mengt met de rustige wateren van de gracht, ontstaat een spiegelbeeld dat de essentie van Nederlandse schoonheid vangt. Deze levendige weergave van de bekende grachtenpanden, met hun karakteristieke gevels en reflectie in het kalme water, biedt een venster naar het hart van de stad. Het is een kunstdoekje dat niet alleen de geest van Amsterdam in je huis brengt, maar ook een vleugje serene contemplatie biedt in elke ruimte waar het mag schitteren.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1343.png',(select id from categories where slug='fotografie'),array['fotografie'],false,true,29960) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('een-ode-aan-de-dag','Een Ode aan de Dag','Florale Zonnestraal: Een Ode aan de Dag \n \nDit kunstdoekje is een viering van licht en leven, waar de zachte pasteltinten van de ochtendzon zich vermengen met de levendige kleuren van bloeiende flora. Elk detail, van de fijne stengels tot de zorgvuldig geplaatste bloemblaadjes, vertelt een verhaal van groei en nieuwe beginnen. Het is een uitnodiging om te genieten van de eenvoudige schoonheid van de natuur, gevangen in een moment van tijdloze elegantie. Perfect voor diegene die zijn ruimte wil opfleuren met een kunstwerk dat warmte en positiviteit uitstraalt. \n \n','https://kunstdoekje.nl/wp-content/uploads/2023/12/1345-1.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,30020) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stedelijke-weerspiegeling-lichtspel-in-de-nacht','Stedelijke Weerspiegeling: Lichtspel in de Nacht','Stedelijke Weerspiegeling: Lichtspel in de Nacht \n \nDit kunstwerk brengt de dynamiek van de stad naar je huis, waar de fonkelende lichten van een bruisende metropool zich weerspiegelen in rustige wateren. De diepe nachttinten contrasteren met het levendige neon, symboliserend de constante energie en het altijd bedrijvige leven in het hart van Shanghai.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1346-1.png',(select id from categories where slug='fotografie'),array['fotografie'],false,true,30022) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-vos-in-het-gouden-uur','De Vos in het Gouden Uur','De Vos in het Gouden Uur \n \nDit kunstdoekje vangt de essentie van het plattelandsleven, met een sluwe vos die elegant zijn weg door de velden kiest. Het warme licht van de late middag benadrukt de roestige vacht van dit prachtige dier, een symbool van slimheid en schoonheid in de natuur.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1347.png',(select id from categories where slug='dieren'),array['dieren','fotografie'],false,true,30024) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vrijheid-in-de-vallei-harmonie-onder-de-hemel','Vrijheid in de Vallei: Harmonie onder de Hemel','Vrijheid in de Vallei: Harmonie onder de Hemel \n \nDit kunstdoekje toont een vredig tafereel van ongerepte natuur, waar imposante bergen op de achtergrond dienen als decor voor twee gracieuze paarden die rustig grazen in de gouden vallei. Hun kalme aanwezigheid symboliseert de natuurlijke harmonie en de serene rust die de wereld te bieden heeft, ver weg van de hectiek van alledag.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1349.png',(select id from categories where slug='dieren'),array['dieren','fotografie'],false,true,30028) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ontwaken-van-de-aarde','Ontwaken van de Aarde','Ontwaken van de Aarde \n \nBij zonsopkomst omarmen de eerste zonnestralen de majestueuze bergtoppen, die baden in een gouden gloed. De Torres del Paine, een natuurwonder, worden vastgelegd op deze foto, dat zowel de kracht van de natuur als de stille pracht van de dageraad weerspiegelt.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1350.png',(select id from categories where slug='fotografie'),array['fotografie'],false,true,30030) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sneeuw-uil','Sneeuw uil','door John Gould, Edward Lear en Charles Joseph Hullmande (1832–1837) \n \nDe "Snowy Owl" print door John Gould, Edward Lear, en Charles Joseph Hullmande, gedateerd tussen 1832 en 1837, toont de statige schoonheid van de sneeuwuil in hoge resolutie. Dit werk combineert de expertise van drie prominente figuren in de natuurhistorische illustratie, resulterend in een gedetailleerd en levensecht portret van deze indrukwekkende vogel.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1351.png',(select id from categories where slug='dieren'),array['dieren'],false,true,30032) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('miss-beatrice','Miss Beatrice','door John Singer Sargent (1882) \n \n"Miss Beatrice Townsend" door John Singer Sargent is een portret uit 1882 dat de jeugdige elegantie en verfijnde gratie van zijn onderwerp vastlegt. Dit werk is exemplarisch voor Sargent''s meesterschap in het gebruik van licht en schaduw om diepte en karakter te geven aan zijn portretten.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1353.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,30034) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('paarden-hoofd','Paarden hoofd','door Richard Roland Holst (1881) \n \n"Horse Head" door Richard Roland Holst, een schilderij uit 1881 en origineel van het Rijksmuseum, toont de krachtige uitstraling en de fijne details van een paardenhoofd in hoge resolutie. Dit werk illustreert Holst''s vaardigheid in het vastleggen van de essentie en schoonheid van zijn onderwerpen met een opmerkelijke precisie en gevoel voor vorm.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1352.png',(select id from categories where slug='dieren'),array['dieren','impressionisme'],false,true,30036) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-een-vrouw','Portret van een vrouw','door Egon Schiele (1910) \n \n"Portrait of a Woman" door Egon Schiele, een originele lijntekening van een vrouw uit 1910 bewaard door The MET museum, toont de unieke stijl en expressieve lijnvoering van Schiele. Dit portret weerspiegelt de diepe emotionele intensiteit en psychologische diepgang die kenmerkend zijn voor Schiele''s werk.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1354.png',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,30038) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemen-in-een-vaas','Bloemen in een vaas','door Odilon Redon (1910) \n \n"Flowers in a Vase" door Odilon Redon is een kleurrijk schilderij uit 1910, origineel van de National Gallery of Art. Het stuk toont Redon''s kenmerkende gebruik van levendige kleuren en dromerige compositie om de schoonheid van bloemen in een vaas vast te leggen.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1357.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,30042) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('evocation-of-roussel','Evocation of Roussel','door Odilon Redon (1912) \n \n"Evocation of Roussel" door Odilon Redon, gecreëerd in 1912, weerspiegelt de symbolistische benadering van Redon in de kunst, waarbij hij zich richt op het uitdrukken van emoties en ideeën. Dit werk toont zijn meesterschap in het gebruik van kleur en vorm om een diepe, contemplatieve ervaring te bieden.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1358-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,30051) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('peaches-and-plum','Peaches and plum','door Elisabeth Geertruida van de Kasteele (naar Michiel van Huysum) (1700-1800) \n \n"Peaches and a Plum" is een prachtig stilleven dat de weelde van rijpe vruchten viert, geschilderd door Elisabeth Geertruida van de Kasteele, geïnspireerd door Michiel van Huysum. Het kunstwerk, te bewonderen in The Rijksmuseum, betovert met levendige kleuren en rijke texturen, waardoor de kijker wordt uitgenodigd om de heerlijke eenvoud van de natuur te ervaren.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1360-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30057) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pear-and-plum','Pear and plum','door Elisabeth Geertruida van de Kasteele (naar Michiel van Huysum) (1700-1800) \n \nDit betoverende stilleven, "Pear and Plum", geschilderd door Elisabeth Geertruida van de Kasteele en geïnspireerd door Michiel van Huysum, belichaamt de weelde van rijpend fruit.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1363-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','natuur'],false,true,30060) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('colorful-abstraction','Colorful abstraction','Kunstenaar onbekend','https://kunstdoekje.nl/wp-content/uploads/2023/12/1365-1.png',(select id from categories where slug='asbtract'),array['asbtract'],false,true,30066) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-in-een-vaas','Stilleven in een vaas','Schilder onbekend','https://kunstdoekje.nl/wp-content/uploads/2023/12/1368-1.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,30077) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-call','The call','door Paul Gauguin (1902) \n \n"The Call" is een intrigerend kunstwerk van Paul Gauguin, voltooid in 1902. Dit meesterwerk, te bewonderen in The Cleveland Museum, toont Gauguin''s kenmerkende stijl en thema''s. Met levendige kleuren en symbolische elementen roept het schilderij vragen op over identiteit, spiritualiteit en de relatie tussen mens en natuur.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1369.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,30080) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('wheat-field-with-view-of-arles','Wheat field with View of Arles','door Vincent van Gogh (1888) \n \n"Wheat field with View of Arles" is een beroemd landschapsschilderij van Vincent van Gogh, geschilderd in 1888. Dit meesterwerk vangt de schoonheid en sereniteit van het Zuid-Franse platteland, met zijn golvende tarwevelden en de karakteristieke architectuur van Arles in de verte.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1372.png',(select id from categories where slug='van-gogh'),array['van-gogh'],false,true,30089) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flower-studies','Flower studies','door Abbott Handerson Thayer (ca. 1886) \n \n"Flower Studies" is een prachtig schilderij uit circa 1886, gemaakt door Abbott Handerson Thayer. In dit werk verkent Thayer de delicate schoonheid en complexiteit van bloemen met een scherp oog voor detail.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1373.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme'],false,true,30092) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('chrysanthemum','Chrysanthemum','door Piet Mondriaan (1900) \n \nDe tekening "Chrysanthemum" uit 1900, gemaakt door Piet Mondriaan, is een verfijnd voorbeeld van zijn vroege werk. Met scherpe lijnen en een beperkt kleurenpalet legt Mondriaan de delicate schoonheid van de chrysant vast. Deze tekening, in hoge resolutie te bewonderen, laat zien hoe Mondriaan al vroeg zijn unieke stijl en gevoel voor compositie ontwikkelde, waarmee hij later de abstracte kunst zou domineren.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1374.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,30095) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('girl-in-green-turba','Girl in Green Turba','door William James Glackens (1913) \n \n"Girl in Green Turban" is een betoverend schilderij uit 1913, gemaakt door William James Glackens. In dit werk vangt Glackens de charme en mysterie van een jonge vrouw gehuld in een groene tulband. Met levendige kleuren en expressieve penseelstreken brengt hij de levendigheid en persoonlijkheid van het onderwerp tot leven op het doek','https://kunstdoekje.nl/wp-content/uploads/2023/12/1377.png',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,30122) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portrait-of-a-lady','Portrait of a lady','door Sandro Botticelli (1480–1485) \n \n"Sandro Botticelli''s Portrait of a Lady" is een meesterwerk uit de periode 1480-1485, ook wel bekend als "Portrait of Simonetta Vespucci as Nymph". In dit portret legt Botticelli de tijdloze schoonheid en elegantie van de dame vast, vermoedelijk Simonetta Vespucci, een beroemde Florentijnse schoonheid uit die tijd. Met zachte kleuren en verfijnde details weet Botticelli de gratie en charme van zijn model op indrukwekkende wijze over te brengen.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1378.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,30126) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portrait-of-morton-d-may','Portrait of Morton D. May','door Max Beckmann (1949) \n \n"Portrait of Morton D. May" uit 1949, geschilderd door Max Beckmann, is een meesterwerk in hoog contrast dat de persoonlijkheid en aanwezigheid van de geportretteerde vastlegt. Beckmann staat bekend om zijn expressieve stijl en dramatische composities, en dit portret is daar geen uitzondering op.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1380.png',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,30130) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('carnival-mask-green-violet-and-pink','Carnival Mask, Green, Violet, and Pink','Door: Max Beckmann (1950) \n \n"Carnival Mask, Green, Violet, and Pink (Columbine)" uit 1950 is een intrigerend kunstwerk van Max Beckmann. Dit schilderij, te bewonderen in hoge resolutie, toont Beckmann''s fascinatie voor het theatrale en symbolische aspect van maskers','https://kunstdoekje.nl/wp-content/uploads/2023/12/1381.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','specials'],false,true,30132) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portrait-of-ludwig-berger','Portrait of Ludwig Berger','door Max Beckmann (1945) \n \n"Portrait of Ludwig Berger" uit 1945, geschilderd door Max Beckmann, is een indringend portret dat de kracht en complexiteit van de geportretteerde vastlegt. Beckmann staat bekend om zijn expressieve stijl en diepgaande karakteriseringen, en dit portret is daar een uitstekend voorbeeld van. Met gedurfde penseelstreken en een rijk kleurenpalet weet Beckmann de persoonlijkheid van Ludwig Berger op een krachtige en meeslepende manier over te brengen.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1382.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,30134) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('man-s-face','Man''s face','door Arnold Peter Weisz Kubínčan \n \n"Man''s face" is een intrigerend werk van Arnold Peter Weisz Kubínčan. In dit schilderij vangt Kubínčan de diepte en complexiteit van het menselijke gelaat. Met gedurfde penseelstreken en expressieve details weet hij de emotie en individualiteit van de geportretteerde vast te leggen. Dit werk nodigt de kijker uit om te reflecteren op de innerlijke wereld van de man en de verhalen die zijn gezicht vertelt.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1383.png',(select id from categories where slug='asbtract'),array['asbtract','impressionisme'],false,true,30136) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zelfportet','Zelfportet','door Arnold Peter Weisz Kubínčan \n \nHet zelfportret van Arnold Peter Weisz Kubínčan biedt een intieme blik op de kunstenaar zelf. Met gedurfde penseelstreken en intense expressie legt hij zijn eigen identiteit vast, waardoor de kijker wordt uitgenodigd om een diepere verbinding te voelen met de persoon achter het kunstwerk.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1385.png',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,30140) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('girl-from-ni-n-hrabovec','Girl from Nižný Hrabovec"','door Štefan Polkoráb \n \n"Girl from Nižný Hrabovec" is een intrigerend werk van Štefan Polkoráb. In dit schilderij wordt de schoonheid en eenvoud van het alledaagse leven op het Slowaakse platteland vastgelegd. Met zachte penseelstreken en een subtiele kleurenpalet weet Polkoráb de charme en de rust van het dorpse leven te vangen','https://kunstdoekje.nl/wp-content/uploads/2023/12/1387.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,30144) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('winter-landscape-near-diar','Winter landscape near Ždiar','door Ferdinand Katona \n \n"Winter landscape near Ždiar" is een betoverend werk van Ferdinand Katona. In dit schilderij wordt de serene schoonheid van een winterlandschap bij Ždiar op meesterlijke wijze vastgelegd. omgeving te vangen.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1390.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','natuur'],false,true,30150) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('study-of-blooming-trees-in-an-orchard','Study of blooming trees in an orchard','door László Mednyánszky \n \n"Study of blooming trees in an orchard" is een prachtig werk van László Mednyánszky. In dit schilderij worden de prachtige bloesems van een boomgaard op indrukwekkende wijze vastgelegd. Met subtiele penseelstreken en een zacht kleurenpalet weet Mednyánszky de lentepracht en de tijdelijke pracht van de bloesems te vangen.','https://kunstdoekje.nl/wp-content/uploads/2023/12/1391.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','landschapmodus','natuur'],false,true,30152) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lemons-and-orange','Lemons and orange','door Pierre-Auguste Renoir (1913) \n \n"Lemons and Orange" (Citrons et orange) uit 1913, geschilderd door Pierre-Auguste Renoir, is een verfrissend en levendig stilleven dat de eenvoudige schoonheid van citrusvruchten viert. Met zijn kenmerkende penseelstreken en levendige kleurenpalet brengt Renoir de levendigheid en het aroma van de vruchten tot leven op het doek.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1496.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30630) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('a-bar-at-the-folies-bergere','A Bar at the Folies-Bergère','door Édouard Manet (1882) \n \nÉdouard Manets "A Bar at the Folies-Bergère" uit 1882 is een iconisch werk dat een barvrouw in de beroemde Parijse nachtclub toont. Het schilderij is een meesterwerk van de impressionistische stijl en roept vragen op over perspectief en sociale interactie','https://kunstdoekje.nl/wp-content/uploads/2024/01/1495.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30633) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('berthe-morisot-with-a-bouquet-of-violets','Berthe Morisot With a Bouquet of Violets','door Édouard Manet \n \n"Berthe Morisot With a Bouquet of Violets" is een prachtig portret geschilderd door Édouard Manet. In dit meesterwerk uit de 19e eeuw wordt Berthe Morisot, een prominente figuur in de impressionistische kunstbeweging, afgebeeld met een boeket viooltjes. Het schilderij straalt elegantie en tederheid uit, met levendige kleuren en een subtiele compositie die de charme van de geportretteerde benadrukt.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1481.png',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,30675) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fillette-couchee-sur-l-herbe-et-jeune-fille-arrangeant-un-bouquet','Fillette couchée sur l''herbe et jeune fille arrangeant un bouquet','door Pierre-Auguste Renoir \n \nDit kunstdoekje uit 1890 toont twee meisjes die ontspannen liggen in het gras, bezig met het samenstellen van een boeket bloemen. Deze charmante scène straalt jeugdige vreugde en verbondenheid met de natuur uit, waardoor het een tijdloos en ontroerend kunstwerk is.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1483-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30707) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bon-bock-cafe','Bon Bock Cafe','door Edouard Manet (1881) \n \nDit Kunstdoekje is een hoogwaardige afbeelding die het Parijse caféleven uit die tijd vastlegt. Dit werk illustreert Manet''s interesse in het sociale leven en zijn vaardigheid in het portretteren van licht en sfeer, kenmerkend voor zijn bijdrage aan de moderne kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1484-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30710) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('charing-cross-bridge','Charing Cross Bridge','door Claude Monet (1903) \n \n"Charing Cross Bridge" door Claude Monet uit 1903 is een iconisch schilderij dat de mistige sfeer van Londen over de Thames vastlegt. Dit werk maakt deel uit van een serie waarin Monet de invloed van licht en weer op het stadsgezicht onderzocht, kenmerkend voor zijn impressionistische stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1485-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30713) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gardener-s-house-at-antibes','Gardener''s House at Antibes','door Claude Monet (1888) \n \n"Gardener''s House at Antibes" door Claude Monet, gemaakt in 1888 en behorend tot de collectie van The Cleveland Museum of Art, toont Monet''s meesterlijke gebruik van kleur en licht. Dit werk weerspiegelt de idyllische en zonovergoten omgeving van Antibes, waarbij Monet de unieke sfeer en de levendige natuurlijke schoonheid van de locatie vastlegt.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1486-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30716) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('interior-at-arachon','Interior at Arachon','door Édouard Manet (1871) \n \n"Interior at Arachon" door Édouard Manet uit 1871 illustreert zijn bekwaamheid in het vastleggen van intieme interieurscènes. Dit kunstwerk, bekend om zijn hoge resolutie en aandacht voor detail, toont de sfeervolle binnenruimte met een rijke compositie van licht en schaduw, kenmerkend voor Manet''s werk.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1487-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30719) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('madame-michel-levy','Madame Michel-Lévy','door Édouard Manet (1882) \n \n"Madame Michel-Lévy" door Édouard Manet is een elegante verschijning uit 1882, waar de finesse van de Franse haute société van die tijd in elke penseelstreek weerklinkt. Met een subtiele mix van schaduw en licht brengt Manet ons dichter bij Madame Michel-Lévy, een icoon van stijl en gratie.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1488-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,30722) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-lecture-house','The lecture house','door William Henry','https://kunstdoekje.nl/wp-content/uploads/2024/01/1490-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30728) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landscape-paysage','Landscape (Paysage)','door Pierre-Auguste Renoir (1917) \n \n"Landscape (Paysage)" door Pierre-Auguste Renoir, geschilderd in 1917, is een stralend voorbeeld van Renoir''s latere werk, waarin hij de weelderige natuur met een levendig palet en vloeiende penseelstreken vastlegt. Dit schilderij weerspiegelt Renoir''s ongeëvenaarde vermogen om licht en kleur te gebruiken, waardoor een landschap ontstaat dat zowel rustgevend als vol leven is.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1491-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','natuur'],false,true,30731) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('oesters','Oesters','door Edouard Manet (1862) \n \n"Oesters" door Edouard Manet uit 1862 is een smaakvol stilleven dat de eenvoudige elegantie van oesters op een tafel vastlegt. Dit werk, met zijn rijke texturen en subtiele kleurnuances, toont Manet''s vermogen om alledaagse voorwerpen te transformeren in boeiende kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1493-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30737) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sainte-adresse','Sainte-Adresse','door Claude Monet (1867) \n \n"Sainte-Adresse" door Claude Monet uit 1867 is een levendig landschap dat de kustlijn van Sainte-Adresse vastlegt met zijn typerende impressionistische stijl. De combinatie van heldere kleuren, lichtspel, en dynamische penseelstreken toont Monet''s meesterschap in het vangen van het moment en de sfeer.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1494-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30740) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('konijnen-bij-volle-maan','Konijnen bij volle maan','door Ohara Koson (1920 - 1930) \n \n"Rabbits at Full Moon" door Ohara Koson, uit de periode 1920-1930 en onderdeel van de collectie van het Rijksmuseum, toont een idyllisch en poëtisch tafereel van konijnen onder een stralende volle maan. Dit kunstwerk, met zijn fijne details en subtiele kleurgebruik, weerspiegelt Koson''s meesterschap in het vastleggen van de serene schoonheid van de natuur. Het nodigt de kijker uit tot momenten van rust en reflectie, waarbij de tijdloze verbinding tussen natuur en mystiek wordt gevierd.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1335.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,30755) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-van-vergankelijkheid','Stilleven van Vergankelijkheid','Door: G.A. Audsley-Japanese \n \nIn de nachtelijke stilte ontvouwt zich een levendig stilleven, waarin de natuur in volle pracht schittert. "Japanese Still Life" vangt dit moment, met een elegante vogel die zich tegoed doet aan rijpe vruchten, omringd door herfstbladeren en oogstrijkdom. Granaatappels, druiven en noten vormen een harmonieuze compositie, vol leven en betekenis.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1340.png',(select id from categories where slug='bloemen'),array['bloemen'],false,true,30767) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dans-van-de-leeuw','Dans van de Leeuw','door Kamisaka Sekka (1920) \n \n"Lion Dancer, One of Four" door Kamisaka Sekka uit de jaren 1920, is een levendige weergave van de traditionele Japanse leeuwendans. Sekka''s kunst, die vaak de grenzen van de traditionele Japanse esthetiek verkent, brengt hier de energie en het ritme van deze culturele dans tot leven. Dit werk is kenmerkend voor Sekka''s innovatieve benadering en zijn vaardigheid in het combineren van klassieke thema''s met een moderne flair.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1371.png',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','oude-meesters'],false,true,30807) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portet-van-een-kind','Portet van een kind','Jeugdige Overpeinzing \n \ndoor Gustav Klimt \n \nIn "Portrait of a Child (Marie Moll)", toont Klimt ons een stille wereld vol onschuld en nieuwsgierigheid. Met elke penseelstreek brengt hij Marie tot leven, haar blik diep en dromerig, omgeven door zachte krullen. Dit kunstwerk nodigt uit tot verwondering, een viering van kinderlijke puurheid die elke ruimte verrijkt met een vleugje sereniteit en schoonheid.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1449.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,30810) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('studie-van-twee-gezichten','Studie van twee gezichten','door Peter Paul Rubens \n \nDit kunstdoekje brengt je dichter bij de genialiteit van Rubens, die niet alleen een meester was in het vastleggen van koninklijke portretten en mythologische taferelen, maar ook een scherp observator van de menselijke emotie. Dit stukje kunst geeft ons een kijkje in zijn atelier, waar elke penseelstreek en elke schaduw een verhaal vertelt van twee mensen, vastgelegd met een diepte die alleen Rubens kon bereiken.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1450.png',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,30817) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-milking-place-at-meilg-rd','The Milking Place at Meilgård','door Theodor Philipsen \n \n"The Milking Place at Meilgård" is een schilderij dat het rustieke en vredige boerenleven uitbeeldt, met een focus op de eenvoudige maar essentiële taak van het melken. Philipsen''s werk staat bekend om zijn vermogen om de natuurlijke schoonheid van het Deense landschap en het alledaagse leven vast te leggen met een bijzondere aandacht voor licht en kleur​','https://kunstdoekje.nl/wp-content/uploads/2024/01/1471.png',(select id from categories where slug='dieren'),array['dieren','impressionisme','landschapmodus'],false,true,30820) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('playing-children-meadow-square','Playing Children, Meadow Square','door Peter Hansen (jaartal onbekend) \n \nNeem een kijkje op het dorpsplein op een zonnige dag en zie hoe kinderen zich vermaken te midden van het weelderige groen. Dat is precies wat Peter Hansen vastlegde in zijn schilderij "Playing Children, Meadow Square". Met levendige kleuren en een bruisende energie brengt hij de levendigheid van spelende kinderen tot leven. Het schilderij nodigt je uit om je te laten meeslepen door de vreugde en de speelsheid van het moment, en herinnert ons eraan dat geluk te vinden is in de eenvoudige geneugten van het leven.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1399.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30865) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mist-and-steam','Mist and steam','door Joseph Pennell (1880-1926) \n \n"Mist and Steam" is een vintage illustratie van gebouwen, gemaakt door Joseph Pennell tussen 1880 en 1926. De afbeelding biedt een intrigerende blik op stedelijke landschappen gehuld in mist en stoom, waardoor een sfeer van mysterie en bedrijvigheid ontstaat.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1452.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,30883) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landscape-below-the-low-tatras','Landscape below the Low Tatras','door Zolo Palugyay (1932) \n \nDe vintage illustratie "Landscape below the Low Tatras" uit 1932, gemaakt door Zolo Palugyay, biedt een nostalgische blik op het landschap onder de lage Tatra-bergen. Met een subtiel kleurenpalet en meesterlijk vakmanschap vangt Palugyay de rustieke charme van dit schilderachtige gebied, waardoor de kijker wordt meegenomen op een reis door de tijd naar een vervlogen era van natuurlijke pracht.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1457-1.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','natuur'],false,true,30885) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rocks-and-turbulent-lake-capri','Rocks and Turbulent Lake, Capri','door Christen Købke \n \n"Rocks and Turbulent Lake, Capri" van Christen Købke biedt een levendige weergave van de rotsachtige kustlijn en het onstuimige meer van Capri. Met meesterlijk penseelwerk vangt Købke de kracht en pracht van de natuur, waardoor de kijker wordt meegenomen naar de wilde schoonheid van het Italiaanse landschap.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1472.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','natuur'],false,true,30898) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-tuin','De tuin','door Thomas E. Hill (1915) \n \nDe waterverfillustratie van de tuin en het huis door Thomas E. Hill uit 1915 is een prachtige weergave van rustieke schoonheid. Met zachte penseelstreken vangt Hill de sereniteit en charme van het landschap, waardoor de kijker wordt uitgenodigd om zich onder te dompelen in de vredige sfeer van het tafereel.','https://kunstdoekje.nl/wp-content/uploads/2024/01/1298.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme'],false,true,30916) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('drie-perziken-op-een-stenen-richel-met-een-distelvlinder','Drie Perziken op een Stenen Richel met een Distelvlinder','Door: Adriaan Coorte (ca. 1693-1695) \n \n"Drie Perziken op een Stenen Richel met een Distelvlinder" is een meesterwerk van Adriaan Coorte. Met zijn kenmerkende precisie en aandacht voor detail schilderde Coorte drie sappige perziken op een stenen richel, vergezeld door een elegante distelvlinder. Dit werk straalt een gevoel van rust en eenvoud uit, terwijl het tegelijkertijd de pracht van de natuurlijke wereld viert.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1535.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','rijks'],false,true,36278) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-armand-roulin','Portret van Armand Roulin','Door: Vincent van Gogh (1888) \n \n"Portret van Armand Roulin" is een levendig portret geschilderd door Vincent van Gogh. Met zijn krachtige penseelstreken en levendige kleuren brengt Van Gogh de persoonlijkheid van Armand Roulin tot leven','https://kunstdoekje.nl/wp-content/uploads/2024/04/1500.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters','van-gogh'],false,true,36409) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-aardappeleters','De aardappeleters','Door: Vincent van Gogh (1853-1890) \n \n"De Aardappeleters" uit 1885, geschilderd door Vincent van Gogh, vangt het rauwe leven van het Nederlandse platteland. In dit meesterwerk verbeeldt van Gogh het eenvoudige maar krachtige tafereel van een boerenfamilie die hun avondmaaltijd nuttigt.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1504.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,36411) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('le-palais-matin-d-ete','Le Palais, Matin D’été','Door: Henri Le Sidaner (1908) \n \n"Le Palais, Matin D’été (Hampton Court)" uit 1908 neemt je mee naar een zomerse ochtend bij Hampton Court, een historisch koninklijk paleis in Engeland. Dit betoverende werk van Le Sidaner vangt de serene schoonheid van het paleis en zijn omgeving.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1508.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters'],false,true,36412) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('head-study-of-a-girl','Head Study of a Girl','Door: Gustav Klimt (1862-1918) \n \nWelkom in de betoverende wereld van "Head Study of a Girl" van Gustav Klimt! Laat je meeslepen door de betoverende blik van dit mysterieuze meisje, gevangen in Klimt''s kenmerkende stijl. Ontdek de intrigerende details van haar gelaat en laat je verrassen door de subtiele nuances van kleur en expressie. Dit meesterwerk belichaamt de tijdloze schoonheid en de ongeëvenaarde vaardigheid van een van de meest invloedrijke kunstenaars van de 20e eeuw.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1501.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,36413) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blekerij-te-scheveningen','Blekerij te Scheveningen','Door: Vincent van Gogh (1882) \n \n"Blekerij te Scheveningen" uit 1882 toont een levendig tafereel van het dagelijks leven aan de kust. In dit werk vangt Van Gogh de sfeer en bedrijvigheid van de blekerijen in Scheveningen. Laat je meevoeren door de levendige kleuren en de dynamiek van dit intrigerende kustlandschap.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1507.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,36414) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hoofd-van-een-prostituee','Hoofd van een prostituee','Door: Vincent van Gogh (Nederlands, 1853-1890) \n \nDuik in de diepten van het Parijse nachtleven met "Head Of A Prostitute" door Vincent van Gogh. Dit intrigerende portret weerspiegelt de innerlijke wereld van zijn onderwerp met een ongekende eerlijkheid en diepgang. Laat je meevoeren door de krachtige expressie en subtiele details van dit meesterwerk!','https://kunstdoekje.nl/wp-content/uploads/2024/04/1502.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','van-gogh'],false,true,36415) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('un-moulin-a-zaandam','Un Moulin À Zaandam','Door: Claude Monet (1871) \n \n"Un Moulin À Zaandam" uit 1871 is een prachtig werk van Monet dat een windmolen in Zaandam, Nederland, vastlegt. Met levendige penseelstreken en levendige kleuren brengt Monet de sfeer van het Nederlandse landschap tot leven.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1509.png',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','oude-meesters'],false,true,36416) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('user-the-beach-at-sainte-adresse','User The Beach at Sainte-Adresse','Door: Claude Monet \n \n"The Beach at Sainte-Adresse" biedt een prachtig uitzicht op de kust van het Franse Sainte-Adresse. Monet weet met zijn kenmerkende impressionistische stijl de levendigheid van de kust en de zee vast te leggen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1513.png',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus','oude-meesters'],false,true,36417) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-beach-at-honfleur','The Beach at Honfleur','Door: Claude Monet \n \nLaat je meevoeren naar de serene kust van Honfleur met "The Beach at Honfleur". Dit kunstwerk vangt de ontspannen sfeer van de Franse kust op een prachtige manier. Met levendige kleuren en speelse penseelstreken brengt Monet de rust en schoonheid van deze havenstad tot leven.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1517.png',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','oude-meesters'],false,true,36418) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-armand-roulin-copy','Portret van Armand Roulin (Copy)','Door: Vincent van Gogh (1888) \n \n"Portret van Armand Roulin" is een levendig portret geschilderd door Vincent van Gogh. Met zijn krachtige penseelstreken en levendige kleuren brengt Van Gogh de persoonlijkheid van Armand Roulin tot leven','https://kunstdoekje.nl/wp-content/uploads/2024/04/1500.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters','van-gogh'],false,false,36419) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lachende-rembrandt','Lachende Rembrandt','Door: Rembrandt van Rijn \n \n"Lachende Rembrandt" is een levendig en charmant zelfportret van de kunstenaar, geschilderd door Rembrandt van Rijn in 1628. Met zijn kenmerkende meesterschap in licht en schaduw, vangt Rembrandt hier zijn eigen vrolijke gemoedstoestand in een intiem moment. Het schilderij straalt een warme en uitnodigende sfeer uit, waarbij de kunstenaar de kijker direct betrekt bij zijn oprechte vreugde.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1520.png',(select id from categories where slug='oude-meesters'),array['oude-meesters','rijks'],false,true,36420) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rafael-rembrandt-harmensz-van-rijn-nicolas-poussin-albrecht-durer-en-p','Rafael, Rembrandt Harmensz. van Rijn, Nicolas Poussin, Albrecht Dürer en Peter Paul Rubens:','\n \n \n \n \n \n \n \n \n \n \n \n \n \n Door: Johan Gustaf Sandberg (Zweeds, 1782 - 1854) \n \nRafael, Rembrandt Harmensz. van Rijn, Nicolas Poussin, Albrecht Dürer en Peter Paul Rubens: deze meesters, ongeëvenaard in hun tijd, worden vereeuwigd door de Zweedse kunstenaar Johan Gustaf Sandberg. \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/04/1518.png',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,36421) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-drie-leeftijden-van-de-vrouw','De Drie Leeftijden van de Vrouw','Door: Gustav Klimt \n \n"De Drie Leeftijden van de Vrouw" is een iconisch werk van Gustav Klimt uit 1905. In dit schilderij verkent Klimt de verschillende fasen van het leven van een vrouw, van jeugd tot volwassenheid. Met zijn kenmerkende symboliek en verfijnde details weet hij de universele thema''s van vergankelijkheid en vrouwelijke kracht op een betoverende manier weer te geven.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1523.png',(select id from categories where slug='gustav-klimt'),array['gustav-klimt','oude-meesters'],false,true,36422) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-molen-van-de-galette','De Molen van de Galette','Door: Vincent van Gogh (1853-1890) \n \n"De Molen van de Galette" is een meesterwerk van Vincent van Gogh, geschilderd rond 1886. In dit schilderij brengt Van Gogh het bruisende leven van Montmartre tot leven, met zijn kenmerkende penseelstreken en levendige kleuren.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1524_1.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters','van-gogh'],false,true,36424) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('head-of-a-peasant','Head Of A Peasant','Door: Vincent van Gogh \n \n"Head Of A Peasant" is een meesterwerk van Vincent van Gogh, waarin hij de diepte van het menselijke bestaan vastlegt. Met krachtige penseelstreken en intense kleuren weet Van Gogh de rauwe emotie en de innerlijke kracht van de boerenklasse te portretteren.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1519-1.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters','van-gogh'],false,true,36425) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-brug-bij-argenteuil-36426','De brug bij Argenteuil','Door: Claude Monet \n \n"De brug bij Argenteuil" is een prachtig voorbeeld van Monet''s impressionistische meesterschap. Met levendige penseelstreken en een subtiel spel van licht en schaduw vangt Monet de schoonheid van de brug en de omliggende omgeving in Argenteuil.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1516.png',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus','oude-meesters'],false,true,36426) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vetheuil','Vétheuil','Door: Claude Monet \n \n"Vétheuil" is een betoverend werk dat de schoonheid van het gelijknamige stadje aan de Seine in Frankrijk vastlegt. Met meesterlijke penseelstreken en een subtiel kleurenpalet weet Monet de rustieke charme en de serene atmosfeer van Vétheuil te vangen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1512.png',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus','oude-meesters'],false,true,36427) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('first-steps-after-millet','First Steps, after Millet','Door: Vincent van Gogh \n \n"First Steps, after Millet" is een interpretatie van het beroemde werk "The First Steps" van Jean-François Millet, gemaakt door Vincent van Gogh. Van Gogh heeft dit meesterwerk gecreëerd als een eerbetoon aan Millet, waarbij hij zijn eigen unieke stijl en expressie toevoegt aan het originele onderwerp. Met levendige penseelstreken en een diepgaand gevoel voor emotie, weet Van Gogh de essentie van het moment vast te leggen,','https://kunstdoekje.nl/wp-content/uploads/2024/04/1519.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters','van-gogh'],false,true,36428) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cabanes-de-bois-parmi-les-oliviers-et-cypres','Cabanes de bois parmi les oliviers et cyprès','Door: Vincent van Gogh \n \nIn "Cabanes de bois parmi les oliviers et cyprès" brengt Van Gogh de serene schoonheid van houten hutten tussen de olijfbomen en cipressen tot leven. Met krachtige penseelstreken en levendige kleuren laat hij de natuurlijke pracht van het landschap schitteren op het doek.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1541.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters','van-gogh'],false,true,36447) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-heuvel-van-montmartre-met-steengroeve','De heuvel van Montmartre met steengroeve','Door: Vincent van Gogh \n \n""De heuvel van Montmartre met steengroeve" neemt je mee naar de levendige straten van Montmartre, vastgelegd door de ogen van de meesterlijke Van Gogh. Zijn expressieve penseelstreken en levendige kleuren brengen de sfeer en energie van deze bruisende wijk tot leven op het doek.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1542.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters','van-gogh'],false,true,36448) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kade-met-mannen-die-zandaken-lossen','Kade met mannen die zandaken lossen','Door: Vincent van Gogh \n \n"Kade met mannen die zandaken lossen" is een levendig werk van Vincent van Gogh uit 1888. In dit schilderij vangt Van Gogh het dagelijkse leven aan de kade, waar mannen bezig zijn met het lossen van zandaken. Met krachtige penseelstreken en levendige kleuren weet Van Gogh de bedrijvigheid en dynamiek van de scène vast te leggen. Dit werk biedt een intrigerende kijk op het arbeidersleven en Van Goghs meesterschap in het vastleggen van het alledaagse.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1549.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters','van-gogh'],false,true,36449) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flairry-fleur','Flairry Fleur','Door: ons creatieve team \n \nFlairy Fleur is een AI-creatie met kleurrijke elementen. Speciaal ontwikkeld voor mensen, die net als wij, van creativiteit en mooie dingen houden.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1564.png',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,36450) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rozen-36451','Rozen','Door: Henri Le Sidaner \n \n"Rozen" is een prachtig werk van de Franse kunstenaar Henri Le Sidaner. Dit schilderij uit 1934 toont Le Sidaners meesterschap in het vastleggen van de schoonheid en teerheid van bloemen. Met subtiele penseelstreken en een zachte kleurenpalet weet hij de prachtige rozen tot leven te brengen op het doek.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1548.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','landschapmodus','oude-meesters'],false,true,36451) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pruimen','Pruimen','Door: Édouard Manet \n \n"Pruimen" is een meesterwerk van de Franse kunstenaar Édouard Manet. Dit schilderij, geschilderd rond 1880, toont Manets vermogen om alledaagse voorwerpen te transformeren tot kunst. Met gedurfde penseelstreken en levendige kleuren brengt Manet de eenvoudige pruimen tot leven op het doek.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1547.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters'],false,true,36452) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-appels-en-druiven','Stilleven met appels en druiven','Door: Arthur-Alfred Brunel de Neuville \n \n"Stilleven met appels en druiven" is een prachtig werk van de Franse kunstenaar Arthur-Alfred Brunel de Neuville. Met levendige kleuren en nauwgezette details laat de kunstenaar ons de schoonheid van alledaagse voorwerpen zien. Dit schilderij nodigt je uit om te genieten van de overvloed aan fruit en de kleurrijke uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1546.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters'],false,true,36453) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-kerkdorp-nuenen','Het kerkdorp Nuenen','Door: Vincent van Gogh \n \nDit schilderij, getiteld "Het kerkdorp Nuenen," vangt een glimp op van het dagelijkse leven in het dorp waar Vincent van Gogh enige tijd heeft doorgebracht. In de periode van 1883 tot 1885 verbleef Van Gogh in Nuenen, waar hij zich onderdompelde in het dorpsleven en veel van zijn meesterwerken schilderde. Dit werk laat de eenvoudige schoonheid van het Brabantse platteland zien, met zijn karakteristieke gebouwen en landelijke omgeving. Het is een eerbetoon aan de tijd die Van Gogh doorbracht in dit rustieke dorp, waar hij inspiratie vond voor zijn kunst en een diepga','https://kunstdoekje.nl/wp-content/uploads/2024/04/1543.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters','van-gogh'],false,true,36454) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jungle-luipaard','Jungle Luipaard','Door: ons creatieve team \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/04/1565.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,true,36455) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-plek-van-de-waterdrinkers-aix-les-bains','De Plek van de Waterdrinkers, Aix-les-Bains','Door: Henri Le Sidaner \n \n"De Plek van de Waterdrinkers, Aix-les-Bains" is een schilderij uit 1937 van Henri Le Sidaner. In dit werk brengt Le Sidaner de sfeer van een levendig plein in Aix-les-Bains tot leven. Met subtiele penseelstreken en warme kleuren weet hij de levendige activiteit en de kenmerkende architectuur van de plaats vast te leggen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1551.png',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','oude-meesters'],false,true,36456) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
