insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-armand-roulin-copy-copy','Portret van Armand Roulin (Copy) (Copy)','Door: Vincent van Gogh (1888) \n \n"Portret van Armand Roulin" is een levendig portret geschilderd door Vincent van Gogh. Met zijn krachtige penseelstreken en levendige kleuren brengt Van Gogh de persoonlijkheid van Armand Roulin tot leven','https://kunstdoekje.nl/wp-content/uploads/2024/04/1500.png',(select id from categories where slug='impressionisme'),array['impressionisme','oude-meesters','van-gogh'],false,false,36458) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-leeuwenhoek','De Leeuwenhoek','Door: Geza Vastagh \n \n"De Leeuwenhoek" (1893) van Geza Vastagh is een meesterwerk dat de kracht en majesteit van de leeuw vangt. Met levendige penseelstreken brengt Vastagh de wildernis tot leven, waardoor je je temidden van de Afrikaanse savanne waant.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1552.png',(select id from categories where slug='dieren'),array['dieren','impressionisme','landschapmodus','natuur','oude-meesters'],false,true,36459) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('paarden-aan-zee','Paarden aan zee','','https://kunstdoekje.nl/wp-content/uploads/2024/04/1580.png',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,36460) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rozen-in-een-vaas','Rozen in een vaas','Door: Charles Philipard \n \n"Rozen in een Vaas" is een prachtig kunstwerk van Charles Philipard. Met levendige kleuren en zachte penseelstreken brengt Philipard de schoonheid van rozen tot leven in een charmante vaas.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1554.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','oude-meesters','van-gogh'],false,true,36461) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('begonia-s','Begonia''s','Door: Henry Golden Dearth (1864-1918) \n \n"Begonias" is een betoverend werk van Henry Golden Dearth. Met levendige penseelstreken vangt Dearth de pracht van deze bloemen op het doek. Laat je meevoeren door de weelderige kleuren en gedetailleerde composities van deze Amerikaanse schilder.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1538.png',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','oude-meesters'],false,true,36462) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-noorderlicht','Het Noorderlicht','Het Noorderlicht, ook wel bekend als de aurora borealis, is een prachtig natuurverschijnsel dat te zien is in de poolgebieden van de aarde. Het ontstaat wanneer geladen deeltjes van de zon de atmosfeer van de aarde binnenkomen en daarbij met gassen in de atmosfeer reageren. Dit veroorzaakt een schitterend lichtspektakel met kleurrijke strepen, golven en gordijnen die aan de nachtelijke hemel dansen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1579.png',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus','natuur'],false,true,36478) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-poema','Kleurrijke Poema','Door: ons creatieve team','https://kunstdoekje.nl/wp-content/uploads/2024/04/1568.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,true,36479) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('estructura-con-formas-trabadas','Estructura con formas trabadas','Door: Joaquín Torres-García (1933) \n \nDit abstracte werk van de Uruguayaanse kunstenaar Joaquín Torres-García is een boeiend spel van verweven vormen en lijnen. "Estructura con formas trabadas" combineert geometrische precisie met een levendige compositie, kenmerkend voor Torres-García''s constructivistische stijl. De harmonieuze opstelling van strakke lijnen en symbolische vormen creëert een dynamische en moderne uitstraling, waarbij traditionele en moderne invloeden naadloos samenkomen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1588.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,36480) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('retrato-de-hombre','Retrato de hombre','\n \n \n Door: Joaquín Torres-García (1946) \n \n \n \n \n \n \n \n \n \n \n \nDit schilderij van de Uruguayaanse kunstenaar Joaquín Torres-García toont een man, waarschijnlijk een hommage aan Louis Pasteur, met een eenvoudige en toch krachtige compositie. Torres-García staat bekend om zijn gebruik van symbolen en geometrische vormen, wat ook in dit portret terugkomt. \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/04/1589.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,36481) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fleural-women','Fleural women','Door: ons creatieve team','https://kunstdoekje.nl/wp-content/uploads/2024/04/1569.png',(select id from categories where slug='ai-kunst'),array['ai-kunst','impressionisme'],false,true,36482) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('scene-carnavalesque','Scène carnavalesque','Door: James Ensor (circa 1890) \n \nDit levendige schilderij van de Belgische kunstenaar James Ensor toont een kleurrijke en chaotische carnavalscène. Ensor, bekend om zijn satirische en groteske stijl, vangt de uitbundige en soms bizarre sfeer van het carnaval met maskers, kostuums en uitbundige personages.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1591.jpg',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,36483) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pintura-constructiva','Pintura constructiva','Door: Joaquín Torres-García (ca. 1929) \n \nDit abstracte werk van de Uruguayaanse kunstenaar Joaquín Torres-García is een voorbeeld van zijn constructivistische stijl. "Pintura constructiva" toont een netwerk van geometrische vormen en symbolen, gerangschikt in een harmonieuze compositie. Torres-García combineert elementen van modernisme met invloeden van pre-Columbiaanse kunst, wat resulteert in een uniek en gestructureerd visueel spektakel.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1594.jpg',(select id from categories where slug='asbtract'),array['asbtract','dieren'],false,true,36484) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('panier-aux-fruits','Panier aux fruits','Door: Joaquín Torres-García (1930) \n \nDit abstracte schilderij van de Uruguayaanse kunstenaar Joaquín Torres-García toont een mand gevuld met fruit, weergegeven in zijn kenmerkende constructivistische stijl. De compositie bestaat uit geometrische vormen en symbolen, waarbij levendige kleuren en strakke lijnen worden gebruikt om een harmonieus geheel te creëren. Het werk weerspiegelt Torres-García''s unieke benadering van modernisme en zijn invloedrijke rol in de abstracte kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1590.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,36485) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('composicion','Composición','Door: Joaquín Torres-García (1928) \n \nDit speelse abstracte werk van de Uruguayaanse kunstenaar Joaquín Torres-García, "Composición", combineert strakheid met flair. Geometrische vormen dansen over het doek, gekleed in levendige kleuren. Torres-García mixt modernisme met een eigenzinnige twist, waardoor het geheel een stoere, chique uitstraling krijgt. Dit schilderij vangt de geest van constructivisme met een knipoog naar zijn Zuid-Amerikaanse roots, en straalt zowel elegantie als dynamiek uit.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1593.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,36486) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('composition','Composition','Door: Georges Valmier (1921) \n \nDit abstracte werk van de Franse kunstenaar Georges Valmier toont een complexe compositie van kleurrijke geometrische vormen. Valmier, een pionier in de abstracte kunst, speelt met balans en contrast in zijn gebruik van kleur en vorm. Het schilderij weerspiegelt de invloed van het kubisme en de zoektocht naar harmonie in abstracte representatie.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1592.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,36487) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('a-mulher','A mulher','\n Door: Amadeo de Souza-Cardoso (1916) \n \nDit intrigerende schilderij van de Portugese kunstenaar Amadeo de Souza-Cardoso, "A mulher", combineert abstracte elementen met figuratieve hints. De Souza-Cardoso''s kenmerkende stijl komt tot uiting in de gedurfde vormen en levendige kleuren die de vrouwelijke figuur omlijnen. Het werk straalt een unieke mix van moderniteit en mysterie uit, waarbij de traditionele portretkunst wordt getransformeerd in een dynamische en eigentijdse compositie. \n','https://kunstdoekje.nl/wp-content/uploads/2024/04/1595.jpg',(select id from categories where slug='dieren'),array['dieren','impressionisme','oude-meesters'],false,true,37237) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('nude-with-a-flower','Nude with a flower','Door: Georges Valmier (1928) \n \nDit abstracte werk van de Franse kunstenaar Georges Valmier toont een naakte figuur met een bloem, weergegeven in een dynamische compositie van geometrische vormen en levendige kleuren. Valmier combineert kubistische invloeden met een speelse benadering van abstractie, waarbij de lijnen en kleuren harmonieus samenkomen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1599.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,37238) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jeune-fille-assise','Jeune fille assise','Door: Georges Valmier (1924) \n \nDit abstracte schilderij van de Franse kunstenaar Georges Valmier toont een zittend meisje, weergegeven in een reeks geometrische vormen en levendige kleuren. Valmier''s werk combineert elementen van kubisme en abstractie, waarbij hij een harmonieuze compositie creëert die zowel dynamisch als gebalanceerd is.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1600.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,false,37239) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('time','Time','Door: Georges Valmier (1929) \n \nDit abstracte schilderij van de Franse kunstenaar Georges Valmier, getiteld "Time", is een meesterlijke compositie van geometrische vormen en levendige kleuren. Valmier speelt met balans en ritme, waarbij hij de illusie van beweging en dynamiek creëert. De gedurfde kleuren en strakke lijnen vormen een harmonieuze en moderne weergave van abstracte kunst. Het werk straalt energie en precisie uit, kenmerkend voor Valmier''s unieke stijl binnen het kubisme en abstractie.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1601.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,37240) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('composition-37241','Composition','Door: Georges Valmier (1923) \n \nDit abstracte werk van de Franse kunstenaar Georges Valmier is een levendige en dynamische compositie van geometrische vormen en kleuren. "Composition" vangt de essentie van Valmier''s kenmerkende stijl, waarbij hij kubistische invloeden combineert met een speelse en ritmische benadering van abstractie. De vormen lijken te dansen over het doek, wat het schilderij een energieke en moderne uitstraling geeft.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1598.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,false,37241) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('composition-37242','Composition','Door: Georges Valmier (1921) \n \nDit abstracte werk van de Franse kunstenaar Georges Valmier is een levendige en dynamische compositie van geometrische vormen en kleuren. Valmier combineert kubistische invloeden met een speelse en ritmische benadering van abstractie','https://kunstdoekje.nl/wp-content/uploads/2024/04/1597.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,37242) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mittlere-meditation','Mittlere Meditation','Door: Alexej von Jawlensky (1936) \n \nDit abstracte werk van de Russische kunstenaar Alexej von Jawlensky, "Mittlere Meditation (Erdgebunden)", combineert diepe kleuren en geometrische vormen om een contemplatieve sfeer te creëren. De aardse tinten en de harmonieuze compositie roepen een gevoel van verbondenheid met de grond op, terwijl de abstracte vormen een spirituele en meditatieve kwaliteit toevoegen. Jawlensky''s unieke benadering van abstractie geeft het schilderij een rustgevende en introspectieve uitstraling, waardoor het een visueel en emotioneel boeiende ervaring biedt.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1612.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37243) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-piano-lesson','The piano lesson','Door: Georges Valmier (1924) \n \nDit abstracte werk van de Franse kunstenaar Georges Valmier, "The Piano Lesson," is een kleurrijke en dynamische compositie. Valmier combineert geometrische vormen en levendige kleuren om de essentie van een pianoles vast te leggen. De speelse lijnen en vormen dansen over het doek, wat het schilderij een energieke en levendige uitstraling geeft','https://kunstdoekje.nl/wp-content/uploads/2024/04/1608.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,37244) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-head-gold-and-pink','Abstract Head, Gold and Pink','Door: Alexej von Jawlensky (1931) \n \nDit speelse en expressieve schilderij van de Russische kunstenaar Alexej von Jawlensky, "Abstract Head, Gold and Pink," toont een gezicht opgebouwd uit geometrische vormen in levendige gouden en roze tinten. Jawlensky''s kenmerkende stijl combineert spiritualiteit en abstractie, waarbij hij dynamische kleuren en krachtige lijnen gebruikt om een intrigerende compositie te creëren.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1611.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37245) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-head-mysterium','Abstract Head, Mysterium','Door: Alexej von Jawlensky (1925) \n \nIn "Abstract Head, Mysterium" combineert de Russische kunstenaar Alexej von Jawlensky abstracte vormen met rijke kleuren om een mystieke en intrigerende compositie te creëren. De gedurfde penseelstreken en subtiele schakeringen van kleur vormen samen een abstract portret dat zowel spiritueel als expressief is.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1610.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37246) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('saviour-s-face','Saviour’s face','Door: Alexej von Jawlensky (1919) \n \n"Saviour’s face, Martyr" is een levendig en speels abstract schilderij van de Russische kunstenaar Alexej von Jawlensky. Dit kleurrijke werk toont een gezicht opgebouwd uit geometrische vormen en dynamische lijnen. Jawlensky''s gebruik van gedurfde kleuren en expressieve vormen geeft het schilderij een energieke uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1613.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37247) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-scream','The Scream','Door: Edvard Munch (1895) \n \nDeze iconische zwart-wit versie van "The Scream" van de Noorse kunstenaar Edvard Munch is een krachtige weergave van existentiële angst en wanhoop. Het toont een vervormd figuur dat schreeuwt onder een dreigende, donkere lucht, waarbij de intense lijnen en schaduwen de emotionele impact versterken. Deze versie behoudt de expressieve stijl van Munch en benadrukt de innerlijke onrust en isolatie, wat het tot een van de meest herkenbare en invloedrijke kunstwerken in de moderne kunst maakt.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1614.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,37248) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-head-inner-vision-green-gold','Abstract Head, Inner Vision Green-Gold','Door: Alexej von Jawlensky (1926) \n \nDit speelse en expressieve werk van de Russische kunstenaar Alexej von Jawlensky, "Abstract Head, Inner Vision Green-Gold", combineert levendige groene en gouden tinten met gedurfde lijnen om een abstract gezicht te creëren. Jawlensky''s kenmerkende stijl, die spiritualiteit en emotie uitdrukt door abstractie, geeft het schilderij een mystieke en introspectieve sfeer.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1609.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,37249) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('josef-lewinsky-als-carlos-in-clavigo','Josef Lewinsky als Carlos in Clavigo','Door: Gustav Klimt (1895) \n \nDit figuratieve werk van Gustav Klimt toont de acteur Josef Lewinsky in de rol van Carlos uit het toneelstuk "Clavigo." Klimt gebruikt gedetailleerde penseelstreken en subtiele kleurtonen om de expressie en het karakter van Lewinsky vast te leggen. De compositie straalt zowel elegantie als dramatiek uit, en laat Klimt''s vaardigheid in portretkunst zien.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1625.jpg',(select id from categories where slug='gustav-klimt'),array['gustav-klimt'],false,true,37250) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sitzende-nach-links','Sitzende nach links','Door: Oskar Schlemmer (circa 1932) \n \nDit figuratieve werk van de Duitse kunstenaar Oskar Schlemmer toont een zittende figuur, naar links gericht. Schlemmer, bekend om zijn interesse in de relatie tussen het menselijk lichaam en geometrische vormen, combineert strakke lijnen en simplistische vormen om een gestileerd maar herkenbaar figuur te creëren.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1627.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37251) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kopf-nach-links','Kopf nach links','Door: Oskar Schlemmer (1928) \n \n"Kopf nach links" van Oskar Schlemmer is een boeiend abstract schilderij dat een naar links gerichte kop toont. Schlemmer gebruikt geometrische vormen en strakke lijnen om een gestileerde, bijna futuristische vorm te creëren. De eenvoudige maar krachtige compositie geeft het werk een moderne uitstraling, waarbij de combinatie van menselijke vorm en geometrie centraal staat.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1626.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37252) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-en-dieren','Stilleven met bloemen en dieren','Door: German School (19e eeuw) \n \nDit levendige stilleven van de German School toont een kleurrijk boeket, een vogel en een sprinkhaan op een stenen rand. Met gedetailleerde penseelstreken en sprankelende kleuren brengt het schilderij de natuur tot leven. Het straalt rust en harmonie uit, en vangt de pracht van bloemen en dieren op een charmante manier. Een betoverend voorbeeld van stillevenkunst.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1654.jpg',(select id from categories where slug='bloemen'),array['bloemen','dieren','oude-meesters'],false,true,37253) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('a-bouquet-of-flowers-with-tulips-and-carnations-in-a-glass-vase-with-b','A Bouquet of Flowers with Tulips and Carnations in a Glass Vase with Butterfly','\n A Bouquet of Flowers with Tulips and Carnations in a Glass Vase with Butterfly \n \n Hans Zatzka (Austrian, 1859 – 1945 \n Still Life','https://kunstdoekje.nl/wp-content/uploads/2024/04/1620.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,false,37254) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('seemann','Seemann','Door: Franz Wilhelm Seiwert (1924) \n \n"Seemann" van Franz Wilhelm Seiwert is een krachtig abstract schilderij dat de essentie van een zeeman vastlegt. Met strakke lijnen en geometrische vormen creëert Seiwert een figuur die zowel stoer als dynamisch is. De gedurfde compositie en beperkte kleurenpalet geven het werk een moderne en energieke uitstraling. Seiwert''s stijl combineert abstractie met een duidelijke figuratieve kracht, waardoor het schilderij zowel toegankelijk als visueel boeiend is.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1617.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37255) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('workers','Workers','Door: Franz Wilhelm Seiwert (1926) \n \n"Workers" van Franz Wilhelm Seiwert is een levendig abstract schilderij dat de kracht van arbeid viert. De geometrische vormen en strakke lijnen vormen samen figuren van arbeiders, waardoor een gevoel van ritme en eenheid ontstaat. De gedurfde compositie en speelse kleuren geven het werk een energieke uitstraling, terwijl het tegelijkertijd toegankelijk en boeiend blijft. Seiwert''s kunst vangt de essentie van collectieve kracht in een moderne, visueel aantrekkelijke stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1616.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37256) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blumenstillleben','Blumenstillleben','Door: Eugene Petit (1839–1886) \n \n"Blumenstillleben" van Eugene Petit is een schitterend stilleven dat de delicate schoonheid van bloemen vastlegt. Petit''s gedetailleerde penseelstreken en levendige kleuren brengen de bloemen tot leven in een harmonieuze compositie. Dit werk straalt zowel rust als elegantie uit, en toont de meesterlijke vaardigheid van Petit in het vastleggen van de natuurlijke pracht.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1649.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters'],false,true,37257) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vase-of-flowers','Vase of Flowers','\n Vase of Flowers (1916) \n \n Odilon Redon (French, 1840-1916) \n Still Life','https://kunstdoekje.nl/wp-content/uploads/2024/04/1650.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,false,37258) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('feldblumen','Feldblumen','Door: Carl Reiser (1920-30) \n \n"Feldblumen" van Carl Reiser is een charmant stilleven dat een kleurrijk boeket wilde bloemen toont. Reiser gebruikt levendige kleuren en fijne details om de natuurlijke schoonheid van de bloemen tot leven te brengen. Het schilderij straalt een frisse en rustieke sfeer uit, perfect voor liefhebbers van eenvoudige, natuurlijke kunst. Een prachtig voorbeeld van Reiser''s talent om de pracht van de natuur vast te leggen in een toegankelijke en betoverende stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1651.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,37259) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bouquet-de-fleurs','Bouquet de fleurs','\n Bouquet de fleurs (circa 1920) \n \n Albert Lebourg (French, 1849-1928) \n Still Life','https://kunstdoekje.nl/wp-content/uploads/2024/04/1653.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,false,37260) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('seventeenth-century-tinsmith','Seventeenth Century Tinsmith','Door: Alexandre Markelbach (1884) \n \n"Seventeenth Century Tinsmith" van Alexandre Markelbach is een levendig figuratief schilderij dat een tinsmid uit de zeventiende eeuw aan het werk toont. Met gedetailleerde penseelstreken en warme kleuren brengt Markelbach de ambachtelijke sfeer van het verleden tot leven. Het schilderij straalt vakmanschap en toewijding uit, terwijl het de kijker een glimp biedt van het historische ambachtsleven.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1655.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,37360) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('symbolic-head','Symbolic Head','Door: Odilon Redon (circa 1890) \n \n"Symbolic Head" van Odilon Redon is een intrigerend figuratief schilderij dat een mysterieuze, etherische kop toont. Met zachte penseelstreken en dromerige kleuren creëert Redon een beeld dat zowel poëtisch als mystiek is. Het schilderij straalt een gevoel van introspectie en symboliek uit, en nodigt de kijker uit om de diepere lagen van het werk te verkennen. Een prachtig voorbeeld van Redon''s unieke stijl en visionaire kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1679.jpg',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,37361) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rouen-cathedral-west-facade-sunlight','Rouen Cathedral, West Façade, Sunlight','Door: Claude Monet (1894) \n \nIn "Rouen Cathedral, West Façade, Sunlight," vangt Claude Monet de indrukwekkende façade van de kathedraal in het stralende zonlicht. Met impressionistische penseelstreken en een meesterlijk gebruik van licht en kleur, brengt Monet de stenen tot leven en laat hij de wisselende effecten van zonlicht zien. Het schilderij straalt zowel monumentaliteit als delicate schoonheid uit, een kenmerkend werk van Monet''s serie van de kathedraal.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1656.jpg',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme'],false,true,37362) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-bloemen-37363','Stilleven met bloemen','Door: Jan van Huysum (1723) \n \n"Stilleven met bloemen" van Jan van Huysum is een prachtig stilleven dat een overvloed aan bloemen toont. Van Huysum staat bekend om zijn gedetailleerde weergave van bloemen, waarbij hij levendige kleuren en fijne details gebruikt om realisme te creëren. Dit werk straalt elegantie en verfijning uit, en laat zijn meesterschap in bloemschilderkunst zien.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1659.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters'],false,true,37363) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flowers-in-a-metal-vase','Flowers in a Metal Vase','Door: Abraham Mignon (circa 1670) \n \n"Flowers in a Metal Vase" van Abraham Mignon is een verfijnd stilleven dat een rijkelijk gevulde metalen vaas met bloemen toont. Mignon''s meesterlijke techniek brengt de delicate bloemblaadjes en de glans van het metaal tot leven. Dit werk straalt elegantie en verfijning uit, waarbij de levendige kleuren en gedetailleerde weergave een gevoel van realisme en schoonheid creëren. Een schitterend voorbeeld van de barokke stillevenkunst.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1660.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters'],false,true,37364) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flowers-in-a-glass-flask','Flowers in a Glass Flask','Door: Jacob de Gheyn II (1612) \n \n"Flowers in a Glass Flask" van Jacob de Gheyn II is een charmant stilleven dat een elegant boeket bloemen in een eenvoudige glazen vaas toont. De Gheyn''s verfijnde penseelstreken en levendige kleuren brengen de bloemen tot leven, terwijl de transparantie van het glas de delicatesse van het werk benadrukt.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1661.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','bloemen','oude-meesters'],false,true,37365) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vase-d-anemones','Vase D’anémones','Door: Odilon Redon (1840-1916) \n \n"Vase D’anémones" van Odilon Redon is een levendig stilleven dat een boeket anemonen in een vaas toont. Redon gebruikt zachte penseelstreken en een dromerig kleurenschema om de delicate bloemen tot leven te brengen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1671.jpg',(select id from categories where slug='bloemen'),array['bloemen','oude-meesters'],false,true,37366) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jeune-garcon-a-la-casquette','Jeune garçon à la casquette','Door: Moïse Kisling (1925) \n \n"Jeune garçon à la casquette" van Moïse Kisling is een levendig portret van een jonge jongen met een pet. Kisling''s warme kleuren en vloeiende lijnen brengen de speelsheid en onschuld van de jeugd tot leven. Het schilderij straalt een gezellige, huiselijke sfeer uit, waarbij de jongen een gevoel van vertrouwdheid en eenvoud oproept.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1680.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,37376) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-pioenen','Stilleven met pioenen','Door: Jan Van Os (1744–1808) \n \n"Still Life Of Peonies" van Jan Van Os is een prachtig stilleven dat de delicate schoonheid van pioenrozen vastlegt. Van Os combineert rijke kleuren en gedetailleerde penseelstreken om de bloemen tot leven te brengen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1681.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,37378) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blumenstuck-mit-schmetterling-und-blaumeise','Blumenstück mit Schmetterling und Blaumeise','Door: Sebastian Wegmayr (1776–1857) \n \n"Blumenstück mit Schmetterling und Blaumeise" van Sebastian Wegmayr is een charmant stilleven dat een kleurrijk boeket bloemen, een vlinder en een pimpelmees toont. Wegmayr''s gedetailleerde penseelstreken en levendige kleuren brengen de natuur tot leven op het doek.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1682.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,37380) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('a-large-bouquet-of-flowers','A large bouquet of flowers','Door: Sebastian Wegmayr (1776–1857) \n \n"A Large Bouquet of Flowers" van Sebastian Wegmayr is een levendig stilleven dat een uitbundig boeket bloemen toont. Met verfijnde penseelstreken en levendige kleuren, brengt Wegmayr elke bloem tot leven. De compositie straalt elegantie en weelde uit, terwijl de subtiele details de natuurlijke pracht van het boeket benadrukken. Een prachtige viering van bloemenpracht in al haar glorie.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1683.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,37381) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pitcher-with-flowers','Pitcher with flowers','Door: Broncia Koller-Pinell (1863-1934) \n \n"Pitcher with Flowers" van Broncia Koller-Pinell is een betoverend stilleven dat een eenvoudig boeket bloemen in een kan toont. Met verfijnde penseelstreken en subtiele kleuren brengt Koller-Pinell de bloemen tot leven tegen een rustige achtergrond.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1685.jpg',(select id from categories where slug='bloemen'),array['bloemen'],false,true,37382) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('contemplation','Contemplation','Door: Odilon Redon (1840-1916) \n \n"Contemplation" van Odilon Redon is een mystiek en dromerig werk dat de diepte van introspectie uitbeeldt. Met zachte penseelstreken en een serene kleurenpalet creëert Redon een sfeer van rust en reflectie. Het schilderij straalt een gevoel van innerlijke vrede en spirituele ontdekking uit, kenmerkend voor Redon''s symbolistische stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1688.jpg',(select id from categories where slug='oude-meesters'),array['oude-meesters'],false,true,37386) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('girl-with-cat','Girl with cat','Door: Meta Plückebaum (1876-1954) \n \n"Girl with Cat" van Meta Plückebaum is een charmant figuratief schilderij dat een jong meisje toont met haar kat. Plückebaum gebruikt zachte penseelstreken en warme kleuren om de tedere band tussen het meisje en haar huisdier vast te leggen.','https://kunstdoekje.nl/wp-content/uploads/2024/04/1586.jpg',(select id from categories where slug='dieren'),array['dieren','impressionisme'],false,true,37395) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('urban-rebel','Urban rebel','"Urban Rebel" vangt de gedurfde energie van stadsleven in levendige kleuren en gedurfde lijnen. Met een abstracte mix van stedelijke invloeden en rauwe emotie, brengt dit kunstwerk de dynamiek van stedelijke expressie tot leven.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-8-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37530) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemige-luipaard','Bloemige Luipaard','Dit prachtige kunstdoekje toont de krachtige blik en de gedetailleerde vacht van een luipaard. Tegen een achtergrond van levendige bloemen straalt de luipaard kracht en elegantie uit. Ideaal voor natuurliefhebbers die de wilde schoonheid van de natuur in hun huis willen halen en genieten van een exotische touch.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-10-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,true,37573) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('portret-van-een-vrouw-met-bril','Portret van een Vrouw met Bril','Dit opvallende portret toont een vrouw met felle, kleurrijke brillen en een mozaïekachtige hoofdband. Haar intense blauwe ogen en rode lippen trekken meteen de aandacht. Dit kunstwerk combineert moderne stijl met een speelse twist en zorgt voor een unieke uitstraling in elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-3-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37607) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('expressieve-portret','Expressieve Portret','Dit kleurrijke en abstracte kunstwerk, genaamd "Expressieve Portret", toont een expressief gezicht met opvallende roze en gele tinten. Het portret, omlijst door levendige kleuren en gedurfde lijnen, straalt emotie en individualiteit uit. Perfect voor wie een dynamische en moderne touch aan hun interieur wil toevoegen.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-13-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37608) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ai-schilderij-5','AI Schilderij 5','Door: ons creatieve team','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-7-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,false,37609) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gezicht-in-de-schaduw','Gezicht in de schaduw','Dit intrigerende kunstwerk combineert expressieve lijnen met donkere tinten, waardoor een mysterieuze sfeer ontstaat. De abstracte vormen nodigen uit tot interpretatie en prikkelen de verbeelding. Perfect voor liefhebbers van moderne kunst die op zoek zijn naar iets unieks en diepzinnigs.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-5-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37610) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-koninklijke-leeuw','De Koninklijke Leeuw','Stap in de wereld van kracht en pracht met dit unieke kunstwerk van een leeuw. Zijn sierlijke manen, gedetailleerd met levendige kleuren, stralen majesteit uit. Elke penseelstreek vangt de essentie van zijn koninklijke natuur.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-11-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37611) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenpracht','Bloemenpracht','Dit prachtige stilleven van bloemen straalt warmte en levendigheid uit. In een rijke kleurencombinatie van oranje, rood en geel, komt dit kunstwerk helemaal tot leven. Perfect om een vleugje natuur in huis te halen en een elegante sfeer te creëren.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-4-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37612) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flasche-symphonie','Flasche Symphonie','Dit levendige abstracte schilderij, genaamd "Flasche Symphonie", toont een dynamische compositie van flessen in verschillende kleuren en vormen. De felle tinten en het speelse ontwerp brengen energie en levendigheid in elke ruimte. Ideaal voor wie houdt van moderne kunst en een vleugje kleur wil toevoegen aan hun interieur. Perfect voor keukens, eetkamers, of wijnkelders!','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-6-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37613) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ai-schilderij-11','AI Schilderij 11','Door: ons creatieve team','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-2-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,false,37615) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-portait','Abstract portait','Dit unieke street art kunstwerk toont een abstract gezicht in levendige kleuren en gedurfde lijnen. De intense contrasten en dynamische penseelstreken maken het tot een opvallende aanvulling voor elke moderne ruimte','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-23-2.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37616) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ai-schilderij-12','AI Schilderij 12','Door: ons creatieve team','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-20-1.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,false,37617) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cool-guy','Cool Guy','De attitude spat van dit schilderij af. Een coole man in een wit pak, met zonnebril en sigaret. De minimalistische achtergrond met felle kleuren zorgt voor een strak contrast, waardoor zijn nonchalante uitstraling nog meer opvalt.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-26-3.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37637) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('the-gentleman-with-the-wine','The Gentleman with the Wine','Dit dynamische street art kunstwerk toont een stijlvolle man met een wijnglas en een speelse hoed. De gedurfde kleuren en expressieve lijnen vangen de essentie van een verfijnd moment vol karakter en charme. Perfect voor een modern interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-22-2.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37639) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('faces-in-the-crowd','Faces in the crowd','Stap in de wereld van moderne street art met "Faces in the Crowd". Dit kleurrijke en levendige kunstwerk laat meerdere gezichten zien, alsof ze gevangen zijn in een zee van emoties en verhalen. De heldere tinten en spontane lijnen zorgen voor een dynamisch en energiek effect, perfect om elke ruimte op te fleuren.','https://kunstdoekje.nl/wp-content/uploads/2024/06/clean-and-simple-room-21-2.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst'],false,true,37640) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gare-1928','Gare (1928)','Door: Joaquín Torres-García \n \n"Gare" betekent "station" in het Nederlands. Dit schilderij van Joaquín Torres-García uit 1928 vangt de dynamiek en beweging van een station. De geometrische vormen en gedurfde lijnen, typisch voor zijn stijl, geven een gevoel van energie en ritme. Met een subtiele kleurenpalet en unieke compositie voegt "Gare" een speelse, yet chique flair toe aan elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1603.jpg',(select id from categories where slug='asbtract'),array['asbtract','landschapmodus','oude-meesters'],false,true,37649) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tetes-1928','Têtes (1928)','Door: Joaquín Torres-García ( 1874-1949) \n \nDit schilderij toont meerdere hoofden in een gestileerde en geometrische stijl. Torres-García gebruikt eenvoudige lijnen en vormen met subtiele kleurcontrasten om een harmonieus en dynamisch beeld te creëren. Een prachtig voorbeeld van zijn constructivistische benadering.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1596.jpg',(select id from categories where slug='asbtract'),array['asbtract','landschapmodus','oude-meesters'],false,true,37800) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('herderin-en-twee-koeien-in-een-weide','Herderin en Twee Koeien in een Weide','\n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n Door: Rosa Bonheur (1822-1899) \n \nOntdek de rust van het platteland met "Herderin en Twee Koeien in een Weide" van Rosa Bonheur. Dit charmante schilderij, gemaakt rond 1842-45, vangt het serene moment van een herderin met haar twee koeien in een weelderige weide. Bonheur, bekend om haar levendige en gedetailleerde werken, brengt de natuur echt tot leven. \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1623.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,37801) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pintura-1928','Pintura (1928)','door: Joaquín Torres-García \n \n"Pintura" betekent "schilderij" in het Nederlands, en dat is precies wat dit kunstwerk van Joaquín Torres-García uit 1928 is. Dit stuk barst van de speelse geometrische vormen en symbolen, typisch voor zijn constructivistische stijl. Met zijn subtiele kleuren en levendige compositie, brengt "Pintura" een frisse, speelse energie in elke ruimte. Perfect voor liefhebbers van abstracte kunst die houden van een vleugje geschiedenis en innovatie aan hun muur.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1602.jpg',(select id from categories where slug='asbtract'),array['asbtract','landschapmodus','oude-meesters'],false,true,37802) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('landschap-met-molen-bij-schiedam-1873','Landschap met Molen bij Schiedam (1873)','Door: Johan Hendrik Weissenbruch (1824 - 1903) \n \n"Landschap met Molen bij Schiedam" van Johan Hendrik Weissenbruch toont een prachtig Hollands landschap met een molen. Gemaakt in 1873, vangt het schilderij de serene en landelijke sfeer van het Nederlandse platteland. Weissenbruch''s meesterlijke gebruik van licht en schaduw brengt de rust en schoonheid van de scène tot leven. Dit werk is een perfecte toevoeging voor liefhebbers van klassieke Nederlandse kunst en pittoreske landschappen.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1630.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,37803) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pompon-chrysant','Pompon Chrysant','Door: Lafayette F. Cargill (20e Eeuw) \n \n"Pompon Chrysant" is een levendig en gedetailleerd schilderij van Lafayette F. Cargill uit 1937. Dit stilleven toont de prachtige pomponchrysanten in volle bloei, met sprankelende kleuren die de bloemen laten stralen. Cargill''s meesterlijke penseelstreken brengen de bloemen tot leven en geven een frisse, elegante uitstraling. Perfect voor liefhebbers van botanische kunst die wat kleur en verfijning aan hun interieur willen toevoegen.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1622.jpg',(select id from categories where slug='bloemen'),array['bloemen','landschapmodus'],false,true,37804) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('demontstration','Demontstration','Door: Franz Wilhelm Seiwert \n \n"Demonstration" is een intrigerend kunstwerk van Franz Wilhelm Seiwert, gemaakt in 1925. Deze krachtige compositie toont figuren in abstracte vormen, die samen een menigte van demonstranten vormen. Seiwert''s gebruik van strakke lijnen en gedurfde vormen brengt de dynamiek en energie van protesten tot leven. Dit schilderij voegt een speelse en toch serieuze flair toe aan elke ruimte, perfect voor liefhebbers van kunst met een boodschap.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1618.jpg',(select id from categories where slug='asbtract'),array['asbtract','landschapmodus','oude-meesters'],false,true,37805) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('een-quai-a-taillebourg','Een Quai Á Taillebourg','Door: Paul Madeline ( 1863-1920) \n \n"Een Quai Á Taillebourg" van Paul Madeline toont de rustige charme van een kade in Taillebourg. Madeline''s impressionistische stijl en gebruik van licht en kleur brengen de serene sfeer tot leven. Dit schilderij straalt kalmte en tijdloze schoonheid uit. Perfect voor liefhebbers van Franse landschapskunst die een vleugje rustieke elegantie aan hun interieur willen toevoegen.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1635.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,37806) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('een-kudde-vee-bij-een-meer-1872','Een kudde vee bij een meer (1872)','Door: Friedrich Voltz (1817-1886) \n \n"Een kudde vee bij een meer" van Friedrich Voltz toont de serene schoonheid van het platteland. In dit schilderij uit 1872 brengt Voltz een groep vee tot leven die vredig graast bij een kalm meer. Zijn gedetailleerde penseelstreken en het spel van licht en schaduw geven het tafereel een rustieke charme.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1646.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,37807) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('drie-peren-en-een-appel-1857','Drie Peren en een Appel (1857)','door: David Johnson (1827-1908) \n \n"Drie Peren en een Appel" van David Johnson is een schitterend stilleven uit 1857. Het toont drie rijpe peren en een appel, weergegeven met gedetailleerde precisie en een meesterlijk oog voor kleur en licht. Johnson''s aandacht voor textuur en vorm brengt de vruchten realistisch tot leven, waardoor dit schilderij een eenvoudige maar elegante uitstraling heeft.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1644.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus'],false,true,37808) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-haven-van-marseille-1938','De haven van Marseille (1938)','door: Moïse Kisling (Frans, 1891 – 1953) \n \n"De haven van Marseille" van Moïse Kisling uit 1938 vangt de levendige sfeer van een van de grootste havens van Frankrijk. Kisling''s levendige kleuren en expressieve penseelstreken brengen de bedrijvigheid en charme van de haven tot leven.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1643.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters','specials'],false,true,37809) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-trekvliet','De Trekvliet','Door: Johan Hendrik Weissenbruch (1824 - 1903) \n \n"De Trekvliet" is een schilderij van Johan Hendrik Weissenbruch dat de rustige charme van het Nederlandse kanaal de Trekvliet weergeeft. Met zijn meesterlijke gebruik van licht en schaduw, brengt Weissenbruch de serene sfeer van het water en het omringende landschap tot leven. Dit werk is perfect voor liefhebbers van Nederlandse landschappen en voegt een vleugje landelijke rust toe aan elk interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1633.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus'],false,true,37810) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomerdag','Zomerdag','Door: Johan Hendrik Weissenbruch ( 1824 - 1903) \n \n"Zomerdag" is een schilderij van Johan Hendrik Weissenbruch dat de rust en warmte van een zomerse dag vastlegt. Weissenbruch gebruikt heldere kleuren en zachte penseelstreken om een serene en idyllische sfeer te creëren. De eenvoudige schoonheid van het Nederlandse platteland komt tot leven in dit tijdloze werk, perfect voor iedereen die een vleugje zomer in huis wil halen.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1634.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,37811) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-drie-vissen','Stilleven met Drie Vissen','Door: Broncia Koller-Pinell (1863-1934) \n \n"Stilleven met Drie Vissen" van Broncia Koller-Pinell is een opvallend stilleven dat drie vissen in levendige kleuren toont. Koller-Pinell''s gebruik van gedetailleerde penseelstreken en subtiele schaduwen brengt de textuur en glans van de vissen prachtig tot leven. Dit schilderij straalt een gevoel van realisme en artistieke verfijning uit, perfect voor liefhebbers van stillevens en maritieme thema''s','https://kunstdoekje.nl/wp-content/uploads/2024/07/1640.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus','oude-meesters'],false,true,37812) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gein-bij-abcoude','De Gein bij Abcoude','\n \n \n \n Door: Willem Roelofs (Nederlands, 1822-1897) \n \n \n \n \n \n \n \n \n \n \n \n \n"De Gein bij Abcoude" van Willem Roelofs toont de serene schoonheid van het Nederlandse landschap langs de Gein-rivier. Met zijn meesterlijke penseelstreken vangt Roelofs de rust en harmonie van de natuur, waarbij het spel van licht en schaduw de scène tot leven brengt. \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1638.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,37813) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blue-cow','Blue cow','Deze expressieve street art schilderij toont een indrukwekkend portret van een blauwe koe. De felle, gedurfde kleuren en abstracte penseelstreken geven het kunstwerk een moderne en energieke uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1744.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren'],false,true,37814) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('parijse-strand-1911','Parijse Strand (1911)','Door: Robert Harris ( 1849-1919) \n \n"Paris Plage (Etaples)" van Robert Harris is een levendig schilderij dat het strand van Etaples toont. Harris vangt de zomerse sfeer met zijn gebruik van licht en kleur, waardoor de levendigheid van de Franse kust tot leven komt. De impressionistische stijl van Harris geeft een gevoel van beweging en energie.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1636.jpg',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus'],false,true,37815) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('herderin-en-twee-koeien-in-een-weide-37828','Herderin en Twee Koeien in een Weide','\n \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n Door: Rosa Bonheur (1822-1899) \n \nOntdek de rust van het platteland met "Herderin en Twee Koeien in een Weide" van Rosa Bonheur. Dit charmante schilderij, gemaakt rond 1842-45, vangt het serene moment van een herderin met haar twee koeien in een weelderige weide. Bonheur, bekend om haar levendige en gedetailleerde werken, brengt de natuur echt tot leven. \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1623.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,false,37828) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('girlande-van-bloemen-en-vruchten-ca-1672','Girlande van Bloemen en Vruchten (ca. 1672)','\n \n \n \n door: Jan Davidsz de Heem (1606-1684 ) \n \n "Girlande van Bloemen en Vruchten" van Jan Davidsz de Heem is een prachtig stilleven uit circa 1672. Dit meesterwerk toont een weelderige guirlande van diverse bloemen en vruchten, levendig en gedetailleerd weergegeven. De Heem''s meesterlijke gebruik van kleur en textuur brengt de natuurlijke schoonheid van de compositie tot leven. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1663.jpg',(select id from categories where slug='bloemen'),array['bloemen','landschapmodus','oude-meesters'],false,true,37841) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven-met-fruit-oesters-en-een-papegaai','Stilleven met Fruit, Oesters en een Papegaai','\n \n \n \n door: Jan Davidsz de Heem (Nederlands, 1606-1684) \n \n \n \n \n \n \n \n \n \n \n \n \n"Stilleven met Fruit, Oesters en een Papegaai" van Jan Davidsz de Heem is een schitterend voorbeeld van de Nederlandse stillevenkunst uit de 17e eeuw. Dit meesterwerk toont een overvloedige opstelling van fruit, oesters en een kleurrijke papegaai, allemaal gedetailleerd weergegeven met een meesterlijk oog voor licht en textuur. \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1662.jpg',(select id from categories where slug='bloemen'),array['bloemen','dieren','landschapmodus'],false,true,37842) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stilleven','Stilleven','door: Paul Burman (1916) \n \n \n \n \n \n "Stilleven (Bloemen)" van Paul Burman uit 1916 is een schitterend voorbeeld van de kunstenaar''s talent in het vastleggen van florale pracht. Dit schilderij toont een levendig boeket bloemen, gedetailleerd en met een levendig kleurenspectrum. Burman''s gebruik van licht en schaduw geeft de bloemen een bijna tastbare textuur en een gevoel van diepte. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1668.jpg',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','landschapmodus'],false,true,37843) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vier-jonge-stieren-in-een-weide','Vier jonge stieren in een weide','\n \n \n \n door: Paulus Potter (1654) \n \n \n \n \n \n \n \n \n \n \n \n \n"Vier jonge stieren in een weide" van Paulus Potter is een meesterlijk schilderij uit 1651 dat de levendige energie van jonge stieren vastlegt. Potter''s oog voor detail en zijn vaardigheid in het weergeven van de dieren en het omringende landschap zijn ongeëvenaard. \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1671.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,37844) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('guirlande-van-fruit-en-bloemen','Guirlande van Fruit en Bloemen','door: Jan Davidsz de Heem (Nederlands, 1606-1684) \n \n"Guirlande van Fruit en Bloemen" van Jan Davidsz de Heem is een prachtig voorbeeld van de barokke stillevenkunst. Dit werk, waarschijnlijk geschilderd tussen 1650 en 1660, toont een weelderige guirlande van diverse vruchten en bloemen, gedetailleerd en levendig weergegeven.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1665.jpg',(select id from categories where slug='bloemen'),array['bloemen','landschapmodus','oude-meesters'],false,true,37845) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blumenstudie','Blumenstudie','\n \n \n \n door: Anselm Feuerbach (1829-1880) \n \n "Blumenstudie" van Anselm Feuerbach is een prachtig bloemenschilderij dat de delicate schoonheid van bloemen vastlegt. Feuerbach''s meesterlijke gebruik van kleur en licht geeft de bloemen een levendige en bijna tastbare kwaliteit. De compositie straalt een gevoel van verfijning en elegantie uit, typerend voor Feuerbach''s stijl. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1669.jpg',(select id from categories where slug='bloemen'),array['bloemen','landschapmodus'],false,true,37846) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rivierlandschap-ca-1650','Rivierlandschap (ca. 1650)','\n \n \n \n \n \n door: Aert van der Neer (1603-1677) \n \n \n \n \n "Rivierlandschap" van Aert van der Neer, geschilderd rond 1650, is een prachtig voorbeeld van de Nederlandse landschapskunst uit de Gouden Eeuw. Dit schilderij toont een serene rivier die door een weelderig landschap stroomt, met gedetailleerde bomen en lucht die de kalme sfeer versterken. Van der Neer''s meesterlijke gebruik van licht en schaduw brengt de scène tot leven en geeft een gevoel van tijdloze rust. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1677.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,37847) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gezicht-op-olinda-brazilie','Gezicht op Olinda, Brazilië','\n \n \n \n Door: Frans Post (1662) \n \n \n \n \n \n \n \n \n \n \n \n \n"Gezicht op Olinda, Brazilië" van Frans Post uit 1662 is een indrukwekkend schilderij dat de stad Olinda in levendige details vastlegt. Als een van de eerste Europese kunstenaars die Zuid-Amerika bezochten, bracht Post de exotische landschappen en architectuur van de Nieuwe Wereld naar Europa. Dit schilderij toont de weelderige vegetatie, koloniale gebouwen en de rustige sfeer van Olinda. \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1676.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,37848) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('arcadisch-landschap-1729','Arcadisch landschap (1729)','\n \n \n \n Jan van Huysum (1682-1749) \n \n "Arcadisch landschap" van Jan van Huysum, geschilderd in 1729, is een schitterend voorbeeld van de idyllische en romantische landschapskunst uit de 18e eeuw. Van Huysum''s meesterlijke gebruik van kleur en licht brengt het serene landschap tot leven, met weelderige vegetatie, een rustige rivier, en klassieke architectuur. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1675.jpg',(select id from categories where slug='landschapmodus'),array['landschapmodus','oude-meesters'],false,true,37849) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('wine-and-whimsy','Wine and Whimsy','\n \n \n \n Dit street art schilderij toont een vrouw die geniet van een glas wijn, omgeven door abstracte vormen en levendige kleuren. Haar dromerige blik en de gedurfde lijnen geven het werk een moderne, speelse uitstraling. Perfect voor wie houdt van een vleugje elegantie met een knipoog. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1748.jpg',(select id from categories where slug='ai-kunst'),array['ai-kunst','specials'],false,true,37850) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('wisteria-1925','Wisteria (1925)','Claude Monet (1840-1926) \n \n"Wisteria" van Claude Monet, geschilderd rond 1925, is een betoverend werk dat de weelderige bloei van blauwe regen vastlegt. Monet''s impressionistische stijl, gekenmerkt door zijn zachte penseelstreken en levendige kleuren, brengt de delicate bloemen tot leven. Het schilderij straalt een gevoel van rust en natuurlijke schoonheid uit, en toont Monet''s meesterlijke vermogen om de essentie van de natuur te vangen.','https://kunstdoekje.nl/wp-content/uploads/2024/07/1674.jpg',(select id from categories where slug='bloemen'),array['bloemen','claude-monet','landschapmodus','oude-meesters'],false,true,37851) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('boeket-mimosas-in-rode-pot','Boeket mimosas in rode pot','\n \n \n \n \n \n door: Moïse Kisling (1891 – 1953) \n \n"Bouquet de mimosas au pot rouge" van Moïse Kisling uit 1941 is een levendig en kleurrijk schilderij dat een boeket mimosabloemen in een rode pot toont. Kisling''s gebruik van felle kleuren en gedetailleerde penseelstreken brengt de bloemen tot leven, terwijl de contrasterende rode pot een opvallend middelpunt vormt. \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/07/1670.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,37852) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vervloeiing-van-silhouetten','Vervloeiing van Silhouetten','\n \n Dit kunstdoekje toont een mysterieus vrouwelijk silhouet dat is opgebouwd uit vloeiende penseelstreken, waardoor een gevoel van elegantie en mysterie ontstaat. De eenvoudige zwart-witte kleuren maken het stuk tijdloos en uitnodigend voor eigen interpretaties. Het is een echte blikvanger voor moderne ruimtes die iets unieks willen uitstralen. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1947.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38017) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rustgevende-kustlijnen','Rustgevende Kustlijnen','\n \n Dit kunstdoekje vangt de rust van een zomerse kustlijn met zachte pastelkleuren die een kalme sfeer creëren. Het laat je wegdromen naar een stille zee en een vredig strand. Perfect voor iedereen die een vleugje natuur en rust in huis wil halen. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1749.jpg',(select id from categories where slug='asbtract'),array['asbtract','natuur','specials'],false,true,38019) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurenexplosie','Kleurenexplosie','\n \n Dit kleurrijke kunstdoekje bruist van energie met zijn felle oranje, roze en gele tinten. Het is een vrolijk en dynamisch stuk dat je ruimte tot leven brengt. Ideaal voor wie zijn interieur een vrolijke en energieke uitstraling wil geven. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1748.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38020) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-harmonie','Abstracte Harmonie','Met een mix van roze, paars, en witte tinten brengt dit kunstdoekje een speelse maar toch serene sfeer in elke kamer. De lagen verf en de subtiele kleurenovergangen maken het een boeiend stuk om naar te kijken. Ideaal voor wie zijn interieur wat extra flair en karakter wil geven.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1747.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38021) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('balans-in-abstractie','Balans in Abstractie','\n \n Dit kunstdoekje toont een elegant spel van vormen en lijnen in zachte neutrale tinten, aangevuld met een subtiele oranje toets voor een vleugje warmte. De cirkels en lijnen brengen een gevoel van balans en rust, waardoor dit stuk ideaal is voor een moderne en minimalistische inrichting. Laat je inspireren door de eenvoud en harmonie die dit doek uitstraalt. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1751.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38022) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rode-dromen','Rode Dromen','\n \n Dit krachtige kunstdoekje laat een dramatisch gezicht zien met opvallende rode lippen tegen een gedurfde, donkere achtergrond. Het stuk straalt een gevoel van mysterie en zelfvertrouwen uit, wat het een perfecte aanvulling maakt voor elke ruimte die een sterke artistieke impact wil maken. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1753.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38023) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('golden-city','Golden City','\n \n Dit kunstdoekje vangt de skyline van een stad in dramatische zwart- en goudtinten, waardoor een luxe en elegante sfeer ontstaat. De abstracte vormen en texturen geven een gevoel van stedelijke dynamiek en verfijning \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/bright-neutral-living-room.webp',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38025) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stadslicht','Stadslicht','\n \n \n \n Een indrukwekkend kunstdoekje dat de skyline van een stad vastlegt in dramatische zwart- en goudtinten. De texturen en kleuren geven een gevoel van luxe en elegantie, waardoor het een geweldige keuze is voor moderne interieurs. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1759.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38026) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stille-overpeinzing','Stille Overpeinzing','\n \n Dit kunstdoekje toont een ingetogen figuur tegen een achtergrond van warme en koele tinten, wat een gevoel van introspectie en rust uitstraalt. De combinatie van oranje, groen, en zwart zorgt voor een opvallend contrast dat de aandacht trekt. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1756.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38027) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('natuurlijke-vibes','Natuurlijke Vibes','\n \n Dit kunstdoekje combineert abstracte en natuurlijke elementen met warme aardetinten en minimalistische lijnen. De eenvoudige vormen en natuurlijke motieven creëren een serene en ontspannen sfeer, ideaal voor een rustgevende omgeving. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1754.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38028) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kosmische-kleuren','Kosmische Kleuren','Dit kunstdoekje barst van de levendige kleuren en geometrische vormen die een kosmisch landschap creëren. De opvallende bogen en cirkels roepen een gevoel van verwondering op en brengen energie in elke ruimte. Perfect voor wie houdt van speelse, dynamische kunst die tot de verbeelding spreekt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1757.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38029) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verbinding-van-figuren','Verbinding van Figuren','\n \n Dit kunstdoekje vangt de intimiteit van menselijke connectie door middel van abstracte figuren en gedurfde penseelstreken. De mix van aardse en rijke kleuren geeft een warme uitstraling die je ruimte tot leven brengt. Perfect voor wie houdt van een artistieke weergave van relaties en emoties. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1750.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38030) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsondergang-dromen','Zonsondergang Dromen','\n \n Maak kennis met: "Zonsondergang Dromen," waar de lucht in pastelkleuren overgaat in een kalme zee. Dit kunstdoekje vangt de magie van een zonsondergang en brengt een vleugje rust in je huis. Perfect voor iedereen die wil ontsnappen naar een wereld van ontspanning en vrede. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1766.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38031) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('schaduwfiguur','Schaduwfiguur','\n \n Maak kennis met de intrigerende schaduwfiguur die een verhaal van mysterie en moderniteit vertelt. De gedurfde penseelstreken en abstracte details voegen een unieke charme toe aan dit kunstdoekje, waardoor het perfect is voor de kunstliefhebber die zijn huis wil verrijken met iets ongewoons. Geef je muur een upgrade met deze intrigerende blikvanger! \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1762.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38032) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hemel-en-aarde','Hemel en Aarde','\n \n Stap in een wereld van contrast en evenwicht met "Hemel en Aarde," een kunstdoekje dat de perfecte harmonie tussen licht en donker laat zien. De centrale cirkel trekt je naar binnen en roept vragen op over de balans van het leven. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1764.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38033) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsverduistering','Zonsverduistering','\n \n Dit indrukwekkende kunstdoekje combineert warme oranje tinten met diepe zwarte accenten om een krachtige visuele impact te creëren. Het lijkt een zonsverduistering te verbeelden, waarbij de centrale zwarte cirkel de aandacht trekt en een gevoel van mystiek oproept. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1763.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38034) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verstilde-schoonheid','Verstilde Schoonheid','\n \n Dit kunstdoekje vangt de serene schoonheid van een figuur in zachte aardetinten, waardoor een kalme en tijdloze uitstraling ontstaat. De eenvoudige vormen en kleuren benadrukken de elegantie en subtiliteit van het ontwerp. Perfect voor wie op zoek is naar een rustige en verfijnde toevoeging aan zijn ruimte. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1758.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38035) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('retro-ritme','Retro Ritme','"Retro Ritme" is een ode aan de modieuze designs van weleer, met zijn gedurfde vormen en aardse tinten die een warme, nostalgische sfeer oproepen. Dit kunstdoekje brengt een uniek karakter in je interieur en is perfect voor iedereen die houdt van vintage vibes met een eigentijdse twist. Voeg een vleugje retro chic toe aan je huis en laat het verleden herleven op je muren.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1961.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38036) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mystieke-reflectie','Mystieke Reflectie','\n \n Laat je meevoeren door de mysterieuze sfeer van "Mystieke Reflectie," waar vage silhouetten en diepe blauwtonen samen een verhaal van introspectie en stilte vertellen. Dit kunstdoekje brengt een gevoel van diepgang en mysterie in elke kamer en is perfect voor wie houdt van kunst die aanzet tot nadenken. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1954.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38037) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('monochrome-melodie','Monochrome Melodie','\n \n "Monochrome Melodie" speelt met de kracht van zwart-wit contrasten in een geometrisch patroon dat zowel eenvoudig als verbluffend is. Dit kunstdoekje brengt een moderne flair naar elke ruimte en is ideaal voor minimalisten die houden van strakke lijnen en stijlvolle eenvoud. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1959.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38038) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gezicht-in-de-schaduw-38039','Gezicht in de Schaduw','\n \n Laat je intrigeren door "Gezicht in de Schaduw," een kunstdoekje dat de grens tussen abstractie en herkenning opzoekt. De eenvoudige, maar krachtige lijnen maken van dit stuk een unieke toevoeging aan elk interieur. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1946.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38039) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dans-van-kleur','Dans van Kleur','\n \n "Dans van Kleur," waar speelse lijnen en zachte tinten samenkomen om een abstract kunstwerk te vormen dat de zintuigen prikkelt. Dit kunstdoekje is een perfecte mix van beweging en rust, en zal elke ruimte transformeren met zijn dynamische charme. Ideaal voor liefhebbers van moderne kunst die op zoek zijn naar een vleugje creativiteit in hun interieur. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1948.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38040) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verstilde-schoonheid-38041','Verstilde Schoonheid','\n \n Dit kunstdoekje toont een abstract portret in zwart-wit met gedurfde penseelstreken, wat een gevoel van mysterie en intrige creëert. De minimalistische stijl benadrukt de expressie en emotie van het stuk. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1761.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38041) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('omarm-de-liefde','Omarm de Liefde','\n \n Dit kunstdoekje vertelt het verhaal van liefde en intimiteit met gedurfde penseelstreken en warme kleuren. "Omarm de Liefde" brengt de passie van een innige omhelzing tot leven, waardoor het een hartverwarmende toevoeging is aan elke kamer. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1767.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38042) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-dans-van-de-schaduwen','De Dans van de Schaduwen','Ontdek de betoverende eenvoud van "De Dans van de Schaduwen," een kunstdoekje dat subtiele elegantie uitstraalt met zijn vloeiende lijnen en contrasterende zwart-wit kleuren. De sierlijke vormen roepen een gevoel van beweging en harmonie op, perfect voor wie op zoek is naar minimalistische kunst met een krachtige impact.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1963.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38050) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gezichten-van-de-ziel','Gezichten van de Ziel','\n \n Ontdek de betoverende eenvoud van "De Dans van de Schaduwen," een kunstdoekje dat subtiele elegantie uitstraalt met zijn vloeiende lijnen en contrasterende zwart-wit kleuren. De sierlijke vormen roepen een gevoel van beweging en harmonie op, perfect voor wie op zoek is naar minimalistische kunst met een krachtige impact. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1964.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38071) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rode-dromen-copy','Rode Dromen (Copy)','\n \n Dit krachtige kunstdoekje laat een dramatisch gezicht zien met opvallende rode lippen tegen een gedurfde, donkere achtergrond. Het stuk straalt een gevoel van mysterie en zelfvertrouwen uit, wat het een perfecte aanvulling maakt voor elke ruimte die een sterke artistieke impact wil maken. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1753.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,false,38072) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwart-wit-contrast','Zwart-Wit Contrast','\n \n "Zwart-Wit Contrast" speelt met de dramatische kracht van licht en schaduw in een gedurfd ontwerp dat elke ruimte transformeert. De robuuste penseelstreken en texturen voegen diepte en karakter toe, perfect voor liefhebbers van moderne en minimalistische kunst. Geef je huis een stijlvolle en eigentijdse uitstraling met dit iconische kunstdoekje. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1971.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38073) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mystieke-vormen','Mystieke Vormen','\n \n Breng mystiek en verfijning in je huis met "Mystieke Vormen," een kunstdoekje dat de grenzen van abstractie verkent. Met zijn gedempte kleuren en organische vormen creëert dit stuk een rustige en contemplatieve sfeer. Perfect voor wie op zoek is naar een vleugje mysterieuze elegantie in zijn interieur. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1966.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38074) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurenexplosie-38075','Kleurenexplosie','\n \n Laat je interieur tot leven komen met "Kleurenexplosie," een kunstdoekje dat je meeneemt op een visueel avontuur vol levendigheid en energie. De sprankelende tinten en dynamische vormen zorgen voor een bruisend middelpunt in elke kamer. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1969.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38075) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('natuurlijke-slag','Natuurlijke Slag','\n \n \n \nErvaar de schoonheid van de natuur gevangen in abstracte kunst met "Natuurlijke Slag." De vloeiende lijnen en organische vormen brengen een kalmte en elegantie in je ruimte, alsof de natuur zelf op je muur danst. Ideaal voor wie een rustige en verfijnde sfeer wil creëren in huis. \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1968.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38076) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rode-dromen-copy-38077','Rode Dromen (Copy)','\n \n Dit krachtige kunstdoekje laat een dramatisch gezicht zien met opvallende rode lippen tegen een gedurfde, donkere achtergrond. Het stuk straalt een gevoel van mysterie en zelfvertrouwen uit, wat het een perfecte aanvulling maakt voor elke ruimte die een sterke artistieke impact wil maken. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1753.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,false,38077) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwart-wit-ritme','Zwart-Wit Ritme','\n \n Ervaar de kracht van eenvoud met "Zwart-Wit Ritme," waar strakke lijnen en geometrische patronen samen een visueel spektakel vormen. Dit kunstdoekje is een moderne ode aan de kracht van contrast en voegt een gedurfde, minimalistische flair toe aan elke kamer. Voor wie houdt van tijdloze elegantie en eigentijdse stijl. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1967.jpg',(select id from categories where slug='asbtract'),array['asbtract'],false,true,38078) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-zebra','Stijlvolle Zebra','Ontmoet de ster van de savanne in je woonkamer met "Stijlvolle Zebra." Dit kunstdoekje vangt de tijdloze elegantie van de zebra in verbluffend detail en maakt van zwart-wit kunst iets buitengewoons. Ideaal voor wie op zoek is naar een gedurfd, maar klassiek stuk dat de ruimte vult met natuur en stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1784.jpg',(select id from categories where slug='dieren'),array['dieren','fotografie'],false,true,38121) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('aziatische-kikker','Aziatische Kikker','Breng rust en eenvoud in je ruimte met "''Aziatische Kikker" Dit kunstdoekje combineert Japanse esthetiek met een minimalistisch ontwerp, waardoor het de perfecte keuze is voor wie een serene sfeer wil creëren.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1951.jpg',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,38222) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bubblegum-safari','Bubblegum Safari','Maak kennis met het ondeugendste leeuwenwelpje dat er is! Deze kleine avonturier blaast kauwgombellen als een echte professional. Dit kunstwerk brengt een speelse touch in elke kamer en zorgt voor een brullend goede tijd! Perfect voor kinderkamers of iedereen die van een beetje fantasie in hun decor houdt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1911.jpg',(select id from categories where slug='dieren'),array['dieren'],false,true,38224) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('luipaard-in-jungle-bloemen','Luipaard in Jungle Bloemen','Betreed de mooie wereld van het regenwoud met dit kunstwerk waar een elegante panter te midden van exotische bloemen de show steelt. De kleuren zijn zo levendig dat het lijkt alsof je zo de jungle in kunt stappen. Ideaal voor diegenen die hun ruimte willen verlevendigen met een beetje wilde flair.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1916.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk','landschapmodus'],false,true,38225) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-schreeuw-van-de-kat','De Schreeuw van de Kat','Deze grappige twist op Edvard Munch''s beroemde schilderij "The Scream" vangt een kat in zijn meest dramatische moment. Dit kunstwerk is perfect voor kunstliefhebbers die humor en een beetje kattenkwaad aan hun muur willen toevoegen. \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1869.jpg',(select id from categories where slug='dieren'),array['dieren'],false,true,38226) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwaan-in-stijl','Zwaan in Stijl','Deze schattige zwaan brengt stijl en charme naar je woonkamer met haar prachtige roze strik. "Zwaan in Stijl" is het perfecte kunstdoekje voor iedereen die wat zachtheid en elegantie aan hun ruimte wil toevoegen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1990.jpg',(select id from categories where slug='dieren'),array['dieren','impressionisme','natuur'],false,true,38227) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('flamingo-fiesta','Flamingo Fiesta','Welkom bij de "Flamingo Fiesta," waar de flamingo''s samenkomen voor hun dagelijkse dans in een zee van kleuren. Deze levendige en kleurrijke compositie brengt een vleugje tropische sfeer en vrolijkheid in elke ruimte. Perfect voor wie een beetje exotisch plezier aan de muur wil hebben.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1976.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk','landschapmodus'],false,true,38228) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vogelkriebels','Vogelkriebels','Laat je verrassen door de charme van "Vogelkriebels," waar elke veeg en lijn een vrolijk melodietje zingt. Dit kunstdoekje brengt de speelsheid van de natuur naar je muren, perfect voor wie houdt van kunst die spreekt en een glimlach tovert op je gezicht.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1955.jpg',(select id from categories where slug='asbtract'),array['asbtract','dieren'],false,true,38229) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('giraf-met-bloem','Giraf met Bloem','Maak kennis met onze vrolijke giraf, die je begroet met een bloemenboeket. Dit kunstdoekje is perfect voor een kinderkamer of om een speelse touch aan je interieur te geven. Een beetje natuur met een artistieke twist die je elke dag opvrolijkt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1904.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38230) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-zebra-copy-copy','Stijlvolle Zebra (Copy) (Copy)','Ontmoet de ster van de savanne in je woonkamer met "Stijlvolle Zebra." Dit kunstdoekje vangt de tijdloze elegantie van de zebra in verbluffend detail en maakt van zwart-wit kunst iets buitengewoons. Ideaal voor wie op zoek is naar een gedurfd, maar klassiek stuk dat de ruimte vult met natuur en stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1784.jpg',(select id from categories where slug='dieren'),array['dieren'],false,false,38231) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomerse-tijger','Zomerse Tijger','Maak kennis met onze coole zomerse tijger, die heerlijk drijft op een zwemband, compleet met zonnebril en attitude. Deze tijger laat zien hoe je in stijl kunt relaxen. Het perfecte kunstwerk om wat zomerse vibes in je huis te brengen, het hele jaar door.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1915.jpg',(select id from categories where slug='dieren'),array['dieren','landschapmodus'],false,true,38232) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('badend-luipaard','Badend Luipaard','Even bijkomen van de drukke dag? Dit badend luipaard doet het je graag voor. Geniet van het speelse contrast tussen de levendige kleuren en de relaxte pose van dit prachtige dier in zijn kleurrijke badkamer. Perfect voor iedereen die houdt van een vleugje humor en stijl in hun interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1913.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38233) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-modekoningin-in-felle-kleuren','De Modekoningin in Felle Kleuren','Welkom in de wereld van stijl en kleur met onze "Modekoningin in Felle Kleuren". Dit kunstwerk straalt flair en elegantie uit, terwijl het de gedurfde en levendige kleuren omarmt. Perfect voor modefanaten en iedereen die wat extra pit aan hun muur wil toevoegen. Deze kleurrijke dame brengt niet alleen mode naar je huis, maar ook een flinke dosis charisma.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1868.jpg',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,38234) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cheetah-en-botanische-schoonheid','Cheetah en Botanische Schoonheid','De cheetah, majestueus tussen een zee van bloemen en bladeren. De levendige kleuren en gedetailleerde botanische elementen zorgen voor een visuele traktatie die je kamer direct een exotische en levendige uitstraling geeft. Een absolute must-have voor liefhebbers van natuur en kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1914.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38235) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-giraffe-38236','Roze Giraffe','Hier is onze roze giraf, een vrolijke en kleurrijke vriend die meteen een glimlach op je gezicht tovert. Dit kunstdoekje voegt een speelse en positieve sfeer toe aan elke ruimte. Ideaal voor iedereen die wat extra kleur en fantasie aan zijn leven wil toevoegen. Wie wil er nou niet zo’n opvallende giraf aan de muur?','https://kunstdoekje.nl/wp-content/uploads/2024/08/1902.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38236) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('husky-lounge','Husky Lounge','Een elegante husky straalt stijl en klasse uit in dit kunstdoekje. De husky draagt een modieus pak in gedempte pasteltinten, perfect passend bij de chique achtergrond. De verfijnde details en het subtiele kleurgebruik maken dit doekje een verfijnde toevoeging aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1909.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38237) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hip-giraffe-op-avontuur','Hip Giraffe op Avontuur','Deze hippe giraffe met zijn kleurrijke bloemenblazer en zonnebril brengt een vleugje humor in je interieur. De gedurfde kleuren oranje, roze en blauw zorgen ervoor dat de giraffe echt opvalt. Perfect voor liefhebbers van een speelse en eigentijdse stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1908.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38238) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cocktail-daschund','Cocktail Daschund','Deze schattige Daschund is klaar voor een feestje met zijn cocktail en vlinderdas. De warme tinten van roze en rood geven het kunstdoekje een uitnodigende sfeer. Een charmante en speelse toevoeging aan je keuken of eetkamer.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1907.jpg',(select id from categories where slug='dieren'),array['dieren','impressionisme','kleurrijk'],false,true,38239) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tijger-in-actie','Tijger in Actie','Ervaar de kracht en majesteit van de tijger met dit kunstdoekje. De tijger komt tot leven met gedetailleerde penseelstreken en warme aardetinten. Dit kunstdoekje vangt het moment van de tijger in actie en is een geweldige keuze voor dierenliefhebbers en diegenen die graag een gevoel van avontuur aan hun interieur willen toevoegen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1779.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38240) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-zebra-copy-copy-38241','Stijlvolle Zebra (Copy) (Copy)','Ontmoet de ster van de savanne in je woonkamer met "Stijlvolle Zebra." Dit kunstdoekje vangt de tijdloze elegantie van de zebra in verbluffend detail en maakt van zwart-wit kunst iets buitengewoons. Ideaal voor wie op zoek is naar een gedurfd, maar klassiek stuk dat de ruimte vult met natuur en stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1784.jpg',(select id from categories where slug='dieren'),array['dieren'],false,false,38241) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('chique-zebra-in-bad','Chique Zebra in Bad','Dit levendige kunstdoekje laat een ontspannen zebra zien die geniet van een bad. De combinatie van felle roze, blauwe en gele tinten zorgt voor een speels en kleurrijk geheel. De zwart-witte strepen van de zebra creëren een prachtig contrast met de bonte achtergrond. Een speelse blikvanger voor elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1910.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38242) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zebra-illusie','Zebra illusie','Dit kunstdoekje speelt met optische illusies en laat een zebra naadloos samensmelten met de zwart-witte strepen van de achtergrond. Een fascinerend en speels kunstdoekje dat je ogen even voor de gek houdt. Perfect voor een modern interieur','https://kunstdoekje.nl/wp-content/uploads/2024/08/1773.jpg',(select id from categories where slug='dieren'),array['dieren','specials'],false,true,38243) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-aap','Stijlvolle Aap','Simpel maar krachtig, deze aap straalt met een klassieke pose tegen een levendige oranje achtergrond. De contrasten in zwart en oranje geven het kunstdoekje een moderne en minimalistische uitstraling. Een perfecte mix van eenvoud en stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1776-1.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38267) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-kat','Kleurrijke Kat','Breng kleur in je ruimte met dit levendige kunstdoekje van een speelse kat. De dikke penseelstreken en het overvloedige gebruik van kleur geven het doekje een energieke uitstraling. Dit kunstdoekje is een ware eyecatcher en voegt een vrolijke touch toe aan elk interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1781.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38268) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('konijn-met-strik','Konijn met strik','Dit kunstdoekje straalt zachtheid en charme uit met een schattig konijn dat trots een stippenstrik draagt. Het subtiele kleurenpalet van zachte pastelkleuren creëert een dromerige sfeer, terwijl de delicate bloemdetails de natuur tot leven brengen. Perfect voor de kinderkamer of als een schattige toevoeging aan je woonkamer.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1912.jpg',(select id from categories where slug='dieren'),array['dieren'],false,true,38269) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
