insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-racoon','Kleurrijke Racoon','Deze schattige wasbeer trekt de aandacht met zijn kleurrijke outfit en nieuwsgierige blik. Het kunstdoekje speelt met warme roze en oranje tinten, gecombineerd met koele blauwe en paarse accenten. Een speels en levendig kunstdoekje voor de kinderkamer of elke ruimte die een vrolijke noot kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1783.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38271) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-streepjes-zebra','Stijlvolle Streepjes (Zebra)','Breng een beetje wilde flair in je ruimte met ons kunstdoekje Stijlvolle Streepjes ! Dit levendige ontwerp combineert oranje en aqua voor een speelse twist op klassieke zebraprints. Het lijkt alsof de zebra bijna uit het doekje stapt met zijn brutale blik en swingende streepjes. Perfect voor wie zijn interieur een hippe en vrolijke boost wil geven!','https://kunstdoekje.nl/wp-content/uploads/2024/08/1777.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38272) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
