insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwarte-kat-in-kleurrijke-stijl','Zwarte Kat in Kleurrijke Stijl','Dit kunstdoekje vangt de essentie van een mooie zwarte kat met een kleurrijke twist. De felle kleuren tegen een diep paarse achtergrond brengen de ogen van de kat tot leven. Het dynamische kleurgebruik en de speelse lijnen maken dit kunstdoekje een geweldige keuze voor liefhebbers van moderne en levendige kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1782.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38274) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('schattige-cowboy','Schattige Cowboy','Rijd de zonsondergang tegemoet met Schattige Cowboy ! Deze kitten is helemaal klaar voor avontuur met zijn stoere cowboyhoed en vrolijke roze sjaaltje. Het kleurrijke kunstdoekje is ideaal om een kinderkamer of speelhoek mee op te vrolijken. Dit kleine cowboykatje is gegarandeerd een glimlach-oproepend kunstwerk!','https://kunstdoekje.nl/wp-content/uploads/2024/08/1906.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38275) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-zebra-copy-copy-copy-38276','Stijlvolle Zebra (Copy) (Copy) (Copy)','Ontmoet de ster van de savanne in je woonkamer met "Stijlvolle Zebra." Dit kunstdoekje vangt de tijdloze elegantie van de zebra in verbluffend detail en maakt van zwart-wit kunst iets buitengewoons. Ideaal voor wie op zoek is naar een gedurfd, maar klassiek stuk dat de ruimte vult met natuur en stijl.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1784.jpg',(select id from categories where slug='dieren'),array['dieren'],false,false,38276) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dappere-ruiter','Dappere Ruiter','Dappere Ruiter vangt de kracht en elegantie van een zwart paard tegen een diep rode achtergrond. De subtiele blauwe accenten zorgen voor extra diepte en maken het kunstdoekje tot een echte blikvanger. Een perfecte keuze voor liefhebbers van paarden en stijlvolle, krachtige kunstwerken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1778.jpg',(select id from categories where slug='dieren'),array['dieren','impressionisme','kleurrijk'],false,true,38277) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ijzige-beer','IJzige Beer','Ontmoet de beer die je winterdagen opvrolijkt! Gekleed in een bont gekleurde, patchwork-sjaal met tinten van roze, blauw en paars, staat deze vriendelijke reus op een turquoise achtergrond. Een hartverwarmend kunstdoekje dat kleur toevoegt aan elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1774.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38278) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('knuffelbeer-in-de-kou','Knuffelbeer in de Kou','Voeg warmte en gezelligheid toe aan je interieur met Knuffelbeer in de Kou . Dit kunstdoekje met een schattige beer in zachte pastelkleuren straalt een rustgevende sfeer uit. Ideaal voor slaapkamers of kinderkamers, het doekje biedt een charmante en uitnodigende uitstraling die past bij elk seizoen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1776.jpg',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38301) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-rode-ballon','Meisje met Rode Ballon','De eenvoud en kracht van dit kunstdoekje spreken boekdelen. Het beeldt een silhouet van een meisje uit dat een rode ballon vasthoudt, een symbool van hoop en dromen. Het zwart-witte silhouet tegen de witte achtergrond laat de rode ballon echt opvallen, waardoor dit stuk een tijdloze charme heeft. Ideaal voor wie zijn ruimte wil verrijken met betekenisvolle kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2009.webp',(select id from categories where slug='banksy'),array['banksy','pop-street-art'],false,true,38305) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('afrikaanse-vrouw-in-kleurrijke-pracht','Afrikaanse Vrouw in Kleurrijke Pracht','Dit kunstdoekje vangt de schoonheid en kracht van een Afrikaanse vrouw gehuld in traditionele kledij. De rijke, levendige kleuren van haar outfit en sieraden stralen warmte en cultuur uit, terwijl de expressie op haar gezicht een verhaal van trots en mysterie vertelt. De contrasterende kleuren tegen de neutrale achtergrond maken dit doekje een krachtig middelpunt voor elk interieur. Perfect voor diegenen die een vleugje wereldse elegantie en diversiteit aan hun ruimte willen toevoegen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2010.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38306) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-een-parel-en-zonnebril','Meisje met een Parel en Zonnebril','Dit kunstdoekje is een speelse en moderne draai aan Vermeer''s meesterwerk. Het meisje met de parel draagt nu een stijlvolle zonnebril en kijkt uit over een serene zee. De warme kleuren van haar kleding contrasteren prachtig met de koele blauwe lucht en oceaan, waardoor er een boeiend visueel evenwicht ontstaat. Dit doekje is perfect voor liefhebbers van klassieke kunst met een eigentijdse twist.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2008.webp',(select id from categories where slug='fotografie'),array['fotografie','pop-street-art'],false,true,38318) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pop-art-copy','Pop-art (Copy)','','https://kunstdoekje.nl/wp-content/uploads/2024/08/1784.jpg',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,false,38323) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('grafitti-leeuw','Grafitti Leeuw','Dit kunstdoekje met leeuw is een explosie van kleur en street art. De graffitistijl brengt de koning van de jungle tot leven met een stoere en eigentijdse uitstraling. Perfect voor liefhebbers van urban art, dit doekje brengt levendigheid en creativiteit in elke kamer. De gedurfde kleuren en de rauwe textuur maken het tot een echte blikvanger.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2007.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','pop-street-art'],false,true,38453) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hip-hop-snoopy','Hip-Hop Snoopy','Dit kunstdoekje brengt je favoriete cartoonhond in een hiphop-outfit tot leven. De levendige graffiti-achtergrond en Snoopy''s stoere uitstraling maken dit tot een speelse toevoeging aan elke ruimte. Perfect voor liefhebbers van cartoons en street art, is dit doekje zowel nostalgisch als modern.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2004.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38515) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('innerlijke-rust','Innerlijke Rust','Dit kunstdoekje straalt een serene elegantie uit. Met zachte aardetinten en levendige oranje bloemen omringt deze vrouw zichzelf met natuurlijke schoonheid. Haar gesloten ogen en ontspannen gelaatstrekken roepen een gevoel van rust en harmonie op. Perfect voor een sfeervolle en uitnodigende ruimte die rust en stijl uitstraalt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1996.webp',(select id from categories where slug='asbtract'),array['asbtract','bloemen'],false,true,38551) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tijger-met-ijsje','Tijger met Ijsje','Dit kleurrijke kunstdoekje toont een tijger die geniet van een kleurrijk ijsje. Met levendige kleuren en speelse details brengt het een vrolijke sfeer in elke ruimte. Perfect voor liefhebbers van dieren en speelse kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1994.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','pop-street-art'],false,true,38565) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('marilyn-monroe','Marilyn Monroe','Dit kunstdoekje brengt een iconische Hollywood-glamour in je huis met een moderne twist. De combinatie van zwart-wit beelden en levendige graffiti geeft je interieur een gedurfde en eigentijdse uitstraling. Perfect voor degenen die van klassieke elegantie met een stoer randje houden.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1998.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38566) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mona-lisa-graffiti','Mona Lisa Graffiti','Met Mona Lisa Graffiti voeg je een speelse en artistieke touch toe aan je muren. Dit kunstdoekje is een frisse kijk op Da Vinci''s meesterwerk, waarbij klassieke charme wordt gecombineerd met de levendigheid van straatkunst. Ideaal voor wie van gedurfde en stijlvolle accenten in huis houdt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1999.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38567) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('krachtige-beweging','Krachtige Beweging','Voeg een vleugje oceaanmagie toe aan je interieur met Krachtige Beweging. Dit kunstdoekje toont een walvis in volle sprong, met een opvallende roze streep die de energie en elegantie van de zee benadrukt. Het spel van zwart-wit en roze maakt het een subtiele, maar indrukwekkende aanvulling voor elke kamer.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1997.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','pop-street-art'],false,true,38568) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('luipaard-met-ijsje','Luipaard met Ijsje','Dit kunstdoekje laat een jachtluipaard zien met een ijsje in de hand. De levendige achtergrondkleuren en het detail in de jachtluipaard zorgen voor een energieke uitstraling. Een perfecte keuze voor een speelse touch in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1995.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','pop-street-art'],false,true,38569) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stijlvolle-blik','Stijlvolle Blik','Dit kunstdoekje vangt de aandacht met zijn krachtige eenvoud. De zwart-wit compositie wordt doorbroken door een felblauw oog en een opvallende gele eyeliner. De subtiele glans op de lippen en de mysterieuze zwarte strepen over het gezicht voegen een moderne en stijlvolle flair toe. Perfect voor een strak en eigentijds interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1993.webp',(select id from categories where slug='asbtract'),array['asbtract','fotografie','pop-street-art'],false,true,38570) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('afrikaanse-schoonheid-in-etherische-stralen-copy','Afrikaanse Schoonheid in Etherische Stralen (Copy)','Dit kunstdoekje toont een betoverend portret van een Afrikaanse vrouw gehuld in zachte pastelkleuren. De stralende hoepels rond haar hoofd geven een futuristische uitstraling, terwijl de serene zonsondergang een gevoel van rust brengt. De combinatie van lichtroze en oranje tinten met de delicate, etherische kleding creëert een beeld dat zowel elegant als inspirerend is. Dit doekje is perfect voor degenen die kunst willen die zowel modern als tijdloos aanvoelt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2000.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,false,38571) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('romeinse-kracht','Romeinse Kracht','"Romeinse Kracht" combineert klassieke Romeinse elementen met moderne kleuren. De subtiele penseelstreken en levendige kleurvlakken vormen een uniek evenwicht tussen traditie en eigentijdse kunst. Dit kunstdoekje voegt een vleugje geschiedenis toe aan je interieur, terwijl het ook een krachtige en stijlvolle uitstraling biedt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2006.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38572) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('het-ongeziene','Het Ongeziene','"Het Ongeziene" is een gedurfd kunstwerk dat nieuwsgierigheid en spanning oproept. De zwarte, anonieme figuur tegen een levendige oranje achtergrond geeft je interieur een moderne twist. De opvallende oranje tint straalt energie uit en trekt direct de aandacht van je gasten. Perfect voor wie houdt van een minimalistische stijl met een edgy flair.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2002.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38573) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-kleurrijke-ridder','De Kleurrijke Ridder','"De Kleurrijke Ridder" brengt middeleeuwse pracht naar je muur met een explosie van kleur. Het kunstwerk vangt de fantasie met zijn gedetailleerde harnas en spatten van vrolijke tinten. Deze combinatie van traditionele ridderlijke symboliek en moderne kunst maakt dit doek een gespreksonderwerp. Perfect voor een speelse en opvallende toevoeging aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2005.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38574) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('street-peace','Street Peace','Street Peace is een kunstdoekje dat een krachtige boodschap van vrede en positiviteit verspreidt. Het kleurrijke graffiti-ontwerp en het iconische vredesteken voegen een moderne, stedelijke sfeer toe aan je ruimte. Perfect voor iedereen die zijn huis wil vullen met een optimistische en stijlvolle uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2001.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38575) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('delicate-elegance','Delicate Elegance','Een zacht, dromerig tafereel dat de schoonheid van bloeiende rozen en een charmant Frans café samenbrengt. Dit kunstdoekje is een ode aan romantiek en verfijning, ideaal voor je woonkamer of slaapkamer. Het brengt een vleugje klassieke charme en schoonheid in elke ruimte, en maakt van je interieur een romantisch toevluchtsoord.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1987.webp',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,38590) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('morning-bliss','Morning Bliss','Geniet van de rust en de luxe van een rustig ontbijt met een warme kop koffie, geurige croissants, en een boeket verse bloemen. Dit kunstdoekje vangt de essentie van een perfect begin van de dag. Het brengt gezelligheid en warmte in je keuken of eetkamer, perfect voor diegenen die houden van een vleugje Franse elegantie in hun interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1979.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','landschapmodus'],false,true,38591) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dansen-aan-zee','Dansen aan Zee','Beleef de vrijheid van een zomerse strandwandeling met dit kunstdoekje van een meisje in roze laarzen aan de kustlijn. De zachte kleuren en dromerige setting geven je interieur een ontspannen en avontuurlijke uitstraling. Ideaal voor een vleugje zomervakantie, het hele jaar door.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1968-1.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38592) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('graceful-steps','Graceful steps','Laat je betoveren door de sierlijke details van deze elegante balletschoentjes. Dit kunstdoekje roept de schoonheid en kracht van dans op, waardoor het een schitterende toevoeging is aan je woonkamer of kinderkamer. Perfect voor liefhebbers van dans en esthetiek, die op zoek zijn naar een stukje verfijning voor hun huis.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1981.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','pop-street-art'],false,true,38593) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cafe-romantiek','Café Romantiek','Dit kunstdoekje toont een betoverend portret van een Afrikaanse vrouw gehuld in zachte pastelkleuren. De stralende hoepels rond haar hoofd geven een futuristische uitstraling, terwijl de serene zonsondergang een gevoel van rust brengt. De combinatie van lichtroze en oranje tinten met de delicate, etherische kleding creëert een beeld dat zowel elegant als inspirerend is. Dit doekje is perfect voor degenen die kunst willen die zowel modern als tijdloos aanvoelt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1983.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38594) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koi-schoonheid','Koi Schoonheid','Breng de rust van een koi-vijver naar je interieur met dit stijlvolle kunstdoekje. De levendige oranje en witte koi-vissen tegen een gouden achtergrond zorgen voor een elegante en ontspannen sfeer in elke ruimte. Perfect voor je woonkamer of kantoor voor een vleugje natuurpracht.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1887.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,38595) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurenpracht-in-de-tuin','Kleurenpracht in de Tuin','Stap in een kleurrijke oase met dit kunstdoekje van een betoverende tuin vol bloemen en sierlijke bogen. De speelse kleuren en vrolijke sfeer maken elke ruimte levendig en uitnodigend. Een perfecte manier om een saaie muur nieuw leven in te blazen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1970.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38596) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cafe-derna','Café Derna','Ervaar de nostalgie van een Parijse straat met dit kunstdoekje van een charmant, ouderwets café. De warme kleuren en gedetailleerde penseelstreken brengen de sfeer van de Franse hoofdstad direct naar jouw interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1891.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38597) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('palmenparadijs','Palmenparadijs','Breng de relaxte vibes van de tropen naar je woonkamer met dit kunstdoekje van majestueuze palmbomen die dansen onder een pastelkleurige hemel. Ideaal voor wie thuis wil ontsnappen naar een zonovergoten paradijs. Het serene tafereel werkt als een dagelijkse herinnering om even te pauzeren en te genieten van de rust.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1974.webp',(select id from categories where slug='landschapmodus'),array['landschapmodus','natuur'],false,true,38598) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-nostalgie','Roze Nostalgie','Droom weg naar zonnige dagen met dit kunstdoekje van een roze cabriolet op een tropisch strand. De levendige kleuren en retro vibe brengen een vleugje nostalgie en avontuur in je interieur. Perfect voor liefhebbers van vintage stijl en zonovergoten paradijzen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1978.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','landschapmodus'],false,true,38599) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-sereniteit','Roze Sereniteit','Het kunstdoekje "Roze Sereniteit" toont twee schattige huisjes omgeven door een zee van roze bloemen. De subtiele texturen en pastelkleurige tinten creëren een serene en dromerige sfeer. Ideaal voor een rustige hoek in je huis waar je even kunt ontsnappen aan de drukte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1898.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','natuur'],false,true,38796) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amalfi-kust','Amalfi Kust','Laat je meevoeren naar de romantische kust van Amalfi met dit levendige kunstdoekje. De kleurrijke huizen en het blauwe water stralen een serene en idyllische sfeer uit, perfect voor iedere ruimte die een vleugje mediterrane charme kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1894.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','natuur'],false,true,38797) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstract-kleurenpracht','Abstract Kleurenpracht','Voeg een explosie van kleur toe aan je muur met dit abstracte kunstdoekje. De gedurfde penseelstreken en het speelse kleurgebruik maken dit doek een echte blikvanger in elke moderne ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1890.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,38798) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vijgenpracht','Vijgenpracht','De rijke, paarse tinten van de vruchten zijn zo levensecht dat je bijna de zoetheid kunt proeven. De zachte grijze achtergrond zorgt ervoor dat de vijgen echt opvallen, waardoor dit kunstwerk een stijlvolle toevoeging is aan elke keuken of eetkamer. Laat je verbeelding de vrije loop en ervaar een vleugje luxe en elegantie in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1957.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','natuur'],false,true,38799) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tropische-oase','Tropische Oase','Voeg een vleugje tropische flair toe aan je interieur met het kunstdoekje "Tropische Oase". Deze kleurrijke illustratie van een zonnige binnenplaats met weelderige planten en een uitnodigend zitje straalt warmte en levendigheid uit. De levendige kleuren en speelse compositie brengen elke ruimte tot leven.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1896.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','natuur'],false,true,38800) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-pracht','Kleurrijke Pracht','Het kunstdoekje "Kleurrijke Pracht" bestaat uit een abstract patroon van stippen in diverse tinten. De levendige kleuren en speelse vormen maken dit doekje een echte blikvanger in elke kamer. Ideaal voor wie houdt van moderne kunst en een vleugje kleur wil toevoegen aan zijn interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1895.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,38801) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-rustiek','Roze Rustiek','Ervaar de rust en sereniteit van het platteland met dit betoverende kunstdoekje. Twee charmante huisjes rusten vredig tussen velden van zachtroze bloemen, en het geheel straalt een gevoel van nostalgie en eenvoud uit. De pastelkleuren en het dromerige landschap zijn perfect om een gevoel van kalmte en ontspanning in je ruimte te creëren. Hang het op in je slaapkamer of leeshoek en laat de rust je omarmen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1901.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,38802) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('elegantie','Elegantie','Dit kunstdoekje, genaamd "Elegantie", vangt een charmant moment in een weelderige tuin. De dame in haar vintage jurk, met een mand vol kleurrijke bloemen, straalt een tijdloze elegantie uit. De zachte penseelstreken en warme kleuren brengen een gevoel van rust en nostalgie in je interieur. Perfect voor liefhebbers van klassieke schoonheid.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1900.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','landschapmodus'],false,true,38803) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('strandgenot','Strandgenot','Dit kunstdoekje brengt je direct naar een zonnige dag aan zee, vol levendigheid en plezier. De strandstoelen en parasols in felle oranje en roze tinten steken prachtig af tegen het glinsterende turquoise water en de zachte beige strandzand. De dynamiek en beweging op het doek herinneren aan zorgeloze zomerdagen, waardoor het een geweldige keuze is voor elke ruimte die een boost van energie en vrolijkheid kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1953.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38804) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('strandgenot-copy','Strandgenot (Copy)','Dit kunstdoekje brengt je direct naar een zonnige dag aan zee, vol levendigheid en plezier. De strandstoelen en parasols in felle oranje en roze tinten steken prachtig af tegen het glinsterende turquoise water en de zachte beige strandzand. De dynamiek en beweging op het doek herinneren aan zorgeloze zomerdagen, waardoor het een geweldige keuze is voor elke ruimte die een boost van energie en vrolijkheid kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1953.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,false,38817) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('winterse-wijsheid','Winterse Wijsheid','Geniet van de serene schoonheid van de winter met dit kunstdoek. De hoge bomen met hun takken die zich uitstrekken naar de heldere blauwe hemel brengen een gevoel van rust en kalmte in elke ruimte. Perfect voor liefhebbers van natuur en rustgevende kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1888.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','natuur'],false,true,38818) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('explosie-van-emoties','Explosie van Emoties','Een dynamische explosie van kleuren en vormen die de rauwe kracht van emoties vastlegt. Dit kunstdoekje brengt energie en creativiteit in je interieur, perfect voor de gedurfde en expressieve ziel.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1870.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38819) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mysterieus-portret','Mysterieus Portret','Dit krachtige schilderij trekt je aandacht met zijn contrasterende kleuren en mystieke uitstraling. Een vrouwelijk gezicht, gedeeltelijk verborgen achter zwarte verfstreken, kijkt je recht aan, omgeven door een levendige, oranje achtergrond. De combinatie van de donkere en felle tinten creëert een boeiend beeld dat vragen oproept en emoties losmaakt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1883.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','pop-street-art'],false,true,38820) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mediterrane-zomer','Mediterrane Zomer','\n \n \n \n \nLaat je betoveren door de charme van een mediterrane tuin met dit kunstdoek. De zonnige gele citroenboom en het huis in de achtergrond stralen warmte en gastvrijheid uit, ideaal om een zomers gevoel in je huis te brengen, het hele jaar door. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1885.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','natuur'],false,true,38821) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tropisch-paradijs','Tropisch Paradijs','Droom weg naar een tropisch eiland met dit kleurrijke kunstdoek. De felgroene palmbomen en het turquoise water creëren een levendige en ontspannende uitstraling, perfect voor een zomerse touch in je woonkamer of kantoor.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1886.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','natuur'],false,true,38822) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('griekse-droom','Griekse Droom','Stap in een droomwereld met dit kunstdoekje van een charmant Grieks dorpje aan zee. De helderblauwe lucht en het sprankelende water contrasteren prachtig met de witte huisjes en groene bomen. De kronkelende weg, bezaaid met bloemen, nodigt je uit om te dromen van mediterrane zomers.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1881.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38823) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ode-aan-de-zon','Ode aan de Zon','Dit kunstdoekje straalt eenvoud en charme uit met een strohoed die nonchalant aan een deur hangt. De pastelkleuren blauw en roze roepen warme zomerdagen op. De gedetailleerde textuur van de hoed en de zachte schaduwen op de muur geven een vleugje nostalgie.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1882.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,38824) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('huisje-aan-de-klif','Huisje aan de Klif','Ontsnap naar dit dromerige klifhuisje met bloeiende bloemen en een adembenemend uitzicht. Perfect voor een vleugje mediterrane charme in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1873.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','natuur'],false,true,38825) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koi-kompas','Koi Kompas','Breng een vleugje oosterse elegantie in je interieur met dit levendige kunstdoekje. De prachtige koi vissen zwemmen sierlijk tegen een achtergrond van gouden en zwarte tinten, symbool voor geluk en voorspoed. Ideaal voor een zen-achtige sfeer.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1887.webp',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','impressionisme','kleurrijk'],false,true,38826) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('schreeuw-van-verbijstering','Schreeuw van verbijstering','Dit kunstdoekje brengt de dramatiek van oude meesters met een moderne twist. De verbijsterde blik knipoogt naar Rembrandt en Caravaggio, terwijl de krachtige penseelstreken het geheel een eigentijds randje geven. Ideaal voor liefhebbers van klassieke kunst met een gedurfd accent. Voeg een vleugje historie en stijl toe aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1872.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','oude-meesters','rijks'],false,true,38827) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dynamische-abstractie','Dynamische Abstractie','Geniet van de levendigheid en energie van dit abstracte kunstdoekje. De dynamische vormen en levendige kleuren brengen beweging en vreugde in elke kamer, ideaal voor een eigentijdse en creatieve inrichting.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1889.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,38828) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('veld-vol-kleur','Veld vol Kleur','Dit levendige kunstdoekje toont een weelderig veld van kleurrijke bloemen, perfect om elke ruimte op te fleuren. De rijke tinten van rood, oranje en blauw springen van het canvas en brengen een vrolijke sfeer in je huis. Een ideale keuze voor wie houdt van een dynamische en energieke uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1818.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','landschapmodus'],false,true,38841) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemrijk-straatje','Bloemrijk Straatje','Wandel door dit charmante straatje vol bloeiende bloemen en voel de warmte van een zomerse dag. De levendige kleuren van de bloemen contrasteren prachtig met de witte muren van de huizen, wat zorgt voor een vrolijke en uitnodigende sfeer.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1817.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','kleurrijk','landschapmodus'],false,true,38842) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blauwe-daisies','Blauwe Daisies','\n \n \n \n \nGeniet van de serene schoonheid van witte daisies tegen een diepblauwe achtergrond. De eenvoudige maar elegante compositie straalt rust en verfijning uit, waardoor dit kunstdoekje een perfecte aanvulling is voor elke rustige en stijlvolle omgeving. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1819.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','kleurrijk'],false,true,38843) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloeipracht-in-pasteltinten','Bloeipracht in Pasteltinten','Laat je betoveren door dit kleurrijke boeket in zachte pasteltinten. De delicate bloemen tegen een lichtroze en blauwe achtergrond brengen een gevoel van lente en frisheid in elke ruimte. Dit kunstdoekje voegt een vleugje romantiek en levendigheid toe aan je interieur, perfect voor liefhebbers van subtiele maar expressieve kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1820.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','landschapmodus'],false,true,38844) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dubbelleven-in-bloei','Dubbelleven in bloei','Laat je betoveren door de schoonheid van deze delicate bloemen tegen een diepe zwarte achtergrond. De zachte pastelkleuren van de bloemblaadjes contrasteren prachtig met het donkere canvas, waardoor elke bloem nog stralender lijkt. Dit kunstdoekje brengt een vleugje elegantie en rust in elke ruimte, perfect voor wie houdt van een subtiele maar krachtige uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1821.webp',(select id from categories where slug='bloemen'),array['bloemen','fotografie','landschapmodus'],false,true,38845) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomerse-bloemenweelde','Zomerse Bloemenweelde','Dompel jezelf onder in een zee van kleurrijke bloemen met dit schitterende kunstdoekje. De uitbundige kleuren en levendige penseelstreken vangen de essentie van een bloeiende zomertuin, ideaal om elke kamer op te fleuren.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1815.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','kleurrijk','landschapmodus'],false,true,38846) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('romantisch-doorkijkje','Romantisch Doorkijkje','Laat je meevoeren naar een serene mediterrane tuin met het kunstdoekje "Romantisch Doorkijkje". Dit kunstdoekje vangt de schoonheid van een bloemrijke poort die uitkijkt op een adembenemend uitzicht over de zee. De levendige kleuren van de bloemen contrasteren prachtig met de kalme blauwe tinten van het water, waardoor een gevoel van rust en romantiek ontstaat. Perfect voor wie een vleugje vakantiegevoel in huis wil halen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1813.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','landschapmodus'],false,true,38847) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-tederheid','Roze Tederheid','"Roze Tederheid" is een ode aan de delicate schoonheid van bloemen. De grote, gedurfde penseelstreken en de intense roze tinten geven dit kunstdoekje een moderne, abstracte uitstraling. Ideaal voor wie houdt van een combinatie van romantiek en hedendaagse kunst. Dit kunstdoekje voegt een vleugje zachtheid en passie toe aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1810.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','kleurrijk'],false,true,38848) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cactus-bloei','Cactus Bloei','Stap in de warmte van de woestijn met dit kunstdoekje, waar een prachtige cactus in volle bloei staat. De levendige groene tinten van de cactus en de delicate roze bloemen komen tot leven tegen een heldere, zonnige achtergrond. Dit kunstdoekje voegt een vleugje natuur en kleur toe aan elke ruimte, perfect voor liefhebbers van unieke en levendige botanische kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1806.webp',(select id from categories where slug='banksy'),array['banksy','impressionisme','kleurrijk'],false,true,38849) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('van-gogh-s-amandelbloesem','Van Gogh''s Amandelbloesem','Ervaar de tijdloze schoonheid van Vincent van Gogh''s "Amandelbloesem". Dit iconische kunstwerk met delicate witte bloemen tegen een serene blauwe achtergrond straalt rust en elegantie uit, een perfecte toevoeging voor elke kunstliefhebber.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1816.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','kleurrijk','landschapmodus','van-gogh'],false,true,38850) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('subtiele-serenade','Subtiele Serenade','Stap in een wereld van zachte tinten en delicate bloemen met dit betoverende kunstdoekje. De combinatie van lila, blauw en roze zorgt voor een serene uitstraling die perfect is voor elke ruimte die een vleugje rust en schoonheid kan gebruiken. Laat je meevoeren door de elegante lijnen en verfijnde details van deze florale compositie.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1804.webp',(select id from categories where slug='bloemen'),array['bloemen','kleurrijk'],false,true,38851) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenmasker','Bloemenmasker','Duik in een wereld van kleur en emotie met dit kunstdoekje, waar een vrouw met een prachtig bloemenmasker centraal staat. De felrode lippen en de levendige bloemen in tinten van roze, oranje en geel springen uit tegen de donkere achtergrond, terwijl kleurrijke verfspetters een dynamisch effect toevoegen. Dit kunstdoekje is een perfecte keuze voor wie een krachtige, artistieke uitstraling wil toevoegen aan hun interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1765.webp',(select id from categories where slug='bloemen'),array['bloemen','kleurrijk','pop-street-art'],false,true,38852) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mystiek-woestijnlandschap','Mystiek Woestijnlandschap','Laat je meeslepen door de mystiek van de woestijn onder een adembenemende sterrenhemel. De warme aardetinten en subtiele gouden accenten geven dit kunstdoekje een luxe uitstraling. Perfect om een serene en toch krachtige sfeer te creëren in je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2020.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','natuur'],false,true,39011) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-verbinding','Abstracte Verbinding','Dit kunstdoekje vangt de essentie van menselijke connectie in een moderne, abstracte stijl. De zachte, aardse tinten maken het een veelzijdige toevoeging aan elk interieur, terwijl het minimalistische design zorgt voor een tijdloze charme.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2021.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39013) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenmasker-copy-copy','Bloemenmasker (Copy) (Copy)','Duik in een wereld van kleur en emotie met dit kunstdoekje, waar een vrouw met een prachtig bloemenmasker centraal staat. De felrode lippen en de levendige bloemen in tinten van roze, oranje en geel springen uit tegen de donkere achtergrond, terwijl kleurrijke verfspetters een dynamisch effect toevoegen. Dit kunstdoekje is een perfecte keuze voor wie een krachtige, artistieke uitstraling wil toevoegen aan hun interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1765.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,false,39014) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vespa-in-de-wolken','Vespa in de Wolken','Breng een vleugje fantasie in je interieur met dit speelse kunstdoekje. De levendige bloemen op de klassieke Vespa, omgeven door zachte, dromerige wolken, creëren een vrolijke en inspirerende sfeer. Ideaal voor wie op zoek is naar iets unieks en kleurrijks.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2024.webp',(select id from categories where slug='fotografie'),array['fotografie','kleurrijk','moderne-kunst'],false,true,39015) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mystery-in-the-desert','Mystery in the Desert','Laat je meeslepen door de mystiek van de woestijn onder een adembenemende sterrenhemel. De warme aardetinten en subtiele gouden accenten geven dit kunstdoekje een luxe uitstraling. Perfect om een serene en toch krachtige sfeer te creëren in je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2025.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst','natuur'],false,true,39016) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-schaduwman','De Schaduwman','Een mysterieuze verschijning gevangen in zwart-wit, dit kunstdoekje roept vragen op en trekt je aandacht. De donkere, silhouetachtige figuur in een hoed tegen een neutrale achtergrond maakt dit werk zowel stijlvol als intrigerend. Perfect voor wie houdt van een vleugje mysterie in huis.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2027.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39017) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verloren-in-de-woestijn','Verloren in de Woestijn','Dompel jezelf onder in de uitgestrekte leegte van dit indrukwekkende woestijnlandschap. De diep contrasterende kleuren van de lucht en het zand trekken direct de aandacht en geven dit kunstdoekje een dramatische en toch serene uitstraling. Een perfecte keuze voor wie houdt van krachtige beelden.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2022.webp',(select id from categories where slug='fotografie'),array['fotografie','kleurrijk','natuur','specials'],false,true,39018) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('urban-liberty','Urban Liberty','Dit kunstdoekje combineert een vrouwelijk gezicht met overlappende krantenkoppen, wat de complexiteit van stedelijke vrijheid weerspiegelt. De gedurfde mix van street art en klassieke schoonheid maakt dit doek tot een echte blikvanger in elke moderne ruimte. Ideaal voor wie houdt van een combinatie van kracht en verfijning.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2035.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','pop-street-art'],false,true,39019) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomers-panorama','Zomers Panorama','Dit kunstdoekje brengt een vleugje zomer in je interieur, met felle kleuren en een zonnig landschap dat je meteen vrolijk maakt. Een sprankelend stuk dat elke ruimte opfleurt en je herinnert aan zonnige dagen en warme avonden. Stoer en toch speels, perfect voor wie graag opvalt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2031.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst','natuur'],false,true,39020) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwart-wit-expressie','Zwart-Wit Expressie','Dit kunstdoekje brengt het contrast van zwart-wit tot leven met een gedurfde en expressieve compositie. De sensuele lijnvoering benadrukt de rauwe emotie van het moment. Perfect voor een interieur dat een statement wil maken, dit stuk trekt gegarandeerd de aandacht en laat een blijvende indruk achter.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2029.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39021) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gouden-gangsters','De Gouden Gangsters','Deze krachtige compositie met een groep silhouetten in donkere tinten en gouden accenten straalt kracht en charisma uit. Het kunstdoekje brengt een moderne twist op klassieke thema’s, en is ideaal voor wie een statement wil maken in huis. Een echte blikvanger die elke ruimte karakter geeft.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2028.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39022) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsondergang-in-kleur','Zonsondergang in Kleur','Laat je meevoeren door de warme kleuren van deze abstracte zonsondergang. De gelaagde bergtoppen in contrasterende tinten trekken het oog naar de feloranje zon, die de hemel verwarmt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2026.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst','natuur'],false,true,39023) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-reflecties','Kleurrijke Reflecties','Dit kunstdoekje is een explosie van kleur en energie, met abstracte vormen die een moderne, chique uitstraling geven. Ideaal voor een ruimte die wat extra pit kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2032.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39024) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('colorful-face','Colorful Face','Dit kunstdoekje vangt de rauwe emoties van een gezicht met felle, krachtige penseelstreken. De levendige kleuren tegen de kalme achtergrond creëren een intens contrast, dat een verhaal van innerlijke strijd en overwinning vertelt. Perfect voor wie zijn ruimte wil verrijken met een vleugje moderniteit en diepgaande expressie.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2033.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39025) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('space-tears','Space Tears','Dit kunstdoekje vangt een surrealistisch moment van kwetsbaarheid. Een ruimtehelm die tranen van goud huilt, tegen een strakke, witte achtergrond. Het is een moderne ode aan kracht en kwetsbaarheid, perfect voor wie durft op te vallen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2038.webp',(select id from categories where slug='fotografie'),array['fotografie','moderne-kunst'],false,true,39041) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stripes-in-motion','Stripes in Motion','Dit kunstdoekje toont een silhouet in een vloeiende jurk met zwart-witte strepen, die een gevoel van beweging en mysterie oproepen. De eenvoudige, maar krachtige compositie is perfect voor liefhebbers van chique en moderne kunst. Een verfijnde toevoeging die iedere kamer stijlvol maakt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2037.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst','pop-street-art'],false,true,39042) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sereniteit-aan-zee','Sereniteit aan Zee','\n \n \n \n \nDit kunstdoekje brengt je de rust van een zomerse dag aan het strand. Een vrouw in een gestreepte jurk zit aan de waterkant, genietend van de golven en de horizon. Het straalt eenvoud en kalmte uit, ideaal voor een serene sfeer in je interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2039.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39043) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('retro-chic','Retro Chic','Strakke lijnen en gedempte kleuren geven dit portret van een vrouw een tijdloze elegantie. Het minimalistische design en de klassieke uitstraling maken dit kunstwerk ideaal voor elke stijlvolle, moderne ruimte. Een subtiele, maar krachtige toevoeging die moeiteloos charme uitstraalt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2036.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,39047) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stoere-beer','Stoere Beer','Dit kunstdoekje laat de kracht en aanwezigheid van een imposante beer zien, in al zijn glorie. Met zijn intense blik en donkere achtergrond is het een statement stuk dat een vleugje wilde natuur aan je ruimte toevoegt. Ideaal voor liefhebbers van krachtige en robuuste beelden.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1945.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39054) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-toekan','Kleurrijke Toekan','Dit kunstdoekje brengt de tropen in huis met een felgekleurde toekan die de show steelt. De scherpe lijnen en het heldere oranje van de snavel zorgen voor een prachtig contrast. Ideaal voor wie van levendige en speelse kunst houdt.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1786.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39123) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sluipende-uil','Sluipende Uil','\n \n \n \n \nDit mystieke kunstdoekje toont een uil die door de nachtelijke lucht zweeft, gevangen in een moment van stille jacht. De donkere, gedempte kleuren creëren een serene en mysterieuze sfeer. Perfect voor wie houdt van subtiele en sfeervolle kunst. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1787.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39124) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('wijze-olifant','Wijze Olifant','Elke rimpel vertelt een verhaal op dit kunstdoekje van een majestueuze olifant. De close-up onthult de textuur en diepte van een dier dat bekendstaat om zijn wijsheid en kracht. Een indrukwekkend statement voor elke kamer die iets meer inhoud kan gebruiken.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1790.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39125) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rustende-vos','Rustende Vos','Dit kunstdoekje vangt een zeldzaam moment van pure rust in de natuur. Een vos, elegant en op zijn hoede, geniet van een moment van vrede. Deze afbeelding brengt een serene, maar mysterieuze sfeer in elke ruimte, perfect voor liefhebbers van de stille kracht van de natuur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1789.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39126) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('indringende-blik','Indringende Blik','Dit kunstdoekje laat de kracht en aanwezigheid van een imposante beer zien, in al zijn glorie. Met zijn intense blik en donkere achtergrond is het een statement stuk dat een vleugje wilde natuur aan je ruimte toevoegt. Ideaal voor liefhebbers van krachtige en robuuste beelden.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1791.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39127) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwart-wit-neushoorn','Zwart-Wit Neushoorn','Dit indrukwekkende kunstdoekje van een neushoorn straalt kracht en elegantie uit. Het gedetailleerde zwart-wit contrast accentueert de robuuste hoorn en de zachte textuur van de huid, waardoor het een tijdloos en krachtig beeld vormt voor iedere ruimte.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1792.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39128) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vlucht-bij-maanlicht','Vlucht bij Maanlicht','Dit betoverende kunstdoekje toont een grote Arend die boven een kalme zee vliegt met de volle maan als achtergrond. Het serene water weerspiegelt de mystieke sfeer van de scène, waardoor het een intrigerend en bijna spiritueel kunstdoekje is. Perfect voor een minimalistisch of modern interieur dat een diepere, betekenisvolle touch verdient.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1794.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39129) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tweelingzebra-s','Tweelingzebra''s','Stap in de wereld van contrast en harmonie met dit kunstdoekje van twee zebra’s, zij aan zij, als een perfect uitgelijnd duo. De zwart-witte strepen creëren een visueel spektakel dat zowel stoer als stijlvol is. Ideaal voor een interieur dat vraagt om een vleugje wilde elegantie.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1788.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39130) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rotsige-hoogtes','Rotsige Hoogtes','"Rotsige Hoogtes" vangt de mystieke sfeer van een zonsopgang boven de ruige bergen. Dit kunstdoekje, met zijn zachte kleuren en dramatische diepte, roept een gevoel van rust en avontuur op, ideaal voor wie een vleugje natuurlijke wonderen aan zijn interieur wil toevoegen. Een prachtig stuk voor aan de muur dat elke ruimte verandert in een serene oase.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1941.webp',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus','natuur'],false,true,39131) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('riviermeander','Riviermeander','Het kunstdoekje "Riviermeander" biedt een indrukwekkend uitzicht op een van de mooiste bochten in een rivier, omgeven door imposante kliffen die getuigen van eeuwenoude krachten. De serene en tijdloze schoonheid van dit doekje brengt een stukje van de wereldberoemde Horseshoe Bend naar jouw interieur, een eyecatcher die elke ruimte meteen een natuurlijke allure geeft.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1940.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39132) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('galop-in-het-donker','Galop in het Donker','Dit kunstdoekje van een galopperend paard op een donkere achtergrond is de belichaming van kracht en gratie. Het spel van licht en schaduw benadrukt de spieren en de beweging van het paard, wat zorgt voor een dynamisch en energiek beeld. Een statement piece dat iedere ruimte verheft met zijn ongeëvenaarde elegantie.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1795.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39133) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurenpracht','Kleurenpracht','Een explosie van kleuren gevangen in een adembenemend kunstdoekje. Dit beeld van een geothermische bron betovert je met zijn levendige tinten van turquoise, oranje en geel, die samen een natuurwonder creëren dat je muur tot leven zal brengen. Dit doekje is een must-have voor elke natuurliefhebber met een voorliefde voor felle kleuren.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1939.webp',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus','natuur'],false,true,39134) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('woestijnkoning','Woestijnkoning','Dit kunstdoekje brengt je direct naar de uitgestrekte zandvlaktes waar de majestueuze kameel de horizon domineert. Met een lucht die bijna surrealistisch blauw is, straalt dit doek avontuur en sereniteit uit. Perfect voor wie houdt van verre reizen en de rust van de woestijn in huis wil halen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1796.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39135) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('levendige-pauw','Levendige Pauw','Laat je betoveren door dit levendige kunstdoekje waarop een pauw zijn prachtige veren in volle glorie toont. De rijke kleuren en het gedetailleerde patroon maken dit doekje een echte blikvanger. Voeg een vleugje exotische flair toe aan je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1785.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39136) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('eindeloze-weg','Eindeloze Weg','Een uitgestrekte weg die zich een weg baant door een dor landschap, vergezeld door imposante bergen in de verte. Het perspectief van dit kunstdoekje roept een gevoel van avontuur en eindeloze mogelijkheden op. Een must-have voor degenen die altijd op zoek zijn naar de volgende reis.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1942.webp',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus','natuur'],false,true,39153) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mystieke-ochtend','Mystieke Ochtend','Beeld jezelf in, omgeven door de serene stilte van de natuur bij zonsopgang. Een kleine eilandengroep weerspiegelt perfect in het kristalheldere water, omhuld door een zachte, paarse gloed. Dit kunstdoekje straalt rust en harmonie uit, ideaal voor een ruimte waar je tot jezelf wilt komen.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1944.webp',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus','natuur'],false,true,39154) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('woeste-golf','Woeste Golf','Een adembenemende opname van een woeste golf middenin zijn krachtige beweging. Het diepblauwe water spat alle kanten op, vol energie en onstuimigheid. Dit kunstdoekje brengt de kracht van de natuur rechtstreeks je interieur binnen, perfect voor wie houdt van dynamiek en het onvoorspelbare karakter van de oceaan.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1943.webp',(select id from categories where slug='fotografie'),array['fotografie','landschapmodus','natuur'],false,true,39155) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijk-heuvellandschap','Kleurrijk Heuvellandschap','\n \n \n \n \nDit kunstdoekje neemt je mee naar een speels, abstract landschap waar glooiende heuvels en bomen in vrolijke kleuren samenkomen. Een vrolijk tafereel dat elke ruimte opvrolijkt met zijn levendige tinten en fantasierijke stijl. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1917.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk','natuur'],false,true,39160) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vruchtenfestijn','Vruchtenfestijn','\n \n \n \n \nEen kunstdoekje vol energie, waar een mand vol kleurrijk fruit tegen een roze achtergrond pronkt. Deze compositie, met zijn levendige weergave van tropisch fruit, brengt een gevoel van frisheid en vitaliteit in elke kamer. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1921.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk'],false,true,39207) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijk-heuvellandschap-copy','Kleurrijk Heuvellandschap (Copy)','\n \n \n \n \nDit kunstdoekje neemt je mee naar een speels, abstract landschap waar glooiende heuvels en bomen in vrolijke kleuren samenkomen. Een vrolijk tafereel dat elke ruimte opvrolijkt met zijn levendige tinten en fantasierijke stijl. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1917.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk','natuur'],false,false,39208) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenportret','Bloemenportret','\n \n \n \n \nDit kunstdoekje combineert de eenvoud van grafische kunst met de schoonheid van de natuur. Een vrouwelijk silhouet omringd door kleurrijke bloemen, dit werk straalt elegantie en rust uit, ideaal voor een serene sfeer in huis. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1920.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk'],false,true,39209) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mediterrane-binnenplaats','Mediterrane Binnenplaats','Een kunstdoekje dat een zonnige, mediterrane binnenplaats vastlegt met sierlijke planten en zachte pastelkleuren. Dit doekje brengt de warme en uitnodigende sfeer van een zonnige oase naar je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/08/1918.webp',(select id from categories where slug='bloemen'),array['bloemen','illustratie','kleurrijk'],false,true,39210) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kattenspel','Kattenspel','\n \n \n \n \nLaat je betoveren door de geometrische charme van "Kattenspel". Dit kunstdoekje, geïnspireerd door Mondriaan, combineert strakke lijnen met speelse kattenfiguren in primaire kleuren. Een echte blikvanger voor iedere kamer. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1922.webp',(select id from categories where slug='asbtract'),array['asbtract','illustratie','kleurrijk'],false,true,39211) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsondergang-surfer','Zonsondergang Surfer','\n \n \n \n \nErvaar de kalmte van een eenzame surfer bij zonsondergang met "Zonsondergang Surfer". Dit kunstdoekje straalt een serene rust uit, perfect om een ontspannen sfeer te creëren in je ruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1925.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','natuur'],false,true,39212) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verlaten-paden','Verlaten Paden','\n \n \n \n \n"Verlaten Paden" neemt je mee op een reis naar het onbekende, waar een eenzame wandelaar door een mysterieus, donker ravijn trekt. De krachtige kleuren en dramatische compositie maken dit kunstdoekje een echte eyecatcher. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1924.webp',(select id from categories where slug='illustratie'),array['illustratie','natuur'],false,true,39213) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomerse-heuvels','Zomerse Heuvels','\n \n \n \n \nDompel je onder in het warme, serene landschap van "Zomerse Heuvels". Dit kunstdoekje vangt de zonovergoten glooiende velden, perfect voor wie houdt van rust en natuur in huis. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1923.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk','natuur'],false,true,39214) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('car-en-flowers','Car & Flowers','\n \n \n \n \nDit kunstdoekje combineert de elegantie van een klassieke auto met de levendigheid van een bloemenveld, waardoor een surrealistisch en dromerig tafereel ontstaat. De glanzende carrosserie van de auto contrasteert prachtig met de weelderige, kleurrijke bloemen die hem omringen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1931.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','landschapmodus'],false,true,39215) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('geestige-bruid','Geestige Bruid','\n \n \n \n \nEen gedurfde en intrigerende compositie van een figuur gehuld in een wit laken, met een boeket kleurrijke bloemen tegen een abstracte achtergrond vol spatten en levendige tinten. Dit kunstdoekje combineert mysterie met een vleugje humor en nodigt uit tot interpretatie en verbeelding. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1926.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk'],false,true,39216) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('margarita','Margarita','\n \n \n \n \nEen verfrissend kunstdoekje dat perfect de essentie van een zomerse cocktail vastlegt. Het heldere glas met een groene margarita, gedrapeerd tegen een roze achtergrond, straalt elegantie en eenvoud uit. Ideaal om elke ruimte een sprankje kleur en een vleugje zomer te geven. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1927.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk'],false,true,39217) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('citroenen-op-doek','Citroenen op doek','\n \n \n \n \nEen uitnodigend en levendig kunstdoekje van een schaal vol sappige citroenen, omlijst door dikke penseelstreken en levendige kleuren. De contrasten van geel, groen en roze zorgen voor een frisse en moderne uitstraling, perfect voor keukens en eetkamers. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1928.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk','natuur'],false,true,39218) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('theepot-fantasie','Theepot Fantasie','\n \n \n \n \nIn deze surrealistische compositie ligt een vrouw ontspannen in een oversized roze theekopje, omringd door een bloeiende bloemenzee. Een perfecte weergave van een fantasiewereld die de grenzen van de werkelijkheid tart. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1862.webp',(select id from categories where slug='collage'),array['collage'],false,true,39234) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mysterieuze-reis','Mysterieuze Reis','\n \n \n \n \nDeze mysterieuze setting daagt je uit om na te denken over wat echt is en wat slechts een fragment van je verbeelding is. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1859.webp',(select id from categories where slug='collage'),array['collage'],false,true,39272) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('klimmen-naar-verbeelding','Klimmen naar Verbeelding','\n \n \n \n \nTwee klimmers bereiden zich voor om de onbekende diepten van een gigantische, roodgelakte lippenstiftmond te verkennen, zwevend boven een bevroren, buitenaardse omgeving. Een intrigerend spel van schaal en realiteit. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1861.webp',(select id from categories where slug='collage'),array['collage'],false,true,39273) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('klimmen-naar-verbeelding-2','Klimmen naar Verbeelding 2','\n \n \n \n \nTwee klimmers bereiden zich voor om de onbekende diepten van een gigantische, roodgelakte lippenstiftmond te verkennen, zwevend boven een bevroren, buitenaardse omgeving. Een intrigerend spel van schaal en realiteit. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1858.webp',(select id from categories where slug='collage'),array['collage'],false,true,39279) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zeilend-naar-de-zonsondergang','Zeilend naar de Zonsondergang','\n \n \n \n \nTwee zeilboten glijden moeiteloos over een spiegelgladde zee, op weg naar de ondergaande zon. Dit kunstdoekje is doordrenkt met warme tinten en dikke penseelstreken, waardoor het de dynamiek en schoonheid van een zeiltocht in de avondschemering perfect weergeeft. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1825.webp',(select id from categories where slug='boten'),array['boten','impressionisme'],false,true,39328) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stille-haven-copy','Stille Haven (Copy)','\n \n \n \n \nDeze prachtige schildering vangt de serene rust van een kleine haven op een zonnige ochtend. De boten dobberen kalm in het water, omgeven door oude gebouwen die verhalen uit het verleden vertellen. Het zachte licht en de rustige reflecties in het water brengen een gevoel van vrede en eenvoud. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1822.webp',(select id from categories where slug='boten'),array['boten','impressionisme'],false,false,39332) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stille-haven-copy-39333','Stille Haven (Copy)','\n \n \n \n \nDeze prachtige schildering vangt de serene rust van een kleine haven op een zonnige ochtend. De boten dobberen kalm in het water, omgeven door oude gebouwen die verhalen uit het verleden vertellen. Het zachte licht en de rustige reflecties in het water brengen een gevoel van vrede en eenvoud. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1822.webp',(select id from categories where slug='boten'),array['boten','impressionisme'],false,false,39333) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zeilen-op-de-golven','Zeilen op de Golven','\n \n \n \n \nDit kunstdoekje toont twee zeilboten die samen over de ruwe blauwe zee varen. De spatwaterdruppels en de wind in de zeilen zijn bijna voelbaar, en de diepte van het blauw maakt dit een dynamische en energieke compositie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1828.webp',(select id from categories where slug='boten'),array['boten','impressionisme','landschapmodus'],false,true,39334) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rustige-boten-in-de-ochtendmist','Rustige boten in de ochtendmist','\n \n \n \n \nEen prachtig kunstdoekje dat een serene haven in de vroege ochtend laat zien, met meerdere boten die zachtjes op het water drijven. De subtiele pastelkleuren en de zachte reflecties in het water brengen een gevoel van rust en stilte over. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1831.webp',(select id from categories where slug='boten'),array['boten','impressionisme','landschapmodus'],false,true,39335) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('boten-in-kleurrijk-avondlicht','Boten in kleurrijk avondlicht','\n \n \n \n \nDit kunstdoekje vangt de levendige kleuren van boten die drijven op een rustige zee tijdens de schemering. Het heldere blauw van het water en de oranje en gele tinten van de boten en lucht creëren een energiek en opgewekt beeld, vol contrast en warmte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1833.webp',(select id from categories where slug='boten'),array['boten','impressionisme','landschapmodus'],false,true,39336) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-zeilboten-bij-zonsopgang','Kleurrijke zeilboten bij zonsopgang','\n \n \n \n \nDit levendige kunstdoekje toont een groep zeilboten die voor anker liggen in het stille water, met een spectaculaire zonsopgang op de achtergrond. De felle kleuren van de lucht weerspiegelen op het wateroppervlak en geven het tafereel een dromerige sfeer. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1832.webp',(select id from categories where slug='boten'),array['boten','impressionisme','landschapmodus'],false,true,39337) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ondergaande-zon-over-de-rivier','Ondergaande Zon over de Rivier','\n \n \n \n \nEen schitterend kunstdoekje van een eenzame boot die op een rustige rivier drijft tijdens een adembenemende zonsondergang. De warme oranje en paarse tinten weerspiegelen in het water en vullen de lucht, wat een gevoel van verwondering oproept. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1829.webp',(select id from categories where slug='boten'),array['boten','fotografie','landschapmodus'],false,true,39338) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roeiboot-op-het-strand','Roeiboot op het Strand','\n \n \n \n \nEen prachtig kunstdoekje dat de sereniteit van een rustende roeiboot vastlegt, aangespoeld aan de oever van een kalm meer, omgeven door gouden rietstengels. De zachte kleuren van de lucht en het water creëren een gevoel van vrede en rust. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1827.webp',(select id from categories where slug='boten'),array['boten','impressionisme','landschapmodus'],false,true,39339) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stille-boot-op-het-meer','Stille Boot op het Meer','\n \n \n \n \nDit minimalistische kunstdoekje vangt de kalmte van een eenzame boot die stil op een spiegelglad meer drijft. De subtiele kleurschakeringen in de lucht en het water versterken het gevoel van eenzaamheid en contemplatie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1830.webp',(select id from categories where slug='boten'),array['boten','fotografie'],false,true,39340) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stille-haven','Stille Haven','\n \n \n \n \nDit prachtige kunstdoekje vangt de serene rust van een kleine haven op een zonnige ochtend. De boten dobberen kalm in het water, omgeven door oude gebouwen die verhalen uit het verleden vertellen. Het zachte licht en de rustige reflecties in het water brengen een gevoel van vrede en eenvoud. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1822.webp',(select id from categories where slug='boten'),array['boten','impressionisme'],false,true,39341) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-kustlijn','Kleurrijke Kustlijn','\n \n \n \n \nEen levendig en expressief kunstdoekje waarin de boten in de haven tot leven komen door het spel van licht en kleur. De abstracte stijl en felle kleuren zorgen voor een dynamische compositie die de energie en het leven langs de kust perfect vastlegt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1826.webp',(select id from categories where slug='boten'),array['boten','impressionisme'],false,true,39342) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mediterrane-droom','Mediterrane Droom','\n \n \n \n \nDit kunstdoekje straalt de ontspannen sfeer van een mediterrane kustlijn uit, met een enkele boot die vredig op het kristalheldere water dobbert. De levendige kleuren van de huizen en de schittering van het water roepen een gevoel van vakantie en vrijheid op. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1823.webp',(select id from categories where slug='boten'),array['boten','impressionisme'],false,true,39343) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zeilboot-in-een-serene-zonsondergang','Zeilboot in een serene Zonsondergang','\n \n \n \n \nDit adembenemende kunstdoekje toont een eenzame zeilboot die rustig op het water drijft tijdens een prachtige zonsondergang. De warme gouden en oranje tinten van de ondergaande zon reflecteren op het kalme water, terwijl de zachte blauwe en paarse kleuren van de lucht een serene sfeer creëren. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/1835.webp',(select id from categories where slug='boten'),array['boten','impressionisme','landschapmodus'],false,true,39357) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pink-astronaut','Pink Astronaut','\n \n \n \n \nEen kleurrijk kunstdoekje van een astronaut, gekleed in een gedetailleerd pak met pastelkleuren, staand in een uitgestrekt veld onder een blauwe hemel. De combinatie van futuristische technologie met de natuurlijke omgeving schept een fascinerend contrast tussen de kosmos en de aarde. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2012.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,true,39361) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gigantische-maan','De Gigantische Maan','\n \n \n \n \nDit kunstdoekje vangt een surrealistisch tafereel waarin een immense maan boven een ruige kustlijn hangt. Het beeld combineert elementen van sci-fi en natuur, waardoor een gevoel van verwondering en ontzag wordt opgeroepen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2015.webp',(select id from categories where slug='fotografie'),array['fotografie','kleurrijk','space'],false,true,39386) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('astronaut-en-de-maan','Astronaut en de Maan','\n \n \n \n \nEen dramatisch kunstdoekje met een astronaut die lijkt op te stijgen in een vurige oranje gloed, met de volle maan op de achtergrond. De intense kleuren en de symboliek van de maan creëren een krachtig beeld van exploratie en doorzettingsvermogen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2014.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,true,39387) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
