insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('eenzame-astronaut-in-de-woestijn','Eenzame Astronaut in de Woestijn','\n \n \n \n \nDit kunstdoekje toont een eenzame astronaut, gekleed in een helder oranje pak, die door een uitgestrekte woestijn wandelt. De reflectie op de gladde ondergrond en de blauwe lucht dragen bij aan het gevoel van isolatie en avontuur in een onbekende wereld. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2013.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,true,39389) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pink-astronaut-copy-39390','Pink Astronaut (Copy)','\n \n \n \n \nEen kleurrijk kunstdoekje van een astronaut, gekleed in een gedetailleerd pak met pastelkleuren, staand in een uitgestrekt veld onder een blauwe hemel. De combinatie van futuristische technologie met de natuurlijke omgeving schept een fascinerend contrast tussen de kosmos en de aarde. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2012.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,false,39390) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('astronaut-in-een-veld-van-madeliefjes','Astronaut in een Veld van Madeliefjes','\n \n \n \n \nEen opvallend kunstdoekje van een astronaut, gehuld in een oranje ruimtepak, zittend in een veld vol bloeiende madeliefjes. De warme, gouden tinten van de bloemen en de avondzon vullen het beeld met een serene, bijna magische atmosfeer, waarin natuur en technologie op harmonieuze wijze samenkomen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2017.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,true,39394) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('astronaut-en-de-gouden-maan','Astronaut en de Gouden Maan','\n \n \n \n \nEen kleurrijk kunstdoekje van een astronaut, gekleed in een gedetailleerd pak met pastelkleuren, staand in een uitgestrekt veld onder een blauwe hemel. De combinatie van futuristische technologie met de natuurlijke omgeving schept een fascinerend contrast tussen de kosmos en de aarde. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2018.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,true,39395) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('astronaut-op-het-strand','Astronaut op het Strand','\n \n \n \n \nDit intrigerende kunstdoekje toont een astronaut die in volledige ruimte-uitrusting over een verlaten strand wandelt. De combinatie van het strandlandschap en de ruimtevaartuitrusting creëert een fascinerend contrast, terwijl de lichte, bewolkte hemel en de zachte, donkere schaduwen een sfeer van kalmte en mysterie oproepen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2016.webp',(select id from categories where slug='fotografie'),array['fotografie','space'],false,true,39396) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koning-van-de-savanne','Koning van de Savanne','\n \n \n \n Een prachtige leeuw loopt trots door het hoge gras van de savanne in dit kunstdoekje. De krachtige expressie en de gedetailleerde weergave van de leeuw vangen de essentie van zijn koninklijke aanwezigheid. De zachte aardetinten en subtiele penseelstreken benadrukken de natuurlijke schoonheid en kracht van dit imposante dier. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2158.webp',(select id from categories where slug='dieren'),array['dieren','natuur'],false,true,39424) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-elegantie','Abstracte Elegantie','\n \n \n \n Dit kunstdoekje toont een modern, abstract ontwerp met rijke groene en marmeren accenten. De geometrische vormen en goudkleurige lijnen geven het kunstwerk een luxe uitstraling. Ideaal voor een minimalistisch of eigentijds interieur, waar het subtiele maar toch opvallende accenten kan toevoegen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2160.webp',(select id from categories where slug='fotografie'),array['fotografie','moderne-kunst'],false,true,39817) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('citrus-vruchtenschoon','Citrus Vruchtenschoon','\n \n \n \n Een eenvoudig maar elegant kunstdoekje met twee rijpe sinaasappels die aan een tak hangen. De delicate penseelstreken en zachte kleuren creëren een rustgevende sfeer, perfect om een keuken of eetkamer op te fleuren. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2163.webp',(select id from categories where slug='illustratie'),array['illustratie','natuur'],false,true,39818) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
