insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dromerige-witte-huizen','Dromerige Witte Huizen','\n \n \n \n Een krachtig kunstdoekje van een sierlijke jachtluipaard die statig op de uitkijk staat. De contrasterende kleuren groen en roze geven dit werk een moderne en dynamische uitstraling, terwijl de elegante lijnen en stippen van het luipaard een gevoel van snelheid en kracht uitstralen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2156.webp',(select id from categories where slug='impressionisme'),array['impressionisme'],false,true,39820) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-jachtluipaard','Kleurrijke Jachtluipaard','\n \n \n \n Een krachtig kunstdoekje van een sierlijke jachtluipaard die statig op de uitkijk staat. De contrasterende kleuren groen en roze geven dit werk een moderne en dynamische uitstraling, terwijl de elegante lijnen en stippen van het luipaard een gevoel van snelheid en kracht uitstralen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2155.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','illustratie','kleurrijk','natuur'],false,true,39821) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('pop-art-bulldog','Pop-Art Bulldog','\n \n \n \n Dit levendige kunstdoekje portretteert een Franse Bulldog in een kleurrijke pop-art stijl. De felle, verzadigde kleuren en gedurfde lijnen geven deze stoere hond een speelse en eigentijdse uitstraling, perfect voor iedereen die van moderne kunst en huisdieren houdt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2154.webp',(select id from categories where slug='dieren'),array['dieren','pop-street-art'],false,true,39822) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rustieke-koffie','Rustieke Koffie','\n \n \n \n Dit kunstdoekje vangt de eenvoudige schoonheid van een rustieke koffiesetting. Een klassieke percolator, een kopje koffie, en een suikerpot staan op een wit tafelkleed, gehuld in warme, uitnodigende tinten. De impressionistische stijl geeft het geheel een tijdloze sfeer, perfect voor een rustige ochtend of een knusse hoek in huis. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2159.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,39823) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('intense-embrace','Intense Embrace','\n \n \n \n Dit kunstdoekje toont een abstracte omhelzing tussen twee figuren, omhuld door krachtige oranje en blauwe tinten. De dramatische penseelstreken en het gebruik van levendige kleuren creëren een intense en emotionele compositie die de kijker uitnodigt om na te denken over liefde, verbondenheid en menselijke relaties. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2153.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39824) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloemenpracht-in-lijnen','Bloemenpracht in Lijnen','\n \n \n \n Een verfijnd kunstdoekje met abstracte bloemen in rijke kleuren van groen, blauw en bruin, omringd door subtiele lijnen. De delicate details en het spel van kleuren maken dit werk een elegante keuze voor elke ruimte. Een perfecte balans tussen modern en organisch design. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2145.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39826) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
