insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-chaos','Kleurrijke Chaos','\n \n \n \n Dit levendige kunstdoekje toont een abstracte weergave van een figuur wiens hoofd lijkt te exploderen in een wirwar van kleurrijke penseelstreken. De felle kleuren, zoals rood, geel en blauw, brengen energie en beweging in elke ruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2152.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39835) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('colorful-cocktail','Colorful Cocktail','\n \n \n \n Dit kunstdoekje vangt de essentie van elegantie en plezier in één beeld: een martini met olijven, omlijst door een explosie van levendige rood- en rozetinten. De dynamische penseelstreken geven het werk een energieke, bijna feestelijke sfeer. Een speelse touch voor elk interieur dat wel wat kleur kan gebruiken. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2146.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,39836) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-horizon','Gouden Horizon','\n \n \n \n Een elegant kunstdoekje dat de contouren van een vrouwelijk profiel combineert met een gouden zonsondergang. De donkere marmeren textuur vormt een prachtig contrast met de stralende goudtinten, wat een gevoel van luxe en tijdloosheid oproept. Een schitterende keuze voor wie houdt van verfijnde en stijlvolle kunst. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2150.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst','natuur'],false,true,39837) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('nachtelijke-bergen','Nachtelijke Bergen','\n \n \n \n it kunstdoekje toont een indrukwekkend berglandschap met strakke lijnen en een mix van aardse kleuren, zoals diep bruin, goud en steenrood. Het contrast tussen de donkere, sterrenhemel en de glinsterende bergtoppen geeft een gevoel van sereniteit en mystiek. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2149.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst','natuur'],false,true,39838) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('speelse-geometrie','Speelse Geometrie','\n \n \n \n Dit kunstdoekje combineert speelse rode en blauwe lijnen die een levendig geometrisch patroon vormen. De eenvoudige, maar dynamische vormen geven een moderne en minimalistische uitstraling, perfect voor een eigentijdse inrichting. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2141.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39845) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-schaduw','Abstracte Schaduw','\n \n \n \n Een krachtig zwart-wit kunstwerk waarin abstracte vormen een intrigerend spel van schaduw en licht creëren. Het contrast tussen de zwarte vormen en de lege ruimte roept een gevoel van mysterie en diepte op. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2137.webp',(select id from categories where slug='asbtract'),array['asbtract'],false,true,39846) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('maanlandschap-in-goud','Maanlandschap in Goud','\n \n \n \n Een betoverend kunstdoekje dat een magisch landschap toont, met gouden accenten die de maan en zonnestralen benadrukken. De combinatie van donkere nachttinten met marmerachtige structuren geeft dit werk een mystieke uitstraling. Ideaal voor een sfeervolle en stijlvolle ambiance. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2148.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39847) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-droom','Kleurrijke Droom','\n \n \n \n Een vrolijke en levendige weergave van een fantasierijk landschap vol felle kleuren. De abstracte vormen en gedurfde kleurkeuzes nodigen je uit om weg te dromen naar een wereld vol mogelijkheden en vreugde. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2138.webp',(select id from categories where slug='asbtract'),array['asbtract','illustratie','kleurrijk'],false,true,39848) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomer-herinnering','Zomer Herinnering','\n \n \n \n Een eenvoudig en warm ontwerp van een meisje met een zonnebloem. De zachte kleuren en de speelse illustratieve stijl brengen je meteen in gedachten terug naar de zonnige dagen van de zomer. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2140.webp',(select id from categories where slug='asbtract'),array['asbtract','illustratie','kleurrijk'],false,true,39849) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-kat-39850','Kleurrijke Kat','\n \n \n \n Dit kunstdoekje vangt de aandacht met een explosie van kleuren die een kattengezicht tot leven brengen tegen een diepe, zwarte achtergrond. De levendige penseelstreken in rood, blauw, geel en groen vormen een fascinerend portret vol energie en mysterie. Perfect voor wie van opvallende en speelse kunst houdt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2122.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','kleurrijk'],false,true,39850) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('botanical-elegance','Botanical Elegance','\n \n \n \n Dit kunstdoekje laat bloemen in hun meest elegante vorm zien, met rijke kleuren zoals diepblauw, wijnrood en goud die prachtig contrasteren tegen de subtiele achtergrond. De fijne, delicate lijnen geven de bloemen een bijna driedimensionaal effect, waardoor ze echt tot leven komen. Ideaal voor een chique, natuurlijke sfeer in huis. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2143.webp',(select id from categories where slug='asbtract'),array['asbtract','bloemen','moderne-kunst'],false,true,39851) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-expressie','Abstracte Expressie','\n \n \n \n Een dynamisch en chaotisch samenspel van kleuren en lijnen komt tot leven op dit kunstdoekje. Met felle tinten roze, blauw en geel, die doorbroken worden door zwarte en witte lijnen, creëert dit werk een levendige sfeer vol beweging en energie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2119.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,39852) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vrouwelijke-blik','Vrouwelijke Blik','\n \n \n \n Dit portret in abstracte stijl vangt de intensiteit van een vrouwelijk gezicht met gedurfde kleuren en scherpe lijnen. De combinatie van warme gele en rode tinten met zachte penseelstreken creëert een intrigerend contrast. Een krachtige toevoeging aan elk modern interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2147.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39853) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mandril-aapje','Mandril Aapje','\n \n \n \n De ogen van de mandril stralen pure kracht uit, gevangen in een betoverend palet van blauwe, gouden en oranje tinten. De artistieke interpretatie legt elk detail van zijn fascinerende gezicht vast, waardoor het lijkt alsof de mandril elk moment tot leven kan komen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2131.webp',(select id from categories where slug='dieren'),array['dieren','landschapmodus','natuur'],false,true,39866) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('basketbal-duck','Basketbal Duck','\n \n \n \n Een iconische eend met een streetwise uitstraling komt tot leven op dit kunstdoekje. Gekleed in stoere kleding, met een basketbal in zijn hand, brengt deze eend een unieke mix van humor en urban stijl. De donkere achtergrond en gedetailleerde afwerking maken dit doekje perfect voor wie een speelse, maar krachtige uitstraling zoekt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2121.webp',(select id from categories where slug='pop-street-art'),array['pop-street-art'],false,true,39867) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zebra-in-de-wildernis','Zebra in de wildernis','\n \n \n \n In "Zebra in de wildernis" komt de unieke schoonheid van de natuur naar voren. De zebra, met zijn kenmerkende zwart-witte strepen, staat in scherp contrast met de zachte, dromerige achtergrond van blauw- en roodtinten. De abstracte interpretatie van dit majestueuze dier maakt dit kunstdoekje een opvallend en intrigerend stuk dat zowel rust als dynamiek uitstraalt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2114.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','landschapmodus','natuur'],false,true,39868) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gele-parasol','De Gele Parasol','\n \n \n \n Een enkel moment van rust op een verlaten strand. De gele parasol staat stoer in het zand, beschermd tegen de zon, terwijl de pastelkleurige omgeving een gevoel van zomer en sereniteit oproept. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2116.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst','natuur'],false,true,39869) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-bossen','Kleurrijke Bossen','\n \n \n \n In "Kleurrijke bossen" wordt je ondergedompeld in een levendige, dromerige wereld waar kleuren de toon zetten. De bomen lijken bijna te dansen in een oceaan van turquoise, diepblauw en pastelkleuren. De bloemen op de voorgrond stralen in felle tinten, wat het geheel een sprookjesachtige uitstraling geeft. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2111.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,39870) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonsondergang-in-het-bloemenlandschap','Zonsondergang in het Bloemenlandschap','\n \n \n \n Dit kunstdoekje, "Zonsondergang in het bloemenlandschap," vangt de magie van een rustige avond in de natuur. De zon, vol warmte en energie, dompelt de hemel en aarde in gouden tinten. De bloeiende boom, vol roze en oranje bloemen, staat trots te midden van het glooiende landschap. Een rustig stromende rivier leidt je blik naar een eenzaam huisje, wat dit kunstdoekje een serene en nostalgische sfeer geeft. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2112.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','natuur'],false,true,39871) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ridderslag-in-kleur','Ridderslag in Kleur','\n \n \n \n n dit kunstdoekje wordt een middeleeuwse ridder gepresenteerd in een kleurrijke explosie van verfspatten. De traditie van het ridderschap wordt hier op creatieve wijze getransformeerd door de moderne kunstbenadering, waarbij de kleuren als wapens worden gebruikt om de kracht en moed van de ridder te benadrukken. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2108.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39872) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('graffiti-face','Graffiti Face','\n \n \n \n Dit kunstdoekje vangt de energie en het dynamische karakter van straatkunst. De kunstenaar heeft een gezicht bedekt met een wirwar van graffiti-stijl teksten en symbolen, wat een levendige en expressieve uitbeelding van stedelijke cultuur creëert. Het contrast tussen het gedetailleerde portret en de rauwe, kleurrijke graffiti maakt dit doekje een krachtige toevoeging aan elke ruimte die de moderne kunst omarmt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2107.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39873) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sunset-landing','Sunset Landing','\n \n \n \n Dit kunstdoekje vangt de magie van een vliegtuig dat landt tegen de achtergrond van een dramatische zonsondergang. De warme tinten van de ondergaande zon smelten samen met de koele kleuren van de lucht, waardoor een adembenemend tafereel ontstaat. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2110.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,true,39874) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-tijger-39875','Kleurrijke Tijger','\n \n \n \n De gedetailleerde penseelstreken creëren een gevoel van energie en kracht, terwijl de contrasterende kleuren het mooie van de leeuw benadrukken. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2115.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','moderne-kunst','natuur','pop-street-art'],false,true,39875) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-hengst','Kleurrijke Hengst','\n \n \n \n Met een mix van zilver, goud en blauw vangt dit kunstdoekje de kracht en schoonheid van een statige hengst. De geometrische lijnen en metallic accenten geven het paard een bijna futuristische uitstraling. Een eyecatcher voor iedere ruimte die kracht en elegantie wil uitstralen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2144.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','moderne-kunst'],false,true,39876) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('wolf-in-kleuren','Wolf in Kleuren','\n \n \n \n De ogen van de mandril stralen pure kracht uit, gevangen in een betoverend palet van blauwe, gouden en oranje tinten. De artistieke interpretatie legt elk detail van zijn fascinerende gezicht vast, waardoor het lijkt alsof de mandril elk moment tot leven kan komen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2134.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','landschapmodus','natuur'],false,true,39882) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('brullende-ijsbeer','Brullende IJsbeer','\n \n \n \n De ijzige wereld van de Noordpool komt tot leven op dit indrukwekkende kunstdoekje. De brullende ijsbeer, vastgelegd tegen een dreigende lucht en onrustige zee, geeft een krachtig statement af over de wilde, ongetemde natuur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2133.webp',(select id from categories where slug='dieren'),array['dieren','fotografie','landschapmodus','natuur'],false,true,39883) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sierlijke-buffel','Sierlijke Buffel','\n \n \n \n Een prachtige mix van traditionele en moderne kunststijlen brengt deze sierlijke buffel tot leven. De ingewikkelde patronen in rijke blauwtinten en warme rood- en goudtonen maken dit kunstdoekje tot een eerbetoon aan de spirituele symboliek van dieren in kunst. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2132.webp',(select id from categories where slug='dieren'),array['dieren','landschapmodus','natuur'],false,true,39884) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
