insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verbonden-stilte','Verbonden Stilte','\n \n \n \n Twee figuren, abstract en mysterieus, delen een moment van verbondenheid op een achtergrond van levendig geel en sober zwart. Dit kunstdoekje vangt de essentie van menselijke relaties in een minimalistisch ontwerp dat tegelijkertijd intiem en krachtig is. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2059.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39899) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
