insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sunset-landing-copy-39901','Sunset Landing (Copy)','\n \n \n \n Dit kunstdoekje vangt de magie van een vliegtuig dat landt tegen de achtergrond van een dramatische zonsondergang. De warme tinten van de ondergaande zon smelten samen met de koele kleuren van de lucht, waardoor een adembenemend tafereel ontstaat. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2110.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk'],false,false,39901) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwevende-kleuren','Zwevende Kleuren','\n \n \n \n Laat je meevoeren door de zachte golven van kleur in dit kunstdoekje. De vloeiende bewegingen van pastelkleurige sluiers tegen een hemelsblauwe achtergrond brengen een gevoel van vrijheid en lichtheid. Perfect om een serene sfeer te creëren in elke ruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2058.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39902) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sereen-landschap','Sereen Landschap','\n \n \n \n Dit kunstdoekje nodigt je uit om even te ontsnappen naar een plek van rust en stilte. De zachte groene en blauwe tinten vloeien als een serene rivier door het beeld en geven je het gevoel alsof je zo een frisse wandeling in de bergen kunt maken. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2082.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39903) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-uitzicht','Abstracte Uitzicht','\n \n \n \n Met diepe blauw- en geeltinten, afgewisseld met speelse roze accenten, creëert dit kunstdoekje een gevoel van rust en verbeelding. Het lijkt een raam te openen naar een andere wereld, een plek waar je fantasie de vrije loop kan gaan. Ideaal voor een ruimte waar je een vleugje mysterie en schoonheid wilt toevoegen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2050.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39904) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('moeder-en-kind','Moeder en Kind','\n \n \n \n Dit eenvoudige, maar diep ontroerende lijnkunstdoekje vangt de essentie van liefde en bescherming in zijn puurste vorm. De zachte lijnen en subtiele kleuren benadrukken de emotionele connectie, een perfecte aanvulling voor een warme en liefdevolle omgeving. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2052.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39905) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('organische-patronen','Organische Patronen','\n \n \n \n Dit kunstdoekje in groen- en wittinten roept de rust en de natuurlijke vormen van bladeren en bomen op. Het subtiele spel van vormen en kleuren maakt het een ideale keuze voor wie een vleugje natuurlijke sereniteit aan zijn ruimte wil toevoegen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2057.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39906) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('ogen-van-de-nacht','Ogen van de Nacht','\n \n \n \n Laat je betoveren door de intensiteit van deze uil, gevangen in een kleurrijk en expressief palet. De felle tinten en gedurfde penseelstreken brengen de krachtige aanwezigheid van deze nachtvogel tot leven, alsof hij je recht aankijkt, wetend dat hij alle geheimen van de nacht bewaart. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2135.webp',(select id from categories where slug='impressionisme'),array['impressionisme','kleurrijk','landschapmodus','natuur'],false,true,39907) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verstilde-kleuren','Verstilde Kleuren','\n \n \n \n Een subtiel en dromerig kunstdoekje, waar zachte kleurtonen harmonieus in elkaar overvloeien. Ideaal om een rustgevende sfeer in huis te brengen, perfect voor een moment van reflectie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2126.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,39908) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurenstreep','Kleurenstreep','\n \n \n \n Dit kunstdoekje speelt met gedurfde, kleurrijke strepen die een silhouet vormen, alsof een persoon is ingepakt in de meest levendige kleuren van de regenboog. Het roept vragen op en laat ruimte voor interpretatie, een perfecte blikvanger voor wie houdt van modern en gedurfd. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2047.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39909) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('schilderachtig-silhouet','Schilderachtig Silhouet','\n \n \n \n Een abstract kunstdoekje dat de contouren van een gezicht in levendige kleuren weergeeft, alsof het met brede penseelstreken in de wind is gevormd. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2118.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39910) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cupido-met-een-twist','Cupido met een Twist','\n \n \n \n Dit kunstdoekje toont een moderne interpretatie van Cupido, de klassieke liefdesengel, maar met een edgy twist. In plaats van een pijl en boog, richt deze kleine engel een machinegeweer dat hartjes schiet. Het contrast tussen de schattige engel en het krachtige wapen creëert een spannend visueel effect. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2083.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','pop-street-art'],false,true,39960) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloeiende-elegantie','Bloeiende Elegantie','\n \n \n \n Dit kunstdoekje vangt de tijdloze schoonheid van irissen in een vaas. De levendige paarse en gele tinten contrasteren prachtig tegen de subtiele achtergrond, waardoor het een perfecte toevoeging is aan elke ruimte die een vleugje klassieke charme en verfijning kan gebruiken. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2078.webp',(select id from categories where slug='bloemen'),array['bloemen','impressionisme','moderne-kunst'],false,true,39961) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('schaduw-en-licht','Schaduw en Licht','\n \n \n \n Dit kunstdoekje is als een mysterieuze film noir in de kunstwereld. Met een naakte rug als hoofdrolspeler en een spannende scheidslijn tussen licht en donker, zet het je aan het denken: is dit een schaduwspel of de meest stijlvolle stripfiguur ooit? \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2080.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39962) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-abstracte-bloem','Kleurrijke Abstracte Bloem','\n \n \n \n oor degenen die van wat chaos met een knipoog houden: dit kunstdoekje is een kleurrijke knal van energie! De gedurfde penseelstreken hebben een eigen wil en lijken te dansen op het canvas. Perfect als je huis een vleugje ‘wow’ kan gebruiken. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2079.webp',(select id from categories where slug='asbtract'),array['asbtract','bloemen','impressionisme','kleurrijk','moderne-kunst'],false,true,39963) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-ritmes','Abstracte Ritmes','Een levendig kunstdoekje dat een speelse en toch strakke compositie van vormen en kleuren toont. De contrasterende tinten en texturen brengen een dynamische energie in elke ruimte, perfect voor liefhebbers van moderne en abstracte kunst.','https://kunstdoekje.nl/wp-content/uploads/2024/08/2076.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39964) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomerdromen-aan-de-kust','Zomerdromen aan de Kust','\n \n \n \n Een nostalgisch kunstdoekje dat je meeneemt naar een idyllische zomerdag aan de kust van de Middellandse Zee. De ontspannen sfeer, het zachte zand en de rustige golven roepen herinneringen op aan zorgeloze zomerdagen. Ideaal om een warme, zomerse sfeer in je interieur te brengen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2075.webp',(select id from categories where slug='impressionisme'),array['impressionisme','landschapmodus','moderne-kunst'],false,true,39965) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('elegantie-in-de-woestijn','Elegantie in de Woestijn','\n \n \n \n Een kunstdoekje dat de kracht en schoonheid van een vrouw uitstraalt, omringd door de serene en warme tonen van de woestijn. Dit werk brengt een gevoel van rust en vastberadenheid, perfect voor een ruimte die behoefte heeft aan een vleugje elegantie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2073.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk','moderne-kunst'],false,true,39966) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vleugels-van-vrijheid','Vleugels van Vrijheid','\n \n \n \n Een prachtig kunstdoekje dat de onschuld en verwondering van een kind laat zien, omringd door vlinders die opstijgen naar de hemel. Dit beeld vangt de essentie van vrijheid en het magische moment van dromen en mogelijkheden. Ideaal voor een ruimte waar inspiratie en hoop centraal staan. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2070.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','pop-street-art'],false,true,39967) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('maskerade-van-emoties','Maskerade van Emoties','\n \n \n \n Een abstract kunstdoekje dat de contouren van een gezicht in levendige kleuren weergeeft, alsof het met brede penseelstreken in de wind is gevormd. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2074.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39968) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('elegantie-in-de-woestijn-39969','Elegantie in de Woestijn','\n \n \n \n Een kunstdoekje dat de kracht en schoonheid van een vrouw uitstraalt, omringd door de serene en warme tonen van de woestijn. Dit werk brengt een gevoel van rust en vastberadenheid, perfect voor een ruimte die behoefte heeft aan een vleugje elegantie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2073.webp',(select id from categories where slug='illustratie'),array['illustratie','moderne-kunst'],false,true,39969) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-trap-nieuw-begin','De Trap Nieuw Begin','\n \n \n \n Dit kunstdoekje intrigeert met zijn abstracte weergave van een trap, subtiel doordrongen van warme roodtinten. Het beeld lijkt bijna een uitnodiging om een nieuwe reis te beginnen, misschien symbolisch voor vooruitgang of persoonlijke groei. Een krachtig statement voor elke moderne ruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2072.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39970) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tropische-bananen','Tropische Bananen','\n \n \n \n Dit kunstdoekje spat van het doek met zijn levendige kleuren en energieke penseelstreken. De gele bananen tegen de roze achtergrond brengen een vrolijke, tropische sfeer in elke ruimte. Perfect voor wie een vleugje exotische vrolijkheid wil toevoegen aan zijn interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2065.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,39971) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kustmist','Kustmist','\n \n \n \n Dit kunstdoekje vangt de kalmte van een mistige ochtend aan zee. Met subtiele tonen van blauw en wit creëert het een serene, dromerige sfeer die rust brengt in elke kamer. Ideaal voor wie houdt van minimalistische en kalmerende kunst. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2066.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst','natuur'],false,true,39972) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zen-cirkel','Zen Cirkel','\n \n \n \n \nDe kracht van eenvoud spreekt uit dit kunstdoekje, waar één enkele, zwarte cirkel op een witte achtergrond de essentie van balans en harmonie uitstraalt. Een prachtige keuze voor wie een zen-gevoel in zijn ruimte wil brengen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2067.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39973) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('jazzsfeer','Jazzsfeer','\n \n \n \n Dit kunstdoekje brengt de jazzy vibes naar je muur met een unieke weergave van een saxofonist in een mix van kubistische en abstracte elementen. De warme kleuren en geometrische vormen nodigen je uit om het ritme te voelen en de sfeer van een rokerige jazzclub te ervaren \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2063.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,39974) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kruis-van-expressie','Kruis van Expressie','\n \n \n \n Met een gedurfde X in zwarte verf op een wit doek, trekt dit kunstdoekje direct de aandacht. Het is een statement piece dat kracht en individualiteit uitstraalt, perfect voor wie een uitgesproken en krachtige toevoeging aan zijn interieur zoekt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2068.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39975) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-lippen','Gouden Lippen','\n \n \n \n Dit kunstdoekje vangt direct je blik met de luxueuze uitstraling van gouden lippen op een diepe, donkere achtergrond. Het straalt een gevoel van kracht en elegantie uit, alsof het een stille maar overtuigende oproep doet om te spreken. Perfect voor een interieur dat vraagt om een vleugje glamour. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2069.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,39976) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-poort-naar-dromen','De Poort naar Dromen','\n \n \n \n Stap binnen in een wereld van serene schoonheid en mysterie met dit kunstdoekje. Het schildert een surrealistisch tafereel van een poort die leidt naar een betoverende zonsondergang, omgeven door warme, uitnodigende tinten. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2071.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39977) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dromerig-uitzicht','Dromerig Uitzicht','\n \n \n \n Stap in een wereld van zachte pasteltinten en dromerige structuren. Dit kunstdoekje roept de sfeer op van een stille ochtend, waarin de zon voorzichtig door de nevel breekt en een vleugje magie aan de dag toevoegt. Ideaal voor wie houdt van rust en verstilling. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2060.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,39978) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
