insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tranquil-boats','Tranquil Boats','\n \n \n \n \nEen rustgevend kunstdoekje met boten die zachtjes deinen in kalm water, omgeven door subtiele beige tinten. Dit doek straalt sereniteit uit en brengt een gevoel van vrede en ontspanning in elke ruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2090.webp',(select id from categories where slug='boten'),array['boten','impressionisme','moderne-kunst'],false,true,40001) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lost-in-space','Lost in Space','\n \n \n \n Dit kunstdoekje vangt de magie van een toevallige ontmoeting met een UFO boven een verlaten snelweg. Een retro-stijl afbeelding die nostalgische gevoelens oproept en tegelijkertijd intrigeert. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2096.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','space'],false,true,40002) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-poort-naar-dromen-copy-40003','De Poort naar Dromen (Copy)','\n \n \n \n Stap binnen in een wereld van serene schoonheid en mysterie met dit kunstdoekje. Het schildert een surrealistisch tafereel van een poort die leidt naar een betoverende zonsondergang, omgeven door warme, uitnodigende tinten. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2071.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,false,40003) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('neon-flora','Neon Flora','\n \n \n \n In dit kunstdoekje wordt een bloem tot leven gebracht met stralende neonkleuren, waardoor een magische en bijna buitenaardse schoonheid ontstaat. Ideaal voor wie van moderne en levendige kunst houdt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2098.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,40004) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vegeta-s-legacy','Vegeta''s Legacy','\n \n \n \n Dit kunstdoekje is een knipoog naar het jeugdsentiment van millennials, met een iconische afbeelding van Vegeta uit Dragon Ball Z. De combinatie van zijn krachtige uitstraling en moderne streetwear maakt dit doek tot een uniek statement piece voor iedere fan van popcultuur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2094.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','pop-street-art'],false,true,40005) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lemon-groves','Lemon Groves','\n \n \n \n \nDit kunstdoekje vangt de essentie van de Mediterrane kust met rijpe citroenen die hangen over een pittoresk dorpje aan zee. De levendige kleuren en texturen brengen je meteen naar een zonnige, zorgeloze zomer aan de Amalfikust. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2088.webp',(select id from categories where slug='illustratie'),array['illustratie','kleurrijk','moderne-kunst'],false,true,40006) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('witte-blossom','Witte Blossom','\n \n \n \n Een elegante weergave van een serene witte bloementuin tegen een rustige, lichte achtergrond. Dit kunstdoekje straalt eenvoud en schoonheid uit, perfect om een vleugje rust en verfijning toe te voegen aan je interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2091.webp',(select id from categories where slug='fotografie'),array['fotografie','kleurrijk','moderne-kunst','natuur'],false,true,40007) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('glanzende-future','Glanzende Future','\n \n \n \n Dit opvallende kunstdoekje toont een metallic, glanzend menselijk figuur tegen een opvallende roze achtergrond. Het strakke, futuristische design spreekt van minimalisme en avant-garde esthetiek. Perfect voor een modern interieur dat een vleugje futurisme kan gebruiken, of gewoon voor iedereen die houdt van unieke, gedurfde kunst. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2085.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,40008) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-expressie','Kleurrijke Expressie','\n \n \n \n Dit kunstdoekje vangt een close-up van een gezicht met een intense, expressieve blik. De felle kleuren van blauw, roze, en goud spatten letterlijk van het doek af, wat het een levendige toevoeging maakt aan elk interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2087.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,40009) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lezen-onder-de-sterren','Lezen onder de Sterren','\n \n \n \n Dit kunstdoekje toont een serene scène van een meisje dat onder de sterrenhemel zit en leest, met een adembenemend uitzicht op een verre planeet. Een perfecte combinatie van rust en fantasie voor elke ruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2102.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','space'],false,true,40010) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gemaskerde-identiteit','De Gemaskerde Identiteit','\n \n \n \n Op dit kunstdoekje zien we een kleurrijk beschilderde Guy Fawkes-masker, vaak geassocieerd met anonimiteit en protest. De graffiti-stijl voegt een extra laag van stedelijke cultuur en expressie toe. Dit doekje is ideaal voor liefhebbers van moderne kunst en stedelijke invloeden, en het zal zeker een gespreksonderwerp zijn in je woonkamer. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2084.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','pop-street-art'],false,true,40011) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('delftsblauwe-koe','Delftsblauwe koe ||','\n \n \n \n Deze betoverende koe met haar sierlijke Delftsblauwe patronen brengt een vleugje Nederlandse allure naar je interieur. Op een fluweelzacht doek komt het contrast tussen de donkere achtergrond en de elegante blauwe details nog mooier tot leven, waardoor je een uniek statement piece creëert dat al je gasten zal verrassen. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-65.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','fotografie','moderne-kunst'],false,true,40533) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hemelse-rust','Hemelse Rust','\n \n \n \n Een eyecatcher die toch rust uitstraalt... deze gorilla in zachtgroene tinten is dé manier om je interieur een stijlvolle boost te geven. De subtiele aquarel look past perfect in een lichte moderne ruimte en op een fluweelzacht doek krijgt dit statement piece nog meer sfeer en elegantie. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-67.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','asbtract','dieren','moderne-kunst','natuur'],false,true,40534) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koning-van-de-jungle-chic','Koning van de Jungle Chic','\n \n \n \n Deze trendy aap in pak steelt gegarandeerd de show in jouw interieur met zijn koninklijke uitstraling en speelse pop art stijl. Op een fluweelzacht doek komt dit kleurrijke kunstwerk nog meer tot leven en geeft het direct een vrolijke luxe touch aan je muur! \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-64.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren','kleurrijk','moderne-kunst','pop-street-art'],false,true,40535) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-expressie-copy','Kleurrijke Expressie (Copy)','\n \n \n \n Dit kunstdoekje vangt een close-up van een gezicht met een intense, expressieve blik. De felle kleuren van blauw, roze, en goud spatten letterlijk van het doek af, wat het een levendige toevoeging maakt aan elk interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/08/2087.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,false,40536) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('delftsblauwe-koe-40537','Delftsblauwe Koe','\n \n \n \n Wat een plaatje hè? Deze koe met haar prachtige Delfts blauwe patronen is een echte blikvanger voor je interieur. De diepzwarte achtergrond laat het blauw-witte design extra spreken, en als je kiest voor de fluwelen uitvoering? Dan geef je dit eigenzinnige kunstwerk nóg meer luxe en diepte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-66.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren','moderne-kunst','natuur','pop-street-art'],false,true,40537) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('glamour-en-grace','Glamour & Grace','\n \n \n \n Pure elegantie straalt van dit portret af, waarbij vintage Hollywood glamour samensmelt met moderne chic. Het contrast tussen de glanzende sieraden en de zachte vacht van het hondje maakt dit een verrassend warm statement piece, dat op fluweelzacht doek nóg meer luxe uitstraalt. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-63.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','fotografie'],false,true,40728) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koninklijke-eenvoud','Koninklijke Eenvoud','\n \n \n \n Een uniek portret in een stijl die doet denken aan kindertekeningen, maar dan met een verfijnde twist. De zachte pasteltinten en het minimalistische lijnenspel creëren samen met de gouden kroon een dromerig kunstwerk dat warmte en karakter aan je interieur geeft. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-58.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','illustratie','moderne-kunst','pop-street-art'],false,true,40729) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koninklijke-bohemien','Koninklijke Bohemien','\n \n \n \n Een charmant portret dat speelse eenvoud combineert met artistieke verfijning in warme zachtroze en hemelsblauwe tinten. De pure lijnen en subtiele details vertellen een eigen verhaal, waardoor dit kunstwerk een persoonlijke touch geeft aan elk modern interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-57.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','moderne-kunst','natuur','pop-street-art'],false,true,40730) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('culinaire-rebel','Culinaire Rebel','\n \n \n \n Een sprankelend kunstwerk dat een getatoeëerde chef vastlegt in een opvallende pop art stijl tegen een vurig rode achtergrond. De combinatie van urban art en culinaire flair maakt dit een gedurfd statement piece dat direct energie geeft aan je keuken of eetkamer. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-62.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren','moderne-kunst','pop-street-art'],false,true,40731) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dromerige-ziel','Dromerige Ziel','\n \n \n \n Een stijlvol kunstwerk dat speelsheid en verfijning samenbrengt in een palet van zachtroze, geel en subtiel blauw. De pure, kinderlijke lijnen en de kleine verrassende details creëren een intrigerend portret dat een vleugje bohemian charme toevoegt aan je interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-56.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','moderne-kunst','pop-street-art'],false,true,40732) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('magische-zonsondergang','Magische Zonsondergang','\n \n \n \n \n \n \n Een betoverend landschap waar warme rozetinten versmelten met rustgevend turquoise in een dromerige aquarel stijl. Dit kunstwerk vangt dat perfecte moment bij zonsondergang en brengt instant rust en romantiek in je interieur. \n \n \n \n \n \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-60.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','asbtract','dieren','moderne-kunst'],false,true,40733) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('urban-spirit','Urban Spirit','\n \n \n \n Een expressief kunstwerk dat street art en moderne kunst samenbrengt in een levendig kleurenspel van blauw, roze en geel tegen een krachtige rode achtergrond. Dit karaktervolle portret voegt direct een vleugje stedelijke energie en eigenwijze charme toe aan je interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-61.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren','moderne-kunst','pop-street-art'],false,true,40734) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-vrijheid','Kleurrijke Vrijheid','\n \n \n \n Een explosief portret dat energie uitstraalt door levendige penseelstreken in turquoise, roze en geel tegen een stralende achtergrond. Dit eigentijdse kunstdoekje viert pure expressie en levensvreugde, en brengt instant een vleugje modern urban art glamour in je woonruimte. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/2215.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,40735) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dromerig-bloemenmeisje','Dromerig Bloemenmeisje','\n \n \n \n Wat een plaatje hè? Deze koe met haar prachtige Delfts blauwe patronen is een echte blikvanger voor je interieur. De diepzwarte achtergrond laat het blauw-witte design extra spreken, en als je kiest voor de fluwelen uitvoering? Dan geef je dit eigenzinnige kunstwerk nóg meer luxe en diepte. \n\n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/clean-and-simple-room-66.webp',(select id from categories where slug='ai-kunst'),array['ai-kunst','dieren','moderne-kunst','natuur','pop-street-art'],false,false,40736) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
