insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mediterane-droom','Mediterane Droom','Een sereen abstract doek waarin verschillende tinten blauw samensmelten met subtiele accenten van roze en goud, als een mediterrane kustlijn bij zonsondergang. Dit stijlvolle kunstdoekje brengt direct een gevoel van kalmte en ruimte in je interieur, waarbij de zachte kleurovergangen voor een moderne maar tijdloze sfeer zorgen.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2219.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,41202) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('oosterse-sereniteit','Oosterse Sereniteit','Een verfijnd portret van een geisha waar traditionele Japanse elegantie samensmelt met moderne penseelstreken in zwart, grijs en een opvallende rode lip. Dit stijlvolle kunstdoekje brengt een vleugje Aziatische rust en mysterie in je interieur, perfect voor wie houdt van minimalistische elegantie met een twist.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2220.webp',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','moderne-kunst'],false,true,41204) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('elegenante-rust','Elegenante Rust','Een sierlijke schets van een vrouwelijk silhouet, vertaald in losse penseelstreken en zachte pasteltinten van roze, groen en goud. Dit sfeervolle kunstdoekje combineert moderne abstractie met klassieke elegantie, en brengt een vleugje verfijnde femininiteit in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2222.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,41206) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vintage-mickey','Vintage Mickey','Een nostalgische interpretatie van Disney''s iconische muis in verweerde kleuren die doen denken aan oude foto''s en vergane glorie. Dit charmante kunstdoekje combineert jeugdsentiment met vintage stijl, perfect voor liefhebbers van retro design met een speelse twist.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2223.webp',(select id from categories where slug='pop-street-art'),array['pop-street-art'],false,true,41208) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('urban-superman','Urban Superman','Een dynamisch pop art portret waar street art en superhelden samenkomen in een explosie van kleur en urban culture. Dit stoere kunstdoekje mengt nostalgische stripboekencharme met moderne street art elementen, perfect voor wie houdt van een gedurfde statement in huis.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2227.webp',(select id from categories where slug='pop-street-art'),array['pop-street-art'],false,true,41210) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-bergen','Abstracte Bergen','Een modern landschap in warme aardetinten waar terracotta, zacht grijs en crème elkaar afwisselen in golvende lijnen. Dit rustgevende kunstdoekje brengt de serene sfeer van een berglandschap in je interieur, waarbij de abstracte vormen perfect samengaan met elke woonstijl.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2231.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,41212) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mistige-bergen','Mistige Bergen','Een adembenemend berglandschap in verschillende tinten blauw, waar dennenbomen als silhouetten tegen een nevelige achtergrond van glooiende bergtoppen staan. Dit serene kunstdoekje vertelt een verhaal van rust en natuur, ideaal voor wie een vleugje bergromantiek in huis wil halen.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2235.webp',(select id from categories where slug='asbtract'),array['asbtract','natuur'],false,true,41214) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gestilleerde-vogel','Gestilleerde Vogel','Een krachtig minimalistisch portret van een vogel in zwarte inkt, opvallend geaccentueerd met spetters levendig oranje. Dit elegante kunstdoekje brengt een perfecte balans tussen Japanse eenvoud en moderne expressie in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2247.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','natuur'],false,true,41216) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blauwe-reflectie','Blauwe Reflectie','Een krachtig abstract silhouet in verschillende tinten kobaltblauw, waarbij licht en schaduw op een intrigerende manier samensmelten tegen een contrastrijke achtergrond. Dit stijlvolle kunstdoekje brengt een vleugje moderne sophistication in je interieur, perfect voor liefhebbers van minimalistische elegantie.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2249.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,41219) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zachte-abstractie-41221','Zachte Abstractie','Een sfeervol abstract doek in harmonieuze tinten van marineblauw, zacht beige en wolkengrijs die als een gracieuze dans in elkaar overlopen. Dit serene kunstdoekje brengt met zijn subtiele kleurenpalet en vloeiende bewegingen een gevoel van rust en elegantie in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2238.webp',(select id from categories where slug='asbtract'),array['asbtract'],false,true,41221) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('meisje-met-de-slurf','Meisje met de Slurf','Een speelse knipoog naar Vermeers meesterwerk, waarbij het iconische meisje is vervangen door een olifant in dezelfde klassieke pose en lichtval. Dit charmante kunstdoekje combineert klassieke kunstgeschiedenis met een verrassende twist, perfect voor wie houdt van verfijnde humor in een stijlvol jasje.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2251.webp',(select id from categories where slug='dieren'),array['dieren','oude-meesters'],false,true,41223) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('terracotta-maan','Terracotta Maan','Een sfeervol abstract landschap in warme aardetinten waar golvende lijnen dansen onder een zachte roze maan. Dit serene kunstdoekje vertaalt woestijnachtige vormen in moderne abstractie, perfect voor wie houdt van pure, minimalistische elegantie met een organische touch.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2252.webp',(select id from categories where slug='asbtract'),array['asbtract'],false,true,41225) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('urban-rood','Urban Rood','Een strak modern abstract kunstdoekje waar zwart en koraalrood dansen tegen een lichte achtergrond in een spel van geometrische vormen. Dit stijlvolle stuk brengt instant stedelijke flair in je interieur, waarbij de warme accenten zorgen voor een perfecte balans tussen kracht en verfijning.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2253.webp',(select id from categories where slug='asbtract'),array['asbtract'],false,true,41229) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('oranje-rust','Oranje Rust','Een elegant samenspel van oranje en aqua raakt perfect in balans met neutrale tinten in dit verfijnde abstracte kunstdoekje. De luchtige compositie met subtiele lijnen en zachtgrijze accenten zorgt voor een stijlvolle, moderne touch in elk interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2254.webp',(select id from categories where slug='asbtract'),array['asbtract'],false,true,41231) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-surfer','Roze Surfer','Een dromerig strandtafereel in zachte roze tinten waar een surfer uitkijkt over de oceaan bij zonsondergang. Dit romantische kunstdoekje brengt instant die relaxte beach vibe in huis en geeft elk interieur een vleugje endless summer gevoel.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2260.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,41233) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('dynamisch-contrast','Dynamisch Contrast','Een krachtig abstract kunstdoekje waar zwart, rood en geel samenkomen in gedurfde geometrische vlakken met expressieve penseelstreken. De dynamische compositie met het opvallende zwarte accent geeft je interieur direct een moderne art gallery uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2262.webp',(select id from categories where slug='asbtract'),array['asbtract','aziatische-kunst','moderne-kunst'],false,true,41235) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('serene-zeilboot','Serene Zeilboot','Een rustgevend tafereel van een traditionele zeilboot op spiegelglad water, omringd door majestueuze groene bergen. Dit sfeervolle kunstdoekje in zachte aquatinten en warme oranje accenten brengt een vleugje Aziatische sereniteit in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2267.webp',(select id from categories where slug='boten'),array['boten','moderne-kunst'],false,true,41237) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('koninklijke-olifant','Koninklijke Olifant','Een betoverend oosters tafereel waarin een sierlijk versierde olifant wandelt tussen felroze bloemen tegen een achtergrond van mistige turquoise bergen. Dit weelderige kunstdoekje met zijn rijke details en luxueuze gouden accenten brengt instant een vleugje exotische grandeur in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2268.webp',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,41239) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('avontuurlijke-ziel','Avontuurlijke Ziel','Een prachtig versierde olifant baant zich een weg door het mystieke junglepad, gehuld in kleurrijke traditionele kleden die schitteren in het zachte avondlicht. Dit sfeervolle kunstdoekje vertelt een verhaal van Thaise mystiek en avontuur, perfect voor wie een vleugje oosterse magie in huis wil halen.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2269.webp',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren','natuur'],false,true,41242) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kersenbloesems-reiger','Kersenbloesems Reiger','\n \n \n \n \n Twee elegante witte reigers staan verstild tussen de bloeiende kersenbloesem, in een stijl die Japanse traditie ademt. Dit poëtische kunstdoekje brengt met zijn zachte koraalroze bloesems en subtiele grijstinten een vleugje zen-achtige rust in je interieur. \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2024/11/2282.webp',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst','dieren'],false,true,41244) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kattendans','Kattendans','Een speels artistiek portret van twee verliefde katten in zwart en goud, omringd door sierlijke krullen en hartjes in warme herfsttinten en turquoise accenten. Dit vrolijke kunstdoekje brengt met zijn kleurrijke abstracte stijl direct een vleugje fantasie en warmte in je interieur.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2291.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','kleurrijk'],false,true,41246) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kattenliefde','Kattenliefde','Een modern portret van twee katten die elkaar ontmoeten tussen een caleidoscoop van levendige kleuren in blauw, roze en goud. Dit vrolijke kunstdoekje vertelt een verhaal van liefde in een speelse kubistische stijl, perfect voor wie houdt van kleurrijke expressie met een knipoog.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2292.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,41248) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('urban-dog','Urban Dog','Een speelse compositie van gestileerde honden in een urban street art stijl, uitgevoerd in levendige kleuren rood, blauw en goud tegen een energieke achtergrond. Dit vrolijke kunstdoekje brengt een vleugje rebelse creativiteit in je interieur en is perfect voor wie houdt van moderne kunst met een knipoog.','https://kunstdoekje.nl/wp-content/uploads/2024/11/2294.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk'],false,true,41252) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
