insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('folklore-danser','Folklore Danser','Een wervelwind van kleuren in traditionele klederdracht. Dit vrolijke kunstwerk brengt het feest in huis. Op fluweel krijgen al die vrolijke kleuren een warme, rijke gloed die je blijft boeien. Voor wie het leven graag viert en dat ook aan de muur laat zien.','https://kunstdoekje.nl/wp-content/uploads/2025/08/2402.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,43751) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('plafondbevestiging','Plafondbevestiging','Wordt apart geleverd. \n \n Prijs 85,- \n Waarom deze plafondbevestiging? \n \n \n Creëert een luxe, zwevend effect in je interieur \n Extra lange kabels (3 meter) voor de perfecte hoogte \n Moeiteloos te monteren - binnen enkele minuten hangt je kunstwerk \n Set van 2 stuks voor optimale balans \n Speciaal ontworpen voor Heavy 27 frames \n \n Details: \n \n \n Materiaal: Robuust staal met zilveren afwerking \n Kabellengte: 3 meter verstelbaar \n Gewicht: 141 gram per stuk \n Montage: Plafond of wand \n','https://kunstdoekje.nl/wp-content/uploads/2025/09/Tekengebied-1.webp',(select id from categories where slug='ophangsystemen'),array['ophangsystemen'],false,true,45811) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('muurbeugels','Muurbeugels','Wall Mount Heavy - Muurbeugels Set van 2 \n Professionele muurbeugels voor het perfect waterpas ophangen van je Kunstdoekje met frame. Extra stevige constructie voor een strakke, onzichtbare wandmontage. \n Highlights: \n \n \n Eenvoudig waterpas te stellen \n Extra robuuste kwaliteit \n Set van 2 stuks \n Inclusief bevestigingsmateriaal \n \n Prijs: €15,00 (zonder kunstdoekje inc. frame besteld) \n Tip: Bestel je een Kunstdoekje? Vermeld "muurbeugels" in het notitieveld bij je bestelling en we sturen deze GRATIS mee! \n','https://kunstdoekje.nl/wp-content/uploads/2025/09/Tekengebied-6.webp',(select id from categories where slug='ophangsystemen'),array['ophangsystemen'],false,true,45838) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blauwe-emotie','Blauwe Emotie','Een indrukwekkend kunstdoekje in verschillende tinten blauw, met een silhouet en een opvallend rood hart. De diepe blauwtonen creëren een serene maar krachtige sfeer, terwijl het felle rode accent een boeiend contrast vormt. Een stijlvolle toevoeging aan elk interieur met een vleugje emotie.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2430.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46623) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('innerlijke-kracht','Innerlijke Kracht','Een intrigerend silhouet tegen een fris groene achtergrond, met een paars hart en gedachtenspiralen. Dit kunstdoekje combineert anatomie en emotie op een kunstzinnige manier. De levendige kleuren en symboliek maken het een boeiend gespreksonderwerp in elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2432.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46624) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('berg-vrijheid','Berg Vrijheid','Een rustgevend berglandschap in zachte groentinten met een eenzame vogel die door de nevelige lucht zweeft. Dit kunstdoekje brengt direct een gevoel van rust en vrijheid in je interieur. Perfect voor wie houdt van minimalistische natuurtaferelen met een vleugje symboliek.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2434.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','natuur'],false,true,46625) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('elegante-chaos','Elegante Chaos','Dynamische zwarte penseelstreken dansen samen met subtiele goudtinten op een stralend witte achtergrond. Dit kunstdoekje creëert een verrassend rustige sfeer in huis, als een bevroren moment van inspiratie aan je muur.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2419.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,46626) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('scharlaken-stilte','Scharlaken Stilte','Een indrukwekkend silhouet baadt in diep scharlakenrood, waarbij het donkere figuur half ondergedompeld staat in mysterieuze wateren. De krachtige contrasten en minimalistische compositie roepen een gevoel van contemplatie en introspectie op.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2416.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','pop-street-art'],false,true,46627) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amber-silhouet','Amber Silhouet','Een elegante lijntekening van een figuur die gracieus poseert tegen een levendig oranje achtergrond. De minimalistische benadering en het verfijnde lijnenspel creëren een intieme, tijdloze sfeer. Dit stijlvolle portret voegt een vleugje sofisticatie toe aan elke woonkamer of slaapkamer.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2420.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46628) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-getijden','Roze Getijden','Een fotogeniek roze surfhuisje met kleurrijke surfplanken tegen een achtergrond van zachte golven. Dit kunstdoekje brengt instant vakantievibes naar je interieur. Een vleugje zomer voor het hele jaar door.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2426.webp',(select id from categories where slug='fotografie'),array['fotografie','kleurrijk','moderne-kunst'],false,true,46630) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rebel-rider','Rebel Rider','Een speelse twist op pop art met Homer Simpson op een rode motor, omringd door graffiti en iconische merken. Dit kunstdoekje voegt direct een vrolijke noot van rebelse streetart toe aan je woonkamer. Perfect voor liefhebbers van eigentijdse kunst met een knipoog.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2428.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','pop-street-art'],false,true,46631) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('spiraalvloei','Spiraalvloei','Een weelderige interpretatie van Klimt''s beroemde werk, waar zachte figuren vervloeien in een tapijt van kleurrijke patronen. De levendige spiralen in paars, blauw en goud creëren een dromerige, sensuele sfeer die elke ruimte verrijkt met diepgang en emotie. Perfect voor liefhebbers van expressieve kunst met een klassieke invloed.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2414.webp',(select id from categories where slug='gustav-klimt'),array['gustav-klimt'],false,true,46632) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('primaire-balans','Primaire Balans','Een vrolijke compositie in de onmiskenbare stijl van Fernand Léger. Geometrische vormen in groen, rood en geel vormen samen een feestelijk kubistisch gesprek. Dit kunstdoekje bewijst dat verfijnde kunst ook speels en toegankelijk kan zijn.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2421.webp',(select id from categories where slug='asbtract'),array['asbtract','oude-meesters'],false,true,46638) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('banksy-madonna','Banksy Madonna','Een prikkelende twist op religieuze iconografie door de beroemde street artist Banksy. Dit kunstdoekje toont een Madonna figuur met kind, die een medicijnflesje toedient. De contrasterende zwart-wit stencil techniek met het felgele accent maakt het een krachtig statement stuk voor je interieur. Een perfecte eyecatcher voor liefhebbers van hedendaagse kunst met een boodschap. \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/09/2441.webp',(select id from categories where slug='banksy'),array['banksy','pop-street-art'],false,true,46654) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('roze-knuffel','Roze Knuffel','Een stijlvol Banksy kunstdoekje dat een meisje toont dat een bom omhelst als een teddybeer. De zachte roze achtergrond vormt een verrassend contrast met het krachtige beeld. Dit doek voegt direct karakter toe aan je woonkamer, slaapkamer of kantoor. Voor wie houdt van kunst die een verhaal vertelt met een vleugje ironie','https://kunstdoekje.nl/wp-content/uploads/2025/09/2443.webp',(select id from categories where slug='banksy'),array['banksy'],false,true,46655) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
