insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('cash-duck','Cash Duck','Dagobert Duck met zijn typische hoge hoed en wandelstok, tegen een levendige oranje achtergrond met groene dollartekens. Dit kunstdoekje brengt een speelse knipoog naar rijkdom en luxe in je interieur. Ideaal voor wie houdt van pop art met een vleugje ironie.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2438.webp',(select id from categories where slug='pop-street-art'),array['pop-street-art'],false,true,46657) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('money-duck','Money Duck','DJ Dagobert Duck in luxe LV outfit achter een wasmachine vol bankbiljetten. Dit kunstdoekje combineert humor, streetart en popcultuur in één opvallend beeld. De levendige kleuren en bekende figuur maken het een gespreksstarter in elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2437.webp',(select id from categories where slug='pop-street-art'),array['pop-street-art'],false,true,46658) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('peaky-portrait','Peaky Portrait','Een stijlvol portret van Tommy Shelby uit Peaky Blinders, omlijst door graffiti en urban teksten op een vurige rode achtergrond. Dit kunstdoekje combineert een iconisch tv-personage met street art elementen. Perfect voor fans van de serie en liefhebbers van hedendaagse portretkunst.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2440.webp',(select id from categories where slug='dieren'),array['dieren','pop-street-art'],false,true,46659) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('fast-food-bear','Fast Food Bear','Een brutale mix van kindervriend Winnie met fast food logo''s en graffiti stijl. Dit kunstdoekje is een statement stuk voor liefhebbers van street art en pop culture. De felle kleuren en herkenbare beelden maken het een perfecte eyecatcher voor moderne interieurs.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2436.webp',(select id from categories where slug='dieren'),array['dieren','pop-street-art'],false,true,46660) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('abstracte-ziel','Abstracte Ziel','Een krachtig portret in urban stijl met een mix van blauw, rood en goud. De gelaagde penseelstreken en lijnen creëren een fascinerende diepte. Dit kunstdoekje voegt direct karakter en energie toe aan elke ruimte.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2449.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,46682) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('african-women-46683','African women','Een fascinerend portret met een explosie van kleur en patroon. De gouden sieraden en intense blik creëren een hypnotiserende uitstraling. Dit kunstdoekje combineert traditionele portretkunst met hedendaagse expressie.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2448.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46683) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tesco-vlag','Tesco Vlag','Een bekend Banksy kunstdoekje waarin kinderen een supermarkt vlag hijsen. De lichtblauwe achtergrond en silhouetten creëren een krachtig contrast. Dit doek combineert speelse eenvoud met scherpe maatschappijkritiek. Een subtiel statement stuk voor je woonkamer of werkruimte.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2454.webp',(select id from categories where slug='banksy'),array['banksy'],false,true,46684) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('amber-silhouet-copy','Amber Silhouet (Copy)','Een elegante lijntekening van een figuur die gracieus poseert tegen een levendig oranje achtergrond. De minimalistische benadering en het verfijnde lijnenspel creëren een intieme, tijdloze sfeer. Dit stijlvolle portret voegt een vleugje sofisticatie toe aan elke woonkamer of slaapkamer.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2420.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,false,46685) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('japanse-katten','Japanse Katten','Een charmant kunstdoekje in klassieke Japanse ukiyo-e stijl, met speelse katten in verschillende poses. Dit is een reproductie van een beroemd werk van de Japanse kunstenaar Utagawa Kuniyoshi (1798-1861), bekend om zijn meesterlijke houtsneden van katten.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2455.webp',(select id from categories where slug='aziatische-kunst'),array['aziatische-kunst'],false,true,46686) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijk-profiel','Kleurrijk Profiel','Een levendig portret in zijaanzicht met een explosieve mix van regenboogkleuren. De dynamische penseelstreken en rijke textuur springen van het doek. Dit kunstdoekje brengt direct energie en vrolijkheid in elke ruimte. Ideaal voor een kleurrijk, expressief interieur.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2457.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46687) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('turquoise-portret','Turquoise Portret','Een indrukwekkend portret met dynamische penseelstreken in warme huidtinten tegen een turquoise achtergrond. Dit kunstdoekje brengt direct diepte en karakter in je ruimte. De levendige kleuren en expressieve techniek maken het een boeiend middelpunt in elk modern interieur.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2447.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46688) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurlijnen','Kleurlijnen','Een elegant abstract kunstdoekje met vloeiende, gekleurde lijnen die in harmonie samenkomen. De zachte kleurverloop van roze naar blauw en oranje creëert een rustgevend maar boeiend visueel effect.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2466.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,46696) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bubblegum-hepburn','Bubblegum Hepburn','Een stijlvol zwart-wit portret van filmicoon Audrey Hepburn, compleet met haar kenmerkende opgestoken haar en parelsieraden. De roze kauwgombal en achtergrond geven dit klassieke beeld een speelse, moderne twist. Dit kunstdoekje combineert tijdloze elegantie met een vleugje humor en kleur.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2467.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46697) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('geo-sunset','Geo Sunset','Een strak geometrisch kunstdoekje met warme tinten koraal, groen en crème. De zachte kleuren en vloeiende vormen creëren een rustige maar boeiende compositie die doet denken aan een gestileerde zonsondergang. Perfect voor minimalistische interieurs en liefhebbers van moderne abstracte kunst.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2469.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,46698) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('turquoise-portret-copy','Turquoise Portret (Copy)','Een indrukwekkend portret met dynamische penseelstreken in warme huidtinten tegen een turquoise achtergrond. Dit kunstdoekje brengt direct diepte en karakter in je ruimte. De levendige kleuren en expressieve techniek maken het een boeiend middelpunt in elk modern interieur.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2447.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,false,46699) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('turquoise-portret-copy-46700','Turquoise Portret (Copy)','Een indrukwekkend portret met dynamische penseelstreken in warme huidtinten tegen een turquoise achtergrond. Dit kunstdoekje brengt direct diepte en karakter in je ruimte. De levendige kleuren en expressieve techniek maken het een boeiend middelpunt in elk modern interieur.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2447.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,false,46700) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bubblegum-luipaard','Bubblegum Luipaard','Een speels kunstdoekje met een luipaard die een roze kauwgombal blaast tegen een paarse achtergrond. De hippe roze zonnebril maakt het plaatje compleet. Dit vrolijke doek voegt direct een vleugje humor en kleur toe aan je interieur. Perfect voor wie houdt van kunst met een knipoog.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2461.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','moderne-kunst'],false,true,46701) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('mona-pop','Mona Pop','Een speelse twist op het beroemdste schilderij ter wereld! Da Vinci''s Mona Lisa blaast een roze kauwgombel terwijl ze je met die mysterieuze glimlach aankijkt. Dit kunstdoekje voegt direct een vleugje humor en kleur toe aan je interieur. Perfect voor wie houdt van klassieke kunst met een hedendaagse knipoog.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2462.webp',(select id from categories where slug='da-vinci'),array['da-vinci','oude-meesters','pop-street-art'],false,true,46702) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verstilde-schets','Verstilde Schets','Een indrukwekkend portret met dynamische penseelstreken in warme huidtinten tegen een turquoise achtergrond. Dit kunstdoekje brengt direct diepte en karakter in je ruimte.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2463.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,46703) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurvakken','Kleurvakken','Een vrolijke explosie van kleur en vorm in abstracte stijl. De energieke penseelstreken in levendig roze, oranje, geel en turquoise dansen met elkaar op het doek. Dit kunstdoekje brengt direct warmte en beweging in je interieur. Perfect voor wie houdt van expressieve, kleurrijke kunst met een moderne uitstraling.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2464.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,46704) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-golf','Gouden Golf','Een meeslepend kunstdoekje met een krachtige golf in verschillende tinten blauw die ontmoet met warm goud. De dynamische penseelstreken creëren een gevoel van beweging en kracht.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2458.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst','natuur'],false,true,46705) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('blauwe-hoofddoek','Blauwe Hoofddoek','Een levendig portret van een vrouw met een prachtige blauwe hoofddoek tegen een stralend gele achtergrond. De rijke kleuren en gedetailleerde uitwerking maken dit kunstdoekje tot een opvallende blikvanger in elk interieur. Perfect voor wie houdt van kleurrijke, expressieve portretkunst met culturele invloeden.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2473.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46723) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rode-horizon','Rode horizon','Een krachtig kunstdoekje met een silhouet tegen een intens rode achtergrond. De minimalistische compositie en het gebruik van contrast creëren een boeiend en emotioneel beeld. Dit doek voegt direct diepgang en karakter toe aan elke ruimte, perfect voor liefhebbers van kunst met een boodschap.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2472.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,46726) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomers-tafereel','Zomers Tafereel','Een heerlijk levendig stilleven met oesters, citroen en zonnebril op een knalroze tafelkleed. De frisse kleuren en losse penseelstreken roepen direct zomerse vibes op. Dit kunstdoekje brengt een vleugje vakantiegevoel in huis, perfect voor de keuken of eetkamer.','https://kunstdoekje.nl/wp-content/uploads/2025/09/2471.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk'],false,true,46727) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('versluierde-blik','Versluierde Blik','Een paar doordringende ogen kijkt tussen rode horizontale banen door, geflankt door wit en zwart. De fotografische precisie van de ogen contrasteert met de abstracte verfstreken die het gezicht verhullen. Dit kunstdoekje speelt met zichtbaarheid en mysterie, een intrigerend statement piece dat vragen oproept.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2429.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst','specials'],false,true,47177) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('brandend-hart','Brandend Hart','Diepe blauwtinten omarmen een silhouet dat een gloeiend rood hart tegen de borst houdt. Het contrast tussen koel blauw en warm rood creëert een intense visuele spanning vol emotie. Dit kunstdoekje vertelt een verhaal van passie en innerlijke vuur, krachtig en indringend zonder opdringerig te zijn.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2430.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,47197) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('diepblauw-zweven','Diepblauw Zweven','Een eenzame zwemmer drijft door een oceaan van turkoois en kobaltblauw. Textuurrijke verflagen suggereren waterdiepte, terwijl lichte spatten zonlicht door het oppervlak laten breken. Dit kunstdoekje vangt de vrijheid van zweven in eindeloos water, een moment van volledige rust en overgave.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2423.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,47201) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('hart-van-indigo','Hart van Indigo','Expressieve blauwe verfstreken vormen een figuur dat een wit hart vasthoudt. Druipende verf en krachtige lijnen creëren beweging en emotie in deze rauwe compositie. Een kunstdoekje over kwetsbaarheid en innerlijke kracht, dat vraagt om een plek waar je jezelf mag zijn. \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2485.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst'],false,true,47203) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kustlijn-van-herinneringen','Kustlijn van Herinneringen','Abstracte penseelstreken in verschillende tinten blauw ontmoeten beige en wit op het canvas. Donkere accenten zorgen voor contrast en diepte in deze vrije compositie waar kleuren naadloos in elkaar overlopen. Dit kunstdoekje brengt een gevoel van openheid en rust, ideaal voor moderne interieurs die ademruimte zoeken. \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2492.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,47205) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gesluierd-portret','Gesluierd Portret','\n \n Dikke lagen witte en grijze verf vormen een gezicht dat half verborgen blijft achter textuur. Dikke penseelstreken stapelen zich op elkaar, waardoor schaduwen en diepte ontstaan in monochrome tinten. Dit kunstdoekje speelt met zichtbaarheid en verbergen, waarbij de verf zelf deel wordt van het verhaal. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2483.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,47207) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stokstaartje-in-stijl','Stokstaartje in Stijl','\n \n Een stokstaart in een felroze jas met zwart wit gestreept shirt poseert tegen een roze achtergrond. Oranje en blauwe verfaccenten geven speelsheid aan dit onverwachte portret vol humor. Dit kunstdoekje brengt een glimlach op je gezicht en past perfect in interieurs die niet te serieus willen zijn. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2491.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','moderne-kunst'],false,true,47209) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('aarden-gedachten','Aarden Gedachten','\n \n Een gezicht opgebouwd uit dikke lagen beige en bruine verf, waar textuur alles bepaalt. De penseelstreken vormen gezichtstrekken door pure massa en richting, abstract maar herkenbaar tegelijk. Dit kunstdoekje heeft een tastbare aanwezigheid die vraagt om van dichtbij bekeken te worden. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2484.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,47212) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-blik-47214','Gouden Blik','\n \n Een half gezicht met een doordringend blauw oog en rode lippen tegen een gestructureerde gouden achtergrond. Verflagen vertonen barsten en textuur die tijd suggereren, terwijl zwarte en rode accenten spanning toevoegen. Dit kunstdoekje combineert klassieke schoonheid met moderne textuur, krachtig en verfijnd tegelijk. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2494.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst'],false,true,47214) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('rood-profiel','Rood Profiel','\n \n Een profiel in silhouet tegen een diepe blauwe achtergrond, waarbij het gezicht intens rood oplicht. Het contrast tussen koel blauw en warm rood creëert een krachtige visuele spanning vol emotie. Dit kunstdoekje maakt een statement zonder woorden, sterk en expressief in zijn eenvoud. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2488.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk','moderne-kunst'],false,true,47216) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('botanische-symfonie','Botanische Symfonie','\n \n Een verticale compositie waar kolibries, vlinders en bloemen samenkomen tegen een neutrale achtergrond. Witte bloesems met gele harten mengen zich met bordeauxrode bloemen, terwijl bruine vlinders en kleurrijke vogels de compositie leven geven. Dit kunstdoekje brengt de rijkdom van de natuur naar binnen in een klassieke botanische stijl vol detail. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2477.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','moderne-kunst','natuur','specials'],false,true,47218) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('delicate-harmonie','Delicate Harmonie','\n \n Witte bloemen met roze accenten vormen een arrangement samen met vluchtige vlinders in zachte tinten. Een kolibrie en een pauwenveer voegen exotische elementen toe aan deze verfijnde compositie tegen een rustige grijze achtergrond. Dit kunstdoekje ademt elegantie en brengt natuurlijke schoonheid op subtiele wijze naar je interieur. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2478.webp',(select id from categories where slug='asbtract'),array['asbtract','dieren','moderne-kunst','natuur','specials'],false,true,47220) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('vlinderdroom','Vlinderdroom','\n \n Blauwe morphovlinders zweven tussen bloemen in roze, wit en paars tegen een zachte pastelachtergrond. Een kolibrie vliegt tussen de bloesems door, terwijl gouden accenten de compositie doen glanzen. Dit kunstdoekje combineert sprookjesachtige tinten met botanische details voor een dromerige uitstraling. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2480.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','moderne-kunst','natuur','specials'],false,true,47222) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('kleurrijke-sculptuur','Kleurrijke Sculptuur','\n \n Een klassiek buste getransformeerd door expressieve verfstreken in oranje, turquoise, roze en paars. Het gezicht kijkt omhoog, opgebouwd uit geometrische vlakken vol beweging en kleur. Dit kunstdoekje geeft een eigentijdse twist aan klassieke kunst en brengt energie door elke penseelstreek. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2493.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,47224) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zwevende-botaniek','Zwevende Botaniek','\n \n Kolibries, vlinders en bloemblaadjes dansen door de lucht in een compositie vol beweging. Roze, witte en paarse bloesems met gouden harten zweven tussen beige vlinders, terwijl alles lijkt gevangen in een moment van gewichtloosheid. Dit kunstdoekje brengt de luchtigheid van de lente het hele jaar door naar binnen. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2481.webp',(select id from categories where slug='dieren'),array['dieren','kleurrijk','moderne-kunst'],false,true,47226) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('moment-van-innerlijke-vrede','Moment van Innerlijke Vrede','\n \n Een vrouw met gesloten ogen en gevouwen handen in een gebaar van contemplatie, getooid met gouden oorbellen. De achtergrond combineert zachte roze, grijs en beige tinten met subtiele botanische elementen. Dit kunstdoekje creëert een rustige sfeer van bezinning en brengt sereniteit in ruimtes waar je tot jezelf wilt komen. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2511.webp',(select id from categories where slug='illustratie'),array['illustratie','moderne-kunst'],false,true,47229) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonnegroet','Zonnegroet','\n \n Een vrouw met sproeten en gesloten ogen baadt in warm zonlicht, omringd door groene bladeren en witte bloemen. Parelwitte oorbellen accentueren haar serene uitdrukking tegen een zachte achtergrond. Dit kunstdoekje straalt natuurlijke rust uit en voegt een harmonische touch toe aan je interieur zonder opdringerig te zijn. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2512.webp',(select id from categories where slug='illustratie'),array['illustratie','moderne-kunst'],false,true,47231) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stille-gezelligheid','Stille Gezelligheid','\n \n Een vrouw houdt haar oranje witte-oranje kat liefdevol vast tegen een groene gestructureerde achtergrond met geometrische vlakken. Witte madeliefjes in een terracotta pot versterken de huiselijke sfeer. Dit kunstdoekje brengt warmte en verbondenheid, perfect voor een plek in huis waar geborgenheid centraal staat. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2513.webp',(select id from categories where slug='illustratie'),array['illustratie','moderne-kunst'],false,true,47233) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('bloeiende-hoop','Bloeiende Hoop','\n \n Een vrouw houdt haar oranje witte-oranje kat liefdevol vast tegen een groene gestructureerde achtergrond met geometrische vlakken. Witte madeliefjes in een terracotta pot versterken de huiselijke sfeer. Dit kunstdoekje brengt warmte en verbondenheid, perfect voor een plek in huis waar geborgenheid centraal staat. \n \n \n \n \n \n \n \n \n \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/2514.webp',(select id from categories where slug='bloemen'),array['bloemen','kleurrijk','moderne-kunst'],false,true,47242) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('gouden-fragmenten','Gouden Fragmenten','Een vrouwengezicht opgebouwd uit abstracte vlakken in oker, bordeauxrood en aubergine. Zwarte lijnen geven structuur aan de compositie terwijl aquarelachtige verfstreken zachtheid toevoegen. Dit kunstdoekje combineert emotionele diepte met artistieke vrijheid en vraagt om aandacht zonder te overheersen.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2516.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst'],false,true,47255) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('oceaan-mozaiek','Oceaan Mozaïek','Turkoois water gefragmenteerd in geometrische vlakken, waar witte schuimkoppen een fascinerende choreografie vormen. Van diep donkerblauw tot licht turquoise stromen de tinten door elkaar. Dit kunstdoekje brengt de dynamiek van water naar binnen door een moderne lens, fris en verrassend.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2519.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','natuur'],false,true,47257) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('oranje-impuls','Oranje Impuls','Een vrouwengezicht getekend met zwarte lijnen tegen een crèmekleurige achtergrond, met felle oranje vlakken als accent. Rode lippen en minimalistische lijnen vormen een expressief portret vol persoonlijkheid. Dit kunstdoekje speelt met abstractie en herkenning, eigenzinnig en modern.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2520.webp',(select id from categories where slug='asbtract'),array['asbtract','kleurrijk'],false,true,47261) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zilveren-dromen','Zilveren Dromen','Grijstinten vormen een vrouwelijk portret tegen een gestructureerde achtergrond. Zachte penseelstreken en subtiele schaduwen creëren diepte in deze monochrome compositie. Dit kunstdoekje ademt tijdloze elegantie en brengt een gevoel van verstilde schoonheid die past in strakke, moderne interieurs.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2521.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,47263) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-charing-cross-brug','De Charing Cross Brug','Claude Monet, 1903 \n De beroemde brug over de Theems, geschilderd tijdens Monets verblijf in Londen. Hij was gefascineerd door hoe de mist en industriële rook het licht kleurden. In dit werk zie je paarse, blauwe en gouden tinten over het water, terwijl de brug zich aftekent tegen de mistige lucht. Een klassiek impressionistisch meesterwerk dat laat zien hoe Monet zelfs een stadsgezicht poëtisch wist te vangen. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2495.webp',(select id from categories where slug='asbtract'),array['asbtract','claude-monet','impressionisme','landschapmodus'],false,true,47265) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('schaduwen-op-zee-de-kliffen-bij-pourville','Schaduwen op Zee, De Kliffen bij Pourville','Claude Monet, 1882 \n De krijtrotsen van de Normandische kust in zacht ochtend- of avondlicht. Monet ving hier de subtiele overgangen tussen roze, paarse en blauwe tinten, terwijl schaduwen van wolken over het kalme water glijden. De kliffen aan de horizon vormen een rustige achtergrond bij het glinsterende zeeoppervlak. Een serene kustscène die de rust en ruimte van de Normandische kust naar je interieur brengt. \n Maten in de configurator zijn aangegeven als hoogte x breedte. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2508.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47269) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-corniche-bij-monaco','De Corniche bij Monaco','Claude Monet, 1884 \n De dramatische kustlijn van de Côte d''Azur, waar Monet de Middellandse Zee vastlegde. Blauwe golven slaan tegen rotsachtige oevers terwijl witte wolken over de hemel drijven. Een eenzame wandelaar op het kiezelstrand geeft schaal aan het landschap. Monet bracht hier de helderheid en intensiteit van het zuidelijke licht op doek, anders dan zijn mistige Normandische kustscènes. Het origineel hangt in het Rijksmuseum in Amsterdam. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2510.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47272) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-promenade-met-de-spoorwegbrug-argenteuil','De Promenade met de Spoorwegbrug, Argenteuil','Claude Monet, 1874 \n Een zomerse dag langs de Seine bij Argenteuil, waar Monet woonde en vaak schilderde. Een vrouw met parasol en kind wandelen langs de groene oever, terwijl de moderne spoorwegbrug zich uitstrekt over het water. Monet combineert hier het traditionele landschap met de nieuwe industriële werkelijkheid van zijn tijd. De levendige groene weide contrasteert met het kalme blauwe water en de wolkenlucht, typerend voor zijn Argenteuil periode. Het origineel bevindt zich in het Musée Marmottan Monet in Parijs. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2499.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47275) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-weg-naar-vetheuil','De Weg naar Vétheuil','Claude Monet, 1879 \n Een levendig landschap met een geel veld op de voorgrond en kleurrijke huizen met rode daken in het dorp Vétheuil. Fabrieksschoorstenen steken af tegen een turquoise lucht vol witte wolken. Monet woonde in deze periode in Vétheuil, een moeilijke tijd in zijn leven na het overlijden van zijn eerste vrouw. Toch toont dit werk de levendige kleuren en energie waarmee hij het landschap bleef vastleggen. Het origineel bevindt zich in het Musée d''Orsay in Parijs. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2503.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47277) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('klaprozen-veld-in-een-vallei-bij-giverny','Klaprozen Veld in een Vallei bij Giverny','Claude Monet, 1885 \n Een golvend veld vol rode klaprozen strekt zich uit voor groene heuvels en bomen. Monet was kort daarvoor naar Giverny verhuisd, het dorp waar hij de rest van zijn leven zou blijven. De klaprozen waren een terugkerend thema in zijn werk, symbool voor de Franse landelijke zomer. In dit schilderij zie je hoe hij de bloemen liet dansen tussen het geel en groen van het graanveld, met losse penseelstreken die beweging suggereren. Het origineel hangt in het Museum of Fine Arts in Boston. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2506.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47279) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-seine-bij-giverny','De Seine bij Giverny','Claude Monet, 1888 \n De rivier de Seine kronkelt door het landschap nabij Monets huis in Giverny. Zachte tinten van groen, blauw en roze weerspiegelen in het kalme water, omringd door bomen en vegetatie langs de oevers. Monet vond in Giverny zijn definitieve thuis en de Seine was een onuitputtelijke bron van inspiratie, die hij in alle seizoenen en lichtomstandigheden vastlegde. Dit werk toont zijn meesterschap in het weergeven van waterreflecties en de subtiele kleurnuances van de natuur. \n Het origineel bevindt zich in het Musée d''Orsay in Parijs.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2509.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47281) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('laag-water-bij-pourville-nabij-dieppe','Laag Water bij Pourville, nabij Dieppe','Claude Monet, 1882 \n De Normandische kust bij eb, waar het strand breed en vlak wordt. Roze en gele krijtrotsen steken af tegen het heldere blauw van zee en lucht, terwijl kleine figuren op het strand de schaal aangeven. Monet schilderde meerdere werken in Pourville tijdens zijn verblijf aan de kust, gefascineerd door het veranderende getij en licht. De horizontale compositie benadrukt de rust en ruimte van het laagtij moment. Het origineel bevindt zich in het Nationalmuseum in Stockholm. \n Maten in de configurator zijn aangegeven als hoogte x breedte','https://kunstdoekje.nl/wp-content/uploads/2025/10/2497.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47286) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tuinmanshuis-bij-antibes','Tuinmanshuis bij Antibes','Claude Monet, 1888 \n Een levendig tuinmanshuis omringd door bloeiende bomen en weelderige vegetatie aan de Côte d''Azur. Monet reisde naar het zuiden van Frankrijk en werd overweldigd door het intense licht en de felle kleuren. Roze bloesems, groene bladeren en het heldere blauw van de Middellandse Zee vormen een kleurrijk contrast met de zachte tinten van zijn Noordelijke werken. De losse penseelvoering vangt de mediterrane sfeer en het trillende licht van de regio. Het origineel hangt in het Cleveland Museum of Art. \n Maten in de configurator zijn aangegeven als hoogte x breedte.','https://kunstdoekje.nl/wp-content/uploads/2025/10/2496.webp',(select id from categories where slug='claude-monet'),array['claude-monet','impressionisme','landschapmodus'],false,true,47288) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tropical-paradise','Tropical Paradise','Ontsnap naar een tropisch strand waar turquoise golven het gouden zand raken. Dit kunstwerk brengt rust, warmte en een vleugje luxe in elke ruimte. Perfect voor wie droomt van eindeloze zomers en serene kustmomenten.','https://kunstdoekje.nl/wp-content/uploads/2025/10/Tropical-Paradise2.webp',(select id from categories where slug='impressionisme'),array['impressionisme','natuur','specials'],false,true,47591) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tuin-van-verwondering','Tuin Van Verwondering','Laat je betoveren door de ''Tuin van Verwondering''. Dit unieke fluwelen of deco kunstdoekje brengt de serene schoonheid van vliegende edelstenen en bloeiende pracht tot leven. Een visueel feest dat je interieur verrijkt met een vleugje natuurlijke magie. \n','https://kunstdoekje.nl/wp-content/uploads/2025/10/clean-and-simple-room-14.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','natuur'],false,true,47752) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('door-vele-ogen','Door vele ogen','Een explosie van perspectieven gevangen in één intens gezicht. Turquoise, oranje, roze en paars dansen over het canvas alsof Picasso en Basquiat samen aan de borrel zaten. Dit statement piece is voor wie niet bang is voor kleur en karakter. Het eist aandacht en krijgt die ook. Modern, gedurfd en onmogelijk te negeren.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2534.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,48125) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('stadsterras','Stadsterras','De energie van een zondagmiddag in de stad, gevangen in neon pink en olijfgroen. Anonieme figuren op het terras, maar het gevoel is universeel - dat moment waarop de wereld even perfect is met een drankje en goed gezelschap. Dit kunstdoek brengt urbane levendigheid in huis en doet je verlangen naar de volgende borrel met vrienden.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2528.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst'],false,true,48126) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('de-gentleman','De Gentleman','Wie zegt dat stijl alleen voor mensen is? Deze panda heeft meer klasse in zijn gouden zonnebril en vlinderdas dan de meeste mensen op een bruiloft. Perfect voor de kinderkamer, studeerkamer of overal waar je dagelijks even wil glimlachen. Dit doek ademt charme en speelsheid, en zorgt gegarandeerd voor gespreksstof bij gasten.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2538.webp',(select id from categories where slug='moderne-kunst'),array['moderne-kunst'],false,true,48127) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('onderwaterballetje','Onderwaterballetje','Een school vissen gevangen in pastelroze, lila en turquoise die door elkaar heen dansen. De dikke verflagen geven elke vis een eigen karakter en beweging. Dit kunstdoek brengt rust en flow in huis, ideaal voor de slaapkamer, badkamer of overal waar je even wilt wegdromen in de onderwaterwereld.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2541.webp',(select id from categories where slug='impasto'),array['impasto','kleurrijk'],false,true,48129) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('eerste-sneeuw','Eerste Sneeuw','Die magische ochtend waarop alles bedekt is met een deken van verse sneeuw en het rode hutje zijn warmte uitstraalt. De dikke verfstreken geven dit werk een tactiele kwaliteit die je bijna de kou kan voelen. Perfect voor wie van wintersport houdt of gewoon verlangt naar die knusse hut in de bergen waar de chocolademelk al klaar staat.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2540.webp',(select id from categories where slug='impasto'),array['impasto'],false,true,48130) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('balans','Balans','Geometrische vormen gestapeld als een abstract bouwwerk in aardse tinten. Dit werk speelt met textuur, vorm en negatieve ruimte op een manier die minimalisme combineert met warmte. Voor de liefhebber van Scandinavisch design en architectuur die houdt van kunst die subtiel statement maakt zonder te schreeuwen.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2548.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,48140) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('sprookjesdorp','Sprookjesdorp','Een urban skyline die oplost in blauwe nevel en gouden lichtflitsen. Abstractie ontmoet architectuur in een moderne compositie die zowel rustig als dynamisch is. Perfect voor het moderne interieur waar je iets wil ophangen dat net zo goed in een New Yorkse loft zou passen als in een Nederlandse stadswoning.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2545.webp',(select id from categories where slug='impasto'),array['impasto'],false,true,48145) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('apres-ski-droom','Après-ski Droom','Het perfecte skigebied zoals het alleen in je herinnering bestaat. Kleine chalets met warme lichtjes, gouden dennenbomen en een levendig tafereel van skiërs die hun dag beleven. Dit doek brengt vakantiegevoel het hele jaar door, ook als de dichtstbijzijnde berg drie landen verderop is.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2542.webp',(select id from categories where slug='impasto'),array['impasto'],false,true,48146) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('verwachting','Verwachting','Serene elegantie met een vleugje speelsheid door die vrolijke bloemenoorbellen. De zachte pasteltinten en vintage feel maken dit kunstwerk tijdloos, terwijl de gesloten ogen iets mysterieus bewaren. Als een stille belofte aan mooie dingen die komen gaan. Past prachtig in moderne interieurs die warmte en karakter zoeken.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2549.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,48150) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('baadster-in-goud','Baadster in Goud','Dramatische schoonheid ontmoet vintage glamour in deze krachtige compositie. De witte tulband en gouden oorbellen tegen die donkere achtergrond maken dit een statement piece dat niet om subtiliteit vraagt. Voor wie niet bang is voor een beetje theater aan de muur en zelfvertrouwen uitstraalt in elke kamer.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2550.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,49125) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zonnegloed','Zonnegloed','Een moment van pure rust gevangen in warme tinten goud en roze. Ze heeft haar ogen gesloten en geniet van dat eerste kopje koffie op een zondagochtend, terwijl de wereld nog even stil staat. Dit kunstwerk straalt gezelligheid en zachtheid uit, perfect voor de slaapkamer of leeshoek waar je zelf even wil wegdromen.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2551.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,49126) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('zomerkrans','Zomerkrans','Als een zachte zomerbries bloemen in je haar legt en je er moeiteloos mooi uitziet. Die directe blik trekt je meteen het canvas in, terwijl de roze en oranje bloemen feest vieren tegen die ingetogen achtergrond. Perfect voor wie houdt van romantiek zonder zoetsappigheid en karakter zonder bombarie.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2555.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,49146) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('aperitivo','Aperitivo','Die gelukkige limbo tussen werk en weekend, wanneer het eerste glas wijn precies goed smaakt en de wereld even mag wachten. De warme gouden tinten en die oversized oorbellen schreeuwen sophistication zonder moeite. Voor de eethoek, keuken of elke plek waar je graag proost op het goede leven.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2553.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,49147) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('lentedag','Lentedag','Onschuld en vrolijkheid gevangen in zachte lijnen en warme kleuren. Die bloemenoorbellen en het gestreepte truitje met geborduurde veldbloemen voelen als een zondagmiddag in de lente. Dit lieve portret past perfect in de kinderkamer, maar is ook stylish genoeg voor volwassen ruimtes die warmte en speelsheid zoeken.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2557.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,49150) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tuingeheimen','Tuingeheimen','Alsof je door een zachte ochtendmist naar een verborgen tuin kijkt waar een vogel rust tussen wilde dahlia''s en lavendel. Dit dromerige stilleven heeft iets magisch en breekbaars, perfect voor wie houdt van bloemen maar niet van klassieke stijfheid. Een kunstwerk dat fluistert in plaats van schreeuwt.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2556.webp',(select id from categories where slug='dieren'),array['dieren','moderne-kunst'],false,true,49151) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('poolside-attitude','Poolside Attitude','Zelfverzekerdheid in verf gegoten, met die oversized zonnebril en fuchsia lippen die niet om toestemming vragen. De explosieve kleurcombinaties van turquoise, oranje en geel maken dit een kunstwerk voor wie graag opvalt en niet bang is voor een beetje drama. Statement piece voor moderne interieurs met lef.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2559.webp',(select id from categories where slug='kleurrijk'),array['kleurrijk','moderne-kunst'],false,true,49154) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('tropisch-ritueel','Tropisch Ritueel','Dat perfecte moment tussen werk en weekend, wanneer je je eerste koffie in alle rust nuttigt onder een monstera schaduw. De zachte roze tinten en minimalistische compositie ademen pure rust en lifestyle goals. Dit kunstwerk past in elke moderne keuken of thuiswerkplek die vakantievibes nodig heeft zonder het huis uit te gaan.','https://kunstdoekje.nl/wp-content/uploads/2025/11/2560.webp',(select id from categories where slug='asbtract'),array['asbtract','moderne-kunst'],false,true,49156) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
insert into artworks (slug,titel,beschrijving,image_url,category_id,tags,is_featured,is_active,woo_id) values ('frame','Frame','','https://kunstdoekje.nl/wp-content/uploads/2025/11/Frames_.webp',(select id from categories where slug='lose-frame'),array['lose-frame'],false,true,49329) on conflict (slug) do update set titel=excluded.titel,image_url=excluded.image_url,beschrijving=excluded.beschrijving,category_id=excluded.category_id,tags=excluded.tags,is_active=excluded.is_active;
